{
  "name": "羽球社财务助手",
  "description": "一个专为羽毛球俱乐部设计的财务统计工具，支持结算周期管理、人员档案管理、打球记录统计及集资包月人员的盈余结算。",
  "requestFramePermissions": []
}

export enum PlayerType {
  MONTHLY = '包月',
  HALF_MONTHLY = '包半月',
  PER_SESSION = '按次'
}

export interface Player {
  id: string;
  name: string;
  type: PlayerType;
  defaultFee: number;
  isFunder: boolean;
}

export interface Session {
  id: string;
  date: string;
  attendees: {
    playerId: string;
    fee: number;
  }[];
}

export interface Period {
  id: string;
  name: string;
  startDate: string;
  endDate: string;
  courtCost: number; // 场地总成本
  sessions: Session[];
}

export type View = 'dashboard' | 'players' | 'periods' | 'finance';

import React from 'react';

export const DEFAULT_SESSION_FEE = 12;

export const INITIAL_FUNDERS = [
  "张三", "李四", "王五", "赵六", "孙七", "周八", "吴九", "郑十", "陈十一", "林十二"
].map((name, index) => ({
  id: `funder-${index}`,
  name,
  type: '包月' as any,
  defaultFee: 0,
  isFunder: true
}));

export const Icons = {
  Home: () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6" />
    </svg>
  ),
  Users: () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" />
    </svg>
  ),
  Calendar: () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" />
    </svg>
  ),
  Chart: () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" />
    </svg>
  ),
  Plus: () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
    </svg>
  ),
  Trash: () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
    </svg>
  )
};

import React, { useState, useEffect, useMemo } from 'react';
import { Player, Period, View, PlayerType } from './types';
import { INITIAL_FUNDERS, Icons, DEFAULT_SESSION_FEE } from './constants';
import Dashboard from './components/Dashboard';
import PlayersList from './components/PlayersList';
import PeriodsList from './components/PeriodsList';
import FinanceReport from './components/FinanceReport';

const App: React.FC = () => {
  const [view, setView] = useState<View>('dashboard');
  const [players, setPlayers] = useState<Player[]>(() => {
    const saved = localStorage.getItem('badminton_players');
    return saved ? JSON.parse(saved) : INITIAL_FUNDERS;
  });
  const [periods, setPeriods] = useState<Period[]>(() => {
    const saved = localStorage.getItem('badminton_periods');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('badminton_players', JSON.stringify(players));
  }, [players]);

  useEffect(() => {
    localStorage.setItem('badminton_periods', JSON.stringify(periods));
  }, [periods]);

  const activePeriod = useMemo(() => {
    return periods.length > 0 ? periods[periods.length - 1] : null;
  }, [periods]);

  const renderView = () => {
    switch (view) {
      case 'dashboard':
        return <Dashboard players={players} periods={periods} activePeriod={activePeriod} />;
      case 'players':
        return <PlayersList players={players} setPlayers={setPlayers} />;
      case 'periods':
        return <PeriodsList periods={periods} setPeriods={setPeriods} players={players} />;
      case 'finance':
        return <FinanceReport periods={periods} players={players} />;
      default:
        return <Dashboard players={players} periods={periods} activePeriod={activePeriod} />;
    }
  };

  return (
    <div className="flex flex-col h-screen max-w-md mx-auto bg-gray-50">
      {/* Header */}
      <header className="bg-emerald-600 text-white p-4 shadow-md sticky top-0 z-50">
        <h1 className="text-xl font-bold flex items-center">
          <span className="mr-2">🏸</span>
          羽球社财务助手
        </h1>
      </header>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto pb-20">
        {renderView()}
      </main>

      {/* Tab Bar (WeChat Style) */}
      <nav className="fixed bottom-0 left-0 right-0 max-w-md mx-auto bg-white border-t border-gray-200 flex justify-around py-2 px-1 z-50">
        <button 
          onClick={() => setView('dashboard')}
          className={`flex flex-col items-center flex-1 py-1 transition-colors ${view === 'dashboard' ? 'text-emerald-600' : 'text-gray-400'}`}
        >
          <Icons.Home />
          <span className="text-xs mt-1 font-medium">首页</span>
        </button>
        <button 
          onClick={() => setView('players')}
          className={`flex flex-col items-center flex-1 py-1 transition-colors ${view === 'players' ? 'text-emerald-600' : 'text-gray-400'}`}
        >
          <Icons.Users />
          <span className="text-xs mt-1 font-medium">人员</span>
        </button>
        <button 
          onClick={() => setView('periods')}
          className={`flex flex-col items-center flex-1 py-1 transition-colors ${view === 'periods' ? 'text-emerald-600' : 'text-gray-400'}`}
        >
          <Icons.Calendar />
          <span className="text-xs mt-1 font-medium">结算周期</span>
        </button>
        <button 
          onClick={() => setView('finance')}
          className={`flex flex-col items-center flex-1 py-1 transition-colors ${view === 'finance' ? 'text-emerald-600' : 'text-gray-400'}`}
        >
          <Icons.Chart />
          <span className="text-xs mt-1 font-medium">财务</span>
        </button>
      </nav>
    </div>
  );
};

export default App;

import React from 'react';
import { Player, Period } from '../types';

interface DashboardProps {
  players: Player[];
  periods: Period[];
  activePeriod: Period | null;
}

const Dashboard: React.FC<DashboardProps> = ({ players, periods, activePeriod }) => {
  const totalIncome = activePeriod?.sessions.reduce((acc, s) => acc + s.attendees.reduce((sum, a) => sum + a.fee, 0), 0) || 0;
  const courtCost = activePeriod?.courtCost || 0;
  const surplus = totalIncome - courtCost;
  const funderCount = players.filter(p => p.isFunder).length;
  const perFunderSurplus = funderCount > 0 ? surplus / funderCount : 0;

  return (
    <div className="p-4 space-y-4">
      {/* Active Period Summary Card */}
      <div className="bg-white rounded-2xl p-5 shadow-sm border border-gray-100">
        <div className="flex justify-between items-center mb-4">
          <h2 className="text-lg font-bold text-gray-800">当前周期概览</h2>
          <span className="text-xs bg-emerald-100 text-emerald-700 px-2 py-1 rounded-full font-bold">
            {activePeriod?.name || '无活跃周期'}
          </span>
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div className="bg-blue-50 p-4 rounded-xl">
            <p className="text-xs text-blue-600 mb-1">本期总收入</p>
            <p className="text-2xl font-black text-blue-700">¥{totalIncome.toFixed(2)}</p>
          </div>
          <div className="bg-red-50 p-4 rounded-xl">
            <p className="text-xs text-red-600 mb-1">场地费成本</p>
            <p className="text-2xl font-black text-red-700">¥{courtCost.toFixed(2)}</p>
          </div>
        </div>

        <div className="mt-4 p-4 bg-emerald-50 rounded-xl border border-emerald-100">
          <p className="text-xs text-emerald-600 mb-1">可分配盈余</p>
          <p className="text-3xl font-black text-emerald-700">¥{surplus.toFixed(2)}</p>
          <div className="mt-2 text-xs text-emerald-600 flex justify-between">
            <span>集资人数：{funderCount}人</span>
            <span>人均返现：¥{perFunderSurplus.toFixed(2)}</span>
          </div>
        </div>
      </div>

      {/* Quick Stats */}
      <div className="grid grid-cols-2 gap-4">
        <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100 flex flex-col items-center">
          <p className="text-2xl mb-1">👥</p>
          <p className="text-xs text-gray-500">成员档案</p>
          <p className="text-lg font-bold">{players.length} 位</p>
        </div>
        <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100 flex flex-col items-center">
          <p className="text-2xl mb-1">🗓️</p>
          <p className="text-xs text-gray-500">结算历史</p>
          <p className="text-lg font-bold">{periods.length} 期</p>
        </div>
      </div>

      {/* Helpful Tips */}
      <div className="bg-orange-50 p-4 rounded-2xl border border-orange-100">
        <h3 className="text-sm font-bold text-orange-800 mb-1">💡 财务提示</h3>
        <p className="text-xs text-orange-700 leading-relaxed">
          每次打球后请及时录入报名名单和费用。包月、包半月成员通常在周期开始前确认，按次成员则每场单独结算。
        </p>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { Player, PlayerType } from '../types';
import { Icons, DEFAULT_SESSION_FEE } from '../constants';

interface PlayersListProps {
  players: Player[];
  setPlayers: React.Dispatch<React.SetStateAction<Player[]>>;
}

const PlayersList: React.FC<PlayersListProps> = ({ players, setPlayers }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState<Partial<Player>>({
    name: '',
    type: PlayerType.PER_SESSION,
    defaultFee: DEFAULT_SESSION_FEE,
    isFunder: false
  });

  const handleSave = () => {
    if (!formData.name) return;

    if (editingId) {
      setPlayers(prev => prev.map(p => p.id === editingId ? { ...p, ...formData } as Player : p));
      setEditingId(null);
    } else {
      const newPlayer: Player = {
        id: Date.now().toString(),
        name: formData.name!,
        type: formData.type as PlayerType || PlayerType.PER_SESSION,
        defaultFee: formData.defaultFee || 0,
        isFunder: false // New players are never funders as requested
      };
      setPlayers(prev => [...prev, newPlayer]);
      setIsAdding(false);
    }
    setFormData({ name: '', type: PlayerType.PER_SESSION, defaultFee: DEFAULT_SESSION_FEE, isFunder: false });
  };

  const startEdit = (player: Player) => {
    setEditingId(player.id);
    setFormData(player);
  };

  const handleDelete = (id: string) => {
    if (confirm('确定要删除该人员吗？')) {
      setPlayers(prev => prev.filter(p => p.id !== id));
    }
  };

  return (
    <div className="p-4">
      <div className="flex justify-between items-center mb-4">
        <h2 className="text-lg font-bold">人员档案</h2>
        <button 
          onClick={() => setIsAdding(true)}
          className="bg-emerald-600 text-white px-3 py-1.5 rounded-lg text-sm flex items-center gap-1 font-bold shadow-sm"
        >
          <Icons.Plus /> 新增人员
        </button>
      </div>

      {(isAdding || editingId) && (
        <div className="mb-6 bg-white p-4 rounded-xl shadow-sm border-2 border-emerald-500">
          <h3 className="font-bold mb-4">{editingId ? '编辑人员' : '添加新成员'}</h3>
          <div className="space-y-4">
            <div>
              <label className="block text-xs text-gray-500 mb-1">姓名</label>
              <input 
                type="text" 
                value={formData.name}
                onChange={e => setFormData({ ...formData, name: e.target.value })}
                className="w-full border border-gray-300 rounded-lg p-2 text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500"
                placeholder="请输入姓名"
              />
            </div>
            <div>
              <label className="block text-xs text-gray-500 mb-1">人员类型</label>
              <select 
                value={formData.type}
                onChange={e => {
                   const type = e.target.value as PlayerType;
                   setFormData({ ...formData, type, defaultFee: type === PlayerType.PER_SESSION ? DEFAULT_SESSION_FEE : 0 });
                }}
                className="w-full border border-gray-300 rounded-lg p-2 text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500"
              >
                <option value={PlayerType.MONTHLY}>包月</option>
                <option value={PlayerType.HALF_MONTHLY}>包半月</option>
                <option value={PlayerType.PER_SESSION}>按次</option>
              </select>
            </div>
            <div>
              <label className="block text-xs text-gray-500 mb-1">默认收费金额 (元)</label>
              <input 
                type="number" 
                value={formData.defaultFee}
                onChange={e => setFormData({ ...formData, defaultFee: Number(e.target.value) })}
                className="w-full border border-gray-300 rounded-lg p-2 text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500"
              />
            </div>
            {editingId && (
               <div className="flex items-center gap-2">
                 <input 
                   type="checkbox" 
                   checked={formData.isFunder}
                   onChange={e => setFormData({ ...formData, isFunder: e.target.checked })}
                   id="isFunder"
                 />
                 <label htmlFor="isFunder" className="text-sm text-gray-600">是否为集资成员 (10人名单)</label>
               </div>
            )}
            <div className="flex gap-2 pt-2">
              <button 
                onClick={handleSave}
                className="flex-1 bg-emerald-600 text-white py-2 rounded-lg font-bold text-sm"
              >
                保存
              </button>
              <button 
                onClick={() => { setIsAdding(false); setEditingId(null); }}
                className="flex-1 bg-gray-200 text-gray-600 py-2 rounded-lg font-bold text-sm"
              >
                取消
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="space-y-3">
        {players.map(player => (
          <div key={player.id} className={`bg-white p-3 rounded-xl shadow-sm border flex justify-between items-center ${player.isFunder ? 'border-amber-200' : 'border-gray-100'}`}>
            <div>
              <div className="flex items-center gap-2">
                <span className="font-bold text-gray-800">{player.name}</span>
                {player.isFunder && (
                  <span className="text-[10px] bg-amber-100 text-amber-700 px-1.5 py-0.5 rounded-full font-bold">集资人</span>
                )}
              </div>
              <div className="text-xs text-gray-500 mt-0.5 flex items-center gap-2">
                <span className={`px-1.5 py-0.5 rounded ${
                  player.type === PlayerType.MONTHLY ? 'bg-purple-50 text-purple-600' :
                  player.type === PlayerType.HALF_MONTHLY ? 'bg-blue-50 text-blue-600' :
                  'bg-green-50 text-green-600'
                }`}>{player.type}</span>
                <span>默认收费: ¥{player.defaultFee}</span>
              </div>
            </div>
            <div className="flex gap-3">
              <button onClick={() => startEdit(player)} className="text-emerald-600 text-sm font-medium">编辑</button>
              <button onClick={() => handleDelete(player.id)} className="text-red-400">
                <Icons.Trash />
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default PlayersList;

import React, { useState } from 'react';
import { Period, Player, Session, PlayerType } from '../types';
import { Icons, DEFAULT_SESSION_FEE } from '../constants';

interface PeriodsListProps {
  periods: Period[];
  setPeriods: React.Dispatch<React.SetStateAction<Period[]>>;
  players: Player[];
}

const PeriodsList: React.FC<PeriodsListProps> = ({ periods, setPeriods, players }) => {
  const [isAddingPeriod, setIsAddingPeriod] = useState(false);
  const [expandedPeriodId, setExpandedPeriodId] = useState<string | null>(null);
  const [activeSessionPeriod, setActiveSessionPeriod] = useState<string | null>(null);

  const [newPeriod, setNewPeriod] = useState<Partial<Period>>({
    name: '',
    startDate: new Date().toISOString().split('T')[0],
    endDate: '',
    courtCost: 0,
    sessions: []
  });

  const [newSessionDate, setNewSessionDate] = useState(new Date().toISOString().split('T')[0]);
  const [selectedAttendees, setSelectedAttendees] = useState<{playerId: string, fee: number}[]>([]);

  const handleSavePeriod = () => {
    if (!newPeriod.name) return;
    const period: Period = {
      id: Date.now().toString(),
      name: newPeriod.name!,
      startDate: newPeriod.startDate!,
      endDate: newPeriod.endDate || '',
      courtCost: newPeriod.courtCost || 0,
      sessions: []
    };
    setPeriods(prev => [...prev, period]);
    setIsAddingPeriod(false);
    setNewPeriod({ name: '', startDate: new Date().toISOString().split('T')[0], courtCost: 0, sessions: [] });
  };

  const deletePeriod = (id: string) => {
    if (confirm('确定要删除该结算周期吗？删除后所有打球记录将消失。')) {
      setPeriods(prev => prev.filter(p => p.id !== id));
    }
  };

  const addSession = (periodId: string) => {
    if (selectedAttendees.length === 0) {
      alert('请选择至少一名打球成员');
      return;
    }
    const session: Session = {
      id: Date.now().toString(),
      date: newSessionDate,
      attendees: selectedAttendees
    };
    setPeriods(prev => prev.map(p => p.id === periodId ? { ...p, sessions: [...p.sessions, session] } : p));
    setActiveSessionPeriod(null);
    setSelectedAttendees([]);
  };

  const removeSession = (periodId: string, sessionId: string) => {
    setPeriods(prev => prev.map(p => p.id === periodId ? { ...p, sessions: p.sessions.filter(s => s.id !== sessionId) } : p));
  };

  const toggleAttendee = (player: Player) => {
    const exists = selectedAttendees.find(a => a.playerId === player.id);
    if (exists) {
      setSelectedAttendees(prev => prev.filter(a => a.playerId !== player.id));
    } else {
      setSelectedAttendees(prev => [...prev, { playerId: player.id, fee: player.defaultFee }]);
    }
  };

  return (
    <div className="p-4">
      <div className="flex justify-between items-center mb-4">
        <h2 className="text-lg font-bold">结算周期</h2>
        <button 
          onClick={() => setIsAddingPeriod(true)}
          className="bg-emerald-600 text-white px-3 py-1.5 rounded-lg text-sm flex items-center gap-1 font-bold shadow-sm"
        >
          <Icons.Plus /> 新增周期
        </button>
      </div>

      {isAddingPeriod && (
        <div className="mb-6 bg-white p-4 rounded-xl shadow-sm border-2 border-emerald-500">
          <h3 className="font-bold mb-4">创建新周期</h3>
          <div className="space-y-3">
            <input 
              type="text" 
              placeholder="周期名称 (如: 2024年3月)" 
              value={newPeriod.name}
              onChange={e => setNewPeriod({...newPeriod, name: e.target.value})}
              className="w-full border border-gray-300 rounded-lg p-2 text-sm"
            />
            <div className="flex gap-2">
              <input 
                type="date" 
                value={newPeriod.startDate}
                onChange={e => setNewPeriod({...newPeriod, startDate: e.target.value})}
                className="flex-1 border border-gray-300 rounded-lg p-2 text-sm"
              />
              <input 
                type="date" 
                placeholder="结束日期"
                value={newPeriod.endDate}
                onChange={e => setNewPeriod({...newPeriod, endDate: e.target.value})}
                className="flex-1 border border-gray-300 rounded-lg p-2 text-sm"
              />
            </div>
            <input 
              type="number" 
              placeholder="场地总成本 (元)" 
              value={newPeriod.courtCost || ''}
              onChange={e => setNewPeriod({...newPeriod, courtCost: Number(e.target.value)})}
              className="w-full border border-gray-300 rounded-lg p-2 text-sm"
            />
            <div className="flex gap-2 pt-2">
              <button onClick={handleSavePeriod} className="flex-1 bg-emerald-600 text-white py-2 rounded-lg font-bold text-sm">保存</button>
              <button onClick={() => setIsAddingPeriod(false)} className="flex-1 bg-gray-200 text-gray-600 py-2 rounded-lg font-bold text-sm">取消</button>
            </div>
          </div>
        </div>
      )}

      <div className="space-y-4">
        {periods.map(period => (
          <div key={period.id} className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
            <div 
              className="p-4 flex justify-between items-center cursor-pointer hover:bg-gray-50"
              onClick={() => setExpandedPeriodId(expandedPeriodId === period.id ? null : period.id)}
            >
              <div>
                <h3 className="font-bold text-gray-800">{period.name}</h3>
                <p className="text-[10px] text-gray-400 mt-1">{period.startDate} 至 {period.endDate || '未定'}</p>
              </div>
              <div className="flex items-center gap-3">
                <div className="text-right">
                  <p className="text-xs text-gray-500">本期次数</p>
                  <p className="font-bold text-emerald-600">{period.sessions.length}</p>
                </div>
                <button onClick={(e) => { e.stopPropagation(); deletePeriod(period.id); }} className="text-gray-300 hover:text-red-400">
                  <Icons.Trash />
                </button>
              </div>
            </div>

            {expandedPeriodId === period.id && (
              <div className="border-t border-gray-100 bg-gray-50 p-4 space-y-4">
                {/* Session Records */}
                <div className="space-y-3">
                  <div className="flex justify-between items-center">
                    <h4 className="text-sm font-bold text-gray-600">打球记录</h4>
                    <button 
                      onClick={() => setActiveSessionPeriod(period.id)}
                      className="text-xs bg-emerald-100 text-emerald-700 px-2 py-1 rounded font-bold"
                    >
                      + 录入打球
                    </button>
                  </div>

                  {activeSessionPeriod === period.id && (
                    <div className="bg-white p-3 rounded-lg border-2 border-emerald-200 shadow-sm animate-in fade-in duration-300">
                      <p className="text-xs font-bold text-gray-500 mb-2 uppercase">录入本次打球</p>
                      <input 
                        type="date" 
                        value={newSessionDate}
                        onChange={e => setNewSessionDate(e.target.value)}
                        className="w-full border border-gray-300 rounded-lg p-2 text-sm mb-3"
                      />
                      <p className="text-xs text-gray-400 mb-2">选择出席人员:</p>
                      <div className="flex flex-wrap gap-2 max-h-40 overflow-y-auto p-2 border border-gray-100 rounded-lg mb-3">
                        {players.map(p => {
                          const isSelected = selectedAttendees.find(a => a.playerId === p.id);
                          return (
                            <button 
                              key={p.id}
                              onClick={() => toggleAttendee(p)}
                              className={`text-xs px-2 py-1 rounded-full border transition-all ${
                                isSelected ? 'bg-emerald-600 border-emerald-600 text-white shadow-sm' : 'bg-gray-50 border-gray-200 text-gray-600'
                              }`}
                            >
                              {p.name}
                            </button>
                          );
                        })}
                      </div>

                      {selectedAttendees.length > 0 && (
                        <div className="mb-3 space-y-1">
                          <p className="text-[10px] text-gray-400">已选金额调整 (默认自动填充):</p>
                          {selectedAttendees.map(a => {
                            const player = players.find(p => p.id === a.playerId);
                            return (
                              <div key={a.playerId} className="flex justify-between items-center bg-gray-50 p-1.5 rounded text-[11px]">
                                <span>{player?.name}</span>
                                <input 
                                  type="number" 
                                  value={a.fee}
                                  onChange={e => {
                                    const val = Number(e.target.value);
                                    setSelectedAttendees(prev => prev.map(sa => sa.playerId === a.playerId ? {...sa, fee: val} : sa));
                                  }}
                                  className="w-12 border rounded px-1"
                                />
                              </div>
                            );
                          })}
                        </div>
                      )}

                      <div className="flex gap-2">
                        <button onClick={() => addSession(period.id)} className="flex-1 bg-emerald-600 text-white py-1.5 rounded font-bold text-xs">确认录入</button>
                        <button onClick={() => setActiveSessionPeriod(null)} className="flex-1 bg-gray-200 text-gray-600 py-1.5 rounded font-bold text-xs">取消</button>
                      </div>
                    </div>
                  )}

                  {period.sessions.length === 0 ? (
                    <p className="text-center text-xs text-gray-400 py-4 italic">暂无记录</p>
                  ) : (
                    period.sessions.map(session => (
                      <div key={session.id} className="bg-white p-3 rounded-lg shadow-sm border border-gray-100 flex justify-between items-center">
                        <div>
                          <p className="text-xs font-bold text-gray-700">{session.date}</p>
                          <p className="text-[10px] text-gray-500 mt-0.5 truncate max-w-[180px]">
                            {session.attendees.map(a => players.find(p => p.id === a.playerId)?.name).join(', ')}
                          </p>
                        </div>
                        <div className="flex items-center gap-2">
                          <div className="text-right">
                            <p className="text-[10px] text-gray-400">收费额</p>
                            <p className="text-xs font-bold text-emerald-600">¥{session.attendees.reduce((sum, a) => sum + a.fee, 0)}</p>
                          </div>
                          <button onClick={() => removeSession(period.id, session.id)} className="text-gray-300 ml-1">
                            <Icons.Trash />
                          </button>
                        </div>
                      </div>
                    ))
                  )}
                </div>
              </div>
            )}
          </div>
        ))}
        {periods.length === 0 && (
          <div className="text-center py-20 text-gray-400">
            <p className="text-4xl mb-4 opacity-20">📅</p>
            <p className="text-sm">点击右上角“新增周期”开始管理</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default PeriodsList;

import React from 'react';
import { Period, Player, PlayerType } from '../types';

interface FinanceReportProps {
  periods: Period[];
  players: Player[];
}

const FinanceReport: React.FC<FinanceReportProps> = ({ periods, players }) => {
  const funders = players.filter(p => p.isFunder);

  const calculatePeriodStats = (period: Period) => {
    const totalIncome = period.sessions.reduce((acc, s) => acc + s.attendees.reduce((sum, a) => sum + a.fee, 0), 0);
    const courtCost = period.courtCost;
    const surplus = totalIncome - courtCost;
    const perFunderSurplus = funders.length > 0 ? surplus / funders.length : 0;
    return { totalIncome, courtCost, surplus, perFunderSurplus };
  };

  return (
    <div className="p-4">
      <h2 className="text-lg font-bold mb-4">财务统计报表</h2>

      {periods.length === 0 ? (
        <div className="text-center py-20 text-gray-400">
          <p className="text-4xl mb-4 opacity-20">📊</p>
          <p className="text-sm">暂无结算数据</p>
        </div>
      ) : (
        <div className="space-y-6">
          {/* Funder Roster */}
          <div className="bg-amber-50 rounded-2xl p-4 border border-amber-100">
            <h3 className="text-sm font-bold text-amber-800 mb-2 flex items-center gap-1">
              ✨ 集资包月人员名单 (共{funders.length}人)
            </h3>
            <div className="flex flex-wrap gap-2">
              {funders.map(f => (
                <span key={f.id} className="text-xs bg-white border border-amber-200 text-amber-700 px-2 py-1 rounded-lg">
                  {f.name}
                </span>
              ))}
            </div>
            <p className="text-[10px] text-amber-600 mt-3 leading-relaxed">
              * 集资成员负责提前支付场地预订费用，盈余部分将平均分配给以上成员。
            </p>
          </div>

          {/* Period Breakdown */}
          {periods.slice().reverse().map(period => {
            const stats = calculatePeriodStats(period);
            return (
              <div key={period.id} className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
                <div className="bg-gray-50 px-4 py-3 border-b border-gray-100 flex justify-between items-center">
                  <span className="font-bold text-gray-800">{period.name} 财务明细</span>
                  <span className="text-[10px] text-gray-400 font-medium">结算完成</span>
                </div>

                <div className="p-4 space-y-4">
                  <div className="grid grid-cols-2 gap-x-8 gap-y-4">
                    <div>
                      <p className="text-[10px] text-gray-400 uppercase tracking-wider">总收入</p>
                      <p className="text-lg font-black text-emerald-600">¥{stats.totalIncome.toFixed(2)}</p>
                    </div>
                    <div>
                      <p className="text-[10px] text-gray-400 uppercase tracking-wider">场地支出</p>
                      <p className="text-lg font-black text-red-500">¥{stats.courtCost.toFixed(2)}</p>
                    </div>
                    <div>
                      <p className="text-[10px] text-gray-400 uppercase tracking-wider">总盈余</p>
                      <p className="text-lg font-black text-blue-600">¥{stats.surplus.toFixed(2)}</p>
                    </div>
                    <div>
                      <p className="text-[10px] text-gray-400 uppercase tracking-wider">每人分红</p>
                      <p className="text-lg font-black text-amber-500">¥{stats.perFunderSurplus.toFixed(2)}</p>
                    </div>
                  </div>

                  <div className="border-t border-dashed border-gray-100 pt-3">
                    <p className="text-xs font-bold text-gray-500 mb-2">打球人员明细 ({period.sessions.length}场次):</p>
                    <div className="space-y-1 max-h-40 overflow-y-auto pr-1">
                      {/* Unique attendees and their total contribution */}
                      {Array.from(new Set(period.sessions.flatMap(s => s.attendees.map(a => a.playerId))))
                        .map(pid => {
                          const player = players.find(p => p.id === pid);
                          const totalPaid = period.sessions.reduce((sum, s) => {
                             const att = s.attendees.find(a => a.playerId === pid);
                             return sum + (att ? att.fee : 0);
                          }, 0);
                          const attendCount = period.sessions.filter(s => s.attendees.some(a => a.playerId === pid)).length;
                          return (
                            <div key={pid} className="flex justify-between items-center text-[11px] py-1 border-b border-gray-50 last:border-0">
                              <span className="text-gray-600">
                                {player?.name} 
                                <span className="text-[9px] text-gray-400 ml-1">({player?.type} · {attendCount}次)</span>
                              </span>
                              <span className="font-bold">¥{totalPaid.toFixed(2)}</span>
                            </div>
                          );
                        })}
                    </div>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

export default FinanceReport;

