import React, { useState } from 'react';
import { Period, Player, Session, PlayerType } from '../types';
import { Icons, DEFAULT_SESSION_FEE } from '../constants';

interface PeriodsListProps {
  periods: Period[];
  setPeriods: React.Dispatch<React.SetStateAction<Period[]>>;
  players: Player[];
}

const PeriodsList: React.FC<PeriodsListProps> = ({ periods, setPeriods, players }) => {
  const [isAddingPeriod, setIsAddingPeriod] = useState(false);
  const [editingPeriodId, setEditingPeriodId] = useState<string | null>(null);
  const [expandedPeriodId, setExpandedPeriodId] = useState<string | null>(null);
  const [activeSessionPeriod, setActiveSessionPeriod] = useState<string | null>(null);

  const initialPeriodData = {
    name: '',
    startDate: new Date().toISOString().split('T')[0],
    endDate: '',
    courtCost: 0,
    funderIds: players.filter(p => p.isFunder).map(p => p.id),
    sessions: []
  };

  const [periodFormData, setPeriodFormData] = useState<Partial<Period>>(initialPeriodData);

  const [newSessionDate, setNewSessionDate] = useState(new Date().toISOString().split('T')[0]);
  const [selectedAttendees, setSelectedAttendees] = useState<{playerId: string, fee: number}[]>([]);

  const handleSavePeriod = () => {
    if (!periodFormData.name) return;

    if (editingPeriodId) {
      setPeriods(prev => prev.map(p => p.id === editingPeriodId ? { ...p, ...periodFormData } as Period : p));
      setEditingPeriodId(null);
    } else {
      const period: Period = {
        id: Date.now().toString(),
        name: periodFormData.name!,
        startDate: periodFormData.startDate!,
        endDate: periodFormData.endDate || '',
        courtCost: periodFormData.courtCost || 0,
        funderIds: periodFormData.funderIds || [],
        sessions: []
      };
      setPeriods(prev => [...prev, period]);
      setIsAddingPeriod(false);
    }
    setPeriodFormData(initialPeriodData);
  };

  const startEditPeriod = (e: React.MouseEvent, period: Period) => {
    e.stopPropagation();
    setEditingPeriodId(period.id);
    setPeriodFormData(period);
  };

  const deletePeriod = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (confirm('确定要删除该结算周期吗？删除后所有打球记录将消失。')) {
      setPeriods(prev => prev.filter(p => p.id !== id));
    }
  };

  const toggleFunderSelection = (funderId: string) => {
    const current = periodFormData.funderIds || [];
    if (current.includes(funderId)) {
      setPeriodFormData({...periodFormData, funderIds: current.filter(id => id !== funderId)});
    } else {
      setPeriodFormData({...periodFormData, funderIds: [...current, funderId]});
    }
  };

  const addSession = (periodId: string) => {
    if (selectedAttendees.length === 0) {
      alert('请选择至少一名打球成员');
      return;
    }
    const session: Session = {
      id: Date.now().toString(),
      date: newSessionDate,
      attendees: selectedAttendees
    };
    setPeriods(prev => prev.map(p => p.id === periodId ? { ...p, sessions: [...p.sessions, session] } : p));
    setActiveSessionPeriod(null);
    setSelectedAttendees([]);
  };

  const removeSession = (periodId: string, sessionId: string) => {
    setPeriods(prev => prev.map(p => p.id === periodId ? { ...p, sessions: p.sessions.filter(s => s.id !== sessionId) } : p));
  };

  const toggleAttendee = (player: Player) => {
    const exists = selectedAttendees.find(a => a.playerId === player.id);
    if (exists) {
      setSelectedAttendees(prev => prev.filter(a => a.playerId !== player.id));
    } else {
      setSelectedAttendees(prev => [...prev, { playerId: player.id, fee: player.defaultFee }]);
    }
  };

  const originalFunders = players.filter(p => p.isFunder);

  return (
    <div className="p-4">
      <div className="flex justify-between items-center mb-4">
        <h2 className="text-lg font-bold">结算周期</h2>
        <button 
          onClick={() => { setIsAddingPeriod(true); setPeriodFormData(initialPeriodData); }}
          className="bg-emerald-600 text-white px-3 py-1.5 rounded-lg text-sm flex items-center gap-1 font-bold shadow-sm"
        >
          <Icons.Plus /> 新增周期
        </button>
      </div>

      {(isAddingPeriod || editingPeriodId) && (
        <div className="mb-6 bg-white p-4 rounded-xl shadow-sm border-2 border-emerald-500 overflow-hidden">
          <h3 className="font-bold mb-4">{editingPeriodId ? '编辑周期' : '创建新周期'}</h3>
          <div className="space-y-4">
            <div>
              <label className="block text-xs text-gray-400 mb-1">周期名称</label>
              <input 
                type="text" 
                placeholder="如: 2024年4月 第一期" 
                value={periodFormData.name}
                onChange={e => setPeriodFormData({...periodFormData, name: e.target.value})}
                className="w-full border border-gray-300 rounded-lg p-2 text-sm focus:ring-2 focus:ring-emerald-500 focus:outline-none"
              />
            </div>
            <div className="flex gap-2">
              <div className="flex-1">
                <label className="block text-xs text-gray-400 mb-1">开始日期</label>
                <input 
                  type="date" 
                  value={periodFormData.startDate}
                  onChange={e => setPeriodFormData({...periodFormData, startDate: e.target.value})}
                  className="w-full border border-gray-300 rounded-lg p-2 text-sm"
                />
              </div>
              <div className="flex-1">
                <label className="block text-xs text-gray-400 mb-1">结束日期</label>
                <input 
                  type="date" 
                  value={periodFormData.endDate}
                  onChange={e => setPeriodFormData({...periodFormData, endDate: e.target.value})}
                  className="w-full border border-gray-300 rounded-lg p-2 text-sm"
                />
              </div>
            </div>
            <div>
              <label className="block text-xs text-gray-400 mb-1">场地预订总成本 (元)</label>
              <input 
                type="number" 
                placeholder="场地支出" 
                value={periodFormData.courtCost || ''}
                onChange={e => setPeriodFormData({...periodFormData, courtCost: Number(e.target.value)})}
                className="w-full border border-gray-300 rounded-lg p-2 text-sm"
              />
            </div>

            <div>
              <label className="block text-xs text-gray-400 mb-2 font-bold uppercase tracking-tight">选择参加集资的人员 (返款对象)</label>
              <div className="flex flex-wrap gap-2 p-2 bg-gray-50 rounded-lg border border-gray-100">
                {originalFunders.map(f => (
                  <button
                    key={f.id}
                    onClick={() => toggleFunderSelection(f.id)}
                    className={`text-xs px-2.5 py-1.5 rounded-lg border transition-all font-medium ${
                      periodFormData.funderIds?.includes(f.id) 
                      ? 'bg-amber-100 border-amber-300 text-amber-800' 
                      : 'bg-white border-gray-200 text-gray-400'
                    }`}
                  >
                    {f.name}
                  </button>
                ))}
              </div>
              <p className="text-[10px] text-gray-400 mt-1">* 只有在这里选中的集资成员才会参与本期的费用返款结算。</p>
            </div>

            <div className="flex gap-2 pt-2">
              <button onClick={handleSavePeriod} className="flex-1 bg-emerald-600 text-white py-2 rounded-lg font-bold text-sm shadow-sm">保存</button>
              <button onClick={() => { setIsAddingPeriod(false); setEditingPeriodId(null); }} className="flex-1 bg-gray-200 text-gray-600 py-2 rounded-lg font-bold text-sm">取消</button>
            </div>
          </div>
        </div>
      )}

      <div className="space-y-4">
        {periods.map(period => (
          <div key={period.id} className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
            <div 
              className="p-4 flex justify-between items-center cursor-pointer hover:bg-gray-50"
              onClick={() => setExpandedPeriodId(expandedPeriodId === period.id ? null : period.id)}
            >
              <div>
                <h3 className="font-bold text-gray-800">{period.name}</h3>
                <p className="text-[10px] text-gray-400 mt-1">{period.startDate} 至 {period.endDate || '未定'}</p>
                <div className="mt-2 flex gap-1 overflow-x-auto pb-1 max-w-[200px]">
                  {period.funderIds.map(fid => (
                    <span key={fid} className="text-[8px] bg-amber-50 text-amber-600 border border-amber-100 px-1 rounded">
                      {players.find(p => p.id === fid)?.name}
                    </span>
                  ))}
                </div>
              </div>
              <div className="flex items-center gap-3">
                <div className="text-right">
                  <p className="text-xs text-gray-500">打球次数</p>
                  <p className="font-bold text-emerald-600">{period.sessions.length}</p>
                </div>
                <div className="flex flex-col gap-2">
                   <button onClick={(e) => startEditPeriod(e, period)} className="text-emerald-600 text-xs font-bold p-1">编辑</button>
                   <button onClick={(e) => deletePeriod(e, period.id)} className="text-gray-300 hover:text-red-400 p-1">
                      <Icons.Trash />
                    </button>
                </div>
              </div>
            </div>

            {expandedPeriodId === period.id && (
              <div className="border-t border-gray-100 bg-gray-50 p-4 space-y-4 animate-in slide-in-from-top-2 duration-300">
                {/* Session Records */}
                <div className="space-y-3">
                  <div className="flex justify-between items-center">
                    <h4 className="text-sm font-bold text-gray-600">本期活动记录</h4>
                    <button 
                      onClick={() => setActiveSessionPeriod(period.id)}
                      className="text-xs bg-emerald-100 text-emerald-700 px-2 py-1 rounded font-bold"
                    >
                      + 录入打球
                    </button>
                  </div>

                  {activeSessionPeriod === period.id && (
                    <div className="bg-white p-3 rounded-lg border-2 border-emerald-200 shadow-sm">
                      <p className="text-xs font-bold text-gray-500 mb-2 uppercase tracking-tighter">录入单场报名明细</p>
                      <input 
                        type="date" 
                        value={newSessionDate}
                        onChange={e => setNewSessionDate(e.target.value)}
                        className="w-full border border-gray-300 rounded-lg p-2 text-sm mb-3"
                      />
                      <p className="text-xs text-gray-400 mb-2">选择出席人员:</p>
                      <div className="flex flex-wrap gap-2 max-h-40 overflow-y-auto p-2 border border-gray-100 rounded-lg mb-3 bg-gray-50">
                        {players.map(p => {
                          const isSelected = selectedAttendees.find(a => a.playerId === p.id);
                          return (
                            <button 
                              key={p.id}
                              onClick={() => toggleAttendee(p)}
                              className={`text-xs px-2 py-1 rounded-full border transition-all ${
                                isSelected ? 'bg-emerald-600 border-emerald-600 text-white shadow-sm' : 'bg-white border-gray-200 text-gray-600'
                              }`}
                            >
                              {p.name}
                            </button>
                          );
                        })}
                      </div>

                      {selectedAttendees.length > 0 && (
                        <div className="mb-3 space-y-1">
                          <p className="text-[10px] text-gray-400">核对收费金额:</p>
                          {selectedAttendees.map(a => {
                            const player = players.find(p => p.id === a.playerId);
                            return (
                              <div key={a.playerId} className="flex justify-between items-center bg-gray-50 p-1.5 rounded text-[11px]">
                                <span>{player?.name} ({player?.type})</span>
                                <div className="flex items-center gap-1">
                                  <span className="text-gray-400">¥</span>
                                  <input 
                                    type="number" 
                                    value={a.fee}
                                    onChange={e => {
                                      const val = Number(e.target.value);
                                      setSelectedAttendees(prev => prev.map(sa => sa.playerId === a.playerId ? {...sa, fee: val} : sa));
                                    }}
                                    className="w-12 border rounded px-1 focus:ring-1 focus:ring-emerald-400 outline-none"
                                  />
                                </div>
                              </div>
                            );
                          })}
                        </div>
                      )}

                      <div className="flex gap-2">
                        <button onClick={() => addSession(period.id)} className="flex-1 bg-emerald-600 text-white py-1.5 rounded font-bold text-xs shadow-sm">确认保存</button>
                        <button onClick={() => setActiveSessionPeriod(null)} className="flex-1 bg-gray-200 text-gray-600 py-1.5 rounded font-bold text-xs">取消</button>
                      </div>
                    </div>
                  )}

                  {period.sessions.length === 0 ? (
                    <p className="text-center text-xs text-gray-400 py-4 italic">本周期暂无打球记录</p>
                  ) : (
                    period.sessions.map(session => (
                      <div key={session.id} className="bg-white p-3 rounded-lg shadow-sm border border-gray-100 flex justify-between items-center">
                        <div>
                          <p className="text-xs font-bold text-gray-700">{session.date}</p>
                          <p className="text-[10px] text-gray-500 mt-0.5 truncate max-w-[180px]">
                            {session.attendees.map(a => players.find(p => p.id === a.playerId)?.name).join(', ')}
                          </p>
                        </div>
                        <div className="flex items-center gap-2">
                          <div className="text-right">
                            <p className="text-[10px] text-gray-400">应收小计</p>
                            <p className="text-xs font-bold text-emerald-600">¥{session.attendees.reduce((sum, a) => sum + a.fee, 0)}</p>
                          </div>
                          <button onClick={() => removeSession(period.id, session.id)} className="text-gray-300 ml-1 hover:text-red-400">
                            <Icons.Trash />
                          </button>
                        </div>
                      </div>
                    ))
                  )}
                </div>
              </div>
            )}
          </div>
        ))}
        {periods.length === 0 && (
          <div className="text-center py-20 text-gray-400">
            <p className="text-4xl mb-4 opacity-20">📅</p>
            <p className="text-sm">点击右上角“新增周期”开始管理</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default PeriodsList;

import React from 'react';
import { Period, Player, PlayerType } from '../types';

interface FinanceReportProps {
  periods: Period[];
  players: Player[];
}

const FinanceReport: React.FC<FinanceReportProps> = ({ periods, players }) => {
  const calculatePeriodStats = (period: Period) => {
    // Total fees collected from attendees
    const totalIncome = period.sessions.reduce((acc, s) => acc + s.attendees.reduce((sum, a) => sum + a.fee, 0), 0);
    const courtCost = period.courtCost;
    const surplus = totalIncome - courtCost;

    // Funders for this specific period
    const periodFunderCount = period.funderIds?.length || 0;

    // Per user logic: All external income divided by funders
    const perFunderRefund = periodFunderCount > 0 ? totalIncome / periodFunderCount : 0;

    return { totalIncome, courtCost, surplus, perFunderRefund, periodFunderCount };
  };

  return (
    <div className="p-4">
      <h2 className="text-lg font-bold mb-4">财务统计报表</h2>

      {periods.length === 0 ? (
        <div className="text-center py-20 text-gray-400">
          <p className="text-4xl mb-4 opacity-20">📊</p>
          <p className="text-sm">暂无结算数据</p>
        </div>
      ) : (
        <div className="space-y-6">
          {/* Legend */}
          <div className="bg-amber-50 rounded-2xl p-4 border border-amber-100">
            <h3 className="text-sm font-bold text-amber-800 mb-2 flex items-center gap-1">
              ✨ 结算说明
            </h3>
            <p className="text-[10px] text-amber-600 leading-relaxed">
              1. <b>每人返款</b> = (本期所有活动收费总额) / (本期参加集资人数)。<br/>
              2. 外部收入指“包月”、“包半月”及“按次”人员在该周期内产生的所有费用。<br/>
              3. 集资人盈亏平衡点：若返款额 &gt; 集资摊派款，则为盈利。
            </p>
          </div>

          {/* Period Breakdown */}
          {periods.slice().reverse().map(period => {
            const stats = calculatePeriodStats(period);
            return (
              <div key={period.id} className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
                <div className="bg-gray-50 px-4 py-3 border-b border-gray-100 flex justify-between items-center">
                  <span className="font-bold text-gray-800">{period.name}</span>
                  <span className="text-[10px] text-gray-400 font-medium bg-white px-2 py-0.5 rounded-full border border-gray-200">
                    集资: {stats.periodFunderCount}人
                  </span>
                </div>

                <div className="p-4 space-y-4">
                  <div className="grid grid-cols-2 gap-x-8 gap-y-4">
                    <div>
                      <p className="text-[10px] text-gray-400 uppercase tracking-wider">周期总收入</p>
                      <p className="text-lg font-black text-emerald-600">¥{stats.totalIncome.toFixed(2)}</p>
                    </div>
                    <div>
                      <p className="text-[10px] text-gray-400 uppercase tracking-wider">场地支出成本</p>
                      <p className="text-lg font-black text-red-500">¥{stats.courtCost.toFixed(2)}</p>
                    </div>
                    <div>
                      <p className="text-[10px] text-gray-400 uppercase tracking-wider">每人返款额</p>
                      <p className="text-lg font-black text-amber-500">¥{stats.perFunderRefund.toFixed(2)}</p>
                    </div>
                    <div>
                      <p className="text-[10px] text-gray-400 uppercase tracking-wider">财务差额</p>
                      <p className={`text-lg font-black ${stats.surplus >= 0 ? 'text-emerald-500' : 'text-red-400'}`}>
                        ¥{stats.surplus.toFixed(2)}
                      </p>
                    </div>
                  </div>

                  {/* List of Participating Funders */}
                  <div className="bg-gray-50 p-2 rounded-lg">
                    <p className="text-[9px] text-gray-400 mb-1 uppercase font-bold">本期返款人员清单:</p>
                    <div className="flex flex-wrap gap-1">
                       {period.funderIds.map(fid => {
                         const player = players.find(p => p.id === fid);
                         return (
                           <span key={fid} className="text-[10px] bg-white border border-gray-200 px-1.5 py-0.5 rounded text-gray-600">
                             {player?.name}
                           </span>
                         );
                       })}
                    </div>
                  </div>

                  <div className="border-t border-dashed border-gray-100 pt-3">
                    <p className="text-xs font-bold text-gray-500 mb-2 flex justify-between">
                      <span>人员收费详情</span>
                      <span className="text-[10px] font-normal">{period.sessions.length} 场次</span>
                    </p>
                    <div className="space-y-1 max-h-40 overflow-y-auto pr-1">
                      {Array.from(new Set(period.sessions.flatMap(s => s.attendees.map(a => a.playerId))))
                        .map(pid => {
                          const player = players.find(p => p.id === pid);
                          const totalPaid = period.sessions.reduce((sum, s) => {
                             const att = s.attendees.find(a => a.playerId === pid);
                             return sum + (att ? att.fee : 0);
                          }, 0);
                          const attendCount = period.sessions.filter(s => s.attendees.some(a => a.playerId === pid)).length;
                          return (
                            <div key={pid} className="flex justify-between items-center text-[11px] py-1 border-b border-gray-50 last:border-0">
                              <span className="text-gray-600">
                                {player?.name} 
                                <span className="text-[9px] text-gray-400 ml-1">({player?.type} · {attendCount}次)</span>
                              </span>
                              <span className="font-bold">¥{totalPaid.toFixed(2)}</span>
                            </div>
                          );
                        })}
                    </div>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

