import React, { useState, useMemo } from 'react';
import { Period, Player, Session, PlayerType } from '../types';
import { Icons, DEFAULT_SESSION_FEE } from '../constants';

interface PeriodsListProps {
  periods: Period[];
  setPeriods: React.Dispatch<React.SetStateAction<Period[]>>;
  players: Player[];
}

const PeriodsList: React.FC<PeriodsListProps> = ({ periods, setPeriods, players }) => {
  const [isAddingPeriod, setIsAddingPeriod] = useState(false);
  const [editingPeriodId, setEditingPeriodId] = useState<string | null>(null);
  const [expandedPeriodId, setExpandedPeriodId] = useState<string | null>(null);
  const [activeSessionPeriod, setActiveSessionPeriod] = useState<string | null>(null);
  const [editingSessionId, setEditingSessionId] = useState<string | null>(null);

  const initialPeriodData = {
    name: '',
    startDate: new Date().toISOString().split('T')[0],
    endDate: '',
    courtCost: 0,
    funderIds: players.filter(p => p.isFunder).map(p => p.id),
    sessions: []
  };

  const [periodFormData, setPeriodFormData] = useState<Partial<Period>>(initialPeriodData);

  // Session form state
  const [sessionFormDate, setSessionFormDate] = useState(new Date().toISOString().split('T')[0]);
  const [selectedAttendees, setSelectedAttendees] = useState<{playerId: string, fee: number}[]>([]);

  const handleSavePeriod = () => {
    if (!periodFormData.name) return;

    if (editingPeriodId) {
      setPeriods(prev => prev.map(p => p.id === editingPeriodId ? { ...p, ...periodFormData } as Period : p));
      setEditingPeriodId(null);
    } else {
      const period: Period = {
        id: Date.now().toString(),
        name: periodFormData.name!,
        startDate: periodFormData.startDate!,
        endDate: periodFormData.endDate || '',
        courtCost: periodFormData.courtCost || 0,
        funderIds: periodFormData.funderIds || [],
        sessions: []
      };
      setPeriods(prev => [...prev, period]);
      setIsAddingPeriod(false);
    }
    setPeriodFormData(initialPeriodData);
  };

  const startEditPeriod = (e: React.MouseEvent, period: Period) => {
    e.stopPropagation();
    setEditingPeriodId(period.id);
    setPeriodFormData(period);
  };

  const deletePeriod = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (confirm('确定要删除该结算周期吗？删除后所有打球记录将消失。')) {
      setPeriods(prev => prev.filter(p => p.id !== id));
    }
  };

  const toggleFunderSelection = (funderId: string) => {
    const current = periodFormData.funderIds || [];
    if (current.includes(funderId)) {
      setPeriodFormData({...periodFormData, funderIds: current.filter(id => id !== funderId)});
    } else {
      setPeriodFormData({...periodFormData, funderIds: [...current, funderId]});
    }
  };

  const handleOpenAddSession = (periodId: string) => {
    setActiveSessionPeriod(periodId);
    setEditingSessionId(null);
    setSessionFormDate(new Date().toISOString().split('T')[0]);
    setSelectedAttendees([]);
  };

  const handleEditSession = (periodId: string, session: Session) => {
    setActiveSessionPeriod(periodId);
    setEditingSessionId(session.id);
    setSessionFormDate(session.date);
    setSelectedAttendees(session.attendees);
  };

  const saveSession = (periodId: string) => {
    if (selectedAttendees.length === 0) {
      alert('请选择至少一名打球成员');
      return;
    }

    if (editingSessionId) {
      setPeriods(prev => prev.map(p => p.id === periodId ? {
        ...p,
        sessions: p.sessions.map(s => s.id === editingSessionId ? { ...s, date: sessionFormDate, attendees: selectedAttendees } : s)
      } : p));
    } else {
      const session: Session = {
        id: Date.now().toString(),
        date: sessionFormDate,
        attendees: selectedAttendees
      };
      setPeriods(prev => prev.map(p => p.id === periodId ? { ...p, sessions: [...p.sessions, session] } : p));
    }

    setActiveSessionPeriod(null);
    setEditingSessionId(null);
    setSelectedAttendees([]);
  };

  const removeSession = (periodId: string, sessionId: string) => {
    if (confirm('确定删除此条活动记录？')) {
      setPeriods(prev => prev.map(p => p.id === periodId ? { ...p, sessions: p.sessions.filter(s => s.id !== sessionId) } : p));
    }
  };

  const toggleAttendee = (player: Player, periodId: string) => {
    const exists = selectedAttendees.find(a => a.playerId === player.id);
    if (exists) {
      setSelectedAttendees(prev => prev.filter(a => a.playerId !== player.id));
    } else {
      // LOGIC: If monthly/half-monthly and already paid in this period, default fee is 0
      const currentPeriod = periods.find(p => p.id === periodId);
      const isMonthlyType = player.type === PlayerType.MONTHLY || player.type === PlayerType.HALF_MONTHLY;

      let defaultFee = player.defaultFee;

      if (isMonthlyType && currentPeriod) {
        // Check if player has any non-zero fee entries in this period's previous sessions
        const hasPaidInPeriod = currentPeriod.sessions.some(s => 
          s.id !== editingSessionId && // Exclude currently editing session
          s.attendees.some(a => a.playerId === player.id && a.fee > 0)
        );
        if (hasPaidInPeriod) {
          defaultFee = 0;
        }
      }

      setSelectedAttendees(prev => [...prev, { playerId: player.id, fee: defaultFee }]);
    }
  };

  const originalFunders = players.filter(p => p.isFunder);

  return (
    <div className="p-4">
      <div className="flex justify-between items-center mb-4">
        <h2 className="text-lg font-bold">结算周期</h2>
        <button 
          onClick={() => { setIsAddingPeriod(true); setPeriodFormData(initialPeriodData); }}
          className="bg-emerald-600 text-white px-3 py-1.5 rounded-lg text-sm flex items-center gap-1 font-bold shadow-sm active:scale-95 transition-transform"
        >
          <Icons.Plus /> 新增周期
        </button>
      </div>

      {(isAddingPeriod || editingPeriodId) && (
        <div className="mb-6 bg-white p-4 rounded-xl shadow-sm border-2 border-emerald-500 overflow-hidden animate-in fade-in slide-in-from-top-4 duration-300">
          <h3 className="font-bold mb-4">{editingPeriodId ? '编辑周期' : '创建新周期'}</h3>
          <div className="space-y-4">
            <div>
              <label className="block text-xs text-gray-400 mb-1">周期名称</label>
              <input 
                type="text" 
                placeholder="如: 2024年4月 第一期" 
                value={periodFormData.name}
                onChange={e => setPeriodFormData({...periodFormData, name: e.target.value})}
                className="w-full border border-gray-300 rounded-lg p-2 text-sm focus:ring-2 focus:ring-emerald-500 focus:outline-none"
              />
            </div>
            <div className="flex gap-2">
              <div className="flex-1">
                <label className="block text-xs text-gray-400 mb-1">开始日期</label>
                <input 
                  type="date" 
                  value={periodFormData.startDate}
                  onChange={e => setPeriodFormData({...periodFormData, startDate: e.target.value})}
                  className="w-full border border-gray-300 rounded-lg p-2 text-sm"
                />
              </div>
              <div className="flex-1">
                <label className="block text-xs text-gray-400 mb-1">结束日期</label>
                <input 
                  type="date" 
                  value={periodFormData.endDate}
                  onChange={e => setPeriodFormData({...periodFormData, endDate: e.target.value})}
                  className="w-full border border-gray-300 rounded-lg p-2 text-sm"
                />
              </div>
            </div>
            <div>
              <label className="block text-xs text-gray-400 mb-1 font-bold">场地支出成本 (元)</label>
              <input 
                type="number" 
                placeholder="0.00" 
                value={periodFormData.courtCost || ''}
                onChange={e => setPeriodFormData({...periodFormData, courtCost: Number(e.target.value)})}
                className="w-full border border-gray-300 rounded-lg p-2 text-sm"
              />
            </div>

            <div>
              <label className="block text-xs text-gray-400 mb-2 font-bold uppercase tracking-tight">选择集资人员 (本期返款对象)</label>
              <div className="flex flex-wrap gap-2 p-2 bg-gray-50 rounded-lg border border-gray-100">
                {originalFunders.map(f => (
                  <button
                    key={f.id}
                    onClick={() => toggleFunderSelection(f.id)}
                    className={`text-xs px-2.5 py-1.5 rounded-lg border transition-all font-medium ${
                      periodFormData.funderIds?.includes(f.id) 
                      ? 'bg-amber-100 border-amber-300 text-amber-800' 
                      : 'bg-white border-gray-200 text-gray-400'
                    }`}
                  >
                    {f.name}
                  </button>
                ))}
              </div>
            </div>

            <div className="flex gap-2 pt-2">
              <button onClick={handleSavePeriod} className="flex-1 bg-emerald-600 text-white py-2 rounded-lg font-bold text-sm shadow-sm">保存</button>
              <button onClick={() => { setIsAddingPeriod(false); setEditingPeriodId(null); }} className="flex-1 bg-gray-200 text-gray-600 py-2 rounded-lg font-bold text-sm">取消</button>
            </div>
          </div>
        </div>
      )}

      <div className="space-y-4">
        {periods.map(period => (
          <div key={period.id} className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
            <div 
              className="p-4 flex justify-between items-center cursor-pointer hover:bg-gray-50 active:bg-gray-100"
              onClick={() => setExpandedPeriodId(expandedPeriodId === period.id ? null : period.id)}
            >
              <div className="flex-1">
                <h3 className="font-bold text-gray-800">{period.name}</h3>
                <p className="text-[10px] text-gray-400 mt-1">{period.startDate} 至 {period.endDate || '未定'}</p>
                <div className="mt-2 flex gap-1 flex-wrap">
                  {period.funderIds.map(fid => (
                    <span key={fid} className="text-[8px] bg-amber-50 text-amber-600 border border-amber-100 px-1 rounded">
                      {players.find(p => p.id === fid)?.name}
                    </span>
                  ))}
                </div>
              </div>
              <div className="flex items-center gap-4">
                <div className="text-right">
                  <p className="text-xs text-gray-500 font-medium">活动记录</p>
                  <p className="font-bold text-emerald-600">{period.sessions.length}</p>
                </div>
                <div className="flex flex-col gap-2">
                   <button onClick={(e) => startEditPeriod(e, period)} className="text-emerald-600 text-xs font-bold p-1 bg-emerald-50 rounded">编辑</button>
                   <button onClick={(e) => deletePeriod(e, period.id)} className="text-gray-300 hover:text-red-400 p-1">
                      <Icons.Trash />
                    </button>
                </div>
              </div>
            </div>

            {expandedPeriodId === period.id && (
              <div className="border-t border-gray-100 bg-gray-50 p-4 space-y-4 animate-in slide-in-from-top-2 duration-300">
                <div className="space-y-3">
                  <div className="flex justify-between items-center">
                    <h4 className="text-sm font-bold text-gray-600">打球记录明细</h4>
                    <button 
                      onClick={() => handleOpenAddSession(period.id)}
                      className="text-xs bg-emerald-600 text-white px-3 py-1.5 rounded-full font-bold shadow-sm"
                    >
                      + 录入打球
                    </button>
                  </div>

                  {activeSessionPeriod === period.id && (
                    <div className="bg-white p-4 rounded-xl border-2 border-emerald-500 shadow-lg animate-in zoom-in-95 duration-200">
                      <p className="text-sm font-bold text-gray-700 mb-3">{editingSessionId ? '编辑打球记录' : '新增单场报名'}</p>

                      <div className="mb-4">
                        <label className="block text-[10px] text-gray-400 mb-1">活动日期</label>
                        <input 
                          type="date" 
                          value={sessionFormDate}
                          onChange={e => setSessionFormDate(e.target.value)}
                          className="w-full border border-gray-300 rounded-lg p-2 text-sm focus:ring-1 focus:ring-emerald-400 outline-none"
                        />
                      </div>

                      <div className="mb-4">
                        <p className="text-[10px] text-gray-400 mb-2">出席人员选择 (点选/取消):</p>
                        <div className="flex flex-wrap gap-2 max-h-48 overflow-y-auto p-2 border border-gray-100 rounded-lg bg-gray-50">
                          {players.map(p => {
                            const isSelected = selectedAttendees.find(a => a.playerId === p.id);
                            return (
                              <button 
                                key={p.id}
                                onClick={() => toggleAttendee(p, period.id)}
                                className={`text-xs px-2.5 py-1.5 rounded-lg border transition-all ${
                                  isSelected ? 'bg-emerald-600 border-emerald-600 text-white shadow-sm' : 'bg-white border-gray-200 text-gray-600'
                                }`}
                              >
                                {p.name}
                              </button>
                            );
                          })}
                        </div>
                      </div>

                      {selectedAttendees.length > 0 && (
                        <div className="mb-4 space-y-1">
                          <p className="text-[10px] text-gray-400">核对/调整单人收费:</p>
                          {selectedAttendees.map(a => {
                            const player = players.find(p => p.id === a.playerId);
                            return (
                              <div key={a.playerId} className="flex justify-between items-center bg-gray-50 p-2 rounded text-[11px]">
                                <span className="flex items-center gap-1">
                                  {player?.name} 
                                  <span className="text-[9px] px-1 bg-white text-gray-400 border border-gray-100 rounded">
                                    {player?.type}
                                  </span>
                                </span>
                                <div className="flex items-center gap-1">
                                  <span className="text-gray-400 font-bold">¥</span>
                                  <input 
                                    type="number" 
                                    value={a.fee}
                                    onChange={e => {
                                      const val = Number(e.target.value);
                                      setSelectedAttendees(prev => prev.map(sa => sa.playerId === a.playerId ? {...sa, fee: val} : sa));
                                    }}
                                    className="w-14 border border-gray-200 rounded px-1.5 py-0.5 text-center font-bold text-emerald-600 focus:outline-emerald-500"
                                  />
                                </div>
                              </div>
                            );
                          })}
                        </div>
                      )}

                      <div className="flex gap-2">
                        <button onClick={() => saveSession(period.id)} className="flex-1 bg-emerald-600 text-white py-2 rounded-lg font-bold text-sm shadow-sm active:scale-95 transition-all">保存记录</button>
                        <button onClick={() => setActiveSessionPeriod(null)} className="flex-1 bg-gray-100 text-gray-500 py-2 rounded-lg font-bold text-sm">取消</button>
                      </div>
                    </div>
                  )}

                  <div className="space-y-2">
                    {period.sessions.length === 0 ? (
                      <p className="text-center text-xs text-gray-400 py-6 italic">本周期暂无活动记录</p>
                    ) : (
                      period.sessions.slice().sort((a,b) => b.date.localeCompare(a.date)).map(session => (
                        <div key={session.id} className="bg-white p-3 rounded-xl shadow-sm border border-gray-100 group transition-all">
                          <div className="flex justify-between items-start mb-2">
                            <div>
                              <p className="text-xs font-black text-gray-700">{session.date}</p>
                              <div className="flex items-center gap-2 mt-0.5">
                                <span className="text-[9px] bg-blue-50 text-blue-600 px-1 rounded font-bold">出席: {session.attendees.length}人</span>
                                <span className="text-[9px] bg-emerald-50 text-emerald-600 px-1 rounded font-bold">总收: ¥{session.attendees.reduce((sum, a) => sum + a.fee, 0)}</span>
                              </div>
                            </div>
                            <div className="flex gap-2">
                              <button onClick={() => handleEditSession(period.id, session)} className="text-gray-300 hover:text-emerald-500 p-1">
                                <Icons.Pencil />
                              </button>
                              <button onClick={() => removeSession(period.id, session.id)} className="text-gray-300 hover:text-red-400 p-1">
                                <Icons.Trash />
                              </button>
                            </div>
                          </div>
                          <div className="flex flex-wrap gap-1.5">
                            {session.attendees.map(a => {
                              const p = players.find(pl => pl.id === a.playerId);
                              return (
                                <span key={a.playerId} className={`text-[9px] px-1.5 py-0.5 rounded border ${a.fee === 0 ? 'bg-gray-50 text-gray-400 border-gray-100 italic' : 'bg-white text-gray-600 border-gray-100'}`}>
                                  {p?.name} (¥{a.fee})
                                </span>
                              );
                            })}
                          </div>
                        </div>
                      ))
                    )}
                  </div>
                </div>
              </div>
            )}
          </div>
        ))}
        {periods.length === 0 && (
          <div className="text-center py-20 text-gray-400">
            <p className="text-5xl mb-4 opacity-10">🏸</p>
            <p className="text-sm">点击右上角“新增周期”开始管理</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default PeriodsList;

import React, { useState } from 'react';
import { Player, PlayerType } from '../types';
import { Icons, DEFAULT_SESSION_FEE } from '../constants';

interface PlayersListProps {
  players: Player[];
  setPlayers: React.Dispatch<React.SetStateAction<Player[]>>;
}

const PlayersList: React.FC<PlayersListProps> = ({ players, setPlayers }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState<Partial<Player>>({
    name: '',
    type: PlayerType.PER_SESSION,
    defaultFee: DEFAULT_SESSION_FEE,
    isFunder: false
  });

  const handleSave = () => {
    if (!formData.name) return;

    if (editingId) {
      setPlayers(prev => prev.map(p => p.id === editingId ? { ...p, ...formData } as Player : p));
      setEditingId(null);
    } else {
      const newPlayer: Player = {
        id: Date.now().toString(),
        name: formData.name!,
        type: formData.type as PlayerType || PlayerType.PER_SESSION,
        defaultFee: formData.defaultFee !== undefined ? formData.defaultFee : (formData.type === PlayerType.PER_SESSION ? DEFAULT_SESSION_FEE : 0),
        isFunder: false 
      };
      setPlayers(prev => [...prev, newPlayer]);
      setIsAdding(false);
    }
    setFormData({ name: '', type: PlayerType.PER_SESSION, defaultFee: DEFAULT_SESSION_FEE, isFunder: false });
  };

  const startEdit = (player: Player) => {
    setEditingId(player.id);
    setFormData(player);
  };

  const handleDelete = (id: string) => {
    if (confirm('确定要从档案中删除该人员吗？')) {
      setPlayers(prev => prev.filter(p => p.id !== id));
    }
  };

  return (
    <div className="p-4">
      <div className="flex justify-between items-center mb-4">
        <h2 className="text-lg font-bold">人员档案</h2>
        <button 
          onClick={() => setIsAdding(true)}
          className="bg-emerald-600 text-white px-3 py-1.5 rounded-lg text-sm flex items-center gap-1 font-bold shadow-sm"
        >
          <Icons.Plus /> 新增人员
        </button>
      </div>

      {(isAdding || editingId) && (
        <div className="mb-6 bg-white p-4 rounded-xl shadow-lg border-2 border-emerald-500 animate-in zoom-in-95 duration-200">
          <h3 className="font-bold mb-4">{editingId ? '修改人员信息' : '录入新成员'}</h3>
          <div className="space-y-4">
            <div>
              <label className="block text-xs text-gray-500 mb-1 font-bold">姓名</label>
              <input 
                type="text" 
                value={formData.name}
                onChange={e => setFormData({ ...formData, name: e.target.value })}
                className="w-full border border-gray-300 rounded-lg p-2 text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500"
                placeholder="成员姓名"
              />
            </div>
            <div>
              <label className="block text-xs text-gray-500 mb-1 font-bold">人员类型</label>
              <select 
                value={formData.type}
                onChange={e => {
                   const type = e.target.value as PlayerType;
                   const fee = type === PlayerType.PER_SESSION ? DEFAULT_SESSION_FEE : (formData.defaultFee || 0);
                   setFormData({ ...formData, type, defaultFee: fee });
                }}
                className="w-full border border-gray-300 rounded-lg p-2 text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500"
              >
                <option value={PlayerType.MONTHLY}>包月</option>
                <option value={PlayerType.HALF_MONTHLY}>包半月</option>
                <option value={PlayerType.PER_SESSION}>按次</option>
              </select>
            </div>
            <div>
              <label className="block text-xs text-gray-500 mb-1 font-bold">标准收费金额 (元)</label>
              <input 
                type="number" 
                value={formData.defaultFee}
                onChange={e => setFormData({ ...formData, defaultFee: Number(e.target.value) })}
                className="w-full border border-gray-300 rounded-lg p-2 text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500"
              />
              <p className="text-[10px] text-gray-400 mt-1">
                {formData.type === PlayerType.PER_SESSION ? '* 每次打球默认收取的金额' : '* 包月/包半月第一次录入时收取的总金额'}
              </p>
            </div>
            {editingId && (
               <div className="flex items-center gap-2 p-2 bg-amber-50 rounded-lg">
                 <input 
                   type="checkbox" 
                   checked={formData.isFunder}
                   onChange={e => setFormData({ ...formData, isFunder: e.target.checked })}
                   id="isFunder"
                   className="w-4 h-4 text-amber-600"
                 />
                 <label htmlFor="isFunder" className="text-xs font-bold text-amber-800 uppercase tracking-tighter cursor-pointer">设为创始集资成员 (10人名单)</label>
               </div>
            )}
            <div className="flex gap-2 pt-2">
              <button 
                onClick={handleSave}
                className="flex-1 bg-emerald-600 text-white py-2 rounded-lg font-bold text-sm shadow-sm"
              >
                保存
              </button>
              <button 
                onClick={() => { setIsAdding(false); setEditingId(null); }}
                className="flex-1 bg-gray-100 text-gray-500 py-2 rounded-lg font-bold text-sm"
              >
                取消
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="space-y-3">
        {players.map(player => (
          <div key={player.id} className={`bg-white p-4 rounded-xl shadow-sm border flex justify-between items-center transition-all ${player.isFunder ? 'border-amber-200' : 'border-gray-100'}`}>
            <div className="flex-1">
              <div className="flex items-center gap-2">
                <span className="font-bold text-gray-800">{player.name}</span>
                {player.isFunder && (
                  <span className="text-[10px] bg-amber-100 text-amber-700 px-1.5 py-0.5 rounded-full font-bold">集资人</span>
                )}
              </div>
              <div className="text-xs text-gray-500 mt-1 flex items-center gap-3">
                <span className={`px-2 py-0.5 rounded-md font-medium ${
                  player.type === PlayerType.MONTHLY ? 'bg-purple-100 text-purple-700' :
                  player.type === PlayerType.HALF_MONTHLY ? 'bg-blue-100 text-blue-700' :
                  'bg-green-100 text-green-700'
                }`}>{player.type}</span>
                <span className="flex items-center">
                   <span className="text-gray-400 mr-1">默认:</span>
                   <span className="font-bold text-gray-700 font-mono">¥{player.defaultFee}</span>
                </span>
              </div>
            </div>
            <div className="flex gap-3">
              <button onClick={() => startEdit(player)} className="text-emerald-600 text-sm font-bold bg-emerald-50 px-3 py-1 rounded-lg active:scale-95 transition-all">编辑</button>
              <button onClick={() => handleDelete(player.id)} className="text-red-300 hover:text-red-500 transition-colors p-1">
                <Icons.Trash />
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default PlayersList;

import React, { useState } from 'react';
import { Period, Player, Session, PlayerType } from '../types';
import { Icons } from '../constants';

interface PeriodsListProps {
  periods: Period[];
  setPeriods: React.Dispatch<React.SetStateAction<Period[]>>;
  players: Player[];
}

const PeriodsList: React.FC<PeriodsListProps> = ({ periods, setPeriods, players }) => {
  const [isAddingPeriod, setIsAddingPeriod] = useState(false);
  const [editingPeriodId, setEditingPeriodId] = useState<string | null>(null);
  const [expandedPeriodId, setExpandedPeriodId] = useState<string | null>(null);
  const [activeSessionPeriod, setActiveSessionPeriod] = useState<string | null>(null);
  const [editingSessionId, setEditingSessionId] = useState<string | null>(null);

  const initialPeriodData = {
    name: '',
    startDate: new Date().toISOString().split('T')[0],
    endDate: '',
    courtCost: 0,
    funderIds: players.filter(p => p.isFunder).map(p => p.id),
    sessions: []
  };

  const [periodFormData, setPeriodFormData] = useState<Partial<Period>>(initialPeriodData);
  const [sessionFormDate, setSessionFormDate] = useState(new Date().toISOString().split('T')[0]);
  const [selectedAttendees, setSelectedAttendees] = useState<{playerId: string, fee: number}[]>([]);

  const handleSavePeriod = () => {
    if (!periodFormData.name) return;
    if (editingPeriodId) {
      setPeriods(prev => prev.map(p => p.id === editingPeriodId ? { ...p, ...periodFormData } as Period : p));
      setEditingPeriodId(null);
    } else {
      const period: Period = {
        id: Date.now().toString(),
        name: periodFormData.name!,
        startDate: periodFormData.startDate!,
        endDate: periodFormData.endDate || '',
        courtCost: periodFormData.courtCost || 0,
        funderIds: periodFormData.funderIds || [],
        sessions: []
      };
      setPeriods(prev => [...prev, period]);
      setIsAddingPeriod(false);
    }
    setPeriodFormData(initialPeriodData);
  };

  const startEditPeriod = (e: React.MouseEvent, period: Period) => {
    e.stopPropagation(); // 阻止展开面板
    setEditingPeriodId(period.id);
    setPeriodFormData(period);
  };

  const deletePeriod = (e: React.MouseEvent, id: string) => {
    e.stopPropagation(); // 阻止展开面板
    if (confirm('确定要删除该结算周期吗？删除后该周期内所有打球记录将永久消失。')) {
      setPeriods(prev => prev.filter(p => p.id !== id));
      if (expandedPeriodId === id) setExpandedPeriodId(null);
    }
  };

  const toggleFunderSelection = (funderId: string) => {
    const current = periodFormData.funderIds || [];
    if (current.includes(funderId)) {
      setPeriodFormData({...periodFormData, funderIds: current.filter(id => id !== funderId)});
    } else {
      setPeriodFormData({...periodFormData, funderIds: [...current, funderId]});
    }
  };

  const handleOpenAddSession = (e: React.MouseEvent, periodId: string) => {
    e.stopPropagation();
    setActiveSessionPeriod(periodId);
    setEditingSessionId(null);
    setSessionFormDate(new Date().toISOString().split('T')[0]);
    setSelectedAttendees([]);
  };

  const handleEditSession = (e: React.MouseEvent, periodId: string, session: Session) => {
    e.stopPropagation();
    setActiveSessionPeriod(periodId);
    setEditingSessionId(session.id);
    setSessionFormDate(session.date);
    setSelectedAttendees(session.attendees);
  };

  const saveSession = (periodId: string) => {
    if (selectedAttendees.length === 0) {
      alert('请选择至少一名出席成员');
      return;
    }
    if (editingSessionId) {
      setPeriods(prev => prev.map(p => p.id === periodId ? {
        ...p,
        sessions: p.sessions.map(s => s.id === editingSessionId ? { ...s, date: sessionFormDate, attendees: selectedAttendees } : s)
      } : p));
    } else {
      const session: Session = {
        id: Date.now().toString(),
        date: sessionFormDate,
        attendees: selectedAttendees
      };
      setPeriods(prev => prev.map(p => p.id === periodId ? { ...p, sessions: [...p.sessions, session] } : p));
    }
    setActiveSessionPeriod(null);
    setEditingSessionId(null);
  };

  const removeSession = (e: React.MouseEvent, periodId: string, sessionId: string) => {
    e.stopPropagation();
    if (confirm('确定删除此条打球活动记录吗？')) {
      setPeriods(prev => prev.map(p => p.id === periodId ? { ...p, sessions: p.sessions.filter(s => s.id !== sessionId) } : p));
    }
  };

  const toggleAttendee = (player: Player, periodId: string) => {
    const exists = selectedAttendees.find(a => a.playerId === player.id);
    if (exists) {
      setSelectedAttendees(prev => prev.filter(a => a.playerId !== player.id));
    } else {
      const currentPeriod = periods.find(p => p.id === periodId);
      const isMonthlyType = player.type === PlayerType.MONTHLY || player.type === PlayerType.HALF_MONTHLY;
      let defaultFee = player.defaultFee;
      if (isMonthlyType && currentPeriod) {
        const hasPaidInPeriod = currentPeriod.sessions.some(s => 
          s.id !== editingSessionId && 
          s.attendees.some(a => a.playerId === player.id && a.fee > 0)
        );
        if (hasPaidInPeriod) defaultFee = 0;
      }
      setSelectedAttendees(prev => [...prev, { playerId: player.id, fee: defaultFee }]);
    }
  };

  const originalFunders = players.filter(p => p.isFunder);

  return (
    <div className="p-4">
      <div className="flex justify-between items-center mb-4">
        <h2 className="text-lg font-bold">结算周期</h2>
        <button 
          type="button"
          onClick={() => { setIsAddingPeriod(true); setPeriodFormData(initialPeriodData); }}
          className="bg-emerald-600 text-white px-3 py-1.5 rounded-lg text-sm flex items-center gap-1 font-bold shadow-sm active:scale-95 transition-transform"
        >
          <Icons.Plus /> 新增周期
        </button>
      </div>

      {(isAddingPeriod || editingPeriodId) && (
        <div className="mb-6 bg-white p-4 rounded-xl shadow-sm border-2 border-emerald-500 animate-in fade-in slide-in-from-top-4 duration-300">
          <h3 className="font-bold mb-4">{editingPeriodId ? '编辑结算周期' : '创建新周期'}</h3>
          <div className="space-y-4">
            <div>
              <label className="block text-xs text-gray-400 mb-1">周期名称</label>
              <input 
                type="text" 
                placeholder="如: 2024年4月第一期" 
                value={periodFormData.name}
                onChange={e => setPeriodFormData({...periodFormData, name: e.target.value})}
                className="w-full border border-gray-300 rounded-lg p-2 text-sm focus:ring-2 focus:ring-emerald-500 focus:outline-none"
              />
            </div>
            <div className="flex gap-2">
              <div className="flex-1">
                <label className="block text-xs text-gray-400 mb-1">开始日期</label>
                <input type="date" value={periodFormData.startDate} onChange={e => setPeriodFormData({...periodFormData, startDate: e.target.value})} className="w-full border border-gray-300 rounded-lg p-2 text-sm" />
              </div>
              <div className="flex-1">
                <label className="block text-xs text-gray-400 mb-1">结束日期</label>
                <input type="date" value={periodFormData.endDate} onChange={e => setPeriodFormData({...periodFormData, endDate: e.target.value})} className="w-full border border-gray-300 rounded-lg p-2 text-sm" />
              </div>
            </div>
            <div>
              <label className="block text-xs text-gray-400 mb-1 font-bold">场地支出总成本 (元)</label>
              <input type="number" placeholder="0.00" value={periodFormData.courtCost || ''} onChange={e => setPeriodFormData({...periodFormData, courtCost: Number(e.target.value)})} className="w-full border border-gray-300 rounded-lg p-2 text-sm" />
            </div>
            <div>
              <label className="block text-xs text-gray-400 mb-2 font-bold uppercase tracking-tight">本期集资返款人员</label>
              <div className="flex flex-wrap gap-2 p-2 bg-gray-50 rounded-lg border border-gray-100">
                {originalFunders.map(f => (
                  <button key={f.id} type="button" onClick={() => toggleFunderSelection(f.id)} className={`text-xs px-2.5 py-1.5 rounded-lg border transition-all font-medium ${periodFormData.funderIds?.includes(f.id) ? 'bg-amber-100 border-amber-300 text-amber-800' : 'bg-white border-gray-200 text-gray-400'}`}>
                    {f.name}
                  </button>
                ))}
              </div>
            </div>
            <div className="flex gap-2 pt-2">
              <button type="button" onClick={handleSavePeriod} className="flex-1 bg-emerald-600 text-white py-2 rounded-lg font-bold text-sm shadow-sm">保存</button>
              <button type="button" onClick={() => { setIsAddingPeriod(false); setEditingPeriodId(null); }} className="flex-1 bg-gray-200 text-gray-600 py-2 rounded-lg font-bold text-sm">取消</button>
            </div>
          </div>
        </div>
      )}

      <div className="space-y-4">
        {periods.map(period => (
          <div key={period.id} className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
            <div 
              className="p-4 flex justify-between items-center cursor-pointer hover:bg-gray-50 active:bg-gray-50 transition-colors"
              onClick={() => setExpandedPeriodId(expandedPeriodId === period.id ? null : period.id)}
            >
              <div className="flex-1">
                <h3 className="font-bold text-gray-800">{period.name}</h3>
                <p className="text-[10px] text-gray-400 mt-1">{period.startDate} 至 {period.endDate || '进行中'}</p>
                <div className="mt-2 flex gap-1 flex-wrap">
                  {period.funderIds.map(fid => (
                    <span key={fid} className="text-[8px] bg-amber-50 text-amber-600 border border-amber-100 px-1 rounded">
                      {players.find(p => p.id === fid)?.name || '已删人员'}
                    </span>
                  ))}
                </div>
              </div>
              <div className="flex items-center gap-4">
                <div className="text-right">
                  <p className="text-xs text-gray-500 font-medium">活动数</p>
                  <p className="font-bold text-emerald-600">{period.sessions.length}</p>
                </div>
                <div className="flex flex-col gap-2">
                   <button type="button" onClick={(e) => startEditPeriod(e, period)} className="text-emerald-600 text-xs font-bold p-1 bg-emerald-50 rounded active:bg-emerald-100">编辑</button>
                   <button type="button" onClick={(e) => deletePeriod(e, period.id)} className="text-gray-300 hover:text-red-400 p-1 active:scale-110 transition-transform">
                      <Icons.Trash />
                    </button>
                </div>
              </div>
            </div>

            {expandedPeriodId === period.id && (
              <div className="border-t border-gray-100 bg-gray-50 p-4 space-y-4">
                <div className="flex justify-between items-center">
                  <h4 className="text-sm font-bold text-gray-600">打球记录明细</h4>
                  <button type="button" onClick={(e) => handleOpenAddSession(e, period.id)} className="text-xs bg-emerald-600 text-white px-3 py-1.5 rounded-full font-bold shadow-sm">
                    + 录入打球
                  </button>
                </div>

                {activeSessionPeriod === period.id && (
                  <div className="bg-white p-4 rounded-xl border-2 border-emerald-500 shadow-lg animate-in zoom-in-95">
                    <p className="text-sm font-bold text-gray-700 mb-3">{editingSessionId ? '编辑打球记录' : '新增打球记录'}</p>
                    <div className="mb-4">
                      <label className="block text-[10px] text-gray-400 mb-1">日期</label>
                      <input type="date" value={sessionFormDate} onChange={e => setSessionFormDate(e.target.value)} className="w-full border border-gray-300 rounded-lg p-2 text-sm" />
                    </div>
                    <div className="mb-4">
                      <p className="text-[10px] text-gray-400 mb-2">出席人员 (可多选):</p>
                      <div className="flex flex-wrap gap-2 max-h-48 overflow-y-auto p-2 border border-gray-100 rounded-lg bg-gray-50">
                        {players.map(p => {
                          const isSelected = selectedAttendees.find(a => a.playerId === p.id);
                          return (
                            <button key={p.id} type="button" onClick={() => toggleAttendee(p, period.id)} className={`text-xs px-2.5 py-1.5 rounded-lg border transition-all ${isSelected ? 'bg-emerald-600 border-emerald-600 text-white' : 'bg-white border-gray-200 text-gray-600'}`}>
                              {p.name}
                            </button>
                          );
                        })}
                      </div>
                    </div>
                    {selectedAttendees.length > 0 && (
                      <div className="mb-4 space-y-1">
                        <p className="text-[10px] text-gray-400">核对收费:</p>
                        {selectedAttendees.map(a => {
                          const player = players.find(p => p.id === a.playerId);
                          return (
                            <div key={a.playerId} className="flex justify-between items-center bg-gray-50 p-2 rounded text-[11px]">
                              <span>{player?.name || '未知'} ({player?.type || '次'})</span>
                              <div className="flex items-center gap-1">
                                <span className="text-gray-400">¥</span>
                                <input type="number" value={a.fee} onChange={e => {
                                  const val = Number(e.target.value);
                                  setSelectedAttendees(prev => prev.map(sa => sa.playerId === a.playerId ? {...sa, fee: val} : sa));
                                }} className="w-14 border border-gray-200 rounded px-1.5 py-0.5 text-center font-bold text-emerald-600" />
                              </div>
                            </div>
                          );
                        })}
                      </div>
                    )}
                    <div className="flex gap-2">
                      <button type="button" onClick={() => saveSession(period.id)} className="flex-1 bg-emerald-600 text-white py-2 rounded-lg font-bold text-sm shadow-sm">保存</button>
                      <button type="button" onClick={() => setActiveSessionPeriod(null)} className="flex-1 bg-gray-100 text-gray-500 py-2 rounded-lg font-bold text-sm">取消</button>
                    </div>
                  </div>
                )}

                <div className="space-y-2">
                  {period.sessions.length === 0 ? (
                    <p className="text-center text-xs text-gray-400 py-4">暂无记录</p>
                  ) : (
                    period.sessions.slice().sort((a,b) => b.date.localeCompare(a.date)).map(session => (
                      <div key={session.id} className="bg-white p-3 rounded-xl shadow-sm border border-gray-100">
                        <div className="flex justify-between items-start mb-2">
                          <div>
                            <p className="text-xs font-black text-gray-700">{session.date}</p>
                            <div className="flex items-center gap-2 mt-0.5">
                              <span className="text-[9px] bg-blue-50 text-blue-600 px-1 rounded font-bold">出席: {session.attendees.length}人</span>
                              <span className="text-[9px] bg-emerald-50 text-emerald-600 px-1 rounded font-bold">实收: ¥{session.attendees.reduce((sum, a) => sum + a.fee, 0)}</span>
                            </div>
                          </div>
                          <div className="flex gap-1">
                            <button type="button" onClick={(e) => handleEditSession(e, period.id, session)} className="text-gray-300 hover:text-emerald-500 p-1.5 active:scale-110">
                              <Icons.Pencil />
                            </button>
                            <button type="button" onClick={(e) => removeSession(e, period.id, session.id)} className="text-gray-300 hover:text-red-400 p-1.5 active:scale-110">
                              <Icons.Trash />
                            </button>
                          </div>
                        </div>
                        <div className="flex flex-wrap gap-1.5">
                          {session.attendees.map(a => (
                            <span key={a.playerId} className={`text-[9px] px-1.5 py-0.5 rounded border ${a.fee === 0 ? 'bg-gray-50 text-gray-400 border-gray-100 italic' : 'bg-white text-gray-600 border-gray-100'}`}>
                              {players.find(pl => pl.id === a.playerId)?.name || '已删'} (¥{a.fee})
                            </span>
                          ))}
                        </div>
                      </div>
                    ))
                  )}
                </div>
              </div>
            )}
          </div>
        ))}
        {periods.length === 0 && (
          <div className="text-center py-20 text-gray-400">
            <p className="text-5xl mb-4 opacity-10 text-center">🏸</p>
            <p className="text-sm">暂无结算周期，请点击右上角新增</p>
          </div>
        )}
      </div>
    </div>
  );
};

