import React, { useState } from 'react';
import { Player, PlayerType } from '../types';
import { Icons, DEFAULT_SESSION_FEE } from '../constants';

interface PlayersListProps {
  players: Player[];
  setPlayers: React.Dispatch<React.SetStateAction<Player[]>>;
}

const PlayersList: React.FC<PlayersListProps> = ({ players, setPlayers }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState<Partial<Player>>({
    name: '',
    type: PlayerType.PER_SESSION,
    defaultFee: DEFAULT_SESSION_FEE,
    isFunder: false
  });

  const handleSave = () => {
    if (!formData.name) return;
    if (editingId) {
      setPlayers(prev => prev.map(p => p.id === editingId ? { ...p, ...formData } as Player : p));
      setEditingId(null);
    } else {
      const newPlayer: Player = {
        id: Date.now().toString(),
        name: formData.name!,
        type: formData.type as PlayerType || PlayerType.PER_SESSION,
        defaultFee: formData.defaultFee !== undefined ? formData.defaultFee : (formData.type === PlayerType.PER_SESSION ? DEFAULT_SESSION_FEE : 0),
        isFunder: false 
      };
      setPlayers(prev => [...prev, newPlayer]);
      setIsAdding(false);
    }
    setFormData({ name: '', type: PlayerType.PER_SESSION, defaultFee: DEFAULT_SESSION_FEE, isFunder: false });
  };

  const startEdit = (player: Player) => {
    setEditingId(player.id);
    setFormData(player);
  };

  const handleDelete = (id: string) => {
    if (confirm('确定要从档案中彻底删除该人员吗？此操作不可撤销。')) {
      setPlayers(prev => prev.filter(p => p.id !== id));
    }
  };

  return (
    <div className="p-4">
      <div className="flex justify-between items-center mb-4">
        <h2 className="text-lg font-bold">人员档案</h2>
        <button 
          type="button"
          onClick={() => setIsAdding(true)}
          className="bg-emerald-600 text-white px-3 py-1.5 rounded-lg text-sm flex items-center gap-1 font-bold shadow-sm active:scale-95"
        >
          <Icons.Plus /> 新增人员
        </button>
      </div>

      {(isAdding || editingId) && (
        <div className="mb-6 bg-white p-4 rounded-xl shadow-lg border-2 border-emerald-500 animate-in zoom-in-95 duration-200">
          <h3 className="font-bold mb-4">{editingId ? '修改成员信息' : '录入新成员'}</h3>
          <div className="space-y-4">
            <div>
              <label className="block text-xs text-gray-500 mb-1 font-bold">姓名</label>
              <input type="text" value={formData.name} onChange={e => setFormData({ ...formData, name: e.target.value })} className="w-full border border-gray-300 rounded-lg p-2 text-sm focus:ring-2 focus:ring-emerald-500" placeholder="姓名" />
            </div>
            <div>
              <label className="block text-xs text-gray-500 mb-1 font-bold">类型</label>
              <select value={formData.type} onChange={e => {
                   const type = e.target.value as PlayerType;
                   const fee = type === PlayerType.PER_SESSION ? DEFAULT_SESSION_FEE : (formData.defaultFee || 0);
                   setFormData({ ...formData, type, defaultFee: fee });
              }} className="w-full border border-gray-300 rounded-lg p-2 text-sm">
                <option value={PlayerType.MONTHLY}>包月</option>
                <option value={PlayerType.HALF_MONTHLY}>包半月</option>
                <option value={PlayerType.PER_SESSION}>按次</option>
              </select>
            </div>
            <div>
              <label className="block text-xs text-gray-500 mb-1 font-bold">标准收费金额 (元)</label>
              <input type="number" value={formData.defaultFee} onChange={e => setFormData({ ...formData, defaultFee: Number(e.target.value) })} className="w-full border border-gray-300 rounded-lg p-2 text-sm" />
            </div>
            {editingId && (
               <div className="flex items-center gap-2 p-2 bg-amber-50 rounded-lg">
                 <input type="checkbox" checked={formData.isFunder} onChange={e => setFormData({ ...formData, isFunder: e.target.checked })} id="isFunder" className="w-4 h-4 text-amber-600" />
                 <label htmlFor="isFunder" className="text-xs font-bold text-amber-800 cursor-pointer">设为创始集资成员 (10人名单)</label>
               </div>
            )}
            <div className="flex gap-2 pt-2">
              <button type="button" onClick={handleSave} className="flex-1 bg-emerald-600 text-white py-2 rounded-lg font-bold text-sm shadow-sm">保存</button>
              <button type="button" onClick={() => { setIsAdding(false); setEditingId(null); }} className="flex-1 bg-gray-100 text-gray-500 py-2 rounded-lg font-bold text-sm">取消</button>
            </div>
          </div>
        </div>
      )}

      <div className="space-y-3">
        {players.map(player => (
          <div key={player.id} className={`bg-white p-4 rounded-xl shadow-sm border flex justify-between items-center transition-all ${player.isFunder ? 'border-amber-200' : 'border-gray-100'}`}>
            <div className="flex-1">
              <div className="flex items-center gap-2">
                <span className="font-bold text-gray-800">{player.name}</span>
                {player.isFunder && <span className="text-[10px] bg-amber-100 text-amber-700 px-1.5 py-0.5 rounded-full font-bold">集资人</span>}
              </div>
              <div className="text-xs text-gray-500 mt-1 flex items-center gap-3">
                <span className={`px-2 py-0.5 rounded-md font-medium ${player.type === PlayerType.MONTHLY ? 'bg-purple-100 text-purple-700' : player.type === PlayerType.HALF_MONTHLY ? 'bg-blue-100 text-blue-700' : 'bg-green-100 text-green-700'}`}>{player.type}</span>
                <span className="font-bold text-gray-700">¥{player.defaultFee}</span>
              </div>
            </div>
            <div className="flex gap-2">
              <button type="button" onClick={() => startEdit(player)} className="text-emerald-600 text-sm font-bold bg-emerald-50 px-3 py-1.5 rounded-lg active:bg-emerald-100">编辑</button>
              <button type="button" onClick={() => handleDelete(player.id)} className="text-red-300 hover:text-red-500 p-2 active:scale-125 transition-all">
                <Icons.Trash />
              </button>
            </div>
          </div>
        ))}
        {players.length === 0 && <p className="text-center py-10 text-gray-400 text-sm">档案空空如也，请新增人员</p>}
      </div>
    </div>
  );
};

