import React, { useState, useEffect, useMemo } from 'react';
import { Player, Period, View, PlayerType } from './types';
import { INITIAL_FUNDERS, Icons, DEFAULT_SESSION_FEE } from './constants';
import Dashboard from './components/Dashboard';
import PlayersList from './components/PlayersList';
import PeriodsList from './components/PeriodsList';
import FinanceReport from './components/FinanceReport';

const App: React.FC = () => {
  const [view, setView] = useState<View>('dashboard');
  const [players, setPlayers] = useState<Player[]>(() => {
    const saved = localStorage.getItem('badminton_players');
    return saved ? JSON.parse(saved) : INITIAL_FUNDERS;
  });
  const [periods, setPeriods] = useState<Period[]>(() => {
    const saved = localStorage.getItem('badminton_periods');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('badminton_players', JSON.stringify(players));
  }, [players]);

  useEffect(() => {
    localStorage.setItem('badminton_periods', JSON.stringify(periods));
  }, [periods]);

  const activePeriod = useMemo(() => {
    return periods.length > 0 ? periods[periods.length - 1] : null;
  }, [periods]);

  const renderView = () => {
    switch (view) {
      case 'dashboard':
        return <Dashboard players={players} periods={periods} activePeriod={activePeriod} />;
      case 'players':
        return <PlayersList players={players} setPlayers={setPlayers} />;
      case 'periods':
        return <PeriodsList periods={periods} setPeriods={setPeriods} players={players} setPlayers={setPlayers} />;
      case 'finance':
        return <FinanceReport periods={periods} players={players} />;
      default:
        return <Dashboard players={players} periods={periods} activePeriod={activePeriod} />;
    }
  };

  return (
    <div className="flex flex-col h-screen max-w-md mx-auto bg-gray-50">
      {/* Header */}
      <header className="bg-emerald-600 text-white p-4 shadow-md sticky top-0 z-50">
        <h1 className="text-xl font-bold flex items-center">
          <span className="mr-2">🏸</span>
          羽球社财务助手
        </h1>
      </header>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto pb-20">
        {renderView()}
      </main>

      {/* Tab Bar (WeChat Style) */}
      <nav className="fixed bottom-0 left-0 right-0 max-w-md mx-auto bg-white border-t border-gray-200 flex justify-around py-2 px-1 z-50">
        <button 
          onClick={() => setView('dashboard')}
          className={`flex flex-col items-center flex-1 py-1 transition-colors ${view === 'dashboard' ? 'text-emerald-600' : 'text-gray-400'}`}
        >
          <Icons.Home />
          <span className="text-[10px] mt-1 font-medium">首页</span>
        </button>
        <button 
          onClick={() => setView('players')}
          className={`flex flex-col items-center flex-1 py-1 transition-colors ${view === 'players' ? 'text-emerald-600' : 'text-gray-400'}`}
        >
          <Icons.Users />
          <span className="text-[10px] mt-1 font-medium">人员</span>
        </button>
        <button 
          onClick={() => setView('periods')}
          className={`flex flex-col items-center flex-1 py-1 transition-colors ${view === 'periods' ? 'text-emerald-600' : 'text-gray-400'}`}
        >
          <Icons.Calendar />
          <span className="text-[10px] mt-1 font-medium">结算</span>
        </button>
        <button 
          onClick={() => setView('finance')}
          className={`flex flex-col items-center flex-1 py-1 transition-colors ${view === 'finance' ? 'text-emerald-600' : 'text-gray-400'}`}
        >
          <Icons.Chart />
          <span className="text-[10px] mt-1 font-medium">报表</span>
        </button>
      </nav>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Period, Player, Session, PlayerType } from '../types';
import { Icons, DEFAULT_SESSION_FEE } from '../constants';

interface PeriodsListProps {
  periods: Period[];
  setPeriods: React.Dispatch<React.SetStateAction<Period[]>>;
  players: Player[];
  setPlayers: React.Dispatch<React.SetStateAction<Player[]>>;
}

const PeriodsList: React.FC<PeriodsListProps> = ({ periods, setPeriods, players, setPlayers }) => {
  const [isAddingPeriod, setIsAddingPeriod] = useState(false);
  const [editingPeriodId, setEditingPeriodId] = useState<string | null>(null);
  const [expandedPeriodId, setExpandedPeriodId] = useState<string | null>(null);
  const [activeSessionPeriod, setActiveSessionPeriod] = useState<string | null>(null);
  const [editingSessionId, setEditingSessionId] = useState<string | null>(null);

  // 只筛选档案中被标记为 isFunder 的原始人员作为集资人备选池
  const funderPool = players.filter(p => p.isFunder);

  const initialPeriodData = {
    name: '',
    startDate: new Date().toISOString().split('T')[0],
    endDate: '',
    courtCost: 0,
    funderIds: funderPool.map(p => p.id), // 默认全选
    sessions: []
  };

  const [periodFormData, setPeriodFormData] = useState<Partial<Period>>(initialPeriodData);
  const [sessionFormDate, setSessionFormDate] = useState(new Date().toISOString().split('T')[0]);
  const [selectedAttendees, setSelectedAttendees] = useState<{playerId: string, fee: number}[]>([]);

  const handleSavePeriod = () => {
    if (!periodFormData.name) {
      alert('请输入周期名称');
      return;
    }

    // 1. 确定最终勾选的集资人 IDs
    const finalFunderIds = periodFormData.funderIds && periodFormData.funderIds.length > 0 
      ? periodFormData.funderIds 
      : [];

    // 2. 自动处理“剩下的集资人”逻辑：
    // 如果某人在原集资人池中（isFunder 为 true），但本次周期没被勾选，
    // 则说明他本期退出了集资，自动转为“按次收费”类型。
    setPlayers(prevPlayers => prevPlayers.map(p => {
      if (p.isFunder && !finalFunderIds.includes(p.id)) {
        return {
          ...p,
          type: PlayerType.PER_SESSION,
          isFunder: false, // 失去集资人资格，以后不再出现在备选池中
          defaultFee: DEFAULT_SESSION_FEE
        };
      }
      return p;
    }));

    // 3. 保存周期
    if (editingPeriodId) {
      setPeriods(prev => prev.map(p => p.id === editingPeriodId ? { 
        ...p, 
        ...periodFormData,
        funderIds: finalFunderIds 
      } as Period : p));
      setEditingPeriodId(null);
    } else {
      const period: Period = {
        id: Date.now().toString(),
        name: periodFormData.name!,
        startDate: periodFormData.startDate!,
        endDate: periodFormData.endDate || '',
        courtCost: periodFormData.courtCost || 0,
        funderIds: finalFunderIds,
        sessions: []
      };
      setPeriods(prev => [...prev, period]);
      setIsAddingPeriod(false);
    }
    setPeriodFormData(initialPeriodData);
  };

  const startEditPeriod = (e: React.MouseEvent, period: Period) => {
    e.stopPropagation();
    setEditingPeriodId(period.id);
    setPeriodFormData(period);
  };

  const deletePeriod = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (window.confirm('确定要删除该结算周期吗？警告：周期内的所有打球记录将一并被清除且无法恢复！')) {
      setPeriods(prev => prev.filter(p => p.id !== id));
      if (expandedPeriodId === id) setExpandedPeriodId(null);
    }
  };

  const toggleFunderInPeriod = (funderId: string) => {
    const current = periodFormData.funderIds || [];
    if (current.includes(funderId)) {
      setPeriodFormData({...periodFormData, funderIds: current.filter(id => id !== funderId)});
    } else {
      setPeriodFormData({...periodFormData, funderIds: [...current, funderId]});
    }
  };

  const handleOpenAddSession = (e: React.MouseEvent, periodId: string) => {
    e.stopPropagation();
    setActiveSessionPeriod(periodId);
    setEditingSessionId(null);
    setSessionFormDate(new Date().toISOString().split('T')[0]);
    setSelectedAttendees([]);
  };

  const handleEditSession = (e: React.MouseEvent, periodId: string, session: Session) => {
    e.stopPropagation();
    setActiveSessionPeriod(periodId);
    setEditingSessionId(session.id);
    setSessionFormDate(session.date);
    setSelectedAttendees(session.attendees);
  };

  const saveSession = (periodId: string) => {
    if (selectedAttendees.length === 0) {
      alert('请至少选择一名出席成员');
      return;
    }
    if (editingSessionId) {
      setPeriods(prev => prev.map(p => p.id === periodId ? {
        ...p,
        sessions: p.sessions.map(s => s.id === editingSessionId ? { ...s, date: sessionFormDate, attendees: selectedAttendees } : s)
      } : p));
    } else {
      const session: Session = {
        id: Date.now().toString(),
        date: sessionFormDate,
        attendees: selectedAttendees
      };
      setPeriods(prev => prev.map(p => p.id === periodId ? { ...p, sessions: [...p.sessions, session] } : p));
    }
    setActiveSessionPeriod(null);
    setEditingSessionId(null);
  };

  const removeSession = (e: React.MouseEvent, periodId: string, sessionId: string) => {
    e.stopPropagation();
    if (window.confirm('确定要删除这条活动记录吗？')) {
      setPeriods(prev => prev.map(p => p.id === periodId ? { ...p, sessions: p.sessions.filter(s => s.id !== sessionId) } : p));
    }
  };

  const toggleAttendee = (player: Player, periodId: string) => {
    const exists = selectedAttendees.find(a => a.playerId === player.id);
    if (exists) {
      setSelectedAttendees(prev => prev.filter(a => a.playerId !== player.id));
    } else {
      const currentPeriod = periods.find(p => p.id === periodId);
      const isMonthlyType = player.type === PlayerType.MONTHLY || player.type === PlayerType.HALF_MONTHLY;
      let defaultFee = player.defaultFee;
      if (isMonthlyType && currentPeriod) {
        const hasPaidInPeriod = currentPeriod.sessions.some(s => 
          s.id !== editingSessionId && 
          s.attendees.some(a => a.playerId === player.id && a.fee > 0)
        );
        if (hasPaidInPeriod) defaultFee = 0;
      }
      setSelectedAttendees(prev => [...prev, { playerId: player.id, fee: defaultFee }]);
    }
  };

  return (
    <div className="p-4 pb-10">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-lg font-bold text-gray-800">结算周期管理</h2>
        <button 
          type="button"
          onClick={() => { setIsAddingPeriod(true); setPeriodFormData(initialPeriodData); }}
          className="bg-emerald-600 text-white px-3 py-2 rounded-lg text-sm flex items-center gap-1 font-bold shadow-md active:scale-95 transition-all"
        >
          <Icons.Plus /> 新增周期
        </button>
      </div>

      {(isAddingPeriod || editingPeriodId) && (
        <div className="mb-8 bg-white p-5 rounded-2xl shadow-xl border-2 border-emerald-500 animate-in slide-in-from-top-4 duration-300">
          <h3 className="font-black mb-5 text-emerald-800 text-base">{editingPeriodId ? '📝 编辑结算周期' : '🗓️ 创建新结算周期'}</h3>
          <div className="space-y-5">
            <div>
              <label className="block text-xs font-bold text-gray-500 mb-1.5 uppercase">周期名称</label>
              <input type="text" placeholder="例如：2024年5月 第一期" value={periodFormData.name} onChange={e => setPeriodFormData({...periodFormData, name: e.target.value})} className="w-full border border-gray-300 rounded-xl p-3 text-sm focus:ring-2 focus:ring-emerald-500 outline-none transition-all" />
            </div>
            <div className="flex gap-3">
              <div className="flex-1">
                <label className="block text-xs font-bold text-gray-500 mb-1.5 uppercase">开始日期</label>
                <input type="date" value={periodFormData.startDate} onChange={e => setPeriodFormData({...periodFormData, startDate: e.target.value})} className="w-full border border-gray-300 rounded-xl p-3 text-sm focus:ring-2 focus:ring-emerald-500" />
              </div>
              <div className="flex-1">
                <label className="block text-xs font-bold text-gray-500 mb-1.5 uppercase">结束日期</label>
                <input type="date" value={periodFormData.endDate} onChange={e => setPeriodFormData({...periodFormData, endDate: e.target.value})} className="w-full border border-gray-300 rounded-xl p-3 text-sm focus:ring-2 focus:ring-emerald-500" />
              </div>
            </div>
            <div>
              <label className="block text-xs font-bold text-gray-500 mb-1.5 uppercase">场地预订成本 (元)</label>
              <input type="number" placeholder="0.00" value={periodFormData.courtCost || ''} onChange={e => setPeriodFormData({...periodFormData, courtCost: Number(e.target.value)})} className="w-full border border-gray-300 rounded-xl p-3 text-sm font-mono text-red-600" />
            </div>

            <div className="bg-amber-50 p-4 rounded-xl border border-amber-200">
              <label className="block text-xs font-black text-amber-800 mb-3 flex items-center gap-1 uppercase">
                👑 选择本期参加集资人员 (从现有集资人池中挑选)
              </label>
              <div className="flex flex-wrap gap-2">
                {funderPool.length > 0 ? funderPool.map(f => (
                  <button 
                    key={f.id} 
                    type="button" 
                    onClick={() => toggleFunderInPeriod(f.id)} 
                    className={`text-xs px-3 py-2 rounded-lg border-2 transition-all font-bold ${
                      periodFormData.funderIds?.includes(f.id) 
                      ? 'bg-amber-500 border-amber-600 text-white shadow-sm' 
                      : 'bg-white border-amber-100 text-amber-300'
                    }`}
                  >
                    {f.name}
                  </button>
                )) : <p className="text-[10px] text-amber-600 italic">档案中没有标记为集资人的成员</p>}
              </div>
              <p className="text-[10px] text-amber-700 mt-2 opacity-70">* 保存后，本期未被选中的集资人将自动转为档案中的“按次收费”人员。</p>
            </div>

            <div className="flex gap-3 pt-2">
              <button type="button" onClick={handleSavePeriod} className="flex-2 bg-emerald-600 text-white py-3 rounded-xl font-black text-sm shadow-lg active:scale-95 transition-all">确认保存</button>
              <button type="button" onClick={() => { setIsAddingPeriod(false); setEditingPeriodId(null); }} className="flex-1 bg-gray-100 text-gray-500 py-3 rounded-xl font-bold text-sm">取消</button>
            </div>
          </div>
        </div>
      )}

      <div className="space-y-4">
        {periods.slice().reverse().map(period => (
          <div key={period.id} className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden transition-all active:shadow-md">
            <div 
              className={`p-4 flex justify-between items-center cursor-pointer transition-colors ${expandedPeriodId === period.id ? 'bg-emerald-50/30' : 'hover:bg-gray-50'}`}
              onClick={() => setExpandedPeriodId(expandedPeriodId === period.id ? null : period.id)}
            >
              <div className="flex-1">
                <h3 className="font-black text-gray-800 text-base">{period.name}</h3>
                <p className="text-[10px] text-gray-400 font-medium mt-1">{period.startDate} ~ {period.endDate || '进行中'}</p>
                <div className="mt-3 flex gap-1.5 flex-wrap">
                  {period.funderIds.map(fid => (
                    <span key={fid} className="text-[9px] bg-amber-100 text-amber-700 border border-amber-200 px-1.5 py-0.5 rounded-md font-bold">
                      {players.find(p => p.id === fid)?.name || '已删'}
                    </span>
                  ))}
                </div>
              </div>
              <div className="flex items-center gap-5">
                <div className="text-right">
                  <p className="text-[10px] text-gray-400 font-bold uppercase">活动次数</p>
                  <p className="font-black text-emerald-600 text-lg">{period.sessions.length}</p>
                </div>
                <div className="flex flex-col gap-2">
                   <button type="button" onClick={(e) => startEditPeriod(e, period)} className="text-emerald-700 text-[10px] font-black p-1.5 bg-emerald-100/50 rounded-lg active:bg-emerald-200">编辑</button>
                   <button type="button" onClick={(e) => deletePeriod(e, period.id)} className="text-gray-300 hover:text-red-500 p-1.5 active:scale-110 transition-transform">
                      <Icons.Trash />
                    </button>
                </div>
              </div>
            </div>

            {expandedPeriodId === period.id && (
              <div className="border-t border-gray-100 bg-gray-50/50 p-4 space-y-4 animate-in slide-in-from-top-2 duration-200">
                <div className="flex justify-between items-center">
                  <h4 className="text-xs font-black text-gray-500 uppercase tracking-widest">📋 详细打球记录</h4>
                  <button type="button" onClick={(e) => handleOpenAddSession(e, period.id)} className="text-[10px] bg-emerald-600 text-white px-4 py-2 rounded-full font-black shadow-md active:opacity-80">
                    + 录入单场打球
                  </button>
                </div>

                {activeSessionPeriod === period.id && (
                  <div className="bg-white p-4 rounded-2xl border-2 border-emerald-500 shadow-xl animate-in zoom-in-95">
                    <p className="text-xs font-black text-emerald-800 mb-4 uppercase">{editingSessionId ? '✏️ 修改单场数据' : '✨ 录入全新场次'}</p>
                    <div className="space-y-4">
                      <div>
                        <label className="block text-[10px] font-bold text-gray-400 mb-1">选择活动日期</label>
                        <input type="date" value={sessionFormDate} onChange={e => setSessionFormDate(e.target.value)} className="w-full border border-gray-200 rounded-xl p-3 text-sm focus:ring-2 focus:ring-emerald-500" />
                      </div>
                      <div>
                        <p className="text-[10px] font-bold text-gray-400 mb-2">选择出席人员 (多选):</p>
                        <div className="flex flex-wrap gap-2 max-h-40 overflow-y-auto p-3 border border-gray-100 rounded-xl bg-gray-50/50">
                          {players.map(p => {
                            const isSelected = selectedAttendees.find(a => a.playerId === p.id);
                            return (
                              <button key={p.id} type="button" onClick={() => toggleAttendee(p, period.id)} className={`text-[10px] px-3 py-2 rounded-lg border-2 font-bold transition-all ${isSelected ? 'bg-emerald-600 border-emerald-700 text-white shadow-sm' : 'bg-white border-gray-200 text-gray-400'}`}>
                                {p.name}
                              </button>
                            );
                          })}
                        </div>
                      </div>
                      {selectedAttendees.length > 0 && (
                        <div className="space-y-2">
                          <p className="text-[10px] font-bold text-gray-400">核对/修改个人收费:</p>
                          {selectedAttendees.map(a => {
                            const player = players.find(p => p.id === a.playerId);
                            return (
                              <div key={a.playerId} className="flex justify-between items-center bg-gray-50 p-2.5 rounded-xl text-xs">
                                <span className="font-bold text-gray-700">{player?.name || '未知'} <span className="text-[9px] font-normal opacity-50">({player?.type})</span></span>
                                <div className="flex items-center gap-1 bg-white border border-gray-200 rounded-lg px-2">
                                  <span className="text-[10px] font-bold text-gray-400">¥</span>
                                  <input type="number" value={a.fee} onChange={e => {
                                    const val = Number(e.target.value);
                                    setSelectedAttendees(prev => prev.map(sa => sa.playerId === a.playerId ? {...sa, fee: val} : sa));
                                  }} className="w-12 py-1 text-center font-black text-emerald-600 focus:outline-none" />
                                </div>
                              </div>
                            );
                          })}
                        </div>
                      )}
                      <div className="flex gap-3 pt-2">
                        <button type="button" onClick={() => saveSession(period.id)} className="flex-2 bg-emerald-600 text-white py-3 rounded-xl font-black text-sm shadow-md">保存记录</button>
                        <button type="button" onClick={() => setActiveSessionPeriod(null)} className="flex-1 bg-gray-100 text-gray-500 py-3 rounded-xl font-bold text-sm">取消</button>
                      </div>
                    </div>
                  </div>
                )}

                <div className="space-y-3">
                  {period.sessions.length === 0 ? (
                    <div className="text-center py-10 bg-white/50 rounded-2xl border border-dashed border-gray-200">
                      <p className="text-[10px] text-gray-400 italic">本期暂无打球数据，请点击录入</p>
                    </div>
                  ) : (
                    period.sessions.slice().sort((a,b) => b.date.localeCompare(a.date)).map(session => (
                      <div key={session.id} className="bg-white p-3.5 rounded-2xl shadow-sm border border-gray-100 flex flex-col gap-3">
                        <div className="flex justify-between items-center">
                          <div>
                            <p className="text-xs font-black text-gray-800">{session.date}</p>
                            <div className="flex items-center gap-2 mt-1">
                              <span className="text-[9px] bg-emerald-50 text-emerald-700 border border-emerald-100 px-1.5 py-0.5 rounded font-bold">实收: ¥{session.attendees.reduce((sum, a) => sum + a.fee, 0)}</span>
                              <span className="text-[9px] bg-blue-50 text-blue-700 border border-blue-100 px-1.5 py-0.5 rounded font-bold">{session.attendees.length} 人出席</span>
                            </div>
                          </div>
                          <div className="flex gap-1">
                            <button type="button" onClick={(e) => handleEditSession(e, period.id, session)} className="text-gray-300 hover:text-emerald-500 p-2 active:scale-110">
                              <Icons.Pencil />
                            </button>
                            <button type="button" onClick={(e) => removeSession(e, period.id, session.id)} className="text-gray-300 hover:text-red-500 p-2 active:scale-110">
                              <Icons.Trash />
                            </button>
                          </div>
                        </div>
                        <div className="flex flex-wrap gap-1.5">
                          {session.attendees.map(a => (
                            <span key={a.playerId} className={`text-[9px] px-2 py-1 rounded-md border font-medium ${a.fee === 0 ? 'bg-gray-50 text-gray-400 border-gray-100 italic' : 'bg-white text-gray-600 border-gray-100'}`}>
                              {players.find(pl => pl.id === a.playerId)?.name || '已删'} (¥{a.fee})
                            </span>
                          ))}
                        </div>
                      </div>
                    ))
                  )}
                </div>
              </div>
            )}
          </div>
        ))}
        {periods.length === 0 && (
          <div className="text-center py-20 bg-white rounded-3xl border border-dashed border-gray-200">
            <p className="text-5xl mb-4 opacity-10">📅</p>
            <p className="text-sm text-gray-400">点击右上角按钮创建第一个结算周期</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default PeriodsList;

export enum PlayerType {
  MONTHLY = '包月',
  HALF_MONTHLY = '包半月',
  PER_SESSION = '按次'
}

export interface Player {
  id: string;
  name: string;
  type: PlayerType;
  defaultFee: number;
  isFunder: boolean;
}

export interface Session {
  id: string;
  date: string;
  attendees: {
    playerId: string;
    fee: number;
  }[];
}

export interface Period {
  id: string;
  name: string;
  startDate: string;
  endDate: string;
  courtCost: number; // 场地总成本
  sessions: Session[];
  funderIds: string[]; // IDs of participating funders for this period
}

export type View = 'dashboard' | 'players' | 'periods' | 'finance';

import React, { useState, useEffect, useMemo } from 'react';
import { Player, Period, View, PlayerType } from './types';
import { INITIAL_FUNDERS, Icons, DEFAULT_SESSION_FEE } from './constants';
import Dashboard from './components/Dashboard';
import PlayersList from './components/PlayersList';
import PeriodsList from './components/PeriodsList';
import FinanceReport from './components/FinanceReport';

const App: React.FC = () => {
  const [view, setView] = useState<View>('dashboard');
  const [players, setPlayers] = useState<Player[]>(() => {
    const saved = localStorage.getItem('badminton_players');
    return saved ? JSON.parse(saved) : INITIAL_FUNDERS;
  });
  const [periods, setPeriods] = useState<Period[]>(() => {
    const saved = localStorage.getItem('badminton_periods');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('badminton_players', JSON.stringify(players));
  }, [players]);

  useEffect(() => {
    localStorage.setItem('badminton_periods', JSON.stringify(periods));
  }, [periods]);

  const activePeriod = useMemo(() => {
    return periods.length > 0 ? periods[periods.length - 1] : null;
  }, [periods]);

  const renderView = () => {
    switch (view) {
      case 'dashboard':
        return <Dashboard players={players} periods={periods} activePeriod={activePeriod} />;
      case 'players':
        return <PlayersList players={players} setPlayers={setPlayers} />;
      case 'periods':
        return <PeriodsList periods={periods} setPeriods={setPeriods} players={players} setPlayers={setPlayers} />;
      case 'finance':
        return <FinanceReport periods={periods} players={players} />;
      default:
        return <Dashboard players={players} periods={periods} activePeriod={activePeriod} />;
    }
  };

  return (
    <div className="flex flex-col h-screen max-w-md mx-auto bg-gray-50">
      {/* Header */}
      <header className="bg-emerald-600 text-white p-4 shadow-md sticky top-0 z-50">
        <h1 className="text-xl font-bold flex items-center">
          <span className="mr-2">🏸</span>
          羽球社财务助手
        </h1>
      </header>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto pb-20">
        {renderView()}
      </main>

      {/* Tab Bar (WeChat Style) */}
      <nav className="fixed bottom-0 left-0 right-0 max-w-md mx-auto bg-white border-t border-gray-200 flex justify-around py-2 px-1 z-50">
        <button 
          onClick={() => setView('dashboard')}
          className={`flex flex-col items-center flex-1 py-1 transition-colors ${view === 'dashboard' ? 'text-emerald-600' : 'text-gray-400'}`}
        >
          <Icons.Home />
          <span className="text-[10px] mt-1 font-medium">首页</span>
        </button>
        <button 
          onClick={() => setView('players')}
          className={`flex flex-col items-center flex-1 py-1 transition-colors ${view === 'players' ? 'text-emerald-600' : 'text-gray-400'}`}
        >
          <Icons.Users />
          <span className="text-[10px] mt-1 font-medium">人员</span>
        </button>
        <button 
          onClick={() => setView('periods')}
          className={`flex flex-col items-center flex-1 py-1 transition-colors ${view === 'periods' ? 'text-emerald-600' : 'text-gray-400'}`}
        >
          <Icons.Calendar />
          <span className="text-[10px] mt-1 font-medium">结算</span>
        </button>
        <button 
          onClick={() => setView('finance')}
          className={`flex flex-col items-center flex-1 py-1 transition-colors ${view === 'finance' ? 'text-emerald-600' : 'text-gray-400'}`}
        >
          <Icons.Chart />
          <span className="text-[10px] mt-1 font-medium">报表</span>
        </button>
      </nav>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Period, Player, Session, PlayerType } from '../types';
import { Icons, DEFAULT_SESSION_FEE } from '../constants';

interface PeriodsListProps {
  periods: Period[];
  setPeriods: React.Dispatch<React.SetStateAction<Period[]>>;
  players: Player[];
  setPlayers: React.Dispatch<React.SetStateAction<Player[]>>;
}

const PeriodsList: React.FC<PeriodsListProps> = ({ periods, setPeriods, players, setPlayers }) => {
  const [isAddingPeriod, setIsAddingPeriod] = useState(false);
  const [editingPeriodId, setEditingPeriodId] = useState<string | null>(null);
  const [expandedPeriodId, setExpandedPeriodId] = useState<string | null>(null);
  const [activeSessionPeriod, setActiveSessionPeriod] = useState<string | null>(null);
  const [editingSessionId, setEditingSessionId] = useState<string | null>(null);

  // 只筛选档案中被标记为 isFunder 的人员作为集资人备选池
  const funderPool = players.filter(p => p.isFunder);

  const initialPeriodData = {
    name: '',
    startDate: new Date().toISOString().split('T')[0],
    endDate: '',
    courtCost: 0,
    funderIds: funderPool.map(p => p.id), // 默认全选
    sessions: []
  };

  const [periodFormData, setPeriodFormData] = useState<Partial<Period>>(initialPeriodData);
  const [sessionFormDate, setSessionFormDate] = useState(new Date().toISOString().split('T')[0]);
  const [selectedAttendees, setSelectedAttendees] = useState<{playerId: string, fee: number}[]>([]);

  const handleSavePeriod = () => {
    if (!periodFormData.name) {
      alert('请输入周期名称');
      return;
    }

    // 1. 确定最终勾选的集资人 IDs
    const finalFunderIds = periodFormData.funderIds && periodFormData.funderIds.length > 0 
      ? periodFormData.funderIds 
      : [];

    // 2. 核心逻辑：未被勾选的“潜在集资人”自动转为按次人员
    // 用户要求：勾选集资人后，剩下的集资人自动变成按次收费的人员。
    setPlayers(prevPlayers => prevPlayers.map(p => {
      // 如果该人员原本是集资人名单中的一员，但本次结算周期没有被勾选
      if (p.isFunder && !finalFunderIds.includes(p.id)) {
        return {
          ...p,
          type: PlayerType.PER_SESSION,
          isFunder: false, // 失去集资资格，自动转为按次人员
          defaultFee: DEFAULT_SESSION_FEE // 设为默认按次费
        };
      }
      return p;
    }));

    // 3. 保存周期
    if (editingPeriodId) {
      setPeriods(prev => prev.map(p => p.id === editingPeriodId ? { 
        ...p, 
        ...periodFormData,
        funderIds: finalFunderIds 
      } as Period : p));
      setEditingPeriodId(null);
    } else {
      const period: Period = {
        id: Date.now().toString(),
        name: periodFormData.name!,
        startDate: periodFormData.startDate!,
        endDate: periodFormData.endDate || '',
        courtCost: periodFormData.courtCost || 0,
        funderIds: finalFunderIds,
        sessions: []
      };
      setPeriods(prev => [...prev, period]);
      setIsAddingPeriod(false);
    }
    setPeriodFormData(initialPeriodData);
  };

  const startEditPeriod = (e: React.MouseEvent, period: Period) => {
    e.stopPropagation();
    setEditingPeriodId(period.id);
    setPeriodFormData(period);
  };

  const deletePeriod = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (window.confirm('确定要删除该结算周期吗？警告：周期内的所有打球记录将一并被清除且无法恢复！')) {
      setPeriods(prev => prev.filter(p => p.id !== id));
      if (expandedPeriodId === id) setExpandedPeriodId(null);
    }
  };

  const toggleFunderInPeriod = (funderId: string) => {
    const current = periodFormData.funderIds || [];
    if (current.includes(funderId)) {
      setPeriodFormData({...periodFormData, funderIds: current.filter(id => id !== funderId)});
    } else {
      setPeriodFormData({...periodFormData, funderIds: [...current, funderId]});
    }
  };

  const handleOpenAddSession = (e: React.MouseEvent, periodId: string) => {
    e.stopPropagation();
    setActiveSessionPeriod(periodId);
    setEditingSessionId(null);
    setSessionFormDate(new Date().toISOString().split('T')[0]);
    setSelectedAttendees([]);
  };

  const handleEditSession = (e: React.MouseEvent, periodId: string, session: Session) => {
    e.stopPropagation();
    setActiveSessionPeriod(periodId);
    setEditingSessionId(session.id);
    setSessionFormDate(session.date);
    setSelectedAttendees(session.attendees);
  };

  const saveSession = (periodId: string) => {
    if (selectedAttendees.length === 0) {
      alert('请至少选择一名出席成员');
      return;
    }
    if (editingSessionId) {
      setPeriods(prev => prev.map(p => p.id === periodId ? {
        ...p,
        sessions: p.sessions.map(s => s.id === editingSessionId ? { ...s, date: sessionFormDate, attendees: selectedAttendees } : s)
      } : p));
    } else {
      const session: Session = {
        id: Date.now().toString(),
        date: sessionFormDate,
        attendees: selectedAttendees
      };
      setPeriods(prev => prev.map(p => p.id === periodId ? { ...p, sessions: [...p.sessions, session] } : p));
    }
    setActiveSessionPeriod(null);
    setEditingSessionId(null);
  };

  const removeSession = (e: React.MouseEvent, periodId: string, sessionId: string) => {
    e.stopPropagation();
    if (window.confirm('确定要删除这条活动记录吗？')) {
      setPeriods(prev => prev.map(p => p.id === periodId ? { ...p, sessions: p.sessions.filter(s => s.id !== sessionId) } : p));
    }
  };

  const toggleAttendee = (player: Player, periodId: string) => {
    const exists = selectedAttendees.find(a => a.playerId === player.id);
    if (exists) {
      setSelectedAttendees(prev => prev.filter(a => a.playerId !== player.id));
    } else {
      const currentPeriod = periods.find(p => p.id === periodId);
      const isMonthlyType = player.type === PlayerType.MONTHLY || player.type === PlayerType.HALF_MONTHLY;
      let defaultFee = player.defaultFee;
      if (isMonthlyType && currentPeriod) {
        const hasPaidInPeriod = currentPeriod.sessions.some(s => 
          s.id !== editingSessionId && 
          s.attendees.some(a => a.playerId === player.id && a.fee > 0)
        );
        if (hasPaidInPeriod) defaultFee = 0;
      }
      setSelectedAttendees(prev => [...prev, { playerId: player.id, fee: defaultFee }]);
    }
  };

  return (
    <div className="p-4 pb-10">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-lg font-bold text-gray-800">结算周期管理</h2>
        <button 
          type="button"
          onClick={() => { setIsAddingPeriod(true); setPeriodFormData(initialPeriodData); }}
          className="bg-emerald-600 text-white px-3 py-2 rounded-lg text-sm flex items-center gap-1 font-bold shadow-md active:scale-95 transition-all"
        >
          <Icons.Plus /> 新增周期
        </button>
      </div>

      {(isAddingPeriod || editingPeriodId) && (
        <div className="mb-8 bg-white p-5 rounded-2xl shadow-xl border-2 border-emerald-500 animate-in slide-in-from-top-4 duration-300">
          <h3 className="font-black mb-5 text-emerald-800 text-base">{editingPeriodId ? '📝 编辑结算周期' : '🗓️ 创建新结算周期'}</h3>
          <div className="space-y-5">
            <div>
              <label className="block text-xs font-bold text-gray-500 mb-1.5 uppercase">周期名称</label>
              <input type="text" placeholder="例如：2024年5月 第一期" value={periodFormData.name} onChange={e => setPeriodFormData({...periodFormData, name: e.target.value})} className="w-full border border-gray-300 rounded-xl p-3 text-sm focus:ring-2 focus:ring-emerald-500 outline-none transition-all" />
            </div>
            <div className="flex gap-3">
              <div className="flex-1">
                <label className="block text-xs font-bold text-gray-500 mb-1.5 uppercase">开始日期</label>
                <input type="date" value={periodFormData.startDate} onChange={e => setPeriodFormData({...periodFormData, startDate: e.target.value})} className="w-full border border-gray-300 rounded-xl p-3 text-sm focus:ring-2 focus:ring-emerald-500" />
              </div>
              <div className="flex-1">
                <label className="block text-xs font-bold text-gray-500 mb-1.5 uppercase">结束日期</label>
                <input type="date" value={periodFormData.endDate} onChange={e => setPeriodFormData({...periodFormData, endDate: e.target.value})} className="w-full border border-gray-300 rounded-xl p-3 text-sm focus:ring-2 focus:ring-emerald-500" />
              </div>
            </div>
            <div>
              <label className="block text-xs font-bold text-gray-500 mb-1.5 uppercase">场地预订成本 (元)</label>
              <input type="number" placeholder="0.00" value={periodFormData.courtCost || ''} onChange={e => setPeriodFormData({...periodFormData, courtCost: Number(e.target.value)})} className="w-full border border-gray-300 rounded-xl p-3 text-sm font-mono text-red-600" />
            </div>

            <div className="bg-amber-50 p-4 rounded-xl border border-amber-200">
              <label className="block text-xs font-black text-amber-800 mb-3 flex items-center gap-1 uppercase">
                👑 选择本期参加集资人员 (从现有集资人池中挑选)
              </label>
              <div className="flex flex-wrap gap-2">
                {funderPool.length > 0 ? funderPool.map(f => (
                  <button 
                    key={f.id} 
                    type="button" 
                    onClick={() => toggleFunderInPeriod(f.id)} 
                    className={`text-xs px-3 py-2 rounded-lg border-2 transition-all font-bold ${
                      periodFormData.funderIds?.includes(f.id) 
                      ? 'bg-amber-500 border-amber-600 text-white shadow-sm' 
                      : 'bg-white border-amber-100 text-amber-300'
                    }`}
                  >
                    {f.name}
                  </button>
                )) : <p className="text-[10px] text-amber-600 italic">档案中没有标记为集资人的成员</p>}
              </div>
              <p className="text-[10px] text-amber-700 mt-3 font-medium border-t border-amber-200/50 pt-2">
                * 保存后，本期未被选中的备选人将自动失去集资人资格，转为“按次人员”。
              </p>
            </div>

            <div className="flex gap-3 pt-2">
              <button type="button" onClick={handleSavePeriod} className="flex-2 bg-emerald-600 text-white py-3 rounded-xl font-black text-sm shadow-lg active:scale-95 transition-all">确认并处理成员身份</button>
              <button type="button" onClick={() => { setIsAddingPeriod(false); setEditingPeriodId(null); }} className="flex-1 bg-gray-100 text-gray-500 py-3 rounded-xl font-bold text-sm">取消</button>
            </div>
          </div>
        </div>
      )}

      <div className="space-y-4">
        {periods.slice().reverse().map(period => (
          <div key={period.id} className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden transition-all active:shadow-md">
            <div 
              className={`p-4 flex justify-between items-center cursor-pointer transition-colors ${expandedPeriodId === period.id ? 'bg-emerald-50/30' : 'hover:bg-gray-50'}`}
              onClick={() => setExpandedPeriodId(expandedPeriodId === period.id ? null : period.id)}
            >
              <div className="flex-1">
                <h3 className="font-black text-gray-800 text-base">{period.name}</h3>
                <p className="text-[10px] text-gray-400 font-medium mt-1">{period.startDate} ~ {period.endDate || '进行中'}</p>
                <div className="mt-3 flex gap-1.5 flex-wrap">
                  {period.funderIds.map(fid => (
                    <span key={fid} className="text-[9px] bg-amber-100 text-amber-700 border border-amber-200 px-1.5 py-0.5 rounded-md font-bold">
                      {players.find(p => p.id === fid)?.name || '已删'}
                    </span>
                  ))}
                </div>
              </div>
              <div className="flex items-center gap-5">
                <div className="text-right">
                  <p className="text-[10px] text-gray-400 font-bold uppercase">活动次数</p>
                  <p className="font-black text-emerald-600 text-lg">{period.sessions.length}</p>
                </div>
                <div className="flex flex-col gap-2">
                   <button type="button" onClick={(e) => startEditPeriod(e, period)} className="text-emerald-700 text-[10px] font-black p-1.5 bg-emerald-100/50 rounded-lg active:bg-emerald-200">编辑</button>
                   <button type="button" onClick={(e) => deletePeriod(e, period.id)} className="text-gray-300 hover:text-red-500 p-1.5 active:scale-110 transition-transform">
                      <Icons.Trash />
                    </button>
                </div>
              </div>
            </div>

            {expandedPeriodId === period.id && (
              <div className="border-t border-gray-100 bg-gray-50/50 p-4 space-y-4 animate-in slide-in-from-top-2 duration-200">
                <div className="flex justify-between items-center">
                  <h4 className="text-xs font-black text-gray-500 uppercase tracking-widest">📋 详细打球记录</h4>
                  <button type="button" onClick={(e) => handleOpenAddSession(e, period.id)} className="text-[10px] bg-emerald-600 text-white px-4 py-2 rounded-full font-black shadow-md active:opacity-80">
                    + 录入单场打球
                  </button>
                </div>

                {activeSessionPeriod === period.id && (
                  <div className="bg-white p-4 rounded-2xl border-2 border-emerald-500 shadow-xl animate-in zoom-in-95">
                    <p className="text-xs font-black text-emerald-800 mb-4 uppercase">{editingSessionId ? '✏️ 修改单场数据' : '✨ 录入全新场次'}</p>
                    <div className="space-y-4">
                      <div>
                        <label className="block text-[10px] font-bold text-gray-400 mb-1">选择活动日期</label>
                        <input type="date" value={sessionFormDate} onChange={e => setSessionFormDate(e.target.value)} className="w-full border border-gray-200 rounded-xl p-3 text-sm focus:ring-2 focus:ring-emerald-500" />
                      </div>
                      <div>
                        <p className="text-[10px] font-bold text-gray-400 mb-2">选择出席人员 (多选):</p>
                        <div className="flex flex-wrap gap-2 max-h-40 overflow-y-auto p-3 border border-gray-100 rounded-xl bg-gray-50/50">
                          {players.map(p => {
                            const isSelected = selectedAttendees.find(a => a.playerId === p.id);
                            return (
                              <button key={p.id} type="button" onClick={() => toggleAttendee(p, period.id)} className={`text-[10px] px-3 py-2 rounded-lg border-2 font-bold transition-all ${isSelected ? 'bg-emerald-600 border-emerald-700 text-white shadow-sm' : 'bg-white border-gray-200 text-gray-400'}`}>
                                {p.name}
                              </button>
                            );
                          })}
                        </div>
                      </div>
                      {selectedAttendees.length > 0 && (
                        <div className="space-y-2">
                          <p className="text-[10px] font-bold text-gray-400">核对/修改个人收费:</p>
                          {selectedAttendees.map(a => {
                            const player = players.find(p => p.id === a.playerId);
                            return (
                              <div key={a.playerId} className="flex justify-between items-center bg-gray-50 p-2.5 rounded-xl text-xs">
                                <span className="font-bold text-gray-700">{player?.name || '未知'} <span className="text-[9px] font-normal opacity-50">({player?.type})</span></span>
                                <div className="flex items-center gap-1 bg-white border border-gray-200 rounded-lg px-2">
                                  <span className="text-[10px] font-bold text-gray-400">¥</span>
                                  <input type="number" value={a.fee} onChange={e => {
                                    const val = Number(e.target.value);
                                    setSelectedAttendees(prev => prev.map(sa => sa.playerId === a.playerId ? {...sa, fee: val} : sa));
                                  }} className="w-12 py-1 text-center font-black text-emerald-600 focus:outline-none" />
                                </div>
                              </div>
                            );
                          })}
                        </div>
                      )}
                      <div className="flex gap-3 pt-2">
                        <button type="button" onClick={() => saveSession(period.id)} className="flex-2 bg-emerald-600 text-white py-3 rounded-xl font-black text-sm shadow-md">保存记录</button>
                        <button type="button" onClick={() => setActiveSessionPeriod(null)} className="flex-1 bg-gray-100 text-gray-500 py-3 rounded-xl font-bold text-sm">取消</button>
                      </div>
                    </div>
                  </div>
                )}

                <div className="space-y-3">
                  {period.sessions.length === 0 ? (
                    <div className="text-center py-10 bg-white/50 rounded-2xl border border-dashed border-gray-200">
                      <p className="text-[10px] text-gray-400 italic">本期暂无打球数据，请点击录入</p>
                    </div>
                  ) : (
                    period.sessions.slice().sort((a,b) => b.date.localeCompare(a.date)).map(session => (
                      <div key={session.id} className="bg-white p-3.5 rounded-2xl shadow-sm border border-gray-100 flex flex-col gap-3">
                        <div className="flex justify-between items-center">
                          <div>
                            <p className="text-xs font-black text-gray-800">{session.date}</p>
                            <div className="flex items-center gap-2 mt-1">
                              <span className="text-[9px] bg-emerald-50 text-emerald-700 border border-emerald-100 px-1.5 py-0.5 rounded font-bold">实收: ¥{session.attendees.reduce((sum, a) => sum + a.fee, 0)}</span>
                              <span className="text-[9px] bg-blue-50 text-blue-700 border border-blue-100 px-1.5 py-0.5 rounded font-bold">{session.attendees.length} 人出席</span>
                            </div>
                          </div>
                          <div className="flex gap-1">
                            <button type="button" onClick={(e) => handleEditSession(e, period.id, session)} className="text-gray-300 hover:text-emerald-500 p-2 active:scale-110">
                              <Icons.Pencil />
                            </button>
                            <button type="button" onClick={(e) => removeSession(e, period.id, session.id)} className="text-gray-300 hover:text-red-500 p-2 active:scale-110">
                              <Icons.Trash />
                            </button>
                          </div>
                        </div>
                        <div className="flex flex-wrap gap-1.5">
                          {session.attendees.map(a => (
                            <span key={a.playerId} className={`text-[9px] px-2 py-1 rounded-md border font-medium ${a.fee === 0 ? 'bg-gray-50 text-gray-400 border-gray-100 italic' : 'bg-white text-gray-600 border-gray-100'}`}>
                              {players.find(pl => pl.id === a.playerId)?.name || '已删'} (¥{a.fee})
                            </span>
                          ))}
                        </div>
                      </div>
                    ))
                  )}
                </div>
              </div>
            )}
          </div>
        ))}
        {periods.length === 0 && (
          <div className="text-center py-20 bg-white rounded-3xl border border-dashed border-gray-200">
            <p className="text-5xl mb-4 opacity-10">📅</p>
            <p className="text-sm text-gray-400">点击右上角按钮创建第一个结算周期</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default PeriodsList;

import React, { useState } from 'react';
import { Period, Player, Session, PlayerType } from '../types';
import { Icons, DEFAULT_SESSION_FEE } from '../constants';

interface PeriodsListProps {
  periods: Period[];
  setPeriods: React.Dispatch<React.SetStateAction<Period[]>>;
  players: Player[];
  setPlayers: React.Dispatch<React.SetStateAction<Player[]>>;
}

const PeriodsList: React.FC<PeriodsListProps> = ({ periods, setPeriods, players, setPlayers }) => {
  const [isAddingPeriod, setIsAddingPeriod] = useState(false);
  const [editingPeriodId, setEditingPeriodId] = useState<string | null>(null);
  const [expandedPeriodId, setExpandedPeriodId] = useState<string | null>(null);
  const [activeSessionPeriod, setActiveSessionPeriod] = useState<string | null>(null);
  const [editingSessionId, setEditingSessionId] = useState<string | null>(null);

  // 只筛选档案中被标记为 isFunder 的人员作为集资人备选池（默认那10个及后续手动标记的人）
  const funderPool = players.filter(p => p.isFunder);

  const initialPeriodData = {
    name: '',
    startDate: new Date().toISOString().split('T')[0],
    endDate: '',
    courtCost: 0,
    funderIds: funderPool.map(p => p.id), // 默认全选
    sessions: []
  };

  const [periodFormData, setPeriodFormData] = useState<Partial<Period>>(initialPeriodData);
  const [sessionFormDate, setSessionFormDate] = useState(new Date().toISOString().split('T')[0]);
  const [selectedAttendees, setSelectedAttendees] = useState<{playerId: string, fee: number}[]>([]);

  const handleSavePeriod = () => {
    if (!periodFormData.name) {
      alert('请输入周期名称');
      return;
    }

    // 1. 确定最终勾选的集资人 IDs
    const finalFunderIds = periodFormData.funderIds && periodFormData.funderIds.length > 0 
      ? periodFormData.funderIds 
      : [];

    // 2. 核心逻辑：根据本次勾选结果，自动更新所有潜在集资人的成员性质
    setPlayers(prevPlayers => prevPlayers.map(p => {
      // 情况 A: 被选为本期集资人
      if (finalFunderIds.includes(p.id)) {
        return {
          ...p,
          type: PlayerType.MONTHLY,
          isFunder: true, // 维持集资人资格
          defaultFee: 0   // 包月人员本周期内打球默认不另收单场费
        };
      }

      // 情况 B: 属于原本具备集资资格的人，但本次没被选上
      if (p.isFunder) {
        return {
          ...p,
          type: PlayerType.PER_SESSION,
          isFunder: true, // 重要：保留 isFunder 标记，确保下个周期还能重新挑选他
          defaultFee: DEFAULT_SESSION_FEE // 转为默认按次费
        };
      }

      // 其他普通按次人员保持不变
      return p;
    }));

    // 3. 保存周期
    if (editingPeriodId) {
      setPeriods(prev => prev.map(p => p.id === editingPeriodId ? { 
        ...p, 
        ...periodFormData,
        funderIds: finalFunderIds 
      } as Period : p));
      setEditingPeriodId(null);
    } else {
      const period: Period = {
        id: Date.now().toString(),
        name: periodFormData.name!,
        startDate: periodFormData.startDate!,
        endDate: periodFormData.endDate || '',
        courtCost: periodFormData.courtCost || 0,
        funderIds: finalFunderIds,
        sessions: []
      };
      setPeriods(prev => [...prev, period]);
      setIsAddingPeriod(false);
    }
    setPeriodFormData(initialPeriodData);
  };

  const startEditPeriod = (e: React.MouseEvent, period: Period) => {
    e.stopPropagation();
    setEditingPeriodId(period.id);
    setPeriodFormData(period);
  };

  const deletePeriod = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (window.confirm('确定要删除该结算周期吗？警告：周期内的所有打球记录将一并被清除且无法恢复！')) {
      setPeriods(prev => prev.filter(p => p.id !== id));
      if (expandedPeriodId === id) setExpandedPeriodId(null);
    }
  };

  const toggleFunderInPeriod = (funderId: string) => {
    const current = periodFormData.funderIds || [];
    if (current.includes(funderId)) {
      setPeriodFormData({...periodFormData, funderIds: current.filter(id => id !== funderId)});
    } else {
      setPeriodFormData({...periodFormData, funderIds: [...current, funderId]});
    }
  };

  const handleOpenAddSession = (e: React.MouseEvent, periodId: string) => {
    e.stopPropagation();
    setActiveSessionPeriod(periodId);
    setEditingSessionId(null);
    setSessionFormDate(new Date().toISOString().split('T')[0]);
    setSelectedAttendees([]);
  };

  const handleEditSession = (e: React.MouseEvent, periodId: string, session: Session) => {
    e.stopPropagation();
    setActiveSessionPeriod(periodId);
    setEditingSessionId(session.id);
    setSessionFormDate(session.date);
    setSelectedAttendees(session.attendees);
  };

  const saveSession = (periodId: string) => {
    if (selectedAttendees.length === 0) {
      alert('请至少选择一名出席成员');
      return;
    }
    if (editingSessionId) {
      setPeriods(prev => prev.map(p => p.id === periodId ? {
        ...p,
        sessions: p.sessions.map(s => s.id === editingSessionId ? { ...s, date: sessionFormDate, attendees: selectedAttendees } : s)
      } : p));
    } else {
      const session: Session = {
        id: Date.now().toString(),
        date: sessionFormDate,
        attendees: selectedAttendees
      };
      setPeriods(prev => prev.map(p => p.id === periodId ? { ...p, sessions: [...p.sessions, session] } : p));
    }
    setActiveSessionPeriod(null);
    setEditingSessionId(null);
  };

  const removeSession = (e: React.MouseEvent, periodId: string, sessionId: string) => {
    e.stopPropagation();
    if (window.confirm('确定要删除这条活动记录吗？')) {
      setPeriods(prev => prev.map(p => p.id === periodId ? { ...p, sessions: p.sessions.filter(s => s.id !== sessionId) } : p));
    }
  };

  const toggleAttendee = (player: Player, periodId: string) => {
    const exists = selectedAttendees.find(a => a.playerId === player.id);
    if (exists) {
      setSelectedAttendees(prev => prev.filter(a => a.playerId !== player.id));
    } else {
      const currentPeriod = periods.find(p => p.id === periodId);
      const isMonthlyType = player.type === PlayerType.MONTHLY || player.type === PlayerType.HALF_MONTHLY;
      let defaultFee = player.defaultFee;
      if (isMonthlyType && currentPeriod) {
        const hasPaidInPeriod = currentPeriod.sessions.some(s => 
          s.id !== editingSessionId && 
          s.attendees.some(a => a.playerId === player.id && a.fee > 0)
        );
        if (hasPaidInPeriod) defaultFee = 0;
      }
      setSelectedAttendees(prev => [...prev, { playerId: player.id, fee: defaultFee }]);
    }
  };

  return (
    <div className="p-4 pb-10">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-lg font-bold text-gray-800">结算周期管理</h2>
        <button 
          type="button"
          onClick={() => { setIsAddingPeriod(true); setPeriodFormData(initialPeriodData); }}
          className="bg-emerald-600 text-white px-3 py-2 rounded-lg text-sm flex items-center gap-1 font-bold shadow-md active:scale-95 transition-all"
        >
          <Icons.Plus /> 新增周期
        </button>
      </div>

      {(isAddingPeriod || editingPeriodId) && (
        <div className="mb-8 bg-white p-5 rounded-2xl shadow-xl border-2 border-emerald-500 animate-in slide-in-from-top-4 duration-300">
          <h3 className="font-black mb-5 text-emerald-800 text-base">{editingPeriodId ? '📝 编辑结算周期' : '🗓️ 创建新结算周期'}</h3>
          <div className="space-y-5">
            <div>
              <label className="block text-xs font-bold text-gray-500 mb-1.5 uppercase">周期名称</label>
              <input type="text" placeholder="例如：2024年5月 第一期" value={periodFormData.name} onChange={e => setPeriodFormData({...periodFormData, name: e.target.value})} className="w-full border border-gray-300 rounded-xl p-3 text-sm focus:ring-2 focus:ring-emerald-500 outline-none transition-all" />
            </div>
            <div className="flex gap-3">
              <div className="flex-1">
                <label className="block text-xs font-bold text-gray-500 mb-1.5 uppercase">开始日期</label>
                <input type="date" value={periodFormData.startDate} onChange={e => setPeriodFormData({...periodFormData, startDate: e.target.value})} className="w-full border border-gray-300 rounded-xl p-3 text-sm focus:ring-2 focus:ring-emerald-500" />
              </div>
              <div className="flex-1">
                <label className="block text-xs font-bold text-gray-500 mb-1.5 uppercase">结束日期</label>
                <input type="date" value={periodFormData.endDate} onChange={e => setPeriodFormData({...periodFormData, endDate: e.target.value})} className="w-full border border-gray-300 rounded-xl p-3 text-sm focus:ring-2 focus:ring-emerald-500" />
              </div>
            </div>
            <div>
              <label className="block text-xs font-bold text-gray-500 mb-1.5 uppercase">场地预订成本 (元)</label>
              <input type="number" placeholder="0.00" value={periodFormData.courtCost || ''} onChange={e => setPeriodFormData({...periodFormData, courtCost: Number(e.target.value)})} className="w-full border border-gray-300 rounded-xl p-3 text-sm font-mono text-red-600" />
            </div>

            <div className="bg-amber-50 p-4 rounded-xl border border-amber-200">
              <label className="block text-xs font-black text-amber-800 mb-3 flex items-center gap-1 uppercase">
                👑 选择本期参加集资人员 (从集资人备选池中挑选)
              </label>
              <div className="flex flex-wrap gap-2">
                {funderPool.length > 0 ? funderPool.map(f => (
                  <button 
                    key={f.id} 
                    type="button" 
                    onClick={() => toggleFunderInPeriod(f.id)} 
                    className={`text-xs px-3 py-2 rounded-lg border-2 transition-all font-bold ${
                      periodFormData.funderIds?.includes(f.id) 
                      ? 'bg-amber-500 border-amber-600 text-white shadow-sm' 
                      : 'bg-white border-amber-100 text-amber-300'
                    }`}
                  >
                    {f.name}
                  </button>
                )) : <p className="text-[10px] text-amber-600 italic">档案中没有标记为集资人的成员</p>}
              </div>
              <p className="text-[10px] text-amber-700 mt-3 font-medium border-t border-amber-200/50 pt-2 leading-relaxed">
                * 本期勾选的人员将自动转为“包月”性质。<br/>
                * 未被勾选的备选人员将自动转为“按次人员”，但保留其集资人身份以便下周期重新挑选。
              </p>
            </div>

            <div className="flex gap-3 pt-2">
              <button type="button" onClick={handleSavePeriod} className="flex-2 bg-emerald-600 text-white py-3 rounded-xl font-black text-sm shadow-lg active:scale-95 transition-all">保存周期并同步成员身份</button>
              <button type="button" onClick={() => { setIsAddingPeriod(false); setEditingPeriodId(null); }} className="flex-1 bg-gray-100 text-gray-500 py-3 rounded-xl font-bold text-sm">取消</button>
            </div>
          </div>
        </div>
      )}

      <div className="space-y-4">
        {periods.slice().reverse().map(period => (
          <div key={period.id} className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden transition-all active:shadow-md">
            <div 
              className={`p-4 flex justify-between items-center cursor-pointer transition-colors ${expandedPeriodId === period.id ? 'bg-emerald-50/30' : 'hover:bg-gray-50'}`}
              onClick={() => setExpandedPeriodId(expandedPeriodId === period.id ? null : period.id)}
            >
              <div className="flex-1">
                <h3 className="font-black text-gray-800 text-base">{period.name}</h3>
                <p className="text-[10px] text-gray-400 font-medium mt-1">{period.startDate} ~ {period.endDate || '进行中'}</p>
                <div className="mt-3 flex gap-1.5 flex-wrap">
                  {period.funderIds.map(fid => (
                    <span key={fid} className="text-[9px] bg-amber-100 text-amber-700 border border-amber-200 px-1.5 py-0.5 rounded-md font-bold">
                      {players.find(p => p.id === fid)?.name || '已删'}
                    </span>
                  ))}
                </div>
              </div>
              <div className="flex items-center gap-5">
                <div className="text-right">
                  <p className="text-[10px] text-gray-400 font-bold uppercase">活动次数</p>
                  <p className="font-black text-emerald-600 text-lg">{period.sessions.length}</p>
                </div>
                <div className="flex flex-col gap-2">
                   <button type="button" onClick={(e) => startEditPeriod(e, period)} className="text-emerald-700 text-[10px] font-black p-1.5 bg-emerald-100/50 rounded-lg active:bg-emerald-200">编辑</button>
                   <button type="button" onClick={(e) => deletePeriod(e, period.id)} className="text-gray-300 hover:text-red-500 p-1.5 active:scale-110 transition-transform">
                      <Icons.Trash />
                    </button>
                </div>
              </div>
            </div>

            {expandedPeriodId === period.id && (
              <div className="border-t border-gray-100 bg-gray-50/50 p-4 space-y-4 animate-in slide-in-from-top-2 duration-200">
                <div className="flex justify-between items-center">
                  <h4 className="text-xs font-black text-gray-500 uppercase tracking-widest">📋 详细打球记录</h4>
                  <button type="button" onClick={(e) => handleOpenAddSession(e, period.id)} className="text-[10px] bg-emerald-600 text-white px-4 py-2 rounded-full font-black shadow-md active:opacity-80">
                    + 录入单场打球
                  </button>
                </div>

                {activeSessionPeriod === period.id && (
                  <div className="bg-white p-4 rounded-2xl border-2 border-emerald-500 shadow-xl animate-in zoom-in-95">
                    <p className="text-xs font-black text-emerald-800 mb-4 uppercase">{editingSessionId ? '✏️ 修改单场数据' : '✨ 录入全新场次'}</p>
                    <div className="space-y-4">
                      <div>
                        <label className="block text-[10px] font-bold text-gray-400 mb-1">选择活动日期</label>
                        <input type="date" value={sessionFormDate} onChange={e => setSessionFormDate(e.target.value)} className="w-full border border-gray-200 rounded-xl p-3 text-sm focus:ring-2 focus:ring-emerald-500" />
                      </div>
                      <div>
                        <p className="text-[10px] font-bold text-gray-400 mb-2">选择出席人员 (多选):</p>
                        <div className="flex flex-wrap gap-2 max-h-40 overflow-y-auto p-3 border border-gray-100 rounded-xl bg-gray-50/50">
                          {players.map(p => {
                            const isSelected = selectedAttendees.find(a => a.playerId === p.id);
                            return (
                              <button key={p.id} type="button" onClick={() => toggleAttendee(p, period.id)} className={`text-[10px] px-3 py-2 rounded-lg border-2 font-bold transition-all ${isSelected ? 'bg-emerald-600 border-emerald-700 text-white shadow-sm' : 'bg-white border-gray-200 text-gray-400'}`}>
                                {p.name}
                              </button>
                            );
                          })}
                        </div>
                      </div>
                      {selectedAttendees.length > 0 && (
                        <div className="space-y-2">
                          <p className="text-[10px] font-bold text-gray-400">核对/修改个人收费:</p>
                          {selectedAttendees.map(a => {
                            const player = players.find(p => p.id === a.playerId);
                            return (
                              <div key={a.playerId} className="flex justify-between items-center bg-gray-50 p-2.5 rounded-xl text-xs">
                                <span className="font-bold text-gray-700">{player?.name || '未知'} <span className="text-[9px] font-normal opacity-50">({player?.type})</span></span>
                                <div className="flex items-center gap-1 bg-white border border-gray-200 rounded-lg px-2">
                                  <span className="text-[10px] font-bold text-gray-400">¥</span>
                                  <input type="number" value={a.fee} onChange={e => {
                                    const val = Number(e.target.value);
                                    setSelectedAttendees(prev => prev.map(sa => sa.playerId === a.playerId ? {...sa, fee: val} : sa));
                                  }} className="w-12 py-1 text-center font-black text-emerald-600 focus:outline-none" />
                                </div>
                              </div>
                            );
                          })}
                        </div>
                      )}
                      <div className="flex gap-3 pt-2">
                        <button type="button" onClick={() => saveSession(period.id)} className="flex-2 bg-emerald-600 text-white py-3 rounded-xl font-black text-sm shadow-md">保存记录</button>
                        <button type="button" onClick={() => setActiveSessionPeriod(null)} className="flex-1 bg-gray-100 text-gray-500 py-3 rounded-xl font-bold text-sm">取消</button>
                      </div>
                    </div>
                  </div>
                )}

                <div className="space-y-3">
                  {period.sessions.length === 0 ? (
                    <div className="text-center py-10 bg-white/50 rounded-2xl border border-dashed border-gray-200">
                      <p className="text-[10px] text-gray-400 italic">本期暂无打球数据，请点击录入</p>
                    </div>
                  ) : (
                    period.sessions.slice().sort((a,b) => b.date.localeCompare(a.date)).map(session => (
                      <div key={session.id} className="bg-white p-3.5 rounded-2xl shadow-sm border border-gray-100 flex flex-col gap-3">
                        <div className="flex justify-between items-center">
                          <div>
                            <p className="text-xs font-black text-gray-800">{session.date}</p>
                            <div className="flex items-center gap-2 mt-1">
                              <span className="text-[9px] bg-emerald-50 text-emerald-700 border border-emerald-100 px-1.5 py-0.5 rounded font-bold">实收: ¥{session.attendees.reduce((sum, a) => sum + a.fee, 0)}</span>
                              <span className="text-[9px] bg-blue-50 text-blue-700 border border-blue-100 px-1.5 py-0.5 rounded font-bold">{session.attendees.length} 人出席</span>
                            </div>
                          </div>
                          <div className="flex gap-1">
                            <button type="button" onClick={(e) => handleEditSession(e, period.id, session)} className="text-gray-300 hover:text-emerald-500 p-2 active:scale-110">
                              <Icons.Pencil />
                            </button>
                            <button type="button" onClick={(e) => removeSession(e, period.id, session.id)} className="text-gray-300 hover:text-red-500 p-2 active:scale-110">
                              <Icons.Trash />
                            </button>
                          </div>
                        </div>
                        <div className="flex flex-wrap gap-1.5">
                          {session.attendees.map(a => (
                            <span key={a.playerId} className={`text-[9px] px-2 py-1 rounded-md border font-medium ${a.fee === 0 ? 'bg-gray-50 text-gray-400 border-gray-100 italic' : 'bg-white text-gray-600 border-gray-100'}`}>
                              {players.find(pl => pl.id === a.playerId)?.name || '已删'} (¥{a.fee})
                            </span>
                          ))}
                        </div>
                      </div>
                    ))
                  )}
                </div>
              </div>
            )}
          </div>
        ))}
        {periods.length === 0 && (
          <div className="text-center py-20 bg-white rounded-3xl border border-dashed border-gray-200">
            <p className="text-5xl mb-4 opacity-10">📅</p>
            <p className="text-sm text-gray-400">点击右上角按钮创建第一个结算周期</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default PeriodsList;

import React, { useState } from 'react';
import { Period, Player, Session, PlayerType } from '../types';
import { Icons, DEFAULT_SESSION_FEE } from '../constants';

interface PeriodsListProps {
  periods: Period[];
  setPeriods: React.Dispatch<React.SetStateAction<Period[]>>;
  players: Player[];
  setPlayers: React.Dispatch<React.SetStateAction<Player[]>>;
}

const PeriodsList: React.FC<PeriodsListProps> = ({ periods, setPeriods, players, setPlayers }) => {
  const [isAddingPeriod, setIsAddingPeriod] = useState(false);
  const [editingPeriodId, setEditingPeriodId] = useState<string | null>(null);
  const [expandedPeriodId, setExpandedPeriodId] = useState<string | null>(null);
  const [activeSessionPeriod, setActiveSessionPeriod] = useState<string | null>(null);
  const [editingSessionId, setEditingSessionId] = useState<string | null>(null);

  // 用于删除确认的弹窗状态
  const [deletingPeriod, setDeletingPeriod] = useState<Period | null>(null);

  // 只筛选档案中被标记为 isFunder 的人员作为集资人备选池
  const funderPool = players.filter(p => p.isFunder);

  const initialPeriodData = {
    name: '',
    startDate: new Date().toISOString().split('T')[0],
    endDate: '',
    courtCost: 0,
    funderIds: funderPool.map(p => p.id), // 默认全选
    sessions: []
  };

  const [periodFormData, setPeriodFormData] = useState<Partial<Period>>(initialPeriodData);
  const [sessionFormDate, setSessionFormDate] = useState(new Date().toISOString().split('T')[0]);
  const [selectedAttendees, setSelectedAttendees] = useState<{playerId: string, fee: number}[]>([]);

  const handleSavePeriod = () => {
    if (!periodFormData.name) {
      alert('请输入周期名称');
      return;
    }

    const finalFunderIds = periodFormData.funderIds && periodFormData.funderIds.length > 0 
      ? periodFormData.funderIds 
      : [];

    // 核心逻辑：创建或更新周期时，根据勾选结果同步成员身份
    setPlayers(prevPlayers => prevPlayers.map(p => {
      // 被选中为本期集资人：设为包月，费率为0
      if (finalFunderIds.includes(p.id)) {
        return {
          ...p,
          type: PlayerType.MONTHLY,
          isFunder: true,
          defaultFee: 0
        };
      }

      // 原本是集资人但本周期未被选上：设为按次，费率25，保留备选资格
      if (p.isFunder) {
        return {
          ...p,
          type: PlayerType.PER_SESSION,
          isFunder: true,
          defaultFee: DEFAULT_SESSION_FEE
        };
      }

      return p;
    }));

    if (editingPeriodId) {
      setPeriods(prev => prev.map(p => p.id === editingPeriodId ? { 
        ...p, 
        ...periodFormData,
        funderIds: finalFunderIds 
      } as Period : p));
      setEditingPeriodId(null);
    } else {
      const period: Period = {
        id: Date.now().toString(),
        name: periodFormData.name!,
        startDate: periodFormData.startDate!,
        endDate: periodFormData.endDate || '',
        courtCost: periodFormData.courtCost || 0,
        funderIds: finalFunderIds,
        sessions: []
      };
      setPeriods(prev => [...prev, period]);
      setIsAddingPeriod(false);
    }
    setPeriodFormData(initialPeriodData);
  };

  const startEditPeriod = (e: React.MouseEvent, period: Period) => {
    e.stopPropagation();
    setEditingPeriodId(period.id);
    setPeriodFormData(period);
  };

  const initiateDelete = (e: React.MouseEvent, period: Period) => {
    e.stopPropagation();
    setDeletingPeriod(period);
  };

  const confirmDeletePeriod = () => {
    if (!deletingPeriod) return;
    setPeriods(prev => prev.filter(p => p.id !== deletingPeriod.id));
    if (expandedPeriodId === deletingPeriod.id) setExpandedPeriodId(null);
    setDeletingPeriod(null);
  };

  const toggleFunderInPeriod = (funderId: string) => {
    const current = periodFormData.funderIds || [];
    if (current.includes(funderId)) {
      setPeriodFormData({...periodFormData, funderIds: current.filter(id => id !== funderId)});
    } else {
      setPeriodFormData({...periodFormData, funderIds: [...current, funderId]});
    }
  };

  const handleOpenAddSession = (e: React.MouseEvent, periodId: string) => {
    e.stopPropagation();
    setActiveSessionPeriod(periodId);
    setEditingSessionId(null);
    setSessionFormDate(new Date().toISOString().split('T')[0]);
    setSelectedAttendees([]);
  };

  const handleEditSession = (e: React.MouseEvent, periodId: string, session: Session) => {
    e.stopPropagation();
    setActiveSessionPeriod(periodId);
    setEditingSessionId(session.id);
    setSessionFormDate(session.date);
    setSelectedAttendees(session.attendees);
  };

  const saveSession = (periodId: string) => {
    if (selectedAttendees.length === 0) {
      alert('请至少选择一名出席成员');
      return;
    }
    if (editingSessionId) {
      setPeriods(prev => prev.map(p => p.id === periodId ? {
        ...p,
        sessions: p.sessions.map(s => s.id === editingSessionId ? { ...s, date: sessionFormDate, attendees: selectedAttendees } : s)
      } : p));
    } else {
      const session: Session = {
        id: Date.now().toString(),
        date: sessionFormDate,
        attendees: selectedAttendees
      };
      setPeriods(prev => prev.map(p => p.id === periodId ? { ...p, sessions: [...p.sessions, session] } : p));
    }
    setActiveSessionPeriod(null);
    setEditingSessionId(null);
  };

  const removeSession = (e: React.MouseEvent, periodId: string, sessionId: string) => {
    e.stopPropagation();
    if (window.confirm('确定要删除这条活动记录吗？')) {
      setPeriods(prev => prev.map(p => p.id === periodId ? { ...p, sessions: p.sessions.filter(s => s.id !== sessionId) } : p));
    }
  };

  const toggleAttendee = (player: Player, periodId: string) => {
    const exists = selectedAttendees.find(a => a.playerId === player.id);
    if (exists) {
      setSelectedAttendees(prev => prev.filter(a => a.playerId !== player.id));
    } else {
      const currentPeriod = periods.find(p => p.id === periodId);
      const isMonthlyType = player.type === PlayerType.MONTHLY || player.type === PlayerType.HALF_MONTHLY;
      let defaultFee = player.defaultFee;
      if (isMonthlyType && currentPeriod) {
        const hasPaidInPeriod = currentPeriod.sessions.some(s => 
          s.id !== editingSessionId && 
          s.attendees.some(a => a.playerId === player.id && a.fee > 0)
        );
        if (hasPaidInPeriod) defaultFee = 0;
      }
      setSelectedAttendees(prev => [...prev, { playerId: player.id, fee: defaultFee }]);
    }
  };

  return (
    <div className="p-4 pb-10">
      {/* 核心标题区 */}
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-lg font-bold text-gray-800">结算周期管理</h2>
        <button 
          type="button"
          onClick={() => { setIsAddingPeriod(true); setPeriodFormData(initialPeriodData); }}
          className="bg-emerald-600 text-white px-3 py-2 rounded-lg text-sm flex items-center gap-1 font-bold shadow-md active:scale-95 transition-all"
        >
          <Icons.Plus /> 新增周期
        </button>
      </div>

      {/* 删除确认弹窗 */}
      {deletingPeriod && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-black/60 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-sm rounded-3xl p-6 shadow-2xl border border-red-50 animate-in zoom-in-95 duration-200">
            <div className="w-16 h-16 bg-red-50 text-red-500 rounded-full flex items-center justify-center mx-auto mb-4 text-3xl">⚠️</div>
            <h3 className="text-center font-black text-gray-900 text-lg mb-2">确认删除周期？</h3>
            <p className="text-center text-gray-500 text-xs leading-relaxed mb-6 px-4">
              您正在尝试删除周期 <span className="text-red-600 font-bold">「{deletingPeriod.name}」</span>。<br/><br/>
              注意：此操作将<span className="text-red-600 underline font-black">同步清除该周期内的所有 {deletingPeriod.sessions.length} 条打球记录</span>，且数据无法恢复。
            </p>
            <div className="flex flex-col gap-3">
              <button 
                onClick={confirmDeletePeriod}
                className="w-full bg-red-500 text-white py-3 rounded-xl font-black text-sm shadow-lg shadow-red-200 active:scale-95 transition-all"
              >
                确认删除
              </button>
              <button 
                onClick={() => setDeletingPeriod(null)}
                className="w-full bg-gray-100 text-gray-500 py-3 rounded-xl font-bold text-sm active:bg-gray-200"
              >
                取消
              </button>
            </div>
          </div>
        </div>
      )}

      {/* 新增/编辑周期表单 */}
      {(isAddingPeriod || editingPeriodId) && (
        <div className="mb-8 bg-white p-5 rounded-2xl shadow-xl border-2 border-emerald-500 animate-in slide-in-from-top-4 duration-300">
          <h3 className="font-black mb-5 text-emerald-800 text-base">{editingPeriodId ? '📝 编辑结算周期' : '🗓️ 创建新结算周期'}</h3>
          <div className="space-y-5">
            <div>
              <label className="block text-xs font-bold text-gray-500 mb-1.5 uppercase">周期名称</label>
              <input type="text" placeholder="例如：2024年5月 第一期" value={periodFormData.name} onChange={e => setPeriodFormData({...periodFormData, name: e.target.value})} className="w-full border border-gray-300 rounded-xl p-3 text-sm focus:ring-2 focus:ring-emerald-500 outline-none transition-all" />
            </div>
            <div className="flex gap-3">
              <div className="flex-1">
                <label className="block text-xs font-bold text-gray-500 mb-1.5 uppercase">开始日期</label>
                <input type="date" value={periodFormData.startDate} onChange={e => setPeriodFormData({...periodFormData, startDate: e.target.value})} className="w-full border border-gray-300 rounded-xl p-3 text-sm focus:ring-2 focus:ring-emerald-500" />
              </div>
              <div className="flex-1">
                <label className="block text-xs font-bold text-gray-500 mb-1.5 uppercase">结束日期</label>
                <input type="date" value={periodFormData.endDate} onChange={e => setPeriodFormData({...periodFormData, endDate: e.target.value})} className="w-full border border-gray-300 rounded-xl p-3 text-sm focus:ring-2 focus:ring-emerald-500" />
              </div>
            </div>
            <div>
              <label className="block text-xs font-bold text-gray-500 mb-1.5 uppercase">场地预订成本 (元)</label>
              <input type="number" placeholder="0.00" value={periodFormData.courtCost || ''} onChange={e => setPeriodFormData({...periodFormData, courtCost: Number(e.target.value)})} className="w-full border border-gray-300 rounded-xl p-3 text-sm font-mono text-red-600" />
            </div>

            <div className="bg-amber-50 p-4 rounded-xl border border-amber-200">
              <label className="block text-xs font-black text-amber-800 mb-3 flex items-center gap-1 uppercase">
                👑 选择本期参加集资人员
              </label>
              <div className="flex flex-wrap gap-2">
                {funderPool.length > 0 ? funderPool.map(f => (
                  <button 
                    key={f.id} 
                    type="button" 
                    onClick={() => toggleFunderInPeriod(f.id)} 
                    className={`text-xs px-3 py-2 rounded-lg border-2 transition-all font-bold ${
                      periodFormData.funderIds?.includes(f.id) 
                      ? 'bg-amber-500 border-amber-600 text-white shadow-sm' 
                      : 'bg-white border-amber-100 text-amber-300'
                    }`}
                  >
                    {f.name}
                  </button>
                )) : <p className="text-[10px] text-amber-600 italic">档案中没有标记为集资人的成员</p>}
              </div>
              <p className="text-[10px] text-amber-700 mt-3 font-medium border-t border-amber-200/50 pt-2 leading-relaxed">
                * 勾选者设为“包月”，未勾选的备选者设为“按次”。
              </p>
            </div>

            <div className="flex gap-3 pt-2">
              <button type="button" onClick={handleSavePeriod} className="flex-2 bg-emerald-600 text-white py-3 rounded-xl font-black text-sm shadow-lg active:scale-95 transition-all">保存周期并同步状态</button>
              <button type="button" onClick={() => { setIsAddingPeriod(false); setEditingPeriodId(null); }} className="flex-1 bg-gray-100 text-gray-500 py-3 rounded-xl font-bold text-sm">取消</button>
            </div>
          </div>
        </div>
      )}

      {/* 周期列表展示 */}
      <div className="space-y-4">
        {periods.slice().reverse().map(period => (
          <div key={period.id} className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden transition-all active:shadow-md">
            <div 
              className={`p-4 flex justify-between items-center cursor-pointer transition-colors ${expandedPeriodId === period.id ? 'bg-emerald-50/30' : 'hover:bg-gray-50'}`}
              onClick={() => setExpandedPeriodId(expandedPeriodId === period.id ? null : period.id)}
            >
              <div className="flex-1">
                <h3 className="font-black text-gray-800 text-base">{period.name}</h3>
                <p className="text-[10px] text-gray-400 font-medium mt-1">{period.startDate} ~ {period.endDate || '进行中'}</p>
                <div className="mt-3 flex gap-1.5 flex-wrap">
                  {period.funderIds.map(fid => (
                    <span key={fid} className="text-[9px] bg-amber-100 text-amber-700 border border-amber-200 px-1.5 py-0.5 rounded-md font-bold">
                      {players.find(p => p.id === fid)?.name || '已删'}
                    </span>
                  ))}
                </div>
              </div>
              <div className="flex items-center gap-5">
                <div className="text-right">
                  <p className="text-[10px] text-gray-400 font-bold uppercase">活动次数</p>
                  <p className="font-black text-emerald-600 text-lg">{period.sessions.length}</p>
                </div>
                <div className="flex flex-col gap-2">
                   <button type="button" onClick={(e) => startEditPeriod(e, period)} className="text-emerald-700 text-[10px] font-black p-1.5 bg-emerald-100/50 rounded-lg active:bg-emerald-200">编辑</button>
                   <button type="button" onClick={(e) => initiateDelete(e, period)} className="text-gray-300 hover:text-red-500 p-1.5 active:scale-110 transition-transform">
                      <Icons.Trash />
                    </button>
                </div>
              </div>
            </div>

            {expandedPeriodId === period.id && (
              <div className="border-t border-gray-100 bg-gray-50/50 p-4 space-y-4 animate-in slide-in-from-top-2 duration-200">
                <div className="flex justify-between items-center">
                  <h4 className="text-xs font-black text-gray-500 uppercase tracking-widest">📋 详细打球记录</h4>
                  <button type="button" onClick={(e) => handleOpenAddSession(e, period.id)} className="text-[10px] bg-emerald-600 text-white px-4 py-2 rounded-full font-black shadow-md active:opacity-80">
                    + 录入单场打球
                  </button>
                </div>

                {activeSessionPeriod === period.id && (
                  <div className="bg-white p-4 rounded-2xl border-2 border-emerald-500 shadow-xl animate-in zoom-in-95">
                    <p className="text-xs font-black text-emerald-800 mb-4 uppercase">{editingSessionId ? '✏️ 修改单场数据' : '✨ 录入全新场次'}</p>
                    <div className="space-y-4">
                      <div>
                        <label className="block text-[10px] font-bold text-gray-400 mb-1">选择活动日期</label>
                        <input type="date" value={sessionFormDate} onChange={e => setSessionFormDate(e.target.value)} className="w-full border border-gray-200 rounded-xl p-3 text-sm focus:ring-2 focus:ring-emerald-500" />
                      </div>
                      <div>
                        <p className="text-[10px] font-bold text-gray-400 mb-2">选择出席人员 (多选):</p>
                        <div className="flex flex-wrap gap-2 max-h-40 overflow-y-auto p-3 border border-gray-100 rounded-xl bg-gray-50/50">
                          {players.map(p => {
                            const isSelected = selectedAttendees.find(a => a.playerId === p.id);
                            return (
                              <button key={p.id} type="button" onClick={() => toggleAttendee(p, period.id)} className={`text-[10px] px-3 py-2 rounded-lg border-2 font-bold transition-all ${isSelected ? 'bg-emerald-600 border-emerald-700 text-white shadow-sm' : 'bg-white border-gray-200 text-gray-400'}`}>
                                {p.name}
                              </button>
                            );
                          })}
                        </div>
                      </div>
                      {selectedAttendees.length > 0 && (
                        <div className="space-y-2">
                          <p className="text-[10px] font-bold text-gray-400">核对/修改个人收费:</p>
                          {selectedAttendees.map(a => {
                            const player = players.find(p => p.id === a.playerId);
                            return (
                              <div key={a.playerId} className="flex justify-between items-center bg-gray-50 p-2.5 rounded-xl text-xs">
                                <span className="font-bold text-gray-700">{player?.name || '未知'} <span className="text-[9px] font-normal opacity-50">({player?.type})</span></span>
                                <div className="flex items-center gap-1 bg-white border border-gray-200 rounded-lg px-2">
                                  <span className="text-[10px] font-bold text-gray-400">¥</span>
                                  <input type="number" value={a.fee} onChange={e => {
                                    const val = Number(e.target.value);
                                    setSelectedAttendees(prev => prev.map(sa => sa.playerId === a.playerId ? {...sa, fee: val} : sa));
                                  }} className="w-12 py-1 text-center font-black text-emerald-600 focus:outline-none" />
                                </div>
                              </div>
                            );
                          })}
                        </div>
                      )}
                      <div className="flex gap-3 pt-2">
                        <button type="button" onClick={() => saveSession(period.id)} className="flex-2 bg-emerald-600 text-white py-3 rounded-xl font-black text-sm shadow-md">保存记录</button>
                        <button type="button" onClick={() => setActiveSessionPeriod(null)} className="flex-1 bg-gray-100 text-gray-500 py-3 rounded-xl font-bold text-sm">取消</button>
                      </div>
                    </div>
                  </div>
                )}

                <div className="space-y-3">
                  {period.sessions.length === 0 ? (
                    <div className="text-center py-10 bg-white/50 rounded-2xl border border-dashed border-gray-200">
                      <p className="text-[10px] text-gray-400 italic">本期暂无打球数据，请点击录入</p>
                    </div>
                  ) : (
                    period.sessions.slice().sort((a,b) => b.date.localeCompare(a.date)).map(session => (
                      <div key={session.id} className="bg-white p-3.5 rounded-2xl shadow-sm border border-gray-100 flex flex-col gap-3">
                        <div className="flex justify-between items-center">
                          <div>
                            <p className="text-xs font-black text-gray-800">{session.date}</p>
                            <div className="flex items-center gap-2 mt-1">
                              <span className="text-[9px] bg-emerald-50 text-emerald-700 border border-emerald-100 px-1.5 py-0.5 rounded font-bold">实收: ¥{session.attendees.reduce((sum, a) => sum + a.fee, 0)}</span>
                              <span className="text-[9px] bg-blue-50 text-blue-700 border border-blue-100 px-1.5 py-0.5 rounded font-bold">{session.attendees.length} 人出席</span>
                            </div>
                          </div>
                          <div className="flex gap-1">
                            <button type="button" onClick={(e) => handleEditSession(e, period.id, session)} className="text-gray-300 hover:text-emerald-500 p-2 active:scale-110">
                              <Icons.Pencil />
                            </button>
                            <button type="button" onClick={(e) => removeSession(e, period.id, session.id)} className="text-gray-300 hover:text-red-500 p-2 active:scale-110">
                              <Icons.Trash />
                            </button>
                          </div>
                        </div>
                        <div className="flex flex-wrap gap-1.5">
                          {session.attendees.map(a => (
                            <span key={a.playerId} className={`text-[9px] px-2 py-1 rounded-md border font-medium ${a.fee === 0 ? 'bg-gray-50 text-gray-400 border-gray-100 italic' : 'bg-white text-gray-600 border-gray-100'}`}>
                              {players.find(pl => pl.id === a.playerId)?.name || '已删'} (¥{a.fee})
                            </span>
                          ))}
                        </div>
                      </div>
                    ))
                  )}
                </div>
              </div>
            )}
          </div>
        ))}
        {periods.length === 0 && (
          <div className="text-center py-20 bg-white rounded-3xl border border-dashed border-gray-200">
            <p className="text-5xl mb-4 opacity-10">📅</p>
            <p className="text-sm text-gray-400">点击右上角按钮创建第一个结算周期</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default PeriodsList;

import React, { useState, useEffect, useMemo } from 'react';
import { Player, Period, View, PlayerType } from './types';
import { INITIAL_FUNDERS, Icons, DEFAULT_SESSION_FEE } from './constants';
import Dashboard from './components/Dashboard';
import PlayersList from './components/PlayersList';
import PeriodsList from './components/PeriodsList';
import FinanceReport from './components/FinanceReport';

const App: React.FC = () => {
  const [view, setView] = useState<View>('dashboard');
  const [players, setPlayers] = useState<Player[]>(() => {
    const saved = localStorage.getItem('badminton_players');
    return saved ? JSON.parse(saved) : INITIAL_FUNDERS;
  });
  const [periods, setPeriods] = useState<Period[]>(() => {
    const saved = localStorage.getItem('badminton_periods');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('badminton_players', JSON.stringify(players));
  }, [players]);

  useEffect(() => {
    localStorage.setItem('badminton_periods', JSON.stringify(periods));
  }, [periods]);

  const activePeriod = useMemo(() => {
    return periods.length > 0 ? periods[periods.length - 1] : null;
  }, [periods]);

  const renderView = () => {
    switch (view) {
      case 'dashboard':
        return <Dashboard players={players} periods={periods} activePeriod={activePeriod} />;
      case 'players':
        return <PlayersList players={players} setPlayers={setPlayers} periods={periods} />;
      case 'periods':
        return <PeriodsList periods={periods} setPeriods={setPeriods} players={players} setPlayers={setPlayers} />;
      case 'finance':
        return <FinanceReport periods={periods} players={players} />;
      default:
        return <Dashboard players={players} periods={periods} activePeriod={activePeriod} />;
    }
  };

  return (
    <div className="flex flex-col h-screen max-w-md mx-auto bg-gray-50">
      {/* Header */}
      <header className="bg-emerald-600 text-white p-4 shadow-md sticky top-0 z-50">
        <h1 className="text-xl font-bold flex items-center">
          <span className="mr-2">🏸</span>
          羽球社财务助手
        </h1>
      </header>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto pb-20">
        {renderView()}
      </main>

      {/* Tab Bar (WeChat Style) */}
      <nav className="fixed bottom-0 left-0 right-0 max-w-md mx-auto bg-white border-t border-gray-200 flex justify-around py-2 px-1 z-50">
        <button 
          onClick={() => setView('dashboard')}
          className={`flex flex-col items-center flex-1 py-1 transition-colors ${view === 'dashboard' ? 'text-emerald-600' : 'text-gray-400'}`}
        >
          <Icons.Home />
          <span className="text-[10px] mt-1 font-medium">首页</span>
        </button>
        <button 
          onClick={() => setView('players')}
          className={`flex flex-col items-center flex-1 py-1 transition-colors ${view === 'players' ? 'text-emerald-600' : 'text-gray-400'}`}
        >
          <Icons.Users />
          <span className="text-[10px] mt-1 font-medium">人员</span>
        </button>
        <button 
          onClick={() => setView('periods')}
          className={`flex flex-col items-center flex-1 py-1 transition-colors ${view === 'periods' ? 'text-emerald-600' : 'text-gray-400'}`}
        >
          <Icons.Calendar />
          <span className="text-[10px] mt-1 font-medium">结算</span>
        </button>
        <button 
          onClick={() => setView('finance')}
          className={`flex flex-col items-center flex-1 py-1 transition-colors ${view === 'finance' ? 'text-emerald-600' : 'text-gray-400'}`}
        >
          <Icons.Chart />
          <span className="text-[10px] mt-1 font-medium">报表</span>
        </button>
      </nav>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Player, PlayerType, Period } from '../types';
import { Icons, DEFAULT_SESSION_FEE } from '../constants';

interface PlayersListProps {
  players: Player[];
  setPlayers: React.Dispatch<React.SetStateAction<Player[]>>;
  periods: Period[];
}

const PlayersList: React.FC<PlayersListProps> = ({ players, setPlayers, periods }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);
  const [formData, setFormData] = useState<Partial<Player>>({
    name: '',
    type: PlayerType.PER_SESSION,
    defaultFee: DEFAULT_SESSION_FEE,
    isFunder: false
  });

  // 获取最近的一个周期
  const latestPeriod = useMemo(() => {
    return periods.length > 0 ? periods[periods.length - 1] : null;
  }, [periods]);

  // 3秒后自动重置删除确认状态
  useEffect(() => {
    if (confirmDeleteId) {
      const timer = setTimeout(() => setConfirmDeleteId(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [confirmDeleteId]);

  const handleSave = () => {
    if (!formData.name) return;
    if (editingId) {
      setPlayers(prev => prev.map(p => p.id === editingId ? { ...p, ...formData } as Player : p));
      setEditingId(null);
    } else {
      const newPlayer: Player = {
        id: Date.now().toString(),
        name: formData.name!,
        type: formData.type as PlayerType || PlayerType.PER_SESSION,
        defaultFee: formData.defaultFee !== undefined ? formData.defaultFee : (formData.type === PlayerType.PER_SESSION ? DEFAULT_SESSION_FEE : 0),
        isFunder: false 
      };
      setPlayers(prev => [...prev, newPlayer]);
      setIsAdding(false);
    }
    setFormData({ name: '', type: PlayerType.PER_SESSION, defaultFee: DEFAULT_SESSION_FEE, isFunder: false });
  };

  const startEdit = (player: Player) => {
    setEditingId(player.id);
    setFormData(player);
  };

  const handleDelete = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    e.preventDefault();
    if (confirmDeleteId === id) {
      setPlayers(prev => prev.filter(p => p.id !== id));
      setConfirmDeleteId(null);
    } else {
      setConfirmDeleteId(id);
    }
  };

  // 检查成员是否为最新周期的集资人
  const isCurrentlyFunder = (playerId: string) => {
    return latestPeriod?.funderIds.includes(playerId) || false;
  };

  return (
    <div className="p-4">
      <div className="flex justify-between items-center mb-4">
        <h2 className="text-lg font-bold text-gray-800">人员档案</h2>
        <button 
          type="button"
          onClick={() => setIsAdding(true)}
          className="bg-emerald-600 text-white px-3 py-1.5 rounded-lg text-sm flex items-center gap-1 font-bold shadow-sm active:opacity-80"
        >
          <Icons.Plus /> 新增人员
        </button>
      </div>

      {(isAdding || editingId) && (
        <div className="mb-6 bg-white p-4 rounded-xl shadow-lg border-2 border-emerald-500 animate-in zoom-in-95 duration-200">
          <h3 className="font-bold mb-4 text-emerald-800">{editingId ? '修改成员信息' : '录入新成员'}</h3>
          <div className="space-y-4">
            <div>
              <label className="block text-xs text-gray-500 mb-1 font-bold">姓名</label>
              <input type="text" value={formData.name} onChange={e => setFormData({ ...formData, name: e.target.value })} className="w-full border border-gray-300 rounded-lg p-2 text-sm focus:ring-2 focus:ring-emerald-500" placeholder="请输入姓名" />
            </div>
            <div>
              <label className="block text-xs text-gray-500 mb-1 font-bold">人员性质</label>
              <select value={formData.type} onChange={e => {
                   const type = e.target.value as PlayerType;
                   const fee = type === PlayerType.PER_SESSION ? DEFAULT_SESSION_FEE : (formData.defaultFee || 0);
                   setFormData({ ...formData, type, defaultFee: fee });
              }} className="w-full border border-gray-300 rounded-lg p-2 text-sm bg-gray-50">
                <option value={PlayerType.MONTHLY}>包月</option>
                <option value={PlayerType.HALF_MONTHLY}>包半月</option>
                <option value={PlayerType.PER_SESSION}>按次</option>
              </select>
            </div>
            <div>
              <label className="block text-xs text-gray-500 mb-1 font-bold">标准收费金额 (元)</label>
              <input type="number" value={formData.defaultFee} onChange={e => setFormData({ ...formData, defaultFee: Number(e.target.value) })} className="w-full border border-gray-300 rounded-lg p-2 text-sm" />
            </div>

            <div className="flex items-center gap-2 p-2 bg-amber-50 rounded-lg border border-amber-100">
              <input type="checkbox" checked={formData.isFunder} onChange={e => setFormData({ ...formData, isFunder: e.target.checked })} id="isFunder" className="w-4 h-4 text-amber-600 rounded" />
              <label htmlFor="isFunder" className="text-xs font-bold text-amber-800 cursor-pointer">具备集资资格 (进入下一期勾选池)</label>
            </div>

            <div className="flex gap-2 pt-2">
              <button type="button" onClick={handleSave} className="flex-1 bg-emerald-600 text-white py-2 rounded-lg font-bold text-sm shadow-sm active:scale-95 transition-transform">保存</button>
              <button type="button" onClick={() => { setIsAdding(false); setEditingId(null); }} className="flex-1 bg-gray-100 text-gray-500 py-2 rounded-lg font-bold text-sm">取消</button>
            </div>
          </div>
        </div>
      )}

      <div className="space-y-3">
        {players.map(player => {
          const activeFunder = isCurrentlyFunder(player.id);
          return (
            <div key={player.id} className={`bg-white p-4 rounded-xl shadow-sm border flex justify-between items-center transition-all ${activeFunder ? 'border-amber-300 bg-amber-50/20' : 'border-gray-100'}`}>
              <div className="flex-1">
                <div className="flex items-center gap-2">
                  <span className="font-bold text-gray-800 text-base">{player.name}</span>
                  {activeFunder && (
                    <span className="text-[9px] bg-amber-500 text-white px-1.5 py-0.5 rounded font-black shadow-sm flex items-center gap-0.5">
                      <span className="text-[12px]">👑</span> 本期集资人
                    </span>
                  )}
                  {player.isFunder && !activeFunder && (
                    <span className="text-[9px] bg-gray-100 text-gray-400 px-1.5 py-0.5 rounded font-bold border border-gray-200">
                      备选
                    </span>
                  )}
                </div>
                <div className="text-xs text-gray-500 mt-1.5 flex items-center gap-3">
                  <span className={`px-2 py-0.5 rounded font-bold ${
                    player.type === PlayerType.MONTHLY ? 'bg-purple-100 text-purple-700' : 
                    player.type === PlayerType.HALF_MONTHLY ? 'bg-blue-100 text-blue-700' : 
                    'bg-green-100 text-green-700'
                  }`}>{player.type}</span>
                  <span className="font-mono font-bold text-gray-700">¥{player.defaultFee}</span>
                </div>
              </div>
              <div className="flex gap-2 items-center">
                <button type="button" onClick={() => startEdit(player)} className="text-emerald-600 text-xs font-bold bg-white border border-emerald-100 px-3 py-1.5 rounded-lg shadow-sm active:bg-emerald-50">编辑</button>

                <button 
                  type="button" 
                  onClick={(e) => handleDelete(e, player.id)} 
                  className={`transition-all p-2 rounded-lg flex items-center justify-center relative overflow-hidden ${
                    confirmDeleteId === player.id 
                    ? 'bg-red-500 text-white scale-110 shadow-lg' 
                    : 'text-gray-300 hover:text-red-400 bg-gray-50'
                  }`}
                >
                  {confirmDeleteId === player.id ? (
                    <span className="text-[10px] font-black animate-pulse">确认？</span>
                  ) : (
                    <Icons.Trash />
                  )}
                </button>
              </div>
            </div>
          );
        })}
        {players.length === 0 && (
          <div className="text-center py-20 text-gray-400">
            <p className="text-sm">档案空空如也，请录入人员</p>
          </div>
        )}
      </div>

      {confirmDeleteId && (
        <div className="fixed top-1/4 left-1/2 -translate-x-1/2 bg-gray-800 text-white text-[10px] px-3 py-2 rounded-full shadow-2xl animate-bounce z-[100] pointer-events-none">
          再次点击红色按钮确认删除人员 🗑️
        </div>
      )}
    </div>
  );
};

export default PlayersList;

import React, { useState, useEffect, useMemo } from 'react';
import { Player, PlayerType, Period } from '../types';
import { Icons, DEFAULT_SESSION_FEE } from '../constants';

interface PlayersListProps {
  players: Player[];
  setPlayers: React.Dispatch<React.SetStateAction<Player[]>>;
  periods: Period[];
}

const PlayersList: React.FC<PlayersListProps> = ({ players, setPlayers, periods }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);
  const [formData, setFormData] = useState<Partial<Player>>({
    name: '',
    type: PlayerType.PER_SESSION,
    defaultFee: DEFAULT_SESSION_FEE,
    isFunder: false
  });

  // 获取最近的一个周期，作为当前“身份”的判定基准
  const latestPeriod = useMemo(() => {
    return periods.length > 0 ? periods[periods.length - 1] : null;
  }, [periods]);

  // 3秒后自动重置删除确认状态
  useEffect(() => {
    if (confirmDeleteId) {
      const timer = setTimeout(() => setConfirmDeleteId(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [confirmDeleteId]);

  const handleSave = () => {
    if (!formData.name) return;
    if (editingId) {
      setPlayers(prev => prev.map(p => p.id === editingId ? { ...p, ...formData } as Player : p));
      setEditingId(null);
    } else {
      const newPlayer: Player = {
        id: Date.now().toString(),
        name: formData.name!,
        type: formData.type as PlayerType || PlayerType.PER_SESSION,
        defaultFee: formData.defaultFee !== undefined ? formData.defaultFee : (formData.type === PlayerType.PER_SESSION ? DEFAULT_SESSION_FEE : 0),
        isFunder: !!formData.isFunder // 正确读取表单状态
      };
      setPlayers(prev => [...prev, newPlayer]);
      setIsAdding(false);
    }
    setFormData({ name: '', type: PlayerType.PER_SESSION, defaultFee: DEFAULT_SESSION_FEE, isFunder: false });
  };

  const startEdit = (player: Player) => {
    setEditingId(player.id);
    setFormData(player);
  };

  const handleDelete = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    e.preventDefault();
    if (confirmDeleteId === id) {
      setPlayers(prev => prev.filter(p => p.id !== id));
      setConfirmDeleteId(null);
    } else {
      setConfirmDeleteId(id);
    }
  };

  // 检查成员是否为最新周期的集资人（身份动态化核心）
  const isCurrentlyFunder = (playerId: string) => {
    return latestPeriod?.funderIds.includes(playerId) || false;
  };

  return (
    <div className="p-4">
      <div className="flex justify-between items-center mb-4">
        <h2 className="text-lg font-bold text-gray-800">人员档案</h2>
        <button 
          type="button"
          onClick={() => {
            setIsAdding(true);
            setFormData({ name: '', type: PlayerType.PER_SESSION, defaultFee: DEFAULT_SESSION_FEE, isFunder: false });
          }}
          className="bg-emerald-600 text-white px-3 py-1.5 rounded-lg text-sm flex items-center gap-1 font-bold shadow-sm active:opacity-80 transition-all"
        >
          <Icons.Plus /> 新增人员
        </button>
      </div>

      {(isAdding || editingId) && (
        <div className="mb-6 bg-white p-4 rounded-xl shadow-lg border-2 border-emerald-500 animate-in zoom-in-95 duration-200">
          <h3 className="font-bold mb-4 text-emerald-800">{editingId ? '修改成员信息' : '录入新成员'}</h3>
          <div className="space-y-4">
            <div>
              <label className="block text-xs text-gray-500 mb-1 font-bold tracking-wider">姓名</label>
              <input type="text" value={formData.name} onChange={e => setFormData({ ...formData, name: e.target.value })} className="w-full border border-gray-300 rounded-lg p-2 text-sm focus:ring-2 focus:ring-emerald-500 outline-none" placeholder="请输入姓名" />
            </div>
            <div>
              <label className="block text-xs text-gray-500 mb-1 font-bold tracking-wider">人员性质 (默认)</label>
              <select value={formData.type} onChange={e => {
                   const type = e.target.value as PlayerType;
                   const fee = type === PlayerType.PER_SESSION ? DEFAULT_SESSION_FEE : (formData.defaultFee || 0);
                   setFormData({ ...formData, type, defaultFee: fee });
              }} className="w-full border border-gray-300 rounded-lg p-2 text-sm bg-gray-50 outline-none">
                <option value={PlayerType.MONTHLY}>包月</option>
                <option value={PlayerType.HALF_MONTHLY}>包半月</option>
                <option value={PlayerType.PER_SESSION}>按次</option>
              </select>
            </div>
            <div>
              <label className="block text-xs text-gray-500 mb-1 font-bold tracking-wider">单次活动收费 (元)</label>
              <input type="number" value={formData.defaultFee} onChange={e => setFormData({ ...formData, defaultFee: Number(e.target.value) })} className="w-full border border-gray-300 rounded-lg p-2 text-sm outline-none font-mono" />
            </div>

            <div className="flex items-center gap-2 p-3 bg-amber-50 rounded-lg border border-amber-100">
              <input 
                type="checkbox" 
                checked={formData.isFunder} 
                onChange={e => setFormData({ ...formData, isFunder: e.target.checked })} 
                id="isFunder" 
                className="w-5 h-5 text-amber-600 rounded-md border-amber-300 focus:ring-amber-500" 
              />
              <label htmlFor="isFunder" className="text-xs font-bold text-amber-800 cursor-pointer select-none">
                核心集资备选人 <br/>
                <span className="font-normal text-[10px] opacity-70">开启后，在创建新周期时此人将出现在集资人勾选池中。</span>
              </label>
            </div>

            <div className="flex gap-2 pt-2">
              <button type="button" onClick={handleSave} className="flex-1 bg-emerald-600 text-white py-2 rounded-lg font-bold text-sm shadow-sm active:scale-95 transition-transform">保存</button>
              <button type="button" onClick={() => { setIsAdding(false); setEditingId(null); }} className="flex-1 bg-gray-100 text-gray-500 py-2 rounded-lg font-bold text-sm">取消</button>
            </div>
          </div>
        </div>
      )}

      <div className="space-y-3">
        {players.map(player => {
          const activeFunder = isCurrentlyFunder(player.id);
          return (
            <div key={player.id} className={`bg-white p-4 rounded-xl shadow-sm border flex justify-between items-center transition-all ${activeFunder ? 'border-amber-400 bg-amber-50/10 ring-1 ring-amber-400/20' : 'border-gray-100'}`}>
              <div className="flex-1">
                <div className="flex items-center gap-2">
                  <span className="font-bold text-gray-800 text-base">{player.name}</span>
                  {activeFunder ? (
                    <span className="text-[9px] bg-amber-500 text-white px-2 py-0.5 rounded-full font-black shadow-sm flex items-center gap-0.5 animate-in fade-in zoom-in-90">
                      <span className="text-[11px]">👑</span> 本期集资人
                    </span>
                  ) : player.isFunder ? (
                    <span className="text-[9px] bg-gray-100 text-gray-400 px-1.5 py-0.5 rounded font-bold border border-gray-200">
                      备选集资人
                    </span>
                  ) : null}
                </div>
                <div className="text-xs text-gray-500 mt-2 flex items-center gap-3">
                  <span className={`px-2 py-0.5 rounded font-bold ${
                    player.type === PlayerType.MONTHLY ? 'bg-purple-100 text-purple-700' : 
                    player.type === PlayerType.HALF_MONTHLY ? 'bg-blue-100 text-blue-700' : 
                    'bg-green-100 text-green-700'
                  }`}>{player.type}</span>
                  <span className="font-mono font-bold text-gray-700">¥{player.defaultFee}</span>
                </div>
              </div>
              <div className="flex gap-2 items-center">
                <button type="button" onClick={() => startEdit(player)} className="text-emerald-600 text-xs font-bold bg-white border border-emerald-100 px-3 py-1.5 rounded-lg shadow-sm active:bg-emerald-50 active:scale-95 transition-all">编辑</button>

                <button 
                  type="button" 
                  onClick={(e) => handleDelete(e, player.id)} 
                  className={`transition-all p-2 rounded-lg flex items-center justify-center ${
                    confirmDeleteId === player.id 
                      ? 'bg-red-500 text-white w-20' 
                      : 'bg-red-50 text-red-500 w-10 hover:bg-red-100'
                  }`}
                >
                  {confirmDeleteId === player.id ? (
                    <span className="text-[10px] font-bold">确认删除?</span>
                  ) : (
                    <Icons.Trash />
                  )}
                </button>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default PlayersList;

export enum PlayerType {
  MONTHLY = '包月',
  HALF_MONTHLY = '包半月',
  PER_SESSION = '按次'
}

export interface Player {
  id: string;
  name: string;
  type: PlayerType;
  defaultFee: number;
  isFunder: boolean;
}

export interface Session {
  id: string;
  date: string;
  sessionCost?: number; // 当日额外场地费用
  attendees: {
    playerId: string;
    fee: number;
  }[];
}

export interface Period {
  id: string;
  name: string;
  startDate: string;
  endDate: string;
  courtCost: number; // 周期基础场地总成本
  sessions: Session[];
  funderIds: string[]; // 本期参加集资的人员 ID
}

export type View = 'dashboard' | 'players' | 'periods' | 'finance';

import React, { useState } from 'react';
import { Period, Player, Session, PlayerType } from '../types';
import { Icons, DEFAULT_SESSION_FEE } from '../constants';

interface PeriodsListProps {
  periods: Period[];
  setPeriods: React.Dispatch<React.SetStateAction<Period[]>>;
  players: Player[];
  setPlayers: React.Dispatch<React.SetStateAction<Player[]>>;
}

const PeriodsList: React.FC<PeriodsListProps> = ({ periods, setPeriods, players, setPlayers }) => {
  const [isAddingPeriod, setIsAddingPeriod] = useState(false);
  const [editingPeriodId, setEditingPeriodId] = useState<string | null>(null);
  const [expandedPeriodId, setExpandedPeriodId] = useState<string | null>(null);
  const [activeSessionPeriod, setActiveSessionPeriod] = useState<string | null>(null);
  const [editingSessionId, setEditingSessionId] = useState<string | null>(null);
  const [deletingPeriod, setDeletingPeriod] = useState<Period | null>(null);

  const funderPool = players.filter(p => p.isFunder);

  const initialPeriodData = {
    name: '',
    startDate: new Date().toISOString().split('T')[0],
    endDate: '',
    courtCost: 0,
    funderIds: funderPool.map(p => p.id),
    sessions: []
  };

  const [periodFormData, setPeriodFormData] = useState<Partial<Period>>(initialPeriodData);
  const [sessionFormDate, setSessionFormDate] = useState(new Date().toISOString().split('T')[0]);
  const [sessionFormCost, setSessionFormCost] = useState<number>(0);
  const [selectedAttendees, setSelectedAttendees] = useState<{playerId: string, fee: number}[]>([]);

  const handleSavePeriod = () => {
    if (!periodFormData.name) {
      alert('请输入周期名称');
      return;
    }

    const finalFunderIds = periodFormData.funderIds || [];

    setPlayers(prevPlayers => prevPlayers.map(p => {
      if (finalFunderIds.includes(p.id)) {
        return { ...p, type: PlayerType.MONTHLY, isFunder: true, defaultFee: 0 };
      }
      if (p.isFunder) {
        return { ...p, type: PlayerType.PER_SESSION, isFunder: true, defaultFee: DEFAULT_SESSION_FEE };
      }
      return p;
    }));

    if (editingPeriodId) {
      setPeriods(prev => prev.map(p => p.id === editingPeriodId ? { ...p, ...periodFormData } as Period : p));
      setEditingPeriodId(null);
    } else {
      const period: Period = {
        id: Date.now().toString(),
        name: periodFormData.name!,
        startDate: periodFormData.startDate!,
        endDate: periodFormData.endDate || '',
        courtCost: periodFormData.courtCost || 0,
        funderIds: finalFunderIds,
        sessions: []
      };
      setPeriods(prev => [...prev, period]);
      setIsAddingPeriod(false);
    }
    setPeriodFormData(initialPeriodData);
  };

  const handleOpenAddSession = (e: React.MouseEvent, periodId: string) => {
    e.stopPropagation();
    setActiveSessionPeriod(periodId);
    setEditingSessionId(null);
    setSessionFormDate(new Date().toISOString().split('T')[0]);
    setSessionFormCost(0);
    setSelectedAttendees([]);
  };

  const handleEditSession = (e: React.MouseEvent, periodId: string, session: Session) => {
    e.stopPropagation();
    setActiveSessionPeriod(periodId);
    setEditingSessionId(session.id);
    setSessionFormDate(session.date);
    setSessionFormCost(session.sessionCost || 0);
    setSelectedAttendees(session.attendees);
  };

  const saveSession = (periodId: string) => {
    if (selectedAttendees.length === 0) {
      alert('请至少选择一名出席成员');
      return;
    }
    if (editingSessionId) {
      setPeriods(prev => prev.map(p => p.id === periodId ? {
        ...p,
        sessions: p.sessions.map(s => s.id === editingSessionId ? { ...s, date: sessionFormDate, sessionCost: sessionFormCost, attendees: selectedAttendees } : s)
      } : p));
    } else {
      const session: Session = {
        id: Date.now().toString(),
        date: sessionFormDate,
        sessionCost: sessionFormCost,
        attendees: selectedAttendees
      };
      setPeriods(prev => prev.map(p => p.id === periodId ? { ...p, sessions: [...p.sessions, session] } : p));
    }
    setActiveSessionPeriod(null);
    setEditingSessionId(null);
  };

  const toggleAttendee = (player: Player, periodId: string) => {
    const exists = selectedAttendees.find(a => a.playerId === player.id);
    if (exists) {
      setSelectedAttendees(prev => prev.filter(a => a.playerId !== player.id));
    } else {
      const currentPeriod = periods.find(p => p.id === periodId);
      let defaultFee = player.defaultFee;
      if ((player.type === PlayerType.MONTHLY || player.type === PlayerType.HALF_MONTHLY) && currentPeriod) {
        const hasPaidInPeriod = currentPeriod.sessions.some(s => 
          s.id !== editingSessionId && 
          s.attendees.some(a => a.playerId === player.id && a.fee > 0)
        );
        if (hasPaidInPeriod) defaultFee = 0;
      }
      setSelectedAttendees(prev => [...prev, { playerId: player.id, fee: defaultFee }]);
    }
  };

  const confirmDeletePeriod = () => {
    if (!deletingPeriod) return;
    setPeriods(prev => prev.filter(p => p.id !== deletingPeriod.id));
    setDeletingPeriod(null);
  };

  return (
    <div className="p-4 pb-10">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-lg font-bold text-gray-800">结算周期管理</h2>
        <button type="button" onClick={() => { setIsAddingPeriod(true); setPeriodFormData(initialPeriodData); }} className="bg-emerald-600 text-white px-3 py-2 rounded-lg text-sm flex items-center gap-1 font-bold shadow-md active:scale-95 transition-all">
          <Icons.Plus /> 新增周期
        </button>
      </div>

      {deletingPeriod && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-black/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-sm rounded-3xl p-6 shadow-2xl">
            <h3 className="text-center font-black text-gray-900 text-lg mb-2">确认删除周期？</h3>
            <p className="text-center text-gray-500 text-xs mb-6 px-4">删除后将清除该周期内所有记录。</p>
            <div className="flex flex-col gap-3">
              <button onClick={confirmDeletePeriod} className="w-full bg-red-500 text-white py-3 rounded-xl font-black text-sm">确认删除</button>
              <button onClick={() => setDeletingPeriod(null)} className="w-full bg-gray-100 text-gray-500 py-3 rounded-xl font-bold text-sm">取消</button>
            </div>
          </div>
        </div>
      )}

      {(isAddingPeriod || editingPeriodId) && (
        <div className="mb-8 bg-white p-5 rounded-2xl shadow-xl border-2 border-emerald-500">
          <h3 className="font-black mb-5 text-emerald-800 text-base">{editingPeriodId ? '📝 编辑结算周期' : '🗓️ 创建新结算周期'}</h3>
          <div className="space-y-5">
            <input type="text" placeholder="周期名称" value={periodFormData.name} onChange={e => setPeriodFormData({...periodFormData, name: e.target.value})} className="w-full border border-gray-300 rounded-xl p-3 text-sm focus:ring-2 focus:ring-emerald-500 outline-none" />
            <div className="flex gap-3">
              <input type="date" value={periodFormData.startDate} onChange={e => setPeriodFormData({...periodFormData, startDate: e.target.value})} className="flex-1 border border-gray-300 rounded-xl p-3 text-sm" />
              <input type="date" value={periodFormData.endDate} onChange={e => setPeriodFormData({...periodFormData, endDate: e.target.value})} className="flex-1 border border-gray-300 rounded-xl p-3 text-sm" />
            </div>
            <div>
              <label className="block text-xs font-bold text-gray-500 mb-1">周期基础场地费</label>
              <input type="number" placeholder="基础场地费" value={periodFormData.courtCost || ''} onChange={e => setPeriodFormData({...periodFormData, courtCost: Number(e.target.value)})} className="w-full border border-gray-300 rounded-xl p-3 text-sm font-mono text-red-600" />
            </div>
            <div className="bg-amber-50 p-4 rounded-xl border border-amber-200">
              <p className="text-xs font-black text-amber-800 mb-3 uppercase">👑 选择本期集资人员</p>
              <div className="flex flex-wrap gap-2">
                {funderPool.map(f => (
                  <button key={f.id} type="button" onClick={() => {
                    const current = periodFormData.funderIds || [];
                    setPeriodFormData({...periodFormData, funderIds: current.includes(f.id) ? current.filter(id => id !== f.id) : [...current, f.id]});
                  }} className={`text-xs px-3 py-2 rounded-lg border-2 font-bold ${periodFormData.funderIds?.includes(f.id) ? 'bg-amber-500 border-amber-600 text-white' : 'bg-white border-amber-100 text-amber-300'}`}>
                    {f.name}
                  </button>
                ))}
              </div>
            </div>
            <div className="flex gap-3 pt-2">
              <button type="button" onClick={handleSavePeriod} className="flex-2 bg-emerald-600 text-white py-3 rounded-xl font-black text-sm">保存</button>
              <button type="button" onClick={() => { setIsAddingPeriod(false); setEditingPeriodId(null); }} className="flex-1 bg-gray-100 text-gray-500 py-3 rounded-xl font-bold text-sm">取消</button>
            </div>
          </div>
        </div>
      )}

      <div className="space-y-4">
        {periods.slice().reverse().map(period => (
          <div key={period.id} className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
            <div className={`p-4 flex justify-between items-center cursor-pointer ${expandedPeriodId === period.id ? 'bg-emerald-50/30' : ''}`} onClick={() => setExpandedPeriodId(expandedPeriodId === period.id ? null : period.id)}>
              <div className="flex-1">
                <h3 className="font-black text-gray-800 text-base">{period.name}</h3>
                <p className="text-[10px] text-gray-400 font-medium">{period.startDate} ~ {period.endDate || '进行中'}</p>
                <div className="mt-2 flex gap-1 flex-wrap">
                  {period.funderIds.map(fid => (
                    <span key={fid} className="text-[9px] bg-amber-100 text-amber-700 px-1.5 py-0.5 rounded font-bold">
                      {players.find(p => p.id === fid)?.name || '?'}
                    </span>
                  ))}
                </div>
              </div>
              <div className="text-right flex items-center gap-4">
                <div>
                  <p className="text-[10px] text-gray-400 font-bold">场次</p>
                  <p className="font-black text-emerald-600">{period.sessions.length}</p>
                </div>
                <div className="flex flex-col gap-1">
                  <button type="button" onClick={(e) => { e.stopPropagation(); setEditingPeriodId(period.id); setPeriodFormData(period); }} className="text-emerald-700 text-[10px] font-black p-1 bg-emerald-100/50 rounded">编辑</button>
                  <button type="button" onClick={(e) => { e.stopPropagation(); setDeletingPeriod(period); }} className="text-red-400 p-1"><Icons.Trash /></button>
                </div>
              </div>
            </div>

            {expandedPeriodId === period.id && (
              <div className="border-t border-gray-100 bg-gray-50/50 p-4 space-y-4">
                <div className="flex justify-between items-center">
                  <h4 className="text-xs font-black text-gray-500 uppercase">📋 活动明细</h4>
                  <button type="button" onClick={(e) => handleOpenAddSession(e, period.id)} className="text-[10px] bg-emerald-600 text-white px-4 py-2 rounded-full font-black shadow-md">
                    + 录入打球
                  </button>
                </div>

                {activeSessionPeriod === period.id && (
                  <div className="bg-white p-4 rounded-2xl border-2 border-emerald-500 shadow-xl">
                    <p className="text-xs font-black text-emerald-800 mb-4 uppercase">{editingSessionId ? '✏️ 编辑场次' : '✨ 录入场次'}</p>
                    <div className="space-y-4">
                      <div>
                        <label className="block text-[10px] font-bold text-gray-400 mb-1">日期</label>
                        <input type="date" value={sessionFormDate} onChange={e => setSessionFormDate(e.target.value)} className="w-full border border-gray-200 rounded-xl p-2 text-sm" />
                      </div>
                      <div className="bg-red-50 p-3 rounded-xl border border-red-100">
                        <label className="block text-[10px] font-black text-red-800 mb-1 flex justify-between italic">
                          <span>当日额外场地费</span>
                          <span className="text-[8px] font-normal opacity-60">如无则填0</span>
                        </label>
                        <input type="number" value={sessionFormCost || ''} onChange={e => setSessionFormCost(Number(e.target.value))} className="w-full border-none bg-transparent font-mono text-red-600 font-black text-sm focus:ring-0 p-0" placeholder="0.00" />
                      </div>
                      <div>
                        <p className="text-[10px] font-bold text-gray-400 mb-2">出席人员 (多选):</p>
                        <div className="flex flex-wrap gap-1.5 max-h-40 overflow-y-auto p-2 border border-gray-100 rounded-xl bg-gray-50">
                          {players.map(p => {
                            const isSelected = selectedAttendees.find(a => a.playerId === p.id);
                            return (
                              <button key={p.id} type="button" onClick={() => toggleAttendee(p, period.id)} className={`text-[10px] px-2.5 py-1.5 rounded-lg border font-bold transition-all ${isSelected ? 'bg-emerald-600 border-emerald-700 text-white' : 'bg-white border-gray-200 text-gray-400'}`}>
                                {p.name}
                              </button>
                            );
                          })}
                        </div>
                      </div>
                      {selectedAttendees.length > 0 && (
                        <div className="space-y-2">
                          <p className="text-[10px] font-bold text-gray-400">核对/修改个人收费:</p>
                          {selectedAttendees.map(a => (
                            <div key={a.playerId} className="flex justify-between items-center bg-gray-50 p-2 rounded-xl text-xs">
                              <span className="font-bold text-gray-700">{players.find(p => p.id === a.playerId)?.name}</span>
                              <div className="flex items-center gap-1 bg-white border border-gray-200 rounded px-2">
                                <span className="text-[10px] text-gray-400">¥</span>
                                <input type="number" value={a.fee} onChange={e => {
                                  const val = Number(e.target.value);
                                  setSelectedAttendees(prev => prev.map(sa => sa.playerId === a.playerId ? {...sa, fee: val} : sa));
                                }} className="w-12 py-1 text-center font-black text-emerald-600 focus:outline-none" />
                              </div>
                            </div>
                          ))}
                        </div>
                      )}
                      <div className="flex gap-3">
                        <button type="button" onClick={() => saveSession(period.id)} className="flex-2 bg-emerald-600 text-white py-3 rounded-xl font-black text-sm">保存记录</button>
                        <button type="button" onClick={() => setActiveSessionPeriod(null)} className="flex-1 bg-gray-100 text-gray-500 py-3 rounded-xl font-bold text-sm">取消</button>
                      </div>
                    </div>
                  </div>
                )}

                <div className="space-y-3">
                  {period.sessions.map(session => (
                    <div key={session.id} className="bg-white p-3 rounded-2xl shadow-sm border border-gray-100">
                      <div className="flex justify-between items-center mb-2">
                        <div>
                          <p className="text-xs font-black text-gray-800">{session.date}</p>
                          <div className="flex gap-2 mt-1">
                            {session.sessionCost ? <span className="text-[8px] bg-red-50 text-red-600 px-1 py-0.5 rounded font-bold">当日场地费: ¥{session.sessionCost}</span> : null}
                            <span className="text-[8px] bg-emerald-50 text-emerald-600 px-1 py-0.5 rounded font-bold">收入: ¥{session.attendees.reduce((s, a) => s + a.fee, 0)}</span>
                          </div>
                        </div>
                        <div className="flex gap-1">
                          <button type="button" onClick={(e) => handleEditSession(e, period.id, session)} className="text-gray-300 p-1"><Icons.Pencil /></button>
                          <button type="button" onClick={(e) => { e.stopPropagation(); if (confirm('确定删除?')) setPeriods(prev => prev.map(p => p.id === period.id ? { ...p, sessions: p.sessions.filter(s => s.id !== session.id) } : p)); }} className="text-gray-300 p-1"><Icons.Trash /></button>
                        </div>
                      </div>
                      <div className="flex flex-wrap gap-1">
                        {session.attendees.map(a => (
                          <span key={a.playerId} className="text-[8px] bg-gray-50 text-gray-400 px-1.5 py-0.5 rounded border border-gray-100">
                            {players.find(pl => pl.id === a.playerId)?.name} (¥{a.fee})
                          </span>
                        ))}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

