import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Player, PlayerType, Period } from '../types';
import { Icons, DEFAULT_SESSION_FEE } from '../constants';

interface PlayersListProps {
  players: Player[];
  setPlayers: React.Dispatch<React.SetStateAction<Player[]>>;
  periods: Period[];
}

const PlayersList: React.FC<PlayersListProps> = ({ players, setPlayers, periods }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [formData, setFormData] = useState<Partial<Player>>({
    name: '',
    type: PlayerType.PER_SESSION,
    defaultFee: DEFAULT_SESSION_FEE,
    isFunder: false
  });

  const latestPeriod = useMemo(() => {
    return periods.length > 0 ? periods[periods.length - 1] : null;
  }, [periods]);

  useEffect(() => {
    if (confirmDeleteId) {
      const timer = setTimeout(() => setConfirmDeleteId(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [confirmDeleteId]);

  const handleSave = () => {
    if (!formData.name) return;
    if (editingId) {
      setPlayers(prev => prev.map(p => p.id === editingId ? { ...p, ...formData } as Player : p));
      setEditingId(null);
    } else {
      const newPlayer: Player = {
        id: Date.now().toString(),
        name: formData.name!,
        type: formData.type as PlayerType || PlayerType.PER_SESSION,
        defaultFee: formData.defaultFee !== undefined ? formData.defaultFee : (formData.type === PlayerType.PER_SESSION ? DEFAULT_SESSION_FEE : 0),
        isFunder: !!formData.isFunder
      };
      setPlayers(prev => [...prev, newPlayer]);
      setIsAdding(false);
    }
    setFormData({ name: '', type: PlayerType.PER_SESSION, defaultFee: DEFAULT_SESSION_FEE, isFunder: false });
  };

  const startEdit = (player: Player) => {
    setEditingId(player.id);
    setFormData(player);
  };

  const handleDelete = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    e.preventDefault();
    if (confirmDeleteId === id) {
      setPlayers(prev => prev.filter(p => p.id !== id));
      setConfirmDeleteId(null);
    } else {
      setConfirmDeleteId(id);
    }
  };

  const isCurrentlyFunder = (playerId: string) => {
    return latestPeriod?.funderIds.includes(playerId) || false;
  };

  // CSV 导出功能
  const exportToCSV = () => {
    const headers = ['姓名', '类型', '单次收费', '是否核心集资备选'];
    const rows = players.map(p => [
      p.name,
      p.type,
      p.defaultFee,
      p.isFunder ? '是' : '否'
    ]);

    const csvContent = "\ufeff" + [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `badminton_players_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // CSV 导入功能
  const handleImportClick = () => {
    fileInputRef.current?.click();
  };

  const importFromCSV = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const text = event.target?.result as string;
      const lines = text.split('\n');
      const newPlayers: Player[] = [];

      // 跳过表头
      for (let i = 1; i < lines.length; i++) {
        const line = lines[i].trim();
        if (!line) continue;
        const [name, typeStr, feeStr, isFunderStr] = line.split(',');

        if (!name) continue;

        // 匹配类型
        let type = PlayerType.PER_SESSION;
        if (typeStr?.includes('包月')) type = PlayerType.MONTHLY;
        else if (typeStr?.includes('包半月')) type = PlayerType.HALF_MONTHLY;

        newPlayers.push({
          id: `imported-${Date.now()}-${i}`,
          name: name.trim(),
          type: type,
          defaultFee: Number(feeStr) || 0,
          isFunder: isFunderStr?.includes('是') || isFunderStr?.toLowerCase() === 'true'
        });
      }

      if (newPlayers.length > 0) {
        if (confirm(`检测到 ${newPlayers.length} 名成员，是否合并到当前列表？`)) {
          setPlayers(prev => [...prev, ...newPlayers]);
        }
      }
      // 重置 input
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsText(file);
  };

  return (
    <div className="p-4">
      <div className="flex justify-between items-center mb-4">
        <h2 className="text-lg font-bold text-gray-800">人员档案</h2>
        <div className="flex gap-2">
          {/* 导入导出按钮组 */}
          <button 
            type="button"
            onClick={exportToCSV}
            title="导出 CSV"
            className="p-2 bg-white border border-gray-200 text-gray-500 rounded-lg hover:bg-gray-50 active:bg-gray-100 transition-all shadow-sm"
          >
            <Icons.Download />
          </button>
          <button 
            type="button"
            onClick={handleImportClick}
            title="导入 CSV"
            className="p-2 bg-white border border-gray-200 text-gray-500 rounded-lg hover:bg-gray-50 active:bg-gray-100 transition-all shadow-sm"
          >
            <Icons.Upload />
          </button>
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={importFromCSV} 
            accept=".csv" 
            className="hidden" 
          />
          <button 
            type="button"
            onClick={() => {
              setIsAdding(true);
              setFormData({ name: '', type: PlayerType.PER_SESSION, defaultFee: DEFAULT_SESSION_FEE, isFunder: false });
            }}
            className="bg-emerald-600 text-white px-3 py-1.5 rounded-lg text-sm flex items-center gap-1 font-bold shadow-sm active:opacity-80 transition-all"
          >
            <Icons.Plus /> 新增
          </button>
        </div>
      </div>

      {(isAdding || editingId) && (
        <div className="mb-6 bg-white p-4 rounded-xl shadow-lg border-2 border-emerald-500 animate-in zoom-in-95 duration-200">
          <h3 className="font-bold mb-4 text-emerald-800">{editingId ? '修改成员信息' : '录入新成员'}</h3>
          <div className="space-y-4">
            <div>
              <label className="block text-xs text-gray-500 mb-1 font-bold tracking-wider">姓名</label>
              <input type="text" value={formData.name} onChange={e => setFormData({ ...formData, name: e.target.value })} className="w-full border border-gray-300 rounded-lg p-2 text-sm focus:ring-2 focus:ring-emerald-500 outline-none" placeholder="请输入姓名" />
            </div>
            <div>
              <label className="block text-xs text-gray-500 mb-1 font-bold tracking-wider">人员性质 (默认)</label>
              <select value={formData.type} onChange={e => {
                   const type = e.target.value as PlayerType;
                   const fee = type === PlayerType.PER_SESSION ? DEFAULT_SESSION_FEE : (formData.defaultFee || 0);
                   setFormData({ ...formData, type, defaultFee: fee });
              }} className="w-full border border-gray-300 rounded-lg p-2 text-sm bg-gray-50 outline-none">
                <option value={PlayerType.MONTHLY}>包月</option>
                <option value={PlayerType.HALF_MONTHLY}>包半月</option>
                <option value={PlayerType.PER_SESSION}>按次</option>
              </select>
            </div>
            <div>
              <label className="block text-xs text-gray-500 mb-1 font-bold tracking-wider">单次活动收费 (元)</label>
              <input type="number" value={formData.defaultFee} onChange={e => setFormData({ ...formData, defaultFee: Number(e.target.value) })} className="w-full border border-gray-300 rounded-lg p-2 text-sm outline-none font-mono" />
            </div>

            <div className="flex items-center gap-2 p-3 bg-amber-50 rounded-lg border border-amber-100">
              <input 
                type="checkbox" 
                checked={formData.isFunder} 
                onChange={e => setFormData({ ...formData, isFunder: e.target.checked })} 
                id="isFunder" 
                className="w-5 h-5 text-amber-600 rounded-md border-amber-300 focus:ring-amber-500" 
              />
              <label htmlFor="isFunder" className="text-xs font-bold text-amber-800 cursor-pointer select-none">
                核心集资备选人 <br/>
                <span className="font-normal text-[10px] opacity-70">开启后，在创建新周期时此人将出现在集资人勾选池中。</span>
              </label>
            </div>

            <div className="flex gap-2 pt-2">
              <button type="button" onClick={handleSave} className="flex-1 bg-emerald-600 text-white py-2 rounded-lg font-bold text-sm shadow-sm active:scale-95 transition-transform">保存</button>
              <button type="button" onClick={() => { setIsAdding(false); setEditingId(null); }} className="flex-1 bg-gray-100 text-gray-500 py-2 rounded-lg font-bold text-sm">取消</button>
            </div>
          </div>
        </div>
      )}

      <div className="space-y-3">
        {players.map(player => {
          const activeFunder = isCurrentlyFunder(player.id);
          return (
            <div key={player.id} className={`bg-white p-4 rounded-xl shadow-sm border flex justify-between items-center transition-all ${activeFunder ? 'border-amber-400 bg-amber-50/10 ring-1 ring-amber-400/20' : 'border-gray-100'}`}>
              <div className="flex-1">
                <div className="flex items-center gap-2">
                  <span className="font-bold text-gray-800 text-base">{player.name}</span>
                  {activeFunder ? (
                    <span className="text-[9px] bg-amber-500 text-white px-2 py-0.5 rounded-full font-black shadow-sm flex items-center gap-0.5 animate-in fade-in zoom-in-90">
                      <span className="text-[11px]">👑</span> 本期集资人
                    </span>
                  ) : player.isFunder ? (
                    <span className="text-[9px] bg-gray-100 text-gray-400 px-1.5 py-0.5 rounded font-bold border border-gray-200">
                      备选集资人
                    </span>
                  ) : null}
                </div>
                <div className="text-xs text-gray-500 mt-2 flex items-center gap-3">
                  <span className={`px-2 py-0.5 rounded font-bold ${
                    player.type === PlayerType.MONTHLY ? 'bg-purple-100 text-purple-700' : 
                    player.type === PlayerType.HALF_MONTHLY ? 'bg-blue-100 text-blue-700' : 
                    'bg-green-100 text-green-700'
                  }`}>{player.type}</span>
                  <span className="font-mono font-bold text-gray-700">¥{player.defaultFee}</span>
                </div>
              </div>
              <div className="flex gap-2 items-center">
                <button type="button" onClick={() => startEdit(player)} className="text-emerald-600 text-xs font-bold bg-white border border-emerald-100 px-3 py-1.5 rounded-lg shadow-sm active:bg-emerald-50 active:scale-95 transition-all">编辑</button>

                <button 
                  type="button" 
                  onClick={(e) => handleDelete(e, player.id)} 
                  className={`transition-all p-2 rounded-lg flex items-center justify-center ${
                    confirmDeleteId === player.id 
                      ? 'bg-red-500 text-white w-20' 
                      : 'bg-red-50 text-red-500 w-10 hover:bg-red-100'
                  }`}
                >
                  {confirmDeleteId === player.id ? (
                    <span className="text-[10px] font-bold">确认删除?</span>
                  ) : (
                    <Icons.Trash />
                  )}
                </button>
              </div>
            </div>
          );
        })}
      </div>

      {players.length === 0 && (
        <div className="text-center py-20 text-gray-300">
           <p className="text-4xl mb-4">📭</p>
           <p className="text-sm">暂无人员记录，请新增或从 CSV 导入</p>
        </div>
      )}
    </div>
  );
};

export default PlayersList;

import React, { useState, useMemo } from 'react';
import DatePicker from 'react-datepicker';
import { Period, Player, Session, PlayerType } from '../types';
import { Icons, DEFAULT_SESSION_FEE } from '../constants';

interface PeriodsListProps {
  periods: Period[];
  setPeriods: React.Dispatch<React.SetStateAction<Period[]>>;
  players: Player[];
  setPlayers: React.Dispatch<React.SetStateAction<Player[]>>;
}

const PeriodsList: React.FC<PeriodsListProps> = ({ periods, setPeriods, players, setPlayers }) => {
  const [isAddingPeriod, setIsAddingPeriod] = useState(false);
  const [editingPeriodId, setEditingPeriodId] = useState<string | null>(null);
  const [expandedPeriodId, setExpandedPeriodId] = useState<string | null>(null);
  const [activeSessionPeriod, setActiveSessionPeriod] = useState<string | null>(null);
  const [editingSessionId, setEditingSessionId] = useState<string | null>(null);
  const [deletingPeriod, setDeletingPeriod] = useState<Period | null>(null);

  // 排序相关状态
  const [sortBy, setSortBy] = useState<'date' | 'name'>('date');
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('desc');

  const funderPool = players.filter(p => p.isFunder);

  const initialPeriodData = {
    name: '',
    startDate: new Date().toISOString().split('T')[0],
    endDate: '',
    courtCost: 0,
    funderIds: funderPool.map(p => p.id),
    sessions: []
  };

  const [periodFormData, setPeriodFormData] = useState<Partial<Period>>(initialPeriodData);
  const [sessionFormDate, setSessionFormDate] = useState(new Date().toISOString().split('T')[0]);
  const [sessionFormCost, setSessionFormCost] = useState<number>(0);
  const [selectedAttendees, setSelectedAttendees] = useState<{playerId: string, fee: number}[]>([]);

  // 排序逻辑
  const sortedPeriods = useMemo(() => {
    return [...periods].sort((a, b) => {
      let comparison = 0;
      if (sortBy === 'date') {
        comparison = a.startDate.localeCompare(b.startDate);
      } else {
        comparison = a.name.localeCompare(b.name, 'zh-CN');
      }
      return sortOrder === 'asc' ? comparison : -comparison;
    });
  }, [periods, sortBy, sortOrder]);

  // 辅助函数：将字符串日期转为 Date 对象
  const stringToDate = (str: string | undefined) => {
    if (!str) return null;
    return new Date(str);
  };

  // 辅助函数：将 Date 对象转为 YYYY-MM-DD 字符串
  const dateToString = (date: Date | null) => {
    if (!date) return '';
    return date.toISOString().split('T')[0];
  };

  const handleSavePeriod = () => {
    if (!periodFormData.name) {
      alert('请输入周期名称');
      return;
    }

    const finalFunderIds = periodFormData.funderIds || [];

    setPlayers(prevPlayers => prevPlayers.map(p => {
      if (finalFunderIds.includes(p.id)) {
        return { ...p, type: PlayerType.MONTHLY, isFunder: true, defaultFee: 0 };
      }
      if (p.isFunder) {
        return { ...p, type: PlayerType.PER_SESSION, isFunder: true, defaultFee: DEFAULT_SESSION_FEE };
      }
      return p;
    }));

    if (editingPeriodId) {
      setPeriods(prev => prev.map(p => p.id === editingPeriodId ? { ...p, ...periodFormData } as Period : p));
      setEditingPeriodId(null);
    } else {
      const period: Period = {
        id: Date.now().toString(),
        name: periodFormData.name!,
        startDate: periodFormData.startDate!,
        endDate: periodFormData.endDate || '',
        courtCost: periodFormData.courtCost || 0,
        funderIds: finalFunderIds,
        sessions: []
      };
      setPeriods(prev => [...prev, period]);
      setIsAddingPeriod(false);
    }
    setPeriodFormData(initialPeriodData);
  };

  const handleOpenAddSession = (e: React.MouseEvent, periodId: string) => {
    e.stopPropagation();
    setActiveSessionPeriod(periodId);
    setEditingSessionId(null);
    setSessionFormDate(new Date().toISOString().split('T')[0]);
    setSessionFormCost(0);
    setSelectedAttendees([]);
  };

  const handleEditSession = (e: React.MouseEvent, periodId: string, session: Session) => {
    e.stopPropagation();
    setActiveSessionPeriod(periodId);
    setEditingSessionId(session.id);
    setSessionFormDate(session.date);
    setSessionFormCost(session.sessionCost || 0);
    setSelectedAttendees(session.attendees);
  };

  const saveSession = (periodId: string) => {
    if (selectedAttendees.length === 0) {
      alert('请至少选择一名出席成员');
      return;
    }
    if (editingSessionId) {
      setPeriods(prev => prev.map(p => p.id === periodId ? {
        ...p,
        sessions: p.sessions.map(s => s.id === editingSessionId ? { ...s, date: sessionFormDate, sessionCost: sessionFormCost, attendees: selectedAttendees } : s)
      } : p));
    } else {
      const session: Session = {
        id: Date.now().toString(),
        date: sessionFormDate,
        sessionCost: sessionFormCost,
        attendees: selectedAttendees
      };
      setPeriods(prev => prev.map(p => p.id === periodId ? { ...p, sessions: [...p.sessions, session] } : p));
    }
    setActiveSessionPeriod(null);
    setEditingSessionId(null);
  };

  const toggleAttendee = (player: Player, periodId: string) => {
    const exists = selectedAttendees.find(a => a.playerId === player.id);
    if (exists) {
      setSelectedAttendees(prev => prev.filter(a => a.playerId !== player.id));
    } else {
      const currentPeriod = periods.find(p => p.id === periodId);
      let defaultFee = player.defaultFee;
      if ((player.type === PlayerType.MONTHLY || player.type === PlayerType.HALF_MONTHLY) && currentPeriod) {
        const hasPaidInPeriod = currentPeriod.sessions.some(s => 
          s.id !== editingSessionId && 
          s.attendees.some(a => a.playerId === player.id && a.fee > 0)
        );
        if (hasPaidInPeriod) defaultFee = 0;
      }
      setSelectedAttendees(prev => [...prev, { playerId: player.id, fee: defaultFee }]);
    }
  };

  const confirmDeletePeriod = () => {
    if (!deletingPeriod) return;
    setPeriods(prev => prev.filter(p => p.id !== deletingPeriod.id));
    setDeletingPeriod(null);
  };

  return (
    <div className="p-4 pb-10">
      <div className="flex justify-between items-center mb-4">
        <h2 className="text-lg font-bold text-gray-800">结算周期管理</h2>
        <button type="button" onClick={() => { setIsAddingPeriod(true); setPeriodFormData(initialPeriodData); }} className="bg-emerald-600 text-white px-4 py-2.5 rounded-xl text-sm flex items-center gap-2 font-black shadow-lg shadow-emerald-200 active:scale-95 transition-all">
          <Icons.Plus /> 新增周期
        </button>
      </div>

      {/* 排序控制 */}
      <div className="flex items-center gap-2 mb-6 px-1">
        <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">排序方式:</span>
        <select 
          value={sortBy} 
          onChange={(e) => setSortBy(e.target.value as 'date' | 'name')}
          className="text-[10px] bg-white border border-gray-200 rounded-lg px-2 py-1.5 font-bold text-gray-600 outline-none focus:ring-2 focus:ring-emerald-500/20"
        >
          <option value="date">按日期</option>
          <option value="name">按名称</option>
        </select>
        <button 
          onClick={() => setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc')}
          className="text-[10px] bg-white border border-gray-200 rounded-lg px-3 py-1.5 font-bold text-gray-600 active:bg-gray-50 flex items-center gap-1 shadow-sm"
        >
          {sortOrder === 'asc' ? '升序 ↑' : '降序 ↓'}
        </button>
      </div>

      {deletingPeriod && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-black/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-sm rounded-3xl p-6 shadow-2xl">
            <h3 className="text-center font-black text-gray-900 text-lg mb-2">确认删除周期？</h3>
            <p className="text-center text-gray-500 text-xs mb-6 px-4">删除后将清除该周期内所有记录。</p>
            <div className="flex flex-col gap-3">
              <button onClick={confirmDeletePeriod} className="w-full bg-red-500 text-white py-3 rounded-xl font-black text-sm">确认删除</button>
              <button onClick={() => setDeletingPeriod(null)} className="w-full bg-gray-100 text-gray-500 py-3 rounded-xl font-bold text-sm">取消</button>
            </div>
          </div>
        </div>
      )}

      {/* 新增/编辑周期的全屏遮罩层表单 */}
      {(isAddingPeriod || editingPeriodId) && (
        <div className="fixed inset-0 z-[110] flex flex-col bg-gray-50/95 backdrop-blur-md overflow-y-auto no-scrollbar animate-in fade-in duration-200">
          <div className="w-full max-w-md mx-auto p-4 flex flex-col h-full">
            <div className="flex justify-between items-center mb-6 pt-2">
              <h3 className="text-xl font-black text-emerald-900">{editingPeriodId ? '📝 编辑结算周期' : '🗓️ 创建新结算周期'}</h3>
              <button onClick={() => { setIsAddingPeriod(false); setEditingPeriodId(null); }} className="p-2 bg-white rounded-full shadow-sm text-gray-400">
                 <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                 </svg>
              </button>
            </div>

            <div className="space-y-6 flex-1 pb-10">
              {/* 分区 1: 基础信息 */}
              <div className="bg-white p-5 rounded-3xl shadow-sm border border-gray-100">
                <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-4">基本信息</p>
                <div className="space-y-4">
                  <div className="group">
                    <label className="block text-xs font-bold text-gray-500 mb-1 ml-1">周期名称</label>
                    <input type="text" placeholder="如：2024年10月集资" value={periodFormData.name} onChange={e => setPeriodFormData({...periodFormData, name: e.target.value})} className="w-full bg-gray-50 border-none rounded-2xl p-4 text-sm focus:ring-2 focus:ring-emerald-500 outline-none font-bold" />
                  </div>

                  <div className="grid grid-cols-2 gap-3">
                    <div>
                      <label className="block text-xs font-bold text-gray-500 mb-1 ml-1">开始日期</label>
                      <DatePicker
                        selected={stringToDate(periodFormData.startDate)}
                        onChange={(date) => setPeriodFormData({...periodFormData, startDate: dateToString(date)})}
                        dateFormat="yyyy-MM-dd"
                        className="w-full bg-gray-50 border-none rounded-2xl p-4 text-sm font-bold focus:outline-none focus:ring-2 focus:ring-emerald-500"
                      />
                    </div>
                    <div>
                      <label className="block text-xs font-bold text-gray-500 mb-1 ml-1">结束日期 (选填)</label>
                      <DatePicker
                        selected={stringToDate(periodFormData.endDate)}
                        onChange={(date) => setPeriodFormData({...periodFormData, endDate: dateToString(date)})}
                        dateFormat="yyyy-MM-dd"
                        className="w-full bg-gray-50 border-none rounded-2xl p-4 text-sm font-bold focus:outline-none focus:ring-2 focus:ring-emerald-500"
                        isClearable
                      />
                    </div>
                  </div>
                </div>
              </div>

              {/* 分区 2: 费用配置 */}
              <div className="bg-white p-5 rounded-3xl shadow-sm border border-gray-100">
                <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-4">费用配置</p>
                <div className="relative">
                  <label className="block text-xs font-bold text-gray-500 mb-2 ml-1">预估本期总场地费</label>
                  <div className="relative flex items-center">
                    <span className="absolute left-4 text-gray-400 font-bold">¥</span>
                    <input type="number" placeholder="0.00" value={periodFormData.courtCost || ''} onChange={e => setPeriodFormData({...periodFormData, courtCost: Number(e.target.value)})} className="w-full bg-red-50 border-none rounded-2xl p-4 pl-10 text-2xl font-black text-red-600 outline-none placeholder:text-red-200" />
                  </div>
                  <p className="text-[10px] text-gray-400 mt-2 px-1">此费用将由下方选中的核心集资人平均分摊。</p>
                </div>
              </div>

              {/* 分区 3: 人员选择 */}
              <div className="bg-amber-50 p-5 rounded-3xl border border-amber-100">
                <div className="flex justify-between items-center mb-4">
                   <p className="text-[10px] font-black text-amber-800 uppercase tracking-widest">👑 确认本期集资人 ({periodFormData.funderIds?.length || 0})</p>
                </div>
                <div className="grid grid-cols-3 gap-2">
                  {funderPool.map(f => {
                    const isSelected = periodFormData.funderIds?.includes(f.id);
                    return (
                      <button 
                        key={f.id} 
                        type="button" 
                        onClick={() => {
                          const current = periodFormData.funderIds || [];
                          setPeriodFormData({...periodFormData, funderIds: current.includes(f.id) ? current.filter(id => id !== f.id) : [...current, f.id]});
                        }} 
                        className={`text-xs py-3 rounded-2xl border-2 transition-all font-black flex flex-col items-center justify-center gap-1 ${
                          isSelected ? 'bg-amber-500 border-amber-600 text-white shadow-md shadow-amber-200 scale-105 z-10' : 'bg-white border-white text-amber-200'
                        }`}
                      >
                        <span className="text-lg">{isSelected ? '⭐️' : '👤'}</span>
                        {f.name}
                      </button>
                    )
                  })}
                </div>
              </div>
            </div>

            {/* 底部固定操作栏 */}
            <div className="sticky bottom-0 bg-gray-50/80 backdrop-blur-md pt-4 pb-6 flex gap-3 mt-4 border-t border-gray-100">
              <button type="button" onClick={handleSavePeriod} className="flex-2 bg-emerald-600 text-white py-4 rounded-2xl font-black text-base shadow-xl shadow-emerald-200 active:scale-95 transition-all">
                确认发布周期
              </button>
              <button type="button" onClick={() => { setIsAddingPeriod(false); setEditingPeriodId(null); }} className="flex-1 bg-white border border-gray-200 text-gray-400 py-4 rounded-2xl font-black text-sm active:bg-gray-100">
                取消
              </button>
            </div>
          </div>
        </div>
      )}

      {/* 列表显示 */}
      <div className="space-y-4">
        {sortedPeriods.map(period => (
          <div key={period.id} className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
            <div className={`p-4 flex justify-between items-center cursor-pointer ${expandedPeriodId === period.id ? 'bg-emerald-50/30' : ''}`} onClick={() => setExpandedPeriodId(expandedPeriodId === period.id ? null : period.id)}>
              <div className="flex-1">
                <h3 className="font-black text-gray-800 text-base">{period.name}</h3>
                <p className="text-[10px] text-gray-400 font-medium">{period.startDate} ~ {period.endDate || '进行中'}</p>
                <div className="mt-2 flex gap-1 flex-wrap">
                  {period.funderIds.map(fid => (
                    <span key={fid} className="text-[9px] bg-amber-100 text-amber-700 px-1.5 py-0.5 rounded font-bold">
                      {players.find(p => p.id === fid)?.name || '?'}
                    </span>
                  ))}
                </div>
              </div>
              <div className="text-right flex items-center gap-4">
                <div>
                  <p className="text-[10px] text-gray-400 font-bold">场次</p>
                  <p className="font-black text-emerald-600">{period.sessions.length}</p>
                </div>
                <div className="flex flex-col gap-1">
                  <button type="button" onClick={(e) => { e.stopPropagation(); setEditingPeriodId(period.id); setPeriodFormData(period); }} className="text-emerald-700 text-[10px] font-black p-1 bg-emerald-100/50 rounded">编辑</button>
                  <button type="button" onClick={(e) => { e.stopPropagation(); setDeletingPeriod(period); }} className="text-red-400 p-1"><Icons.Trash /></button>
                </div>
              </div>
            </div>

            {expandedPeriodId === period.id && (
              <div className="border-t border-gray-100 bg-gray-50/50 p-4 space-y-4">
                <div className="flex justify-between items-center">
                  <h4 className="text-xs font-black text-gray-500 uppercase tracking-widest">📋 活动明细</h4>
                  <button type="button" onClick={(e) => handleOpenAddSession(e, period.id)} className="text-[10px] bg-emerald-600 text-white px-4 py-2 rounded-full font-black shadow-md">
                    + 录入打球
                  </button>
                </div>

                {activeSessionPeriod === period.id && (
                  <div className="bg-white p-4 rounded-2xl border-2 border-emerald-500 shadow-xl">
                    <p className="text-xs font-black text-emerald-800 mb-4 uppercase tracking-widest">{editingSessionId ? '✏️ 编辑场次' : '✨ 录入场次'}</p>
                    <div className="space-y-4">
                      <div>
                        <label className="block text-[10px] font-bold text-gray-400 mb-1">日期</label>
                        <DatePicker
                          selected={stringToDate(sessionFormDate)}
                          onChange={(date) => setSessionFormDate(dateToString(date))}
                          dateFormat="yyyy-MM-dd"
                          className="w-full border border-gray-200 rounded-xl p-2 text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500"
                        />
                      </div>
                      <div className="bg-red-50 p-3 rounded-xl border border-red-100">
                        <label className="block text-[10px] font-black text-red-800 mb-1 flex justify-between italic">
                          <span>当日额外场地费</span>
                          <span className="text-[8px] font-normal opacity-60">如无则填0</span>
                        </label>
                        <input type="number" value={sessionFormCost || ''} onChange={e => setSessionFormCost(Number(e.target.value))} className="w-full border-none bg-transparent font-mono text-red-600 font-black text-sm focus:ring-0 p-0" placeholder="0.00" />
                      </div>
                      <div>
                        <p className="text-[10px] font-bold text-gray-400 mb-2">出席人员 (多选):</p>
                        <div className="flex flex-wrap gap-1.5 max-h-40 overflow-y-auto p-2 border border-gray-100 rounded-xl bg-gray-50">
                          {players.map(p => {
                            const isSelected = selectedAttendees.find(a => a.playerId === p.id);
                            return (
                              <button key={p.id} type="button" onClick={() => toggleAttendee(p, period.id)} className={`text-[10px] px-2.5 py-1.5 rounded-lg border font-bold transition-all ${isSelected ? 'bg-emerald-600 border-emerald-700 text-white' : 'bg-white border-gray-200 text-gray-400'}`}>
                                {p.name}
                              </button>
                            );
                          })}
                        </div>
                      </div>
                      {selectedAttendees.length > 0 && (
                        <div className="space-y-2">
                          <p className="text-[10px] font-bold text-gray-400">核对/修改个人收费:</p>
                          {selectedAttendees.map(a => (
                            <div key={a.playerId} className="flex justify-between items-center bg-gray-50 p-2 rounded-xl text-xs">
                              <span className="font-bold text-gray-700">{players.find(p => p.id === a.playerId)?.name}</span>
                              <div className="flex items-center gap-1 bg-white border border-gray-200 rounded px-2">
                                <span className="text-[10px] text-gray-400">¥</span>
                                <input type="number" value={a.fee} onChange={e => {
                                  const val = Number(e.target.value);
                                  setSelectedAttendees(prev => prev.map(sa => sa.playerId === a.playerId ? {...sa, fee: val} : sa));
                                }} className="w-12 py-1 text-center font-black text-emerald-600 focus:outline-none" />
                              </div>
                            </div>
                          ))}
                        </div>
                      )}
                      <div className="flex gap-3">
                        <button type="button" onClick={() => saveSession(period.id)} className="flex-2 bg-emerald-600 text-white py-3 rounded-xl font-black text-sm">保存记录</button>
                        <button type="button" onClick={() => setActiveSessionPeriod(null)} className="flex-1 bg-gray-100 text-gray-500 py-3 rounded-xl font-bold text-sm">取消</button>
                      </div>
                    </div>
                  </div>
                )}

                <div className="space-y-3">
                  {period.sessions.map(session => (
                    <div key={session.id} className="bg-white p-3 rounded-2xl shadow-sm border border-gray-100">
                      <div className="flex justify-between items-center mb-2">
                        <div>
                          <p className="text-xs font-black text-gray-800">{session.date}</p>
                          <div className="flex gap-2 mt-1">
                            {session.sessionCost ? <span className="text-[8px] bg-red-50 text-red-600 px-1 py-0.5 rounded font-bold">当日场地费: ¥{session.sessionCost}</span> : null}
                            <span className="text-[8px] bg-emerald-50 text-emerald-600 px-1 py-0.5 rounded font-bold">收入: ¥{session.attendees.reduce((s, a) => s + a.fee, 0)}</span>
                          </div>
                        </div>
                        <div className="flex gap-1">
                          <button type="button" onClick={(e) => handleEditSession(e, period.id, session)} className="text-gray-300 p-1"><Icons.Pencil /></button>
                          <button type="button" onClick={(e) => { e.stopPropagation(); if (confirm('确定删除?')) setPeriods(prev => prev.map(p => p.id === period.id ? { ...p, sessions: p.sessions.filter(s => s.id !== session.id) } : p)); }} className="text-gray-300 p-1"><Icons.Trash /></button>
                        </div>
                      </div>
                      <div className="flex flex-wrap gap-1">
                        {session.attendees.map(a => (
                          <span key={a.playerId} className="text-[8px] bg-gray-50 text-gray-400 px-1.5 py-0.5 rounded border border-gray-100">
                            {players.find(pl => pl.id === a.playerId)?.name} (¥{a.fee})
                          </span>
                        ))}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default PeriodsList;

import React, { useState, useMemo } from 'react';
import DatePicker from 'react-datepicker';
import { Period, Player, Session, PlayerType } from '../types';
import { Icons, DEFAULT_SESSION_FEE } from '../constants';

interface PeriodsListProps {
  periods: Period[];
  setPeriods: React.Dispatch<React.SetStateAction<Period[]>>;
  players: Player[];
  setPlayers: React.Dispatch<React.SetStateAction<Player[]>>;
}

const PeriodsList: React.FC<PeriodsListProps> = ({ periods, setPeriods, players, setPlayers }) => {
  const [isAddingPeriod, setIsAddingPeriod] = useState(false);
  const [editingPeriodId, setEditingPeriodId] = useState<string | null>(null);
  const [expandedPeriodId, setExpandedPeriodId] = useState<string | null>(null);
  const [activeSessionPeriod, setActiveSessionPeriod] = useState<string | null>(null);
  const [editingSessionId, setEditingSessionId] = useState<string | null>(null);
  const [deletingPeriod, setDeletingPeriod] = useState<Period | null>(null);

  const [sortBy, setSortBy] = useState<'date' | 'name'>('date');
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('desc');

  const funderPool = players.filter(p => p.isFunder);

  const initialPeriodData = {
    name: '',
    startDate: new Date().toISOString().split('T')[0],
    endDate: '',
    courtCost: 0,
    funderIds: funderPool.map(p => p.id),
    sessions: []
  };

  const [periodFormData, setPeriodFormData] = useState<Partial<Period>>(initialPeriodData);
  const [sessionFormDate, setSessionFormDate] = useState(new Date().toISOString().split('T')[0]);
  const [sessionFormCost, setSessionFormCost] = useState<number>(0);
  const [selectedAttendees, setSelectedAttendees] = useState<{playerId: string, fee: number}[]>([]);

  const sortedPeriods = useMemo(() => {
    return [...periods].sort((a, b) => {
      let comparison = 0;
      if (sortBy === 'date') {
        comparison = a.startDate.localeCompare(b.startDate);
      } else {
        comparison = a.name.localeCompare(b.name, 'zh-CN');
      }
      return sortOrder === 'asc' ? comparison : -comparison;
    });
  }, [periods, sortBy, sortOrder]);

  const stringToDate = (str: string | undefined) => {
    if (!str) return null;
    return new Date(str);
  };

  const dateToString = (date: Date | null) => {
    if (!date) return '';
    return date.toISOString().split('T')[0];
  };

  const handleSavePeriod = () => {
    if (!periodFormData.name) {
      alert('请输入周期名称');
      return;
    }

    const finalFunderIds = periodFormData.funderIds || [];

    setPlayers(prevPlayers => prevPlayers.map(p => {
      if (finalFunderIds.includes(p.id)) {
        return { ...p, type: PlayerType.MONTHLY, isFunder: true, defaultFee: 0 };
      }
      if (p.isFunder) {
        return { ...p, type: PlayerType.PER_SESSION, isFunder: true, defaultFee: DEFAULT_SESSION_FEE };
      }
      return p;
    }));

    if (editingPeriodId) {
      setPeriods(prev => prev.map(p => p.id === editingPeriodId ? { ...p, ...periodFormData } as Period : p));
      setEditingPeriodId(null);
    } else {
      const period: Period = {
        id: Date.now().toString(),
        name: periodFormData.name!,
        startDate: periodFormData.startDate!,
        endDate: periodFormData.endDate || '',
        courtCost: periodFormData.courtCost || 0,
        funderIds: finalFunderIds,
        sessions: []
      };
      setPeriods(prev => [...prev, period]);
      setIsAddingPeriod(false);
    }
    setPeriodFormData(initialPeriodData);
  };

  const handleOpenAddSession = (e: React.MouseEvent, periodId: string) => {
    e.stopPropagation();
    setActiveSessionPeriod(periodId);
    setEditingSessionId(null);
    setSessionFormDate(new Date().toISOString().split('T')[0]);
    setSessionFormCost(0);
    setSelectedAttendees([]);
  };

  const handleEditSession = (e: React.MouseEvent, periodId: string, session: Session) => {
    e.stopPropagation();
    setActiveSessionPeriod(periodId);
    setEditingSessionId(session.id);
    setSessionFormDate(session.date);
    setSessionFormCost(session.sessionCost || 0);
    setSelectedAttendees(session.attendees);
  };

  const saveSession = (periodId: string) => {
    if (selectedAttendees.length === 0) {
      alert('请至少选择一名出席成员');
      return;
    }
    if (editingSessionId) {
      setPeriods(prev => prev.map(p => p.id === periodId ? {
        ...p,
        sessions: p.sessions.map(s => s.id === editingSessionId ? { ...s, date: sessionFormDate, sessionCost: sessionFormCost, attendees: selectedAttendees } : s)
      } : p));
    } else {
      const session: Session = {
        id: Date.now().toString(),
        date: sessionFormDate,
        sessionCost: sessionFormCost,
        attendees: selectedAttendees
      };
      setPeriods(prev => prev.map(p => p.id === periodId ? { ...p, sessions: [...p.sessions, session] } : p));
    }
    setActiveSessionPeriod(null);
    setEditingSessionId(null);
  };

  const toggleAttendee = (player: Player, periodId: string) => {
    const exists = selectedAttendees.find(a => a.playerId === player.id);
    if (exists) {
      setSelectedAttendees(prev => prev.filter(a => a.playerId !== player.id));
    } else {
      const currentPeriod = periods.find(p => p.id === periodId);
      let defaultFee = player.defaultFee;
      if ((player.type === PlayerType.MONTHLY || player.type === PlayerType.HALF_MONTHLY) && currentPeriod) {
        const hasPaidInPeriod = currentPeriod.sessions.some(s => 
          s.id !== editingSessionId && 
          s.attendees.some(a => a.playerId === player.id && a.fee > 0)
        );
        if (hasPaidInPeriod) defaultFee = 0;
      }
      setSelectedAttendees(prev => [...prev, { playerId: player.id, fee: defaultFee }]);
    }
  };

  const confirmDeletePeriod = () => {
    if (!deletingPeriod) return;
    setPeriods(prev => prev.filter(p => p.id !== deletingPeriod.id));
    setDeletingPeriod(null);
  };

  return (
    <div className="p-4 pb-10">
      <div className="flex justify-between items-center mb-4">
        <h2 className="text-lg font-bold text-gray-800">结算周期管理</h2>
        <button type="button" onClick={() => { setIsAddingPeriod(true); setPeriodFormData(initialPeriodData); }} className="bg-emerald-600 text-white px-4 py-2.5 rounded-xl text-sm flex items-center gap-2 font-black shadow-lg shadow-emerald-200 active:scale-95 transition-all">
          <Icons.Plus /> 新增周期
        </button>
      </div>

      <div className="flex items-center gap-2 mb-6 px-1">
        <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">排序方式:</span>
        <select 
          value={sortBy} 
          onChange={(e) => setSortBy(e.target.value as 'date' | 'name')}
          className="text-[10px] bg-white border border-gray-200 rounded-lg px-2 py-1.5 font-bold text-gray-600 outline-none focus:ring-2 focus:ring-emerald-500/20"
        >
          <option value="date">按日期</option>
          <option value="name">按名称</option>
        </select>
        <button 
          onClick={() => setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc')}
          className="text-[10px] bg-white border border-gray-200 rounded-lg px-3 py-1.5 font-bold text-gray-600 active:bg-gray-50 flex items-center gap-1 shadow-sm"
        >
          {sortOrder === 'asc' ? '升序 ↑' : '降序 ↓'}
        </button>
      </div>

      {deletingPeriod && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-6 bg-black/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-sm rounded-3xl p-6 shadow-2xl">
            <h3 className="text-center font-black text-gray-900 text-lg mb-2">确认删除周期？</h3>
            <p className="text-center text-gray-500 text-xs mb-6 px-4">删除后将清除该周期内所有记录。</p>
            <div className="flex flex-col gap-3">
              <button onClick={confirmDeletePeriod} className="w-full bg-red-500 text-white py-3 rounded-xl font-black text-sm">确认删除</button>
              <button onClick={() => setDeletingPeriod(null)} className="w-full bg-gray-100 text-gray-500 py-3 rounded-xl font-bold text-sm">取消</button>
            </div>
          </div>
        </div>
      )}

      {/* 新增/编辑周期的全屏遮罩层表单 - 修复移动端显示问题 */}
      {(isAddingPeriod || editingPeriodId) && (
        <div className="fixed inset-0 z-[110] bg-gray-50 w-full min-h-screen overflow-y-auto no-scrollbar animate-slide-up origin-bottom">
          <div className="w-full max-w-md mx-auto p-4 flex flex-col min-h-full">
            <div className="flex justify-between items-center mb-6 pt-2 sticky top-0 bg-gray-50 z-20 py-2">
              <h3 className="text-xl font-black text-emerald-900">{editingPeriodId ? '📝 编辑结算周期' : '🗓️ 创建新结算周期'}</h3>
              <button onClick={() => { setIsAddingPeriod(false); setEditingPeriodId(null); }} className="p-2 bg-white rounded-full shadow-sm text-gray-400 active:scale-90">
                 <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                 </svg>
              </button>
            </div>

            <div className="space-y-6 flex-1 pb-24">
              <div className="bg-white p-5 rounded-3xl shadow-sm border border-gray-100">
                <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-4">基本信息</p>
                <div className="space-y-4">
                  <div className="group">
                    <label className="block text-xs font-bold text-gray-500 mb-1 ml-1">周期名称</label>
                    <input type="text" placeholder="如：2024年10月集资" value={periodFormData.name} onChange={e => setPeriodFormData({...periodFormData, name: e.target.value})} className="w-full bg-gray-50 border-none rounded-2xl p-4 text-sm focus:ring-2 focus:ring-emerald-500 outline-none font-bold" />
                  </div>

                  <div className="grid grid-cols-2 gap-3">
                    <div>
                      <label className="block text-xs font-bold text-gray-500 mb-1 ml-1">开始日期</label>
                      <DatePicker
                        selected={stringToDate(periodFormData.startDate)}
                        onChange={(date) => setPeriodFormData({...periodFormData, startDate: dateToString(date)})}
                        dateFormat="yyyy-MM-dd"
                        className="w-full bg-gray-50 border-none rounded-2xl p-4 text-sm font-bold focus:outline-none focus:ring-2 focus:ring-emerald-500"
                      />
                    </div>
                    <div>
                      <label className="block text-xs font-bold text-gray-500 mb-1 ml-1">结束日期 (选填)</label>
                      <DatePicker
                        selected={stringToDate(periodFormData.endDate)}
                        onChange={(date) => setPeriodFormData({...periodFormData, endDate: dateToString(date)})}
                        dateFormat="yyyy-MM-dd"
                        className="w-full bg-gray-50 border-none rounded-2xl p-4 text-sm font-bold focus:outline-none focus:ring-2 focus:ring-emerald-500"
                        isClearable
                      />
                    </div>
                  </div>
                </div>
              </div>

              <div className="bg-white p-5 rounded-3xl shadow-sm border border-gray-100">
                <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-4">费用配置</p>
                <div className="relative">
                  <label className="block text-xs font-bold text-gray-500 mb-2 ml-1">预估本期总场地费</label>
                  <div className="relative flex items-center">
                    <span className="absolute left-4 text-gray-400 font-bold">¥</span>
                    <input type="number" placeholder="0.00" value={periodFormData.courtCost || ''} onChange={e => setPeriodFormData({...periodFormData, courtCost: Number(e.target.value)})} className="w-full bg-red-50 border-none rounded-2xl p-4 pl-10 text-2xl font-black text-red-600 outline-none placeholder:text-red-200" />
                  </div>
                </div>
              </div>

              <div className="bg-amber-50 p-5 rounded-3xl border border-amber-100">
                <p className="text-[10px] font-black text-amber-800 uppercase tracking-widest mb-4">👑 确认本期集资人 ({periodFormData.funderIds?.length || 0})</p>
                <div className="grid grid-cols-3 gap-2">
                  {funderPool.map(f => {
                    const isSelected = periodFormData.funderIds?.includes(f.id);
                    return (
                      <button 
                        key={f.id} 
                        type="button" 
                        onClick={() => {
                          const current = periodFormData.funderIds || [];
                          setPeriodFormData({...periodFormData, funderIds: current.includes(f.id) ? current.filter(id => id !== f.id) : [...current, f.id]});
                        }} 
                        className={`text-xs py-3 rounded-2xl border-2 transition-all font-black flex flex-col items-center justify-center gap-1 ${
                          isSelected ? 'bg-amber-500 border-amber-600 text-white shadow-md' : 'bg-white border-white text-amber-200'
                        }`}
                      >
                        <span className="text-lg">{isSelected ? '⭐️' : '👤'}</span>
                        {f.name}
                      </button>
                    )
                  })}
                </div>
              </div>
            </div>

            <div className="fixed bottom-0 left-0 right-0 max-w-md mx-auto bg-gray-50/90 backdrop-blur-md pt-4 pb-8 flex gap-3 px-4 border-t border-gray-100 z-30">
              <button type="button" onClick={handleSavePeriod} className="flex-2 bg-emerald-600 text-white py-4 rounded-2xl font-black text-base shadow-xl active:scale-95 transition-all">
                确认发布周期
              </button>
              <button type="button" onClick={() => { setIsAddingPeriod(false); setEditingPeriodId(null); }} className="flex-1 bg-white border border-gray-200 text-gray-400 py-4 rounded-2xl font-black text-sm">
                取消
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="space-y-4">
        {sortedPeriods.map(period => (
          <div key={period.id} className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
            <div className={`p-4 flex justify-between items-center cursor-pointer ${expandedPeriodId === period.id ? 'bg-emerald-50/30' : ''}`} onClick={() => setExpandedPeriodId(expandedPeriodId === period.id ? null : period.id)}>
              <div className="flex-1">
                <h3 className="font-black text-gray-800 text-base">{period.name}</h3>
                <p className="text-[10px] text-gray-400 font-medium">{period.startDate} ~ {period.endDate || '进行中'}</p>
                <div className="mt-2 flex gap-1 flex-wrap">
                  {period.funderIds.map(fid => (
                    <span key={fid} className="text-[9px] bg-amber-100 text-amber-700 px-1.5 py-0.5 rounded font-bold">
                      {players.find(p => p.id === fid)?.name || '?'}
                    </span>
                  ))}
                </div>
              </div>
              <div className="text-right flex items-center gap-4">
                <div>
                  <p className="text-[10px] text-gray-400 font-bold">场次</p>
                  <p className="font-black text-emerald-600">{period.sessions.length}</p>
                </div>
                <div className="flex flex-col gap-1">
                  <button type="button" onClick={(e) => { e.stopPropagation(); setEditingPeriodId(period.id); setPeriodFormData(period); }} className="text-emerald-700 text-[10px] font-black p-1 bg-emerald-100/50 rounded">编辑</button>
                  <button type="button" onClick={(e) => { e.stopPropagation(); setDeletingPeriod(period); }} className="text-red-400 p-1"><Icons.Trash /></button>
                </div>
              </div>
            </div>

            {expandedPeriodId === period.id && (
              <div className="border-t border-gray-100 bg-gray-50/50 p-4 space-y-4">
                <div className="flex justify-between items-center">
                  <h4 className="text-xs font-black text-gray-500 uppercase tracking-widest">📋 活动明细</h4>
                  <button type="button" onClick={(e) => handleOpenAddSession(e, period.id)} className="text-[10px] bg-emerald-600 text-white px-4 py-2 rounded-full font-black shadow-md">
                    + 录入打球
                  </button>
                </div>

                {activeSessionPeriod === period.id && (
                  <div className="bg-white p-4 rounded-2xl border-2 border-emerald-500 shadow-xl">
                    <p className="text-xs font-black text-emerald-800 mb-4 uppercase tracking-widest">{editingSessionId ? '✏️ 编辑场次' : '✨ 录入场次'}</p>
                    <div className="space-y-4">
                      <div>
                        <label className="block text-[10px] font-bold text-gray-400 mb-1">日期</label>
                        <DatePicker
                          selected={stringToDate(sessionFormDate)}
                          onChange={(date) => setSessionFormDate(dateToString(date))}
                          dateFormat="yyyy-MM-dd"
                          className="w-full border border-gray-200 rounded-xl p-2 text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500"
                        />
                      </div>
                      <div className="bg-red-50 p-3 rounded-xl border border-red-100">
                        <label className="block text-[10px] font-black text-red-800 mb-1 flex justify-between italic">
                          <span>当日额外场地费</span>
                        </label>
                        <input type="number" value={sessionFormCost || ''} onChange={e => setSessionFormCost(Number(e.target.value))} className="w-full border-none bg-transparent font-mono text-red-600 font-black text-sm focus:ring-0 p-0" placeholder="0.00" />
                      </div>
                      <div>
                        <p className="text-[10px] font-bold text-gray-400 mb-2">出席人员:</p>
                        <div className="flex flex-wrap gap-1.5 max-h-40 overflow-y-auto p-2 border border-gray-100 rounded-xl bg-gray-50">
                          {players.map(p => {
                            const isSelected = selectedAttendees.find(a => a.playerId === p.id);
                            return (
                              <button key={p.id} type="button" onClick={() => toggleAttendee(p, period.id)} className={`text-[10px] px-2.5 py-1.5 rounded-lg border font-bold ${isSelected ? 'bg-emerald-600 border-emerald-700 text-white' : 'bg-white border-gray-200 text-gray-400'}`}>
                                {p.name}
                              </button>
                            );
                          })}
                        </div>
                      </div>
                      {selectedAttendees.length > 0 && (
                        <div className="space-y-2">
                          <p className="text-[10px] font-bold text-gray-400">收费核对:</p>
                          {selectedAttendees.map(a => (
                            <div key={a.playerId} className="flex justify-between items-center bg-gray-50 p-2 rounded-xl text-xs">
                              <span className="font-bold text-gray-700">{players.find(p => p.id === a.playerId)?.name}</span>
                              <div className="flex items-center gap-1 bg-white border border-gray-200 rounded px-2">
                                <span className="text-[10px] text-gray-400">¥</span>
                                <input type="number" value={a.fee} onChange={e => {
                                  const val = Number(e.target.value);
                                  setSelectedAttendees(prev => prev.map(sa => sa.playerId === a.playerId ? {...sa, fee: val} : sa));
                                }} className="w-12 py-1 text-center font-black text-emerald-600 focus:outline-none" />
                              </div>
                            </div>
                          ))}
                        </div>
                      )}
                      <div className="flex gap-3">
                        <button type="button" onClick={() => saveSession(period.id)} className="flex-2 bg-emerald-600 text-white py-3 rounded-xl font-black text-sm">保存</button>
                        <button type="button" onClick={() => setActiveSessionPeriod(null)} className="flex-1 bg-gray-100 text-gray-500 py-3 rounded-xl font-bold text-sm">取消</button>
                      </div>
                    </div>
                  </div>
                )}

                <div className="space-y-3">
                  {period.sessions.map(session => (
                    <div key={session.id} className="bg-white p-3 rounded-2xl shadow-sm border border-gray-100">
                      <div className="flex justify-between items-center mb-2">
                        <div>
                          <p className="text-xs font-black text-gray-800">{session.date}</p>
                        </div>
                        <div className="flex gap-1">
                          <button type="button" onClick={(e) => handleEditSession(e, period.id, session)} className="text-gray-300 p-1"><Icons.Pencil /></button>
                          <button type="button" onClick={(e) => { e.stopPropagation(); if (confirm('确定删除?')) setPeriods(prev => prev.map(p => p.id === period.id ? { ...p, sessions: p.sessions.filter(s => s.id !== session.id) } : p)); }} className="text-gray-300 p-1"><Icons.Trash /></button>
                        </div>
                      </div>
                      <div className="flex flex-wrap gap-1">
                        {session.attendees.map(a => (
                          <span key={a.playerId} className="text-[8px] bg-gray-50 text-gray-400 px-1.5 py-0.5 rounded border border-gray-100">
                            {players.find(pl => pl.id === a.playerId)?.name} (¥{a.fee})
                          </span>
                        ))}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default PeriodsList;

import React, { useState, useMemo } from 'react';
import DatePicker from 'react-datepicker';
import { Period, Player, Session, PlayerType } from '../types';
import { Icons, DEFAULT_SESSION_FEE } from '../constants';

interface PeriodsListProps {
  periods: Period[];
  setPeriods: React.Dispatch<React.SetStateAction<Period[]>>;
  players: Player[];
  setPlayers: React.Dispatch<React.SetStateAction<Player[]>>;
}

const PeriodsList: React.FC<PeriodsListProps> = ({ periods, setPeriods, players, setPlayers }) => {
  const [isAddingPeriod, setIsAddingPeriod] = useState(false);
  const [editingPeriodId, setEditingPeriodId] = useState<string | null>(null);
  const [expandedPeriodId, setExpandedPeriodId] = useState<string | null>(null);
  const [activeSessionPeriod, setActiveSessionPeriod] = useState<string | null>(null);
  const [editingSessionId, setEditingSessionId] = useState<string | null>(null);
  const [deletingPeriod, setDeletingPeriod] = useState<Period | null>(null);

  const [sortBy, setSortBy] = useState<'date' | 'name'>('date');
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('desc');

  const funderPool = players.filter(p => p.isFunder);

  const initialPeriodData = {
    name: '',
    startDate: new Date().toISOString().split('T')[0],
    endDate: '',
    courtCost: 0,
    funderIds: funderPool.map(p => p.id),
    sessions: []
  };

  const [periodFormData, setPeriodFormData] = useState<Partial<Period>>(initialPeriodData);
  const [sessionFormDate, setSessionFormDate] = useState(new Date().toISOString().split('T')[0]);
  const [sessionFormCost, setSessionFormCost] = useState<number>(0);
  const [selectedAttendees, setSelectedAttendees] = useState<{playerId: string, fee: number}[]>([]);

  const sortedPeriods = useMemo(() => {
    return [...periods].sort((a, b) => {
      let comparison = 0;
      if (sortBy === 'date') {
        comparison = a.startDate.localeCompare(b.startDate);
      } else {
        comparison = a.name.localeCompare(b.name, 'zh-CN');
      }
      return sortOrder === 'asc' ? comparison : -comparison;
    });
  }, [periods, sortBy, sortOrder]);

  const stringToDate = (str: string | undefined) => {
    if (!str) return null;
    return new Date(str);
  };

  const dateToString = (date: Date | null) => {
    if (!date) return '';
    return date.toISOString().split('T')[0];
  };

  const handleSavePeriod = () => {
    if (!periodFormData.name) {
      alert('请输入周期名称');
      return;
    }

    const finalFunderIds = periodFormData.funderIds || [];

    setPlayers(prevPlayers => prevPlayers.map(p => {
      if (finalFunderIds.includes(p.id)) {
        return { ...p, type: PlayerType.MONTHLY, isFunder: true, defaultFee: 0 };
      }
      if (p.isFunder) {
        return { ...p, type: PlayerType.PER_SESSION, isFunder: true, defaultFee: DEFAULT_SESSION_FEE };
      }
      return p;
    }));

    if (editingPeriodId) {
      setPeriods(prev => prev.map(p => p.id === editingPeriodId ? { ...p, ...periodFormData } as Period : p));
      setEditingPeriodId(null);
    } else {
      const period: Period = {
        id: Date.now().toString(),
        name: periodFormData.name!,
        startDate: periodFormData.startDate!,
        endDate: periodFormData.endDate || '',
        courtCost: periodFormData.courtCost || 0,
        funderIds: finalFunderIds,
        sessions: []
      };
      setPeriods(prev => [...prev, period]);
      setIsAddingPeriod(false);
    }
    setPeriodFormData(initialPeriodData);
  };

  const handleOpenAddSession = (e: React.MouseEvent, periodId: string) => {
    e.stopPropagation();
    setActiveSessionPeriod(periodId);
    setEditingSessionId(null);
    setSessionFormDate(new Date().toISOString().split('T')[0]);
    setSessionFormCost(0);
    setSelectedAttendees([]);
  };

  const handleEditSession = (e: React.MouseEvent, periodId: string, session: Session) => {
    e.stopPropagation();
    setActiveSessionPeriod(periodId);
    setEditingSessionId(session.id);
    setSessionFormDate(session.date);
    setSessionFormCost(session.sessionCost || 0);
    setSelectedAttendees(session.attendees);
  };

  const saveSession = (periodId: string) => {
    if (selectedAttendees.length === 0) {
      alert('请至少选择一名出席成员');
      return;
    }
    if (editingSessionId) {
      setPeriods(prev => prev.map(p => p.id === periodId ? {
        ...p,
        sessions: p.sessions.map(s => s.id === editingSessionId ? { ...s, date: sessionFormDate, sessionCost: sessionFormCost, attendees: selectedAttendees } : s)
      } : p));
    } else {
      const session: Session = {
        id: Date.now().toString(),
        date: sessionFormDate,
        sessionCost: sessionFormCost,
        attendees: selectedAttendees
      };
      setPeriods(prev => prev.map(p => p.id === periodId ? { ...p, sessions: [...p.sessions, session] } : p));
    }
    setActiveSessionPeriod(null);
    setEditingSessionId(null);
  };

  const toggleAttendee = (player: Player, periodId: string) => {
    const exists = selectedAttendees.find(a => a.playerId === player.id);
    if (exists) {
      setSelectedAttendees(prev => prev.filter(a => a.playerId !== player.id));
    } else {
      const currentPeriod = periods.find(p => p.id === periodId);
      let defaultFee = player.defaultFee;
      if ((player.type === PlayerType.MONTHLY || player.type === PlayerType.HALF_MONTHLY) && currentPeriod) {
        const hasPaidInPeriod = currentPeriod.sessions.some(s => 
          s.id !== editingSessionId && 
          s.attendees.some(a => a.playerId === player.id && a.fee > 0)
        );
        if (hasPaidInPeriod) defaultFee = 0;
      }
      setSelectedAttendees(prev => [...prev, { playerId: player.id, fee: defaultFee }]);
    }
  };

  const confirmDeletePeriod = () => {
    if (!deletingPeriod) return;
    setPeriods(prev => prev.filter(p => p.id !== deletingPeriod.id));
    setDeletingPeriod(null);
  };

  return (
    <div className="p-4 pb-10">
      <div className="flex justify-between items-center mb-4">
        <h2 className="text-lg font-bold text-gray-800">结算周期管理</h2>
        <button 
          type="button" 
          onClick={() => { setIsAddingPeriod(true); setPeriodFormData(initialPeriodData); }} 
          className="bg-emerald-600 text-white px-4 py-2.5 rounded-xl text-sm flex items-center gap-2 font-black shadow-lg shadow-emerald-200 active:scale-95 transition-all"
        >
          <Icons.Plus /> 新增周期
        </button>
      </div>

      <div className="flex items-center gap-2 mb-6 px-1">
        <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">排序方式:</span>
        <select 
          value={sortBy} 
          onChange={(e) => setSortBy(e.target.value as 'date' | 'name')}
          className="text-[10px] bg-white border border-gray-200 rounded-lg px-2 py-1.5 font-bold text-gray-600 outline-none focus:ring-2 focus:ring-emerald-500/20"
        >
          <option value="date">按日期</option>
          <option value="name">按名称</option>
        </select>
        <button 
          onClick={() => setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc')}
          className="text-[10px] bg-white border border-gray-200 rounded-lg px-3 py-1.5 font-bold text-gray-600 active:bg-gray-50 flex items-center gap-1 shadow-sm"
        >
          {sortOrder === 'asc' ? '升序 ↑' : '降序 ↓'}
        </button>
      </div>

      {deletingPeriod && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 bg-black/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-sm rounded-3xl p-6 shadow-2xl">
            <h3 className="text-center font-black text-gray-900 text-lg mb-2">确认删除周期？</h3>
            <p className="text-center text-gray-500 text-xs mb-6 px-4">删除后将清除该周期内所有记录。</p>
            <div className="flex flex-col gap-3">
              <button onClick={confirmDeletePeriod} className="w-full bg-red-500 text-white py-3 rounded-xl font-black text-sm">确认删除</button>
              <button onClick={() => setDeletingPeriod(null)} className="w-full bg-gray-100 text-gray-500 py-3 rounded-xl font-bold text-sm">取消</button>
            </div>
          </div>
        </div>
      )}

      {/* 新增/编辑周期的全屏遮罩层表单 - 强化移动端兼容性 */}
      {(isAddingPeriod || editingPeriodId) && (
        <div 
          className="fixed top-0 left-0 right-0 bottom-0 z-[999] bg-gray-50 w-full h-dvh overflow-y-auto no-scrollbar animate-slide-up shadow-2xl"
          style={{ overscrollBehavior: 'contain' }}
        >
          <div className="w-full max-w-md mx-auto p-4 flex flex-col min-h-full pb-safe">
            <div className="flex justify-between items-center mb-6 pt-4 sticky top-0 bg-gray-50 z-20 py-2 pt-safe">
              <h3 className="text-xl font-black text-emerald-900">{editingPeriodId ? '📝 编辑结算周期' : '🗓️ 创建新结算周期'}</h3>
              <button 
                onClick={() => { setIsAddingPeriod(false); setEditingPeriodId(null); }} 
                className="p-3 bg-white rounded-full shadow-sm text-gray-400 active:bg-gray-100 transition-colors"
              >
                 <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.3} d="M6 18L18 6M6 6l12 12" />
                 </svg>
              </button>
            </div>

            <div className="space-y-6 flex-1 pb-32">
              <div className="bg-white p-5 rounded-3xl shadow-sm border border-gray-100">
                <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-4">基本信息</p>
                <div className="space-y-4">
                  <div>
                    <label className="block text-xs font-bold text-gray-500 mb-1 ml-1">周期名称</label>
                    <input 
                      type="text" 
                      placeholder="如：2024年10月集资" 
                      value={periodFormData.name} 
                      onChange={e => setPeriodFormData({...periodFormData, name: e.target.value})} 
                      className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm focus:ring-2 focus:ring-emerald-500 outline-none font-bold placeholder:text-gray-300" 
                    />
                  </div>

                  <div className="grid grid-cols-2 gap-3">
                    <div>
                      <label className="block text-xs font-bold text-gray-500 mb-1 ml-1">开始日期</label>
                      <DatePicker
                        selected={stringToDate(periodFormData.startDate)}
                        onChange={(date) => setPeriodFormData({...periodFormData, startDate: dateToString(date)})}
                        dateFormat="yyyy-MM-dd"
                        className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold focus:outline-none focus:ring-2 focus:ring-emerald-500"
                      />
                    </div>
                    <div>
                      <label className="block text-xs font-bold text-gray-500 mb-1 ml-1">结束日期 (选填)</label>
                      <DatePicker
                        selected={stringToDate(periodFormData.endDate)}
                        onChange={(date) => setPeriodFormData({...periodFormData, endDate: dateToString(date)})}
                        dateFormat="yyyy-MM-dd"
                        className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold focus:outline-none focus:ring-2 focus:ring-emerald-500"
                        isClearable
                      />
                    </div>
                  </div>
                </div>
              </div>

              <div className="bg-white p-5 rounded-3xl shadow-sm border border-gray-100">
                <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-4">费用配置</p>
                <div className="relative">
                  <label className="block text-xs font-bold text-gray-500 mb-2 ml-1">预估本期总场地费</label>
                  <div className="relative flex items-center">
                    <span className="absolute left-4 text-gray-400 font-bold">¥</span>
                    <input 
                      type="number" 
                      placeholder="0.00" 
                      value={periodFormData.courtCost || ''} 
                      onChange={e => setPeriodFormData({...periodFormData, courtCost: Number(e.target.value)})} 
                      className="w-full bg-red-50/50 border border-red-100 rounded-2xl p-4 pl-10 text-2xl font-black text-red-600 outline-none placeholder:text-red-200" 
                    />
                  </div>
                </div>
              </div>

              <div className="bg-amber-50 p-5 rounded-3xl border border-amber-100">
                <p className="text-[10px] font-black text-amber-800 uppercase tracking-widest mb-4">👑 确认本期集资人 ({periodFormData.funderIds?.length || 0})</p>
                <div className="grid grid-cols-3 gap-2">
                  {funderPool.map(f => {
                    const isSelected = periodFormData.funderIds?.includes(f.id);
                    return (
                      <button 
                        key={f.id} 
                        type="button" 
                        onClick={() => {
                          const current = periodFormData.funderIds || [];
                          setPeriodFormData({...periodFormData, funderIds: current.includes(f.id) ? current.filter(id => id !== f.id) : [...current, f.id]});
                        }} 
                        className={`text-xs py-3 rounded-2xl border-2 transition-all font-black flex flex-col items-center justify-center gap-1 ${
                          isSelected ? 'bg-amber-500 border-amber-600 text-white shadow-md' : 'bg-white border-white text-amber-200'
                        }`}
                      >
                        <span className="text-lg">{isSelected ? '⭐️' : '👤'}</span>
                        {f.name}
                      </button>
                    )
                  })}
                </div>
              </div>
            </div>

            <div className="fixed bottom-0 left-0 right-0 max-w-md mx-auto bg-white/90 backdrop-blur-lg pt-4 pb-10 flex gap-3 px-4 border-t border-gray-100 z-[1000] pb-safe">
              <button 
                type="button" 
                onClick={handleSavePeriod} 
                className="flex-2 bg-emerald-600 text-white py-4 rounded-2xl font-black text-base shadow-xl active:scale-95 transition-all w-full"
              >
                发布周期
              </button>
              <button 
                type="button" 
                onClick={() => { setIsAddingPeriod(false); setEditingPeriodId(null); }} 
                className="flex-1 bg-gray-100 text-gray-500 py-4 rounded-2xl font-black text-sm active:bg-gray-200"
              >
                取消
              </button>
            </div>
          </div>
        </div>
      )}

      {/* 周期列表展示 */}
      <div className="space-y-4">
        {sortedPeriods.map(period => (
          <div key={period.id} className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
            <div 
              className={`p-4 flex justify-between items-center cursor-pointer active:bg-emerald-50/20 transition-colors ${expandedPeriodId === period.id ? 'bg-emerald-50/30 border-b border-gray-50' : ''}`} 
              onClick={() => setExpandedPeriodId(expandedPeriodId === period.id ? null : period.id)}
            >
              <div className="flex-1">
                <h3 className="font-black text-gray-800 text-base">{period.name}</h3>
                <p className="text-[10px] text-gray-400 font-medium">{period.startDate} ~ {period.endDate || '进行中'}</p>
                <div className="mt-2 flex gap-1 flex-wrap">
                  {period.funderIds.map(fid => (
                    <span key={fid} className="text-[9px] bg-amber-100 text-amber-700 px-1.5 py-0.5 rounded font-bold">
                      {players.find(p => p.id === fid)?.name || '?'}
                    </span>
                  ))}
                </div>
              </div>
              <div className="text-right flex items-center gap-4">
                <div>
                  <p className="text-[10px] text-gray-400 font-bold">场次</p>
                  <p className="font-black text-emerald-600">{period.sessions.length}</p>
                </div>
                <div className="flex flex-col gap-1">
                  <button type="button" onClick={(e) => { e.stopPropagation(); setEditingPeriodId(period.id); setPeriodFormData(period); }} className="text-emerald-700 text-[10px] font-black p-1 bg-emerald-100/50 rounded active:bg-emerald-200">编辑</button>
                  <button type="button" onClick={(e) => { e.stopPropagation(); setDeletingPeriod(period); }} className="text-red-400 p-1 active:scale-90 transition-transform"><Icons.Trash /></button>
                </div>
              </div>
            </div>

            {expandedPeriodId === period.id && (
              <div className="bg-gray-50/50 p-4 space-y-4 border-t border-gray-100/50">
                <div className="flex justify-between items-center">
                  <h4 className="text-xs font-black text-gray-500 uppercase tracking-widest">📋 活动明细</h4>
                  <button 
                    type="button" 
                    onClick={(e) => handleOpenAddSession(e, period.id)} 
                    className="text-[10px] bg-emerald-600 text-white px-4 py-2 rounded-full font-black shadow-md active:bg-emerald-700 transition-colors"
                  >
                    + 录入打球
                  </button>
                </div>

                {activeSessionPeriod === period.id && (
                  <div className="bg-white p-4 rounded-2xl border-2 border-emerald-500 shadow-xl">
                    <p className="text-xs font-black text-emerald-800 mb-4 uppercase tracking-widest">{editingSessionId ? '✏️ 编辑场次' : '✨ 录入场次'}</p>
                    <div className="space-y-4">
                      <div>
                        <label className="block text-[10px] font-bold text-gray-400 mb-1">日期</label>
                        <DatePicker
                          selected={stringToDate(sessionFormDate)}
                          onChange={(date) => setSessionFormDate(dateToString(date))}
                          dateFormat="yyyy-MM-dd"
                          className="w-full border border-gray-200 rounded-xl p-2 text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500"
                        />
                      </div>
                      <div className="bg-red-50 p-3 rounded-xl border border-red-100">
                        <label className="block text-[10px] font-black text-red-800 mb-1 flex justify-between italic">
                          <span>当日额外场地费</span>
                        </label>
                        <input type="number" value={sessionFormCost || ''} onChange={e => setSessionFormCost(Number(e.target.value))} className="w-full border-none bg-transparent font-mono text-red-600 font-black text-sm focus:ring-0 p-0" placeholder="0.00" />
                      </div>
                      <div>
                        <p className="text-[10px] font-bold text-gray-400 mb-2">出席人员:</p>
                        <div className="flex flex-wrap gap-1.5 max-h-40 overflow-y-auto p-2 border border-gray-100 rounded-xl bg-gray-50">
                          {players.map(p => {
                            const isSelected = selectedAttendees.find(a => a.playerId === p.id);
                            return (
                              <button key={p.id} type="button" onClick={() => toggleAttendee(p, period.id)} className={`text-[10px] px-2.5 py-1.5 rounded-lg border font-bold transition-all ${isSelected ? 'bg-emerald-600 border-emerald-700 text-white' : 'bg-white border-gray-200 text-gray-400'}`}>
                                {p.name}
                              </button>
                            );
                          })}
                        </div>
                      </div>
                      {selectedAttendees.length > 0 && (
                        <div className="space-y-2">
                          <p className="text-[10px] font-bold text-gray-400">收费核对:</p>
                          {selectedAttendees.map(a => (
                            <div key={a.playerId} className="flex justify-between items-center bg-gray-50 p-2 rounded-xl text-xs">
                              <span className="font-bold text-gray-700">{players.find(p => p.id === a.playerId)?.name}</span>
                              <div className="flex items-center gap-1 bg-white border border-gray-200 rounded px-2">
                                <span className="text-[10px] text-gray-400">¥</span>
                                <input type="number" value={a.fee} onChange={e => {
                                  const val = Number(e.target.value);
                                  setSelectedAttendees(prev => prev.map(sa => sa.playerId === a.playerId ? {...sa, fee: val} : sa));
                                }} className="w-12 py-1 text-center font-black text-emerald-600 focus:outline-none" />
                              </div>
                            </div>
                          ))}
                        </div>
                      )}
                      <div className="flex gap-3">
                        <button type="button" onClick={() => saveSession(period.id)} className="flex-2 bg-emerald-600 text-white py-3 rounded-xl font-black text-sm">保存</button>
                        <button type="button" onClick={() => setActiveSessionPeriod(null)} className="flex-1 bg-gray-100 text-gray-500 py-3 rounded-xl font-bold text-sm">取消</button>
                      </div>
                    </div>
                  </div>
                )}

                <div className="space-y-3">
                  {period.sessions.map(session => (
                    <div key={session.id} className="bg-white p-3 rounded-2xl shadow-sm border border-gray-100">
                      <div className="flex justify-between items-center mb-2">
                        <div>
                          <p className="text-xs font-black text-gray-800">{session.date}</p>
                        </div>
                        <div className="flex gap-1">
                          <button type="button" onClick={(e) => handleEditSession(e, period.id, session)} className="text-gray-300 p-1 active:scale-90"><Icons.Pencil /></button>
                          <button type="button" onClick={(e) => { e.stopPropagation(); if (confirm('确定删除?')) setPeriods(prev => prev.map(p => p.id === period.id ? { ...p, sessions: p.sessions.filter(s => s.id !== session.id) } : p)); }} className="text-gray-300 p-1 active:scale-90"><Icons.Trash /></button>
                        </div>
                      </div>
                      <div className="flex flex-wrap gap-1">
                        {session.attendees.map(a => (
                          <span key={a.playerId} className="text-[8px] bg-gray-50 text-gray-400 px-1.5 py-0.5 rounded border border-gray-100">
                            {players.find(pl => pl.id === a.playerId)?.name} (¥{a.fee})
                          </span>
                        ))}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default PeriodsList;

import React, { useState, useMemo } from 'react';
import DatePicker from 'react-datepicker';
import { Period, Player, Session, PlayerType } from '../types';
import { Icons, DEFAULT_SESSION_FEE } from '../constants';

interface PeriodsListProps {
  periods: Period[];
  setPeriods: React.Dispatch<React.SetStateAction<Period[]>>;
  players: Player[];
  setPlayers: React.Dispatch<React.SetStateAction<Player[]>>;
}

const PeriodsList: React.FC<PeriodsListProps> = ({ periods, setPeriods, players, setPlayers }) => {
  const [isAddingPeriod, setIsAddingPeriod] = useState(false);
  const [editingPeriodId, setEditingPeriodId] = useState<string | null>(null);
  const [expandedPeriodId, setExpandedPeriodId] = useState<string | null>(null);
  const [activeSessionPeriod, setActiveSessionPeriod] = useState<string | null>(null);
  const [editingSessionId, setEditingSessionId] = useState<string | null>(null);
  const [deletingPeriod, setDeletingPeriod] = useState<Period | null>(null);

  const [sortBy, setSortBy] = useState<'date' | 'name'>('date');
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('desc');

  const funderPool = players.filter(p => p.isFunder);

  const initialPeriodData = {
    name: '',
    startDate: new Date().toISOString().split('T')[0],
    endDate: '',
    courtCost: 0,
    funderIds: funderPool.map(p => p.id),
    sessions: []
  };

  const [periodFormData, setPeriodFormData] = useState<Partial<Period>>(initialPeriodData);
  const [sessionFormDate, setSessionFormDate] = useState(new Date().toISOString().split('T')[0]);
  const [sessionFormCost, setSessionFormCost] = useState<number>(0);
  const [selectedAttendees, setSelectedAttendees] = useState<{playerId: string, fee: number}[]>([]);

  const sortedPeriods = useMemo(() => {
    return [...periods].sort((a, b) => {
      let comparison = 0;
      if (sortBy === 'date') {
        comparison = a.startDate.localeCompare(b.startDate);
      } else {
        comparison = a.name.localeCompare(b.name, 'zh-CN');
      }
      return sortOrder === 'asc' ? comparison : -comparison;
    });
  }, [periods, sortBy, sortOrder]);

  const stringToDate = (str: string | undefined) => {
    if (!str) return null;
    return new Date(str);
  };

  const dateToString = (date: Date | null) => {
    if (!date) return '';
    return date.toISOString().split('T')[0];
  };

  const handleSavePeriod = () => {
    if (!periodFormData.name) {
      alert('请输入周期名称');
      return;
    }

    const finalFunderIds = periodFormData.funderIds || [];

    setPlayers(prevPlayers => prevPlayers.map(p => {
      if (finalFunderIds.includes(p.id)) {
        return { ...p, type: PlayerType.MONTHLY, isFunder: true, defaultFee: 0 };
      }
      if (p.isFunder) {
        return { ...p, type: PlayerType.PER_SESSION, isFunder: true, defaultFee: DEFAULT_SESSION_FEE };
      }
      return p;
    }));

    if (editingPeriodId) {
      setPeriods(prev => prev.map(p => p.id === editingPeriodId ? { ...p, ...periodFormData } as Period : p));
      setEditingPeriodId(null);
    } else {
      const period: Period = {
        id: Date.now().toString(),
        name: periodFormData.name!,
        startDate: periodFormData.startDate!,
        endDate: periodFormData.endDate || '',
        courtCost: periodFormData.courtCost || 0,
        funderIds: finalFunderIds,
        sessions: []
      };
      setPeriods(prev => [...prev, period]);
      setIsAddingPeriod(false);
    }
    setPeriodFormData(initialPeriodData);
  };

  const handleOpenAddSession = (e: React.MouseEvent, periodId: string) => {
    e.stopPropagation();
    setActiveSessionPeriod(periodId);
    setEditingSessionId(null);
    setSessionFormDate(new Date().toISOString().split('T')[0]);
    setSessionFormCost(0);
    setSelectedAttendees([]);
  };

  const handleEditSession = (e: React.MouseEvent, periodId: string, session: Session) => {
    e.stopPropagation();
    setActiveSessionPeriod(periodId);
    setEditingSessionId(session.id);
    setSessionFormDate(session.date);
    setSessionFormCost(session.sessionCost || 0);
    setSelectedAttendees(session.attendees);
  };

  const saveSession = (periodId: string) => {
    if (selectedAttendees.length === 0) {
      alert('请至少选择一名出席成员');
      return;
    }
    if (editingSessionId) {
      setPeriods(prev => prev.map(p => p.id === periodId ? {
        ...p,
        sessions: p.sessions.map(s => s.id === editingSessionId ? { ...s, date: sessionFormDate, sessionCost: sessionFormCost, attendees: selectedAttendees } : s)
      } : p));
    } else {
      const session: Session = {
        id: Date.now().toString(),
        date: sessionFormDate,
        sessionCost: sessionFormCost,
        attendees: selectedAttendees
      };
      setPeriods(prev => prev.map(p => p.id === periodId ? { ...p, sessions: [...p.sessions, session] } : p));
    }
    setActiveSessionPeriod(null);
    setEditingSessionId(null);
  };

  const toggleAttendee = (player: Player, periodId: string) => {
    const exists = selectedAttendees.find(a => a.playerId === player.id);
    if (exists) {
      setSelectedAttendees(prev => prev.filter(a => a.playerId !== player.id));
    } else {
      const currentPeriod = periods.find(p => p.id === periodId);
      let defaultFee = player.defaultFee;
      if ((player.type === PlayerType.MONTHLY || player.type === PlayerType.HALF_MONTHLY) && currentPeriod) {
        const hasPaidInPeriod = currentPeriod.sessions.some(s => 
          s.id !== editingSessionId && 
          s.attendees.some(a => a.playerId === player.id && a.fee > 0)
        );
        if (hasPaidInPeriod) defaultFee = 0;
      }
      setSelectedAttendees(prev => [...prev, { playerId: player.id, fee: defaultFee }]);
    }
  };

  const confirmDeletePeriod = () => {
    if (!deletingPeriod) return;
    setPeriods(prev => prev.filter(p => p.id !== deletingPeriod.id));
    setDeletingPeriod(null);
  };

  return (
    <div className="p-4 pb-10">
      <div className="flex justify-between items-center mb-4">
        <h2 className="text-lg font-bold text-gray-800">结算周期管理</h2>
        <button 
          type="button" 
          onClick={() => { setIsAddingPeriod(true); setPeriodFormData(initialPeriodData); }} 
          className="bg-emerald-600 text-white px-4 py-2.5 rounded-xl text-sm flex items-center gap-2 font-black shadow-lg shadow-emerald-200 active:scale-95 transition-all"
        >
          <Icons.Plus /> 新增周期
        </button>
      </div>

      <div className="flex items-center gap-2 mb-6 px-1">
        <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">排序方式:</span>
        <select 
          value={sortBy} 
          onChange={(e) => setSortBy(e.target.value as 'date' | 'name')}
          className="text-[10px] bg-white border border-gray-200 rounded-lg px-2 py-1.5 font-bold text-gray-600 outline-none focus:ring-2 focus:ring-emerald-500/20"
        >
          <option value="date">按日期</option>
          <option value="name">按名称</option>
        </select>
        <button 
          onClick={() => setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc')}
          className="text-[10px] bg-white border border-gray-200 rounded-lg px-3 py-1.5 font-bold text-gray-600 active:bg-gray-50 flex items-center gap-1 shadow-sm"
        >
          {sortOrder === 'asc' ? '升序 ↑' : '降序 ↓'}
        </button>
      </div>

      {deletingPeriod && (
        <div className="fixed inset-0 z-[1200] flex items-center justify-center p-6 bg-black/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-sm rounded-3xl p-6 shadow-2xl">
            <h3 className="text-center font-black text-gray-900 text-lg mb-2">确认删除周期？</h3>
            <p className="text-center text-gray-500 text-xs mb-6 px-4">删除后将清除该周期内所有记录。</p>
            <div className="flex flex-col gap-3">
              <button onClick={confirmDeletePeriod} className="w-full bg-red-500 text-white py-3 rounded-xl font-black text-sm">确认删除</button>
              <button onClick={() => setDeletingPeriod(null)} className="w-full bg-gray-100 text-gray-500 py-3 rounded-xl font-bold text-sm">取消</button>
            </div>
          </div>
        </div>
      )}

      {/* 周期表单全屏层 - 彻底重构兼容性 */}
      {(isAddingPeriod || editingPeriodId) && (
        <div className="mobile-overlay animate-modal-up flex flex-col overflow-hidden">
          <div className="w-full max-w-md mx-auto flex flex-col h-full bg-white relative">

            {/* 固定的 Header */}
            <div className="flex justify-between items-center p-4 pt-safe bg-white border-b border-gray-100 z-50">
              <h3 className="text-lg font-black text-emerald-900">{editingPeriodId ? '📝 编辑周期' : '🗓️ 新增周期'}</h3>
              <button 
                onClick={() => { setIsAddingPeriod(false); setEditingPeriodId(null); }} 
                className="p-2 bg-gray-50 rounded-full text-gray-400 active:bg-gray-200"
              >
                 <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                 </svg>
              </button>
            </div>

            {/* 可滚动的主体 */}
            <div className="flex-1 overflow-y-auto px-4 py-6 space-y-6 no-scrollbar pb-40">
              {/* 基础信息 */}
              <div className="bg-gray-50 p-5 rounded-3xl border border-gray-100">
                <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-4">基本信息</p>
                <div className="space-y-4">
                  <div>
                    <label className="block text-xs font-bold text-gray-500 mb-1 ml-1">周期名称</label>
                    <input 
                      type="text" 
                      placeholder="例如：2024年11月包月" 
                      value={periodFormData.name} 
                      onChange={e => setPeriodFormData({...periodFormData, name: e.target.value})} 
                      className="w-full bg-white border border-gray-200 rounded-2xl p-4 text-sm font-bold focus:ring-2 focus:ring-emerald-500 outline-none" 
                    />
                  </div>
                  <div className="grid grid-cols-2 gap-3">
                    <div>
                      <label className="block text-xs font-bold text-gray-500 mb-1 ml-1">开始日期</label>
                      <DatePicker
                        selected={stringToDate(periodFormData.startDate)}
                        onChange={(date) => setPeriodFormData({...periodFormData, startDate: dateToString(date)})}
                        dateFormat="yyyy-MM-dd"
                        className="w-full bg-white border border-gray-200 rounded-2xl p-4 text-sm font-bold outline-none"
                      />
                    </div>
                    <div>
                      <label className="block text-xs font-bold text-gray-500 mb-1 ml-1">结束日期</label>
                      <DatePicker
                        selected={stringToDate(periodFormData.endDate)}
                        onChange={(date) => setPeriodFormData({...periodFormData, endDate: dateToString(date)})}
                        dateFormat="yyyy-MM-dd"
                        placeholderText="选填"
                        className="w-full bg-white border border-gray-200 rounded-2xl p-4 text-sm font-bold outline-none"
                        isClearable
                      />
                    </div>
                  </div>
                </div>
              </div>

              {/* 成本 */}
              <div className="bg-white p-5 rounded-3xl border-2 border-red-50 shadow-sm">
                <p className="text-[10px] font-black text-red-800 uppercase tracking-widest mb-4">费用配置</p>
                <div className="relative">
                  <label className="block text-xs font-bold text-gray-500 mb-2 ml-1">本周期预付总场地费</label>
                  <div className="relative flex items-center">
                    <span className="absolute left-4 text-gray-400 font-bold">¥</span>
                    <input 
                      type="number" 
                      placeholder="0.00" 
                      value={periodFormData.courtCost || ''} 
                      onChange={e => setPeriodFormData({...periodFormData, courtCost: Number(e.target.value)})} 
                      className="w-full bg-red-50/50 border border-red-100 rounded-2xl p-4 pl-10 text-2xl font-black text-red-600 outline-none" 
                    />
                  </div>
                </div>
              </div>

              {/* 集资人选择 */}
              <div className="bg-amber-50 p-5 rounded-3xl border border-amber-100">
                <p className="text-[10px] font-black text-amber-800 uppercase tracking-widest mb-4">👑 确认本期集资包月人员 ({periodFormData.funderIds?.length || 0})</p>
                <div className="grid grid-cols-3 gap-2">
                  {funderPool.map(f => {
                    const isSelected = periodFormData.funderIds?.includes(f.id);
                    return (
                      <button 
                        key={f.id} 
                        type="button" 
                        onClick={() => {
                          const current = periodFormData.funderIds || [];
                          setPeriodFormData({...periodFormData, funderIds: current.includes(f.id) ? current.filter(id => id !== f.id) : [...current, f.id]});
                        }} 
                        className={`text-xs py-3 rounded-2xl border-2 transition-all font-black flex flex-col items-center justify-center gap-1 ${
                          isSelected ? 'bg-amber-500 border-amber-600 text-white shadow-md' : 'bg-white border-white text-amber-200'
                        }`}
                      >
                        <span className="text-lg">{isSelected ? '⭐️' : '👤'}</span>
                        {f.name}
                      </button>
                    )
                  })}
                </div>
              </div>
            </div>

            {/* 固定的 Footer */}
            <div className="absolute bottom-0 left-0 right-0 bg-white/90 backdrop-blur-md pt-4 pb-10 flex gap-3 px-4 border-t border-gray-100 z-50 pb-safe">
              <button 
                type="button" 
                onClick={handleSavePeriod} 
                className="flex-[2] bg-emerald-600 text-white py-4 rounded-2xl font-black text-base shadow-xl active:scale-95 transition-all"
              >
                发布并启用周期
              </button>
              <button 
                type="button" 
                onClick={() => { setIsAddingPeriod(false); setEditingPeriodId(null); }} 
                className="flex-1 bg-gray-100 text-gray-500 py-4 rounded-2xl font-black text-sm active:bg-gray-200"
              >
                取消
              </button>
            </div>
          </div>
        </div>
      )}

      {/* 周期列表 */}
      <div className="space-y-4">
        {sortedPeriods.map(period => (
          <div key={period.id} className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
            <div 
              className={`p-4 flex justify-between items-center cursor-pointer active:bg-emerald-50/20 transition-colors ${expandedPeriodId === period.id ? 'bg-emerald-50/30 border-b border-gray-50' : ''}`} 
              onClick={() => setExpandedPeriodId(expandedPeriodId === period.id ? null : period.id)}
            >
              <div className="flex-1">
                <h3 className="font-black text-gray-800 text-base">{period.name}</h3>
                <p className="text-[10px] text-gray-400 font-medium">{period.startDate} ~ {period.endDate || '进行中'}</p>
                <div className="mt-2 flex gap-1 flex-wrap">
                  {period.funderIds.map(fid => (
                    <span key={fid} className="text-[9px] bg-amber-100 text-amber-700 px-1.5 py-0.5 rounded font-bold">
                      {players.find(p => p.id === fid)?.name || '?'}
                    </span>
                  ))}
                </div>
              </div>
              <div className="text-right flex items-center gap-4">
                <div>
                  <p className="text-[10px] text-gray-400 font-bold">场次</p>
                  <p className="font-black text-emerald-600">{period.sessions.length}</p>
                </div>
                <div className="flex flex-col gap-1">
                  <button type="button" onClick={(e) => { e.stopPropagation(); setEditingPeriodId(period.id); setPeriodFormData(period); }} className="text-emerald-700 text-[10px] font-black p-1 bg-emerald-100/50 rounded active:bg-emerald-200">编辑</button>
                  <button type="button" onClick={(e) => { e.stopPropagation(); setDeletingPeriod(period); }} className="text-red-400 p-1 active:scale-90 transition-transform"><Icons.Trash /></button>
                </div>
              </div>
            </div>

            {expandedPeriodId === period.id && (
              <div className="bg-gray-50/50 p-4 space-y-4 border-t border-gray-100/50">
                <div className="flex justify-between items-center">
                  <h4 className="text-xs font-black text-gray-500 uppercase tracking-widest">📋 活动明细</h4>
                  <button 
                    type="button" 
                    onClick={(e) => handleOpenAddSession(e, period.id)} 
                    className="text-[10px] bg-emerald-600 text-white px-4 py-2 rounded-full font-black shadow-md active:bg-emerald-700 transition-colors"
                  >
                    + 录入打球
                  </button>
                </div>

                {activeSessionPeriod === period.id && (
                  <div className="bg-white p-4 rounded-2xl border-2 border-emerald-500 shadow-xl">
                    <p className="text-xs font-black text-emerald-800 mb-4 uppercase tracking-widest">{editingSessionId ? '✏️ 编辑场次' : '✨ 录入场次'}</p>
                    <div className="space-y-4">
                      <div>
                        <label className="block text-[10px] font-bold text-gray-400 mb-1">日期</label>
                        <DatePicker
                          selected={stringToDate(sessionFormDate)}
                          onChange={(date) => setSessionFormDate(dateToString(date))}
                          dateFormat="yyyy-MM-dd"
                          className="w-full border border-gray-200 rounded-xl p-2 text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500"
                        />
                      </div>
                      <div className="bg-red-50 p-3 rounded-xl border border-red-100">
                        <label className="block text-[10px] font-black text-red-800 mb-1">当日场地费</label>
                        <input type="number" value={sessionFormCost || ''} onChange={e => setSessionFormCost(Number(e.target.value))} className="w-full border-none bg-transparent font-mono text-red-600 font-black text-sm focus:ring-0 p-0" placeholder="0.00" />
                      </div>
                      <div>
                        <p className="text-[10px] font-bold text-gray-400 mb-2">出席人员:</p>
                        <div className="flex flex-wrap gap-1.5 max-h-40 overflow-y-auto p-2 border border-gray-100 rounded-xl bg-gray-50">
                          {players.map(p => {
                            const isSelected = selectedAttendees.find(a => a.playerId === p.id);
                            return (
                              <button key={p.id} type="button" onClick={() => toggleAttendee(p, period.id)} className={`text-[10px] px-2.5 py-1.5 rounded-lg border font-bold transition-all ${isSelected ? 'bg-emerald-600 border-emerald-700 text-white' : 'bg-white border-gray-200 text-gray-400'}`}>
                                {p.name}
                              </button>
                            );
                          })}
                        </div>
                      </div>
                      <div className="flex gap-3 pt-2">
                        <button type="button" onClick={() => saveSession(period.id)} className="flex-2 bg-emerald-600 text-white py-3 rounded-xl font-black text-sm">保存</button>
                        <button type="button" onClick={() => setActiveSessionPeriod(null)} className="flex-1 bg-gray-100 text-gray-500 py-3 rounded-xl font-bold text-sm">取消</button>
                      </div>
                    </div>
                  </div>
                )}

                <div className="space-y-3">
                  {period.sessions.map(session => (
                    <div key={session.id} className="bg-white p-3 rounded-2xl shadow-sm border border-gray-100">
                      <div className="flex justify-between items-center mb-2">
                        <p className="text-xs font-black text-gray-800">{session.date}</p>
                        <div className="flex gap-1">
                          <button type="button" onClick={(e) => handleEditSession(e, period.id, session)} className="text-gray-300 p-1 active:scale-90"><Icons.Pencil /></button>
                          <button type="button" onClick={(e) => { e.stopPropagation(); if (confirm('确定删除?')) setPeriods(prev => prev.map(p => p.id === period.id ? { ...p, sessions: p.sessions.filter(s => s.id !== session.id) } : p)); }} className="text-gray-300 p-1 active:scale-90"><Icons.Trash /></button>
                        </div>
                      </div>
                      <div className="flex flex-wrap gap-1">
                        {session.attendees.map(a => (
                          <span key={a.playerId} className="text-[8px] bg-gray-50 text-gray-400 px-1.5 py-0.5 rounded border border-gray-100">
                            {players.find(pl => pl.id === a.playerId)?.name} (¥{a.fee})
                          </span>
                        ))}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

