import React, { useState, useMemo } from 'react';
import DatePicker from 'react-datepicker';
import { Period, Player, Session, PlayerType } from '../types';
import { Icons, DEFAULT_SESSION_FEE } from '../constants';

interface PeriodsListProps {
  periods: Period[];
  setPeriods: React.Dispatch<React.SetStateAction<Period[]>>;
  players: Player[];
  setPlayers: React.Dispatch<React.SetStateAction<Player[]>>;
}

const PeriodsList: React.FC<PeriodsListProps> = ({ periods, setPeriods, players, setPlayers }) => {
  const [isAddingPeriod, setIsAddingPeriod] = useState(false);
  const [editingPeriodId, setEditingPeriodId] = useState<string | null>(null);
  const [expandedPeriodId, setExpandedPeriodId] = useState<string | null>(null);
  const [activeSessionPeriod, setActiveSessionPeriod] = useState<string | null>(null);
  const [editingSessionId, setEditingSessionId] = useState<string | null>(null);
  const [deletingPeriod, setDeletingPeriod] = useState<Period | null>(null);

  const [sortBy, setSortBy] = useState<'date' | 'name'>('date');
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('desc');

  const funderPool = players.filter(p => p.isFunder);

  const initialPeriodData = {
    name: '',
    startDate: new Date().toISOString().split('T')[0],
    endDate: '',
    courtCost: 0,
    funderIds: funderPool.map(p => p.id),
    sessions: []
  };

  const [periodFormData, setPeriodFormData] = useState<Partial<Period>>(initialPeriodData);
  const [sessionFormDate, setSessionFormDate] = useState(new Date().toISOString().split('T')[0]);
  const [sessionFormCost, setSessionFormCost] = useState<number>(0);
  const [selectedAttendees, setSelectedAttendees] = useState<{playerId: string, fee: number}[]>([]);

  const sortedPeriods = useMemo(() => {
    return [...periods].sort((a, b) => {
      let comparison = 0;
      if (sortBy === 'date') {
        comparison = a.startDate.localeCompare(b.startDate);
      } else {
        comparison = a.name.localeCompare(b.name, 'zh-CN');
      }
      return sortOrder === 'asc' ? comparison : -comparison;
    });
  }, [periods, sortBy, sortOrder]);

  const stringToDate = (str: string | undefined) => {
    if (!str) return null;
    return new Date(str);
  };

  const dateToString = (date: Date | null) => {
    if (!date) return '';
    return date.toISOString().split('T')[0];
  };

  const handleSavePeriod = () => {
    if (!periodFormData.name) {
      alert('请输入周期名称');
      return;
    }

    const finalFunderIds = periodFormData.funderIds || [];

    setPlayers(prevPlayers => prevPlayers.map(p => {
      if (finalFunderIds.includes(p.id)) {
        return { ...p, type: PlayerType.MONTHLY, isFunder: true, defaultFee: 0 };
      }
      if (p.isFunder) {
        return { ...p, type: PlayerType.PER_SESSION, isFunder: true, defaultFee: DEFAULT_SESSION_FEE };
      }
      return p;
    }));

    if (editingPeriodId) {
      setPeriods(prev => prev.map(p => p.id === editingPeriodId ? { ...p, ...periodFormData } as Period : p));
      setEditingPeriodId(null);
    } else {
      const period: Period = {
        id: Date.now().toString(),
        name: periodFormData.name!,
        startDate: periodFormData.startDate!,
        endDate: periodFormData.endDate || '',
        courtCost: periodFormData.courtCost || 0,
        funderIds: finalFunderIds,
        sessions: []
      };
      setPeriods(prev => [...prev, period]);
      setIsAddingPeriod(false);
    }
    setPeriodFormData(initialPeriodData);
  };

  const renderPeriodForm = (title: string, onCancel: () => void) => (
    <div className="bg-white rounded-[2rem] border-2 border-emerald-500 p-5 shadow-xl animate-fade-in space-y-6 mb-6">
      <div className="flex justify-between items-center">
        <h3 className="text-base font-black text-emerald-900">{title}</h3>
        <button onClick={onCancel} className="text-gray-400 p-1"><Icons.Trash /></button>
      </div>

      <div className="space-y-4">
        {/* Basic Info */}
        <div className="space-y-3">
          <div>
            <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">周期名称</label>
            <input 
              type="text" 
              placeholder="例如：2024年11月集资" 
              value={periodFormData.name} 
              onChange={e => setPeriodFormData({...periodFormData, name: e.target.value})} 
              className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold focus:ring-2 focus:ring-emerald-500 outline-none" 
            />
          </div>
          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">开始日期</label>
              <DatePicker
                selected={stringToDate(periodFormData.startDate)}
                onChange={(date) => setPeriodFormData({...periodFormData, startDate: dateToString(date)})}
                dateFormat="yyyy-MM-dd"
                className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold outline-none"
              />
            </div>
            <div>
              <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">结束日期</label>
              <DatePicker
                selected={stringToDate(periodFormData.endDate)}
                onChange={(date) => setPeriodFormData({...periodFormData, endDate: dateToString(date)})}
                dateFormat="yyyy-MM-dd"
                placeholderText="选填"
                className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold outline-none"
                isClearable
              />
            </div>
          </div>
        </div>

        {/* Cost Estimation */}
        <div className="bg-red-50 p-4 rounded-2xl border border-red-100">
          <label className="block text-[10px] font-black text-red-800 uppercase tracking-widest mb-2 ml-1">本周期预付总额</label>
          <div className="relative flex items-center">
            <span className="absolute left-4 text-red-300 font-bold">¥</span>
            <input 
              type="number" 
              placeholder="0.00" 
              value={periodFormData.courtCost || ''} 
              onChange={e => setPeriodFormData({...periodFormData, courtCost: Number(e.target.value)})} 
              className="w-full bg-transparent border-none p-0 pl-8 text-2xl font-black text-red-600 outline-none focus:ring-0" 
            />
          </div>
        </div>

        {/* Funders Grid */}
        <div className="bg-amber-50 p-4 rounded-2xl border border-amber-100">
          <p className="text-[10px] font-black text-amber-800 uppercase tracking-widest mb-3">👑 确认本期集资包月人员 ({periodFormData.funderIds?.length || 0})</p>
          <div className="grid grid-cols-3 gap-2">
            {funderPool.length > 0 ? funderPool.map(f => {
              const isSelected = periodFormData.funderIds?.includes(f.id);
              return (
                <button 
                  key={f.id} 
                  type="button" 
                  onClick={() => {
                    const current = periodFormData.funderIds || [];
                    setPeriodFormData({...periodFormData, funderIds: current.includes(f.id) ? current.filter(id => id !== f.id) : [...current, f.id]});
                  }} 
                  className={`text-[10px] py-2 rounded-xl border transition-all font-black flex flex-col items-center justify-center gap-1 ${
                    isSelected ? 'bg-amber-500 border-amber-600 text-white shadow-md' : 'bg-white border-amber-100 text-amber-200'
                  }`}
                >
                  <span className="text-base">{isSelected ? '⭐️' : '👤'}</span>
                  {f.name}
                </button>
              )
            }) : (
              <p className="col-span-3 text-center text-[9px] text-amber-400 py-2">请先在“人员”页面设置备选</p>
            )}
          </div>
        </div>
      </div>

      <div className="flex gap-3">
        <button 
          onClick={handleSavePeriod} 
          className="flex-[2] bg-emerald-600 text-white py-3.5 rounded-2xl font-black text-sm shadow-lg active:scale-95"
        >
          保存周期
        </button>
        <button 
          onClick={onCancel} 
          className="flex-1 bg-gray-100 text-gray-400 py-3.5 rounded-2xl font-black text-sm"
        >
          取消
        </button>
      </div>
    </div>
  );

  const handleOpenAddSession = (e: React.MouseEvent, periodId: string) => {
    e.stopPropagation();
    setActiveSessionPeriod(periodId);
    setEditingSessionId(null);
    setSessionFormDate(new Date().toISOString().split('T')[0]);
    setSessionFormCost(0);
    setSelectedAttendees([]);
  };

  const handleEditSession = (e: React.MouseEvent, periodId: string, session: Session) => {
    e.stopPropagation();
    setActiveSessionPeriod(periodId);
    setEditingSessionId(session.id);
    setSessionFormDate(session.date);
    setSessionFormCost(session.sessionCost || 0);
    setSelectedAttendees(session.attendees);
  };

  const saveSession = (periodId: string) => {
    if (selectedAttendees.length === 0) {
      alert('请至少选择一名出席成员');
      return;
    }
    if (editingSessionId) {
      setPeriods(prev => prev.map(p => p.id === periodId ? {
        ...p,
        sessions: p.sessions.map(s => s.id === editingSessionId ? { ...s, date: sessionFormDate, sessionCost: sessionFormCost, attendees: selectedAttendees } : s)
      } : p));
    } else {
      const session: Session = {
        id: Date.now().toString(),
        date: sessionFormDate,
        sessionCost: sessionFormCost,
        attendees: selectedAttendees
      };
      setPeriods(prev => prev.map(p => {
        if (p.id === periodId) {
          // Sort sessions by date after adding
          const newSessions = [...p.sessions, session].sort((a, b) => b.date.localeCompare(a.date));
          return { ...p, sessions: newSessions };
        }
        return p;
      }));
    }
    setActiveSessionPeriod(null);
    setEditingSessionId(null);
  };

  const toggleAttendee = (player: Player, periodId: string) => {
    const exists = selectedAttendees.find(a => a.playerId === player.id);
    if (exists) {
      setSelectedAttendees(prev => prev.filter(a => a.playerId !== player.id));
    } else {
      const currentPeriod = periods.find(p => p.id === periodId);
      let defaultFee = player.defaultFee;
      if ((player.type === PlayerType.MONTHLY || player.type === PlayerType.HALF_MONTHLY) && currentPeriod) {
        const hasPaidInPeriod = currentPeriod.sessions.some(s => 
          s.id !== editingSessionId && 
          s.attendees.some(a => a.playerId === player.id && a.fee > 0)
        );
        if (hasPaidInPeriod) defaultFee = 0;
      }
      setSelectedAttendees(prev => [...prev, { playerId: player.id, fee: defaultFee }]);
    }
  };

  const confirmDeletePeriod = () => {
    if (!deletingPeriod) return;
    setPeriods(prev => prev.filter(p => p.id !== deletingPeriod.id));
    setDeletingPeriod(null);
  };

  return (
    <div className="p-4 pb-10">
      <div className="flex justify-between items-center mb-4">
        <h2 className="text-lg font-bold text-gray-800">结算周期管理</h2>
        <button 
          type="button" 
          onClick={() => { setIsAddingPeriod(true); setEditingPeriodId(null); setPeriodFormData(initialPeriodData); }} 
          className="bg-emerald-600 text-white px-4 py-2.5 rounded-xl text-sm flex items-center gap-2 font-black shadow-lg shadow-emerald-200 active:scale-95 transition-all"
        >
          <Icons.Plus /> 新增周期
        </button>
      </div>

      <div className="flex items-center gap-2 mb-6 px-1">
        <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">排序方式:</span>
        <select 
          value={sortBy} 
          onChange={(e) => setSortBy(e.target.value as 'date' | 'name')}
          className="text-[10px] bg-white border border-gray-200 rounded-lg px-2 py-1.5 font-bold text-gray-600 outline-none focus:ring-2 focus:ring-emerald-500/20"
        >
          <option value="date">按日期</option>
          <option value="name">按名称</option>
        </select>
        <button 
          onClick={() => setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc')}
          className="text-[10px] bg-white border border-gray-200 rounded-lg px-3 py-1.5 font-bold text-gray-600 active:bg-gray-50 flex items-center gap-1 shadow-sm"
        >
          {sortOrder === 'asc' ? '升序 ↑' : '降序 ↓'}
        </button>
      </div>

      {/* Delete Confirmation Overlay */}
      {deletingPeriod && (
        <div className="fixed inset-0 z-[2500] flex items-center justify-center p-6 bg-black/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-sm rounded-3xl p-6 shadow-2xl">
            <h3 className="text-center font-black text-gray-900 text-lg mb-2">确认删除周期？</h3>
            <p className="text-center text-gray-500 text-xs mb-6 px-4">删除后将清除该周期内所有记录。</p>
            <div className="flex flex-col gap-3">
              <button onClick={confirmDeletePeriod} className="w-full bg-red-500 text-white py-3 rounded-xl font-black text-sm">确认删除</button>
              <button onClick={() => setDeletingPeriod(null)} className="w-full bg-gray-100 text-gray-500 py-3 rounded-xl font-bold text-sm">取消</button>
            </div>
          </div>
        </div>
      )}

      {/* In-place ADD Form */}
      {isAddingPeriod && renderPeriodForm("🗓️ 新增结算周期", () => setIsAddingPeriod(false))}

      {/* List of Periods */}
      <div className="space-y-4">
        {sortedPeriods.map(period => {
          // In-place EDIT Form
          if (editingPeriodId === period.id) {
            return (
              <div key={period.id}>
                {renderPeriodForm("📝 编辑周期内容", () => setEditingPeriodId(null))}
              </div>
            );
          }

          return (
            <div key={period.id} className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
              <div 
                className={`p-4 flex justify-between items-center cursor-pointer active:bg-emerald-50/20 transition-colors ${expandedPeriodId === period.id ? 'bg-emerald-50/30 border-b border-gray-50' : ''}`} 
                onClick={() => setExpandedPeriodId(expandedPeriodId === period.id ? null : period.id)}
              >
                <div className="flex-1">
                  <h3 className="font-black text-gray-800 text-base">{period.name}</h3>
                  <p className="text-[10px] text-gray-400 font-medium">{period.startDate} ~ {period.endDate || '进行中'}</p>
                  <div className="mt-2 flex gap-1 flex-wrap">
                    {period.funderIds.map(fid => (
                      <span key={fid} className="text-[9px] bg-amber-100 text-amber-700 px-1.5 py-0.5 rounded font-bold">
                        {players.find(p => p.id === fid)?.name || '?'}
                      </span>
                    ))}
                  </div>
                </div>
                <div className="text-right flex items-center gap-4">
                  <div>
                    <p className="text-[10px] text-gray-400 font-bold">场次</p>
                    <p className="font-black text-emerald-600">{period.sessions.length}</p>
                  </div>
                  <div className="flex flex-col gap-1">
                    <button type="button" onClick={(e) => { e.stopPropagation(); setEditingPeriodId(period.id); setPeriodFormData(period); setIsAddingPeriod(false); }} className="text-emerald-700 text-[10px] font-black p-1 bg-emerald-100/50 rounded active:bg-emerald-200">编辑</button>
                    <button type="button" onClick={(e) => { e.stopPropagation(); setDeletingPeriod(period); }} className="text-red-400 p-1 active:scale-90 transition-transform"><Icons.Trash /></button>
                  </div>
                </div>
              </div>

              {expandedPeriodId === period.id && (
                <div className="bg-gray-50/50 p-4 space-y-4 border-t border-gray-100/50">
                  <div className="flex justify-between items-center">
                    <h4 className="text-xs font-black text-gray-500 uppercase tracking-widest">📋 活动明细</h4>
                    <button 
                      type="button" 
                      onClick={(e) => handleOpenAddSession(e, period.id)} 
                      className="text-[10px] bg-emerald-600 text-white px-4 py-2 rounded-full font-black shadow-md active:bg-emerald-700 transition-colors"
                    >
                      + 录入打球
                    </button>
                  </div>

                  {activeSessionPeriod === period.id && (
                    <div className="bg-white p-4 rounded-2xl border-2 border-emerald-500 shadow-xl">
                      <p className="text-xs font-black text-emerald-800 mb-4 uppercase tracking-widest">{editingSessionId ? '✏️ 编辑场次' : '✨ 录入场次'}</p>
                      <div className="space-y-4">
                        <div>
                          <label className="block text-[10px] font-bold text-gray-400 mb-1">日期</label>
                          <DatePicker
                            selected={stringToDate(sessionFormDate)}
                            onChange={(date) => setSessionFormDate(dateToString(date))}
                            dateFormat="yyyy-MM-dd"
                            className="w-full border border-gray-200 rounded-xl p-2 text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500"
                          />
                        </div>
                        <div className="bg-red-50 p-3 rounded-xl border border-red-100">
                          <label className="block text-[10px] font-black text-red-800 mb-1">当日场地费</label>
                          <input type="number" value={sessionFormCost || ''} onChange={e => setSessionFormCost(Number(e.target.value))} className="w-full border-none bg-transparent font-mono text-red-600 font-black text-sm focus:ring-0 p-0" placeholder="0.00" />
                        </div>
                        <div>
                          <p className="text-[10px] font-bold text-gray-400 mb-2">出席人员:</p>
                          <div className="flex flex-wrap gap-1.5 max-h-40 overflow-y-auto p-2 border border-gray-100 rounded-xl bg-gray-50">
                            {players.map(p => {
                              const isSelected = selectedAttendees.find(a => a.playerId === p.id);
                              return (
                                <button key={p.id} type="button" onClick={() => toggleAttendee(p, period.id)} className={`text-[10px] px-2.5 py-1.5 rounded-lg border font-bold transition-all ${isSelected ? 'bg-emerald-600 border-emerald-700 text-white' : 'bg-white border-gray-200 text-gray-400'}`}>
                                  {p.name}
                                </button>
                              );
                            })}
                          </div>
                        </div>
                        <div className="flex gap-3 pt-2">
                          <button type="button" onClick={() => saveSession(period.id)} className="flex-[2] bg-emerald-600 text-white py-3 rounded-xl font-black text-sm">保存</button>
                          <button type="button" onClick={() => setActiveSessionPeriod(null)} className="flex-1 bg-gray-100 text-gray-500 py-3 rounded-xl font-bold text-sm">取消</button>
                        </div>
                      </div>
                    </div>
                  )}

                  <div className="space-y-3">
                    {period.sessions.map(session => (
                      <div key={session.id} className="bg-white p-3 rounded-2xl shadow-sm border border-gray-100">
                        <div className="flex justify-between items-center mb-2">
                          <p className="text-xs font-black text-gray-800">{session.date}</p>
                          <div className="flex gap-1">
                            <button type="button" onClick={(e) => handleEditSession(e, period.id, session)} className="text-gray-300 p-1 active:scale-90"><Icons.Pencil /></button>
                            <button type="button" onClick={(e) => { e.stopPropagation(); if (confirm('确定删除?')) setPeriods(prev => prev.map(p => p.id === period.id ? { ...p, sessions: p.sessions.filter(s => s.id !== session.id) } : p)); }} className="text-gray-300 p-1 active:scale-90"><Icons.Trash /></button>
                          </div>
                        </div>
                        <div className="flex flex-wrap gap-1">
                          {session.attendees.map(a => (
                            <span key={a.playerId} className="text-[8px] bg-gray-50 text-gray-400 px-1.5 py-0.5 rounded border border-gray-100">
                              {players.find(pl => pl.id === a.playerId)?.name} (¥{a.fee})
                            </span>
                          ))}
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default PeriodsList;

import React, { useState, useMemo } from 'react';
import DatePicker from 'react-datepicker';
import { Period, Player, Session, PlayerType } from '../types';
import { Icons, DEFAULT_SESSION_FEE } from '../constants';

interface PeriodsListProps {
  periods: Period[];
  setPeriods: React.Dispatch<React.SetStateAction<Period[]>>;
  players: Player[];
  setPlayers: React.Dispatch<React.SetStateAction<Player[]>>;
}

const PeriodsList: React.FC<PeriodsListProps> = ({ periods, setPeriods, players, setPlayers }) => {
  const [isAddingPeriod, setIsAddingPeriod] = useState(false);
  const [editingPeriodId, setEditingPeriodId] = useState<string | null>(null);
  const [expandedPeriodId, setExpandedPeriodId] = useState<string | null>(null);
  const [activeSessionPeriod, setActiveSessionPeriod] = useState<string | null>(null);
  const [editingSessionId, setEditingSessionId] = useState<string | null>(null);
  const [deletingPeriod, setDeletingPeriod] = useState<Period | null>(null);

  const [sortBy, setSortBy] = useState<'date' | 'name'>('date');
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('desc');

  const funderPool = players.filter(p => p.isFunder);

  const initialPeriodData = {
    name: '',
    startDate: new Date().toISOString().split('T')[0],
    endDate: '',
    courtCost: 0,
    funderIds: funderPool.map(p => p.id),
    sessions: []
  };

  const [periodFormData, setPeriodFormData] = useState<Partial<Period>>(initialPeriodData);
  const [sessionFormDate, setSessionFormDate] = useState(new Date().toISOString().split('T')[0]);
  const [sessionFormCost, setSessionFormCost] = useState<number>(0);
  const [selectedAttendees, setSelectedAttendees] = useState<{playerId: string, fee: number}[]>([]);

  const sortedPeriods = useMemo(() => {
    return [...periods].sort((a, b) => {
      let comparison = 0;
      if (sortBy === 'date') {
        comparison = a.startDate.localeCompare(b.startDate);
      } else {
        comparison = a.name.localeCompare(b.name, 'zh-CN');
      }
      return sortOrder === 'asc' ? comparison : -comparison;
    });
  }, [periods, sortBy, sortOrder]);

  const stringToDate = (str: string | undefined) => {
    if (!str) return null;
    return new Date(str);
  };

  const dateToString = (date: Date | null) => {
    if (!date) return '';
    return date.toISOString().split('T')[0];
  };

  const handleSavePeriod = () => {
    if (!periodFormData.name) {
      alert('请输入周期名称');
      return;
    }

    const finalFunderIds = periodFormData.funderIds || [];

    setPlayers(prevPlayers => prevPlayers.map(p => {
      if (finalFunderIds.includes(p.id)) {
        return { ...p, type: PlayerType.MONTHLY, isFunder: true, defaultFee: 0 };
      }
      return p;
    }));

    if (editingPeriodId) {
      setPeriods(prev => prev.map(p => p.id === editingPeriodId ? { ...p, ...periodFormData } as Period : p));
      setEditingPeriodId(null);
    } else {
      const period: Period = {
        id: Date.now().toString(),
        name: periodFormData.name!,
        startDate: periodFormData.startDate!,
        endDate: periodFormData.endDate || '',
        courtCost: periodFormData.courtCost || 0,
        funderIds: finalFunderIds,
        sessions: []
      };
      setPeriods(prev => [period, ...prev]);
      setIsAddingPeriod(false);
    }
    setPeriodFormData(initialPeriodData);
  };

  const renderPeriodForm = (title: string, onCancel: () => void) => (
    <div className="bg-white rounded-3xl border-2 border-emerald-500 p-5 shadow-xl animate-fade-in space-y-5 mb-6">
      <div className="flex justify-between items-center">
        <h3 className="text-sm font-black text-emerald-900 flex items-center gap-2">
          <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
          {title}
        </h3>
        <button onClick={onCancel} className="text-gray-300 hover:text-gray-500 transition-colors"><Icons.Trash /></button>
      </div>

      <div className="space-y-4">
        <div>
          <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">周期名称</label>
          <input 
            type="text" 
            placeholder="例如：2025年3月集资" 
            value={periodFormData.name} 
            onChange={e => setPeriodFormData({...periodFormData, name: e.target.value})} 
            className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold focus:ring-2 focus:ring-emerald-500 outline-none transition-all" 
          />
        </div>

        <div className="grid grid-cols-2 gap-3">
          <div>
            <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">开始日期</label>
            <DatePicker
              selected={stringToDate(periodFormData.startDate)}
              onChange={(date) => setPeriodFormData({...periodFormData, startDate: dateToString(date)})}
              dateFormat="yyyy-MM-dd"
              className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold outline-none"
            />
          </div>
          <div>
            <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">结束日期 (选填)</label>
            <DatePicker
              selected={stringToDate(periodFormData.endDate)}
              onChange={(date) => setPeriodFormData({...periodFormData, endDate: dateToString(date)})}
              dateFormat="yyyy-MM-dd"
              placeholderText="进行中..."
              className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold outline-none"
              isClearable
            />
          </div>
        </div>

        <div className="bg-red-50 p-4 rounded-2xl border border-red-100">
          <label className="block text-[10px] font-black text-red-800 uppercase tracking-widest mb-1 ml-1">本周期预付场地费</label>
          <div className="relative flex items-center">
            <span className="absolute left-4 text-red-300 font-bold italic">¥</span>
            <input 
              type="number" 
              placeholder="0.00" 
              value={periodFormData.courtCost || ''} 
              onChange={e => setPeriodFormData({...periodFormData, courtCost: Number(e.target.value)})} 
              className="w-full bg-transparent border-none p-0 pl-8 text-2xl font-black text-red-600 outline-none focus:ring-0" 
            />
          </div>
        </div>

        <div className="bg-amber-50 p-4 rounded-2xl border border-amber-100">
          <p className="text-[10px] font-black text-amber-800 uppercase tracking-widest mb-3 flex justify-between items-center">
            <span>👑 确认集资名单</span>
            <span className="bg-amber-200 text-amber-800 px-2 py-0.5 rounded-full">{periodFormData.funderIds?.length || 0} 人</span>
          </p>
          <div className="grid grid-cols-3 gap-2">
            {funderPool.map(f => {
              const isSelected = periodFormData.funderIds?.includes(f.id);
              return (
                <button 
                  key={f.id} 
                  type="button" 
                  onClick={() => {
                    const current = periodFormData.funderIds || [];
                    setPeriodFormData({...periodFormData, funderIds: current.includes(f.id) ? current.filter(id => id !== f.id) : [...current, f.id]});
                  }} 
                  className={`text-[10px] py-2 rounded-xl border transition-all font-black ${
                    isSelected ? 'bg-amber-500 border-amber-600 text-white shadow-md scale-105' : 'bg-white border-amber-100 text-amber-200'
                  }`}
                >
                  {f.name}
                </button>
              )
            })}
          </div>
        </div>
      </div>

      <div className="flex gap-3 pt-2">
        <button 
          onClick={handleSavePeriod} 
          className="flex-[2] bg-emerald-600 text-white py-4 rounded-2xl font-black text-sm shadow-lg shadow-emerald-100 active:scale-95 transition-all"
        >
          保存设置
        </button>
        <button 
          onClick={onCancel} 
          className="flex-1 bg-gray-100 text-gray-400 py-4 rounded-2xl font-black text-sm active:bg-gray-200"
        >
          取消
        </button>
      </div>
    </div>
  );

  const handleOpenAddSession = (e: React.MouseEvent, periodId: string) => {
    e.stopPropagation();
    setActiveSessionPeriod(periodId);
    setEditingSessionId(null);
    setSessionFormDate(new Date().toISOString().split('T')[0]);
    setSessionFormCost(0);
    setSelectedAttendees([]);
  };

  const handleEditSession = (e: React.MouseEvent, periodId: string, session: Session) => {
    e.stopPropagation();
    setActiveSessionPeriod(periodId);
    setEditingSessionId(session.id);
    setSessionFormDate(session.date);
    setSessionFormCost(session.sessionCost || 0);
    setSelectedAttendees(session.attendees);
  };

  const saveSession = (periodId: string) => {
    if (selectedAttendees.length === 0) {
      alert('请至少选择一名出席成员');
      return;
    }
    if (editingSessionId) {
      setPeriods(prev => prev.map(p => p.id === periodId ? {
        ...p,
        sessions: p.sessions.map(s => s.id === editingSessionId ? { ...s, date: sessionFormDate, sessionCost: sessionFormCost, attendees: selectedAttendees } : s)
      } : p));
    } else {
      const session: Session = {
        id: Date.now().toString(),
        date: sessionFormDate,
        sessionCost: sessionFormCost,
        attendees: selectedAttendees
      };
      setPeriods(prev => prev.map(p => {
        if (p.id === periodId) {
          const newSessions = [session, ...p.sessions].sort((a, b) => b.date.localeCompare(a.date));
          return { ...p, sessions: newSessions };
        }
        return p;
      }));
    }
    setActiveSessionPeriod(null);
    setEditingSessionId(null);
  };

  const toggleAttendee = (player: Player, periodId: string) => {
    const exists = selectedAttendees.find(a => a.playerId === player.id);
    if (exists) {
      setSelectedAttendees(prev => prev.filter(a => a.playerId !== player.id));
    } else {
      const currentPeriod = periods.find(p => p.id === periodId);
      let defaultFee = player.defaultFee;
      if (player.type === PlayerType.MONTHLY && currentPeriod?.funderIds.includes(player.id)) {
        defaultFee = 0;
      }
      setSelectedAttendees(prev => [...prev, { playerId: player.id, fee: defaultFee }]);
    }
  };

  return (
    <div className="p-4 space-y-4 pb-24">
      <div className="flex justify-between items-center mb-2 px-1">
        <div>
          <h2 className="text-xl font-black text-gray-800">结算管理</h2>
          <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">Period & Sessions</p>
        </div>
        <button 
          onClick={() => { setIsAddingPeriod(true); setEditingPeriodId(null); setPeriodFormData(initialPeriodData); }} 
          className="bg-emerald-600 text-white px-5 py-3 rounded-2xl text-xs flex items-center gap-2 font-black shadow-xl shadow-emerald-100 active:scale-95 transition-all"
        >
          <Icons.Plus /> 新增周期
        </button>
      </div>

      {/* 内联新增表单 */}
      {isAddingPeriod && renderPeriodForm("创建新周期", () => setIsAddingPeriod(false))}

      {/* 排序切换 */}
      <div className="flex gap-2 px-1">
        <button 
          onClick={() => setSortBy(sortBy === 'date' ? 'name' : 'date')}
          className="text-[10px] font-black px-3 py-1.5 bg-white border border-gray-100 rounded-full shadow-sm text-gray-500 active:bg-gray-50 transition-all"
        >
          排序: {sortBy === 'date' ? '时间' : '名称'}
        </button>
        <button 
          onClick={() => setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc')}
          className="text-[10px] font-black px-3 py-1.5 bg-white border border-gray-100 rounded-full shadow-sm text-gray-500 active:bg-gray-50 transition-all"
        >
          {sortOrder === 'asc' ? '升序 ↑' : '降序 ↓'}
        </button>
      </div>

      {/* 周期列表 */}
      <div className="space-y-4">
        {sortedPeriods.map(period => {
          if (editingPeriodId === period.id) {
            return (
              <div key={period.id} className="animate-fade-in">
                {renderPeriodForm("修改周期配置", () => setEditingPeriodId(null))}
              </div>
            );
          }

          const isExpanded = expandedPeriodId === period.id;
          const totalIncome = period.sessions.reduce((acc, s) => acc + s.attendees.reduce((sum, a) => sum + a.fee, 0), 0);

          return (
            <div key={period.id} className={`bg-white rounded-[2rem] shadow-sm border border-gray-100 overflow-hidden transition-all ${isExpanded ? 'ring-2 ring-emerald-500/10 shadow-lg' : ''}`}>
              {/* 卡片头部 */}
              <div 
                onClick={() => setExpandedPeriodId(isExpanded ? null : period.id)}
                className={`p-5 flex justify-between items-center cursor-pointer active:bg-gray-50 transition-colors ${isExpanded ? 'bg-emerald-50/20' : ''}`}
              >
                <div className="flex-1">
                  <div className="flex items-center gap-2 mb-1">
                    <h3 className="font-black text-gray-800 text-base">{period.name}</h3>
                    {(!period.endDate) && (
                      <span className="text-[8px] bg-emerald-500 text-white px-1.5 py-0.5 rounded-full font-black animate-pulse uppercase tracking-tighter">进行中</span>
                    )}
                  </div>
                  <p className="text-[10px] text-gray-400 font-bold">{period.startDate} ~ {period.endDate || '至今'}</p>
                </div>
                <div className="text-right flex items-center gap-4">
                  <div className="hidden sm:block">
                    <p className="text-[9px] text-gray-400 font-black uppercase">记录</p>
                    <p className="font-black text-emerald-600">{period.sessions.length} 场</p>
                  </div>
                  <div className={`transition-transform duration-300 ${isExpanded ? 'rotate-180 text-emerald-500' : 'text-gray-300'}`}>
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M19 9l-7 7-7-7" /></svg>
                  </div>
                </div>
              </div>

              {/* 展开详情区域 */}
              {isExpanded && (
                <div className="p-5 bg-gray-50/30 border-t border-gray-50 space-y-6 animate-fade-in">

                  {/* 1. 核心数据网格 */}
                  <div className="grid grid-cols-2 gap-3">
                    <div className="bg-white p-4 rounded-2xl border border-gray-100">
                      <p className="text-[9px] font-black text-gray-400 uppercase mb-1">预付场地总额</p>
                      <p className="text-xl font-black text-red-500">¥{period.courtCost.toLocaleString()}</p>
                    </div>
                    <div className="bg-white p-4 rounded-2xl border border-gray-100">
                      <p className="text-[9px] font-black text-gray-400 uppercase mb-1">当前采集收入</p>
                      <p className="text-xl font-black text-emerald-600">¥{totalIncome.toLocaleString()}</p>
                    </div>
                  </div>

                  {/* 2. 集资人名单 */}
                  <div>
                    <div className="flex justify-between items-center mb-2 px-1">
                      <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">👑 参与集资人员 ({period.funderIds.length})</p>
                      <button onClick={(e) => { e.stopPropagation(); setEditingPeriodId(period.id); setPeriodFormData(period); }} className="text-[9px] text-emerald-600 font-black px-2 py-1 bg-emerald-50 rounded-lg">编辑名单</button>
                    </div>
                    <div className="flex flex-wrap gap-1.5 p-3 bg-white rounded-2xl border border-gray-100 shadow-sm">
                      {period.funderIds.length > 0 ? period.funderIds.map(fid => {
                        const p = players.find(pl => pl.id === fid);
                        return (
                          <span key={fid} className="text-[10px] bg-amber-50 text-amber-700 px-2.5 py-1 rounded-full font-black border border-amber-100">
                            {p?.name || '未知'}
                          </span>
                        );
                      }) : (
                        <p className="text-[10px] text-gray-300 italic">未选择集资人员</p>
                      )}
                    </div>
                  </div>

                  {/* 3. 打球记录操作台 */}
                  <div className="pt-2">
                    <div className="flex justify-between items-center mb-3">
                      <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">🏸 打球流水 ({period.sessions.length})</h4>
                      <button 
                        onClick={(e) => handleOpenAddSession(e, period.id)}
                        className="text-[10px] bg-gray-900 text-white px-4 py-2 rounded-xl font-black shadow-lg shadow-gray-200 active:scale-95 transition-all"
                      >
                        + 录入打球
                      </button>
                    </div>

                    {activeSessionPeriod === period.id && (
                      <div className="bg-white p-5 rounded-3xl border-2 border-emerald-500 shadow-2xl mb-4 space-y-4 animate-fade-in">
                        <div className="flex justify-between items-center">
                          <p className="text-xs font-black text-emerald-800">{editingSessionId ? '✏️ 修改场次' : '✨ 新增场次'}</p>
                          <button onClick={() => setActiveSessionPeriod(null)} className="text-gray-400"><Icons.Trash /></button>
                        </div>
                        <div className="space-y-4">
                          <div className="grid grid-cols-2 gap-3">
                             <div>
                                <label className="block text-[10px] font-black text-gray-400 mb-1">日期</label>
                                <DatePicker
                                  selected={stringToDate(sessionFormDate)}
                                  onChange={(date) => setSessionFormDate(dateToString(date))}
                                  dateFormat="yyyy-MM-dd"
                                  className="w-full bg-gray-50 border border-gray-100 rounded-xl p-3 text-sm font-bold outline-none"
                                />
                             </div>
                             <div>
                                <label className="block text-[10px] font-black text-gray-400 mb-1">当日场地费</label>
                                <input type="number" value={sessionFormCost || ''} onChange={e => setSessionFormCost(Number(e.target.value))} className="w-full bg-gray-50 border border-gray-100 rounded-xl p-3 text-sm font-bold outline-none text-red-500" placeholder="0.00" />
                             </div>
                          </div>
                          <div>
                            <p className="text-[10px] font-black text-gray-400 mb-2 uppercase">出席成员 (已选 {selectedAttendees.length} 人):</p>
                            <div className="flex flex-wrap gap-1.5 p-3 bg-gray-50 rounded-2xl border border-gray-100 max-h-40 overflow-y-auto">
                              {players.map(p => {
                                const isSelected = selectedAttendees.find(a => a.playerId === p.id);
                                return (
                                  <button key={p.id} onClick={() => toggleAttendee(p, period.id)} className={`text-[10px] px-3 py-2 rounded-xl font-black transition-all border ${isSelected ? 'bg-emerald-600 border-emerald-700 text-white shadow-md' : 'bg-white border-gray-100 text-gray-400'}`}>
                                    {p.name}
                                  </button>
                                );
                              })}
                            </div>
                          </div>
                          <div className="flex gap-3 pt-2">
                            <button onClick={() => saveSession(period.id)} className="flex-[2] bg-emerald-600 text-white py-3.5 rounded-2xl font-black text-sm active:scale-95 shadow-lg shadow-emerald-50">保存场次</button>
                            <button onClick={() => setActiveSessionPeriod(null)} className="flex-1 bg-gray-100 text-gray-400 py-3.5 rounded-2xl font-black text-sm">取消</button>
                          </div>
                        </div>
                      </div>
                    )}

                    <div className="space-y-3">
                      {period.sessions.length > 0 ? period.sessions.map(session => (
                        <div key={session.id} className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm group">
                          <div className="flex justify-between items-center mb-3">
                            <div className="flex items-center gap-2">
                               <span className="text-xs font-black text-gray-800">{session.date}</span>
                               {session.sessionCost ? <span className="text-[8px] bg-red-100 text-red-600 px-1.5 py-0.5 rounded font-bold">加支 ¥{session.sessionCost}</span> : null}
                            </div>
                            <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                              <button onClick={(e) => handleEditSession(e, period.id, session)} className="text-gray-300 p-1.5 hover:text-emerald-500 transition-colors"><Icons.Pencil /></button>
                              <button onClick={(e) => { e.stopPropagation(); if(confirm('删除此打球记录?')) setPeriods(prev => prev.map(p => p.id === period.id ? {...p, sessions: p.sessions.filter(s => s.id !== session.id)} : p)); }} className="text-gray-300 p-1.5 hover:text-red-500 transition-colors"><Icons.Trash /></button>
                            </div>
                          </div>
                          <div className="flex flex-wrap gap-1">
                            {session.attendees.map(a => (
                              <span key={a.playerId} className="text-[9px] bg-gray-50 text-gray-500 px-2 py-0.5 rounded border border-gray-100 font-medium">
                                {players.find(pl => pl.id === a.playerId)?.name} {a.fee > 0 ? `(¥${a.fee})` : ''}
                              </span>
                            ))}
                          </div>
                        </div>
                      )) : (
                        <div className="text-center py-10 bg-white rounded-3xl border border-dashed border-gray-100">
                          <p className="text-xs text-gray-300 font-bold uppercase tracking-widest">暂无记录，快去打球吧 🏸</p>
                        </div>
                      )}
                    </div>
                  </div>

                  {/* 4. 危险操作区 */}
                  <div className="pt-4 border-t border-gray-100 flex justify-center">
                    <button 
                      onClick={(e) => { e.stopPropagation(); if(confirm('核心警告：确定永久删除此周期及所有流水吗？')) setPeriods(prev => prev.filter(p => p.id !== period.id)); }}
                      className="text-[10px] text-red-300 font-bold hover:text-red-500 transition-colors flex items-center gap-1"
                    >
                      <Icons.Trash /> 永久移除此周期
                    </button>
                  </div>
                </div>
              )}
            </div>
          );
        })}

        {periods.length === 0 && !isAddingPeriod && (
          <div className="text-center py-24 bg-white rounded-[2rem] border-2 border-dashed border-gray-100">
            <p className="text-5xl mb-4 opacity-10">🏸</p>
            <p className="text-sm font-black text-gray-300 uppercase tracking-widest">尚未创建结算周期</p>
            <button onClick={() => setIsAddingPeriod(true)} className="mt-4 text-[10px] font-black text-emerald-600 bg-emerald-50 px-4 py-2 rounded-full">立即开启</button>
          </div>
        )}
      </div>
    </div>
  );
};

export default PeriodsList;

import React, { useState, useMemo, useEffect } from 'react';
import DatePicker from 'react-datepicker';
import { Period, Player, Session, PlayerType } from '../types';
import { Icons } from '../constants';

interface PeriodsListProps {
  periods: Period[];
  setPeriods: React.Dispatch<React.SetStateAction<Period[]>>;
  players: Player[];
  setPlayers: React.Dispatch<React.SetStateAction<Player[]>>;
}

const PeriodsList: React.FC<PeriodsListProps> = ({ periods, setPeriods, players, setPlayers }) => {
  const [isAddingPeriod, setIsAddingPeriod] = useState(false);
  const [editingPeriodId, setEditingPeriodId] = useState<string | null>(null);
  const [expandedPeriodId, setExpandedPeriodId] = useState<string | null>(null);
  const [activeSessionPeriod, setActiveSessionPeriod] = useState<string | null>(null);
  const [editingSessionId, setEditingSessionId] = useState<string | null>(null);

  const [sortBy, setSortBy] = useState<'date' | 'name'>('date');
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('desc');

  const funderPool = players.filter(p => p.isFunder);

  const initialPeriodData = {
    name: '',
    startDate: new Date().toISOString().split('T')[0],
    endDate: '',
    courtCost: 0,
    funderIds: funderPool.map(p => p.id),
    sessions: []
  };

  const [periodFormData, setPeriodFormData] = useState<Partial<Period>>(initialPeriodData);
  const [sessionFormDate, setSessionFormDate] = useState(new Date().toISOString().split('T')[0]);
  const [sessionFormCost, setSessionFormCost] = useState<number>(0);
  const [selectedAttendees, setSelectedAttendees] = useState<{playerId: string, fee: number}[]>([]);

  // 排序逻辑
  const sortedPeriods = useMemo(() => {
    return [...periods].sort((a, b) => {
      let comparison = 0;
      if (sortBy === 'date') {
        comparison = a.startDate.localeCompare(b.startDate);
      } else {
        comparison = a.name.localeCompare(b.name, 'zh-CN');
      }
      return sortOrder === 'asc' ? comparison : -comparison;
    });
  }, [periods, sortBy, sortOrder]);

  const stringToDate = (str: string | undefined) => {
    if (!str) return null;
    return new Date(str);
  };

  const dateToString = (date: Date | null) => {
    if (!date) return '';
    return date.toISOString().split('T')[0];
  };

  const handleSavePeriod = () => {
    if (!periodFormData.name) {
      alert('请输入周期名称');
      return;
    }

    const finalFunderIds = periodFormData.funderIds || [];

    // 更新球员类型为包月状态（如果被选中）
    setPlayers(prevPlayers => prevPlayers.map(p => {
      if (finalFunderIds.includes(p.id)) {
        return { ...p, type: PlayerType.MONTHLY };
      }
      return p;
    }));

    if (editingPeriodId) {
      setPeriods(prev => prev.map(p => p.id === editingPeriodId ? { ...p, ...periodFormData } as Period : p));
      setEditingPeriodId(null);
    } else {
      const period: Period = {
        id: Date.now().toString(),
        name: periodFormData.name!,
        startDate: periodFormData.startDate!,
        endDate: periodFormData.endDate || '',
        courtCost: periodFormData.courtCost || 0,
        funderIds: finalFunderIds,
        sessions: []
      };
      setPeriods(prev => [period, ...prev]);
      setIsAddingPeriod(false);
    }
    setPeriodFormData(initialPeriodData);
  };

  // 底部弹出表单渲染
  const renderPeriodDrawer = (title: string, onCancel: () => void) => (
    <div className="fixed inset-0 z-[100] flex items-end justify-center animate-fade-in bg-black/40 backdrop-blur-[2px]">
      <div 
        className="w-full max-w-md bg-white rounded-t-[2.5rem] shadow-2xl p-6 pb-safe animate-slide-up overflow-y-auto max-h-[90vh]"
        onClick={e => e.stopPropagation()}
      >
        {/* 顶部指示条 */}
        <div className="w-12 h-1.5 bg-gray-200 rounded-full mx-auto mb-6"></div>

        <div className="flex justify-between items-center mb-6">
          <h3 className="text-xl font-black text-gray-800">{title}</h3>
          <button onClick={onCancel} className="text-gray-300 p-2 active:bg-gray-100 rounded-full">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>

        <div className="space-y-5">
          <div>
            <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">周期名称</label>
            <input 
              type="text" 
              placeholder="例如：2025年3月集资" 
              value={periodFormData.name} 
              onChange={e => setPeriodFormData({...periodFormData, name: e.target.value})} 
              className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold focus:ring-2 focus:ring-emerald-500 outline-none" 
            />
          </div>

          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">开始日期</label>
              <DatePicker
                selected={stringToDate(periodFormData.startDate)}
                onChange={(date) => setPeriodFormData({...periodFormData, startDate: dateToString(date)})}
                dateFormat="yyyy-MM-dd"
                className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold outline-none"
              />
            </div>
            <div>
              <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">结束日期 (选填)</label>
              <DatePicker
                selected={stringToDate(periodFormData.endDate)}
                onChange={(date) => setPeriodFormData({...periodFormData, endDate: dateToString(date)})}
                dateFormat="yyyy-MM-dd"
                placeholderText="进行中..."
                className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold outline-none"
                isClearable
              />
            </div>
          </div>

          <div className="bg-red-50 p-4 rounded-2xl border border-red-100">
            <label className="block text-[10px] font-black text-red-800 uppercase tracking-widest mb-1 ml-1">本周期预付场地费</label>
            <div className="relative flex items-center">
              <span className="absolute left-4 text-red-300 font-bold italic">¥</span>
              <input 
                type="number" 
                placeholder="0.00" 
                value={periodFormData.courtCost || ''} 
                onChange={e => setPeriodFormData({...periodFormData, courtCost: Number(e.target.value)})} 
                className="w-full bg-transparent border-none p-0 pl-8 text-2xl font-black text-red-600 outline-none focus:ring-0" 
              />
            </div>
          </div>

          <div className="bg-amber-50 p-4 rounded-2xl border border-amber-100">
            <p className="text-[10px] font-black text-amber-800 uppercase tracking-widest mb-3 flex justify-between items-center">
              <span>👑 确认集资名单 ({periodFormData.funderIds?.length || 0})</span>
            </p>
            <div className="grid grid-cols-3 gap-2">
              {funderPool.map(f => {
                const isSelected = periodFormData.funderIds?.includes(f.id);
                return (
                  <button 
                    key={f.id} 
                    type="button" 
                    onClick={() => {
                      const current = periodFormData.funderIds || [];
                      setPeriodFormData({...periodFormData, funderIds: current.includes(f.id) ? current.filter(id => id !== f.id) : [...current, f.id]});
                    }} 
                    className={`text-[10px] py-2.5 rounded-xl border transition-all font-black ${
                      isSelected ? 'bg-amber-500 border-amber-600 text-white shadow-md' : 'bg-white border-amber-100 text-amber-200'
                    }`}
                  >
                    {f.name}
                  </button>
                )
              })}
            </div>
          </div>

          <div className="flex gap-3 pt-2">
            <button 
              onClick={handleSavePeriod} 
              className="flex-[2] bg-emerald-600 text-white py-4 rounded-2xl font-black text-base shadow-lg shadow-emerald-200 active:scale-95 transition-all"
            >
              保存周期配置
            </button>
            <button 
              onClick={onCancel} 
              className="flex-1 bg-gray-100 text-gray-500 py-4 rounded-2xl font-black text-sm active:bg-gray-200"
            >
              取消
            </button>
          </div>
        </div>
      </div>
    </div>
  );

  // 渲染打球场次表单（弹出式）
  const renderSessionForm = (periodId: string) => (
    <div className="fixed inset-0 z-[120] flex items-center justify-center p-6 animate-fade-in bg-black/60 backdrop-blur-sm">
      <div className="w-full max-w-sm bg-white rounded-[2.5rem] p-6 shadow-2xl animate-fade-in">
        <h3 className="text-lg font-black text-gray-800 mb-6">{editingSessionId ? '✏️ 编辑场次' : '✨ 录入场次'}</h3>
        <div className="space-y-4">
          <div className="grid grid-cols-2 gap-3">
             <div>
                <label className="block text-[10px] font-black text-gray-400 mb-1">日期</label>
                <DatePicker
                  selected={stringToDate(sessionFormDate)}
                  onChange={(date) => setSessionFormDate(dateToString(date))}
                  dateFormat="yyyy-MM-dd"
                  className="w-full bg-gray-50 border border-gray-100 rounded-xl p-3 text-sm font-bold outline-none"
                />
             </div>
             <div>
                <label className="block text-[10px] font-black text-gray-400 mb-1">当日加支费</label>
                <input type="number" value={sessionFormCost || ''} onChange={e => setSessionFormCost(Number(e.target.value))} className="w-full bg-gray-50 border border-gray-100 rounded-xl p-3 text-sm font-bold outline-none text-red-500" placeholder="0.00" />
             </div>
          </div>
          <div>
            <p className="text-[10px] font-black text-gray-400 mb-2 uppercase">出席成员 ({selectedAttendees.length}):</p>
            <div className="flex flex-wrap gap-1.5 p-3 bg-gray-50 rounded-2xl border border-gray-100 max-h-48 overflow-y-auto">
              {players.map(p => {
                const isSelected = selectedAttendees.find(a => a.playerId === p.id);
                return (
                  <button key={p.id} onClick={() => toggleAttendee(p, periodId)} className={`text-[10px] px-3 py-2 rounded-xl font-black transition-all border ${isSelected ? 'bg-emerald-600 border-emerald-700 text-white shadow-md' : 'bg-white border-gray-100 text-gray-400'}`}>
                    {p.name}
                  </button>
                );
              })}
            </div>
          </div>
          <div className="flex gap-3 pt-4">
            <button onClick={() => saveSession(periodId)} className="flex-[2] bg-emerald-600 text-white py-3.5 rounded-2xl font-black text-sm active:scale-95 shadow-lg shadow-emerald-100">确认保存</button>
            <button onClick={() => { setActiveSessionPeriod(null); setEditingSessionId(null); }} className="flex-1 bg-gray-100 text-gray-500 py-3.5 rounded-2xl font-black text-sm">取消</button>
          </div>
        </div>
      </div>
    </div>
  );

  const handleOpenAddSession = (e: React.MouseEvent, periodId: string) => {
    e.stopPropagation();
    setActiveSessionPeriod(periodId);
    setEditingSessionId(null);
    setSessionFormDate(new Date().toISOString().split('T')[0]);
    setSessionFormCost(0);
    setSelectedAttendees([]);
  };

  const handleEditSession = (e: React.MouseEvent, periodId: string, session: Session) => {
    e.stopPropagation();
    setActiveSessionPeriod(periodId);
    setEditingSessionId(session.id);
    setSessionFormDate(session.date);
    setSessionFormCost(session.sessionCost || 0);
    setSelectedAttendees(session.attendees);
  };

  const saveSession = (periodId: string) => {
    if (selectedAttendees.length === 0) {
      alert('请至少选择一名出席成员');
      return;
    }
    if (editingSessionId) {
      setPeriods(prev => prev.map(p => p.id === periodId ? {
        ...p,
        sessions: p.sessions.map(s => s.id === editingSessionId ? { ...s, date: sessionFormDate, sessionCost: sessionFormCost, attendees: selectedAttendees } : s)
      } : p));
    } else {
      const session: Session = {
        id: Date.now().toString(),
        date: sessionFormDate,
        sessionCost: sessionFormCost,
        attendees: selectedAttendees
      };
      setPeriods(prev => prev.map(p => {
        if (p.id === periodId) {
          const newSessions = [session, ...p.sessions].sort((a, b) => b.date.localeCompare(a.date));
          return { ...p, sessions: newSessions };
        }
        return p;
      }));
    }
    setActiveSessionPeriod(null);
    setEditingSessionId(null);
  };

  const toggleAttendee = (player: Player, periodId: string) => {
    const exists = selectedAttendees.find(a => a.playerId === player.id);
    if (exists) {
      setSelectedAttendees(prev => prev.filter(a => a.playerId !== player.id));
    } else {
      const currentPeriod = periods.find(p => p.id === periodId);
      let defaultFee = player.defaultFee;
      if (player.type === PlayerType.MONTHLY && currentPeriod?.funderIds.includes(player.id)) {
        defaultFee = 0;
      }
      setSelectedAttendees(prev => [...prev, { playerId: player.id, fee: defaultFee }]);
    }
  };

  return (
    <div className="p-4 space-y-4 pb-32">
      {/* 标题栏 */}
      <div className="px-1 mb-4 flex justify-between items-end">
        <div>
          <h2 className="text-2xl font-black text-gray-800">结算管理</h2>
          <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">Manage your sessions</p>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={() => setSortBy(sortBy === 'date' ? 'name' : 'date')}
            className="text-[10px] font-black px-3 py-1.5 bg-white border border-gray-100 rounded-full shadow-sm text-gray-500 active:bg-gray-50"
          >
            {sortBy === 'date' ? '📅 时间' : '🔤 名称'}
          </button>
          <button 
            onClick={() => setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc')}
            className="text-[10px] font-black px-2 py-1.5 bg-white border border-gray-100 rounded-full shadow-sm text-gray-500 active:bg-gray-50"
          >
            {sortOrder === 'asc' ? '↑' : '↓'}
          </button>
        </div>
      </div>

      {/* 周期列表 */}
      <div className="space-y-4">
        {sortedPeriods.map(period => {
          const isExpanded = expandedPeriodId === period.id;
          const totalIncome = period.sessions.reduce((acc, s) => acc + s.attendees.reduce((sum, a) => sum + a.fee, 0), 0);

          return (
            <div key={period.id} className={`bg-white rounded-[2rem] shadow-sm border border-gray-100 overflow-hidden transition-all ${isExpanded ? 'ring-2 ring-emerald-500/10 shadow-lg' : ''}`}>
              <div 
                onClick={() => setExpandedPeriodId(isExpanded ? null : period.id)}
                className={`p-5 flex justify-between items-center cursor-pointer active:bg-gray-50 transition-colors ${isExpanded ? 'bg-emerald-50/20' : ''}`}
              >
                <div className="flex-1">
                  <div className="flex items-center gap-2 mb-1">
                    <h3 className="font-black text-gray-800 text-base">{period.name}</h3>
                    {(!period.endDate) && (
                      <span className="text-[8px] bg-emerald-500 text-white px-1.5 py-0.5 rounded-full font-black animate-pulse">进行中</span>
                    )}
                  </div>
                  <p className="text-[10px] text-gray-400 font-bold">{period.startDate} ~ {period.endDate || '至今'}</p>
                </div>
                <div className="flex items-center gap-4">
                   <div className="text-right">
                      <p className="text-[9px] text-gray-400 font-black">场次</p>
                      <p className="font-black text-emerald-600">{period.sessions.length}</p>
                   </div>
                   <div className={`transition-transform duration-300 ${isExpanded ? 'rotate-180 text-emerald-500' : 'text-gray-300'}`}>
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M19 9l-7 7-7-7" /></svg>
                  </div>
                </div>
              </div>

              {isExpanded && (
                <div className="p-5 bg-gray-50/30 border-t border-gray-50 space-y-6 animate-fade-in">
                  <div className="grid grid-cols-2 gap-3">
                    <div className="bg-white p-4 rounded-2xl border border-gray-100">
                      <p className="text-[9px] font-black text-gray-400 uppercase mb-1">场地费总支</p>
                      <p className="text-lg font-black text-red-500">¥{period.courtCost + period.sessions.reduce((a,s) => a+(s.sessionCost||0), 0)}</p>
                    </div>
                    <div className="bg-white p-4 rounded-2xl border border-gray-100">
                      <p className="text-[9px] font-black text-gray-400 uppercase mb-1">累计采集收入</p>
                      <p className="text-lg font-black text-emerald-600">¥{totalIncome}</p>
                    </div>
                  </div>

                  <div>
                    <div className="flex justify-between items-center mb-2 px-1">
                      <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">👑 集资名单</p>
                      <button onClick={(e) => { e.stopPropagation(); setEditingPeriodId(period.id); setPeriodFormData(period); }} className="text-[9px] text-emerald-600 font-black px-2 py-1 bg-emerald-50 rounded-lg">编辑周期</button>
                    </div>
                    <div className="flex flex-wrap gap-1.5 p-3 bg-white rounded-2xl border border-gray-100 shadow-sm">
                      {period.funderIds.map(fid => (
                        <span key={fid} className="text-[10px] bg-amber-50 text-amber-700 px-2.5 py-1 rounded-full font-black border border-amber-100">
                          {players.find(pl => pl.id === fid)?.name || '未知'}
                        </span>
                      ))}
                    </div>
                  </div>

                  <div className="pt-2">
                    <div className="flex justify-between items-center mb-3">
                      <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">🏸 打球流水</h4>
                      <button 
                        onClick={(e) => handleOpenAddSession(e, period.id)}
                        className="text-[10px] bg-gray-900 text-white px-4 py-2 rounded-xl font-black active:scale-95"
                      >
                        + 录入单场
                      </button>
                    </div>

                    <div className="space-y-3">
                      {period.sessions.map(session => (
                        <div key={session.id} className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm">
                          <div className="flex justify-between items-center mb-2">
                             <div className="flex items-center gap-2">
                                <span className="text-xs font-black text-gray-800">{session.date}</span>
                                {session.sessionCost ? <span className="text-[8px] bg-red-100 text-red-600 px-1.5 py-0.5 rounded font-bold">加支 ¥{session.sessionCost}</span> : null}
                             </div>
                             <div className="flex gap-1">
                                <button onClick={(e) => handleEditSession(e, period.id, session)} className="text-gray-300 p-1.5"><Icons.Pencil /></button>
                                <button onClick={(e) => { e.stopPropagation(); if(confirm('确认删除?')) setPeriods(prev => prev.map(p => p.id === period.id ? {...p, sessions: p.sessions.filter(s => s.id !== session.id)} : p)); }} className="text-gray-300 p-1.5"><Icons.Trash /></button>
                             </div>
                          </div>
                          <div className="flex flex-wrap gap-1">
                            {session.attendees.map(a => (
                              <span key={a.playerId} className="text-[9px] bg-gray-50 text-gray-500 px-2 py-0.5 rounded border border-gray-100">
                                {players.find(pl => pl.id === a.playerId)?.name} {a.fee > 0 ? `(¥${a.fee})` : ''}
                              </span>
                            ))}
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>

                  <div className="pt-4 border-t border-gray-100 flex justify-center">
                    <button 
                      onClick={(e) => { e.stopPropagation(); if(confirm('确定永久删除此周期及其所有记录吗？')) setPeriods(prev => prev.filter(p => p.id !== period.id)); }}
                      className="text-[10px] text-red-300 font-bold flex items-center gap-1"
                    >
                      <Icons.Trash /> 永久移除此周期
                    </button>
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* 悬浮操作按钮 (FAB) - 确保在手机端任何位置都能轻松点击 */}
      <button 
        onClick={() => { setIsAddingPeriod(true); setEditingPeriodId(null); setPeriodFormData(initialPeriodData); }} 
        className="fixed bottom-24 right-6 w-14 h-14 bg-emerald-600 text-white rounded-full flex items-center justify-center shadow-2xl shadow-emerald-400 z-50 active:scale-90 transition-transform"
      >
        <Icons.Plus />
      </button>

      {/* 底部弹出抽屉：新增周期 */}
      {isAddingPeriod && renderPeriodDrawer("创建结算周期", () => setIsAddingPeriod(false))}

      {/* 底部弹出抽屉：编辑周期（复用抽屉） */}
      {editingPeriodId && renderPeriodDrawer("编辑周期配置", () => setEditingPeriodId(null))}

      {/* 录入场次弹出层 */}
      {activeSessionPeriod && renderSessionForm(activeSessionPeriod)}

      {periods.length === 0 && (
        <div className="text-center py-24 text-gray-300">
          <p className="text-5xl mb-4 opacity-10">🏸</p>
          <p className="text-sm font-black uppercase tracking-widest">尚未创建结算周期</p>
        </div>
      )}
    </div>
  );
};

export default PeriodsList;

import React, { useState, useMemo } from 'react';
import DatePicker from 'react-datepicker';
import { Period, Player, Session, PlayerType } from '../types';
import { Icons } from '../constants';

interface PeriodsListProps {
  periods: Period[];
  setPeriods: React.Dispatch<React.SetStateAction<Period[]>>;
  players: Player[];
  setPlayers: React.Dispatch<React.SetStateAction<Player[]>>;
}

const PeriodsList: React.FC<PeriodsListProps> = ({ periods, setPeriods, players, setPlayers }) => {
  const [isAddingPeriod, setIsAddingPeriod] = useState(false);
  const [editingPeriodId, setEditingPeriodId] = useState<string | null>(null);
  const [expandedPeriodId, setExpandedPeriodId] = useState<string | null>(null);
  const [activeSessionPeriod, setActiveSessionPeriod] = useState<string | null>(null);
  const [editingSessionId, setEditingSessionId] = useState<string | null>(null);
  const [confirmDeletePeriodId, setConfirmDeletePeriodId] = useState<string | null>(null);

  const [sortBy, setSortBy] = useState<'date' | 'name'>('date');
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('desc');

  const funderPool = players.filter(p => p.isFunder);

  const initialPeriodData = {
    name: '',
    startDate: new Date().toISOString().split('T')[0],
    endDate: '',
    courtCost: 0,
    funderIds: funderPool.map(p => p.id),
    sessions: []
  };

  const [periodFormData, setPeriodFormData] = useState<Partial<Period>>(initialPeriodData);
  const [sessionFormDate, setSessionFormDate] = useState(new Date().toISOString().split('T')[0]);
  const [sessionFormCost, setSessionFormCost] = useState<number>(0);
  const [selectedAttendees, setSelectedAttendees] = useState<{playerId: string, fee: number}[]>([]);

  const sortedPeriods = useMemo(() => {
    return [...periods].sort((a, b) => {
      let comparison = 0;
      if (sortBy === 'date') {
        comparison = a.startDate.localeCompare(b.startDate);
      } else {
        comparison = a.name.localeCompare(b.name, 'zh-CN');
      }
      return sortOrder === 'asc' ? comparison : -comparison;
    });
  }, [periods, sortBy, sortOrder]);

  const stringToDate = (str: string | undefined) => {
    if (!str) return null;
    return new Date(str);
  };

  const dateToString = (date: Date | null) => {
    if (!date) return '';
    return date.toISOString().split('T')[0];
  };

  const handleSavePeriod = () => {
    if (!periodFormData.name) {
      alert('请输入周期名称');
      return;
    }
    const finalFunderIds = periodFormData.funderIds || [];
    setPlayers(prevPlayers => prevPlayers.map(p => {
      if (finalFunderIds.includes(p.id)) {
        return { ...p, type: PlayerType.MONTHLY };
      }
      return p;
    }));
    if (editingPeriodId) {
      setPeriods(prev => prev.map(p => p.id === editingPeriodId ? { ...p, ...periodFormData } as Period : p));
      setEditingPeriodId(null);
    } else {
      const period: Period = {
        id: Date.now().toString(),
        name: periodFormData.name!,
        startDate: periodFormData.startDate!,
        endDate: periodFormData.endDate || '',
        courtCost: periodFormData.courtCost || 0,
        funderIds: finalFunderIds,
        sessions: []
      };
      setPeriods(prev => [period, ...prev]);
      setIsAddingPeriod(false);
    }
    setPeriodFormData(initialPeriodData);
  };

  const handleDeleteConfirmed = () => {
    if (!confirmDeletePeriodId) return;
    setPeriods(prev => prev.filter(p => p.id !== confirmDeletePeriodId));
    setConfirmDeletePeriodId(null);
    if (expandedPeriodId === confirmDeletePeriodId) setExpandedPeriodId(null);
  };

  const renderDeleteModal = () => {
    const period = periods.find(p => p.id === confirmDeletePeriodId);
    if (!period) return null;

    return (
      <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 animate-fade-in bg-black/60 backdrop-blur-md">
        <div className="w-full max-w-sm bg-white rounded-[2.5rem] p-8 shadow-2xl animate-fade-in">
          <div className="flex flex-col items-center text-center">
            <div className="w-16 h-16 bg-red-50 text-red-500 rounded-full flex items-center justify-center mb-4">
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
              </svg>
            </div>
            <h3 className="text-xl font-black text-gray-800 mb-2">确认删除周期？</h3>
            <div className="bg-red-50 rounded-2xl p-4 mb-6">
              <p className="text-xs text-red-600 font-bold leading-relaxed">
                删除周期 <span className="underline">"{period.name}"</span> 后，
                内部包含的 <span className="font-black">{period.sessions.length} 场打球记录</span> 将被永久清空，无法找回。
              </p>
            </div>
          </div>
          <div className="flex flex-col gap-3">
            <button 
              onClick={handleDeleteConfirmed} 
              className="w-full bg-red-600 text-white py-4 rounded-2xl font-black text-base shadow-lg shadow-red-200 active:scale-95 transition-all"
            >
              确认永久删除
            </button>
            <button 
              onClick={() => setConfirmDeletePeriodId(null)} 
              className="w-full bg-gray-100 text-gray-500 py-4 rounded-2xl font-black text-sm active:bg-gray-200"
            >
              取消
            </button>
          </div>
        </div>
      </div>
    );
  };

  const renderPeriodDrawer = (title: string, onCancel: () => void) => (
    <div className="fixed inset-0 z-[100] flex items-end justify-center animate-fade-in bg-black/40 backdrop-blur-[2px]">
      <div 
        className="w-full max-w-md bg-white rounded-t-[2.5rem] shadow-2xl p-6 pb-safe animate-slide-up overflow-y-auto max-h-[90vh]"
        onClick={e => e.stopPropagation()}
      >
        <div className="w-12 h-1.5 bg-gray-200 rounded-full mx-auto mb-6"></div>
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-xl font-black text-gray-800">{title}</h3>
          <button onClick={onCancel} className="text-gray-300 p-2 active:bg-gray-100 rounded-full">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>
        <div className="space-y-5">
          <div>
            <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">周期名称</label>
            <input type="text" placeholder="例如：2025年3月集资" value={periodFormData.name} onChange={e => setPeriodFormData({...periodFormData, name: e.target.value})} className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold focus:ring-2 focus:ring-emerald-500 outline-none" />
          </div>
          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">开始日期</label>
              <DatePicker selected={stringToDate(periodFormData.startDate)} onChange={(date) => setPeriodFormData({...periodFormData, startDate: dateToString(date)})} dateFormat="yyyy-MM-dd" className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold outline-none" />
            </div>
            <div>
              <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">结束日期 (选填)</label>
              <DatePicker selected={stringToDate(periodFormData.endDate)} onChange={(date) => setPeriodFormData({...periodFormData, endDate: dateToString(date)})} dateFormat="yyyy-MM-dd" placeholderText="进行中..." className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold outline-none" isClearable />
            </div>
          </div>
          <div className="bg-red-50 p-4 rounded-2xl border border-red-100">
            <label className="block text-[10px] font-black text-red-800 uppercase tracking-widest mb-1 ml-1">本周期预付场地费</label>
            <div className="relative flex items-center">
              <span className="absolute left-4 text-red-300 font-bold italic">¥</span>
              <input type="number" placeholder="0.00" value={periodFormData.courtCost || ''} onChange={e => setPeriodFormData({...periodFormData, courtCost: Number(e.target.value)})} className="w-full bg-transparent border-none p-0 pl-8 text-2xl font-black text-red-600 outline-none focus:ring-0" />
            </div>
          </div>
          <div className="bg-amber-50 p-4 rounded-2xl border border-amber-100">
            <p className="text-[10px] font-black text-amber-800 uppercase tracking-widest mb-3 flex justify-between items-center">
              <span>👑 确认集资名单 ({periodFormData.funderIds?.length || 0})</span>
            </p>
            <div className="grid grid-cols-3 gap-2">
              {funderPool.map(f => {
                const isSelected = periodFormData.funderIds?.includes(f.id);
                return (
                  <button key={f.id} type="button" onClick={() => {
                    const current = periodFormData.funderIds || [];
                    setPeriodFormData({...periodFormData, funderIds: current.includes(f.id) ? current.filter(id => id !== f.id) : [...current, f.id]});
                  }} className={`text-[10px] py-2.5 rounded-xl border transition-all font-black ${isSelected ? 'bg-amber-500 border-amber-600 text-white shadow-md' : 'bg-white border-amber-100 text-amber-200'}`}>
                    {f.name}
                  </button>
                )
              })}
            </div>
          </div>
          <div className="flex gap-3 pt-2">
            <button onClick={handleSavePeriod} className="flex-[2] bg-emerald-600 text-white py-4 rounded-2xl font-black text-base shadow-lg shadow-emerald-200 active:scale-95 transition-all">保存周期配置</button>
            <button onClick={onCancel} className="flex-1 bg-gray-100 text-gray-500 py-4 rounded-2xl font-black text-sm active:bg-gray-200">取消</button>
          </div>
        </div>
      </div>
    </div>
  );

  const renderSessionForm = (periodId: string) => (
    <div className="fixed inset-0 z-[120] flex items-center justify-center p-6 animate-fade-in bg-black/60 backdrop-blur-sm">
      <div className="w-full max-w-sm bg-white rounded-[2.5rem] p-6 shadow-2xl animate-fade-in">
        <h3 className="text-lg font-black text-gray-800 mb-6">{editingSessionId ? '✏️ 编辑场次' : '✨ 录入场次'}</h3>
        <div className="space-y-4">
          <div className="grid grid-cols-2 gap-3">
             <div>
                <label className="block text-[10px] font-black text-gray-400 mb-1">日期</label>
                <DatePicker selected={stringToDate(sessionFormDate)} onChange={(date) => setSessionFormDate(dateToString(date))} dateFormat="yyyy-MM-dd" className="w-full bg-gray-50 border border-gray-100 rounded-xl p-3 text-sm font-bold outline-none" />
             </div>
             <div>
                <label className="block text-[10px] font-black text-gray-400 mb-1">当日加支费</label>
                <input type="number" value={sessionFormCost || ''} onChange={e => setSessionFormCost(Number(e.target.value))} className="w-full bg-gray-50 border border-gray-100 rounded-xl p-3 text-sm font-bold outline-none text-red-500" placeholder="0.00" />
             </div>
          </div>
          <div>
            <p className="text-[10px] font-black text-gray-400 mb-2 uppercase">出席成员 ({selectedAttendees.length}):</p>
            <div className="flex flex-wrap gap-1.5 p-3 bg-gray-50 rounded-2xl border border-gray-100 max-h-48 overflow-y-auto">
              {players.map(p => {
                const isSelected = selectedAttendees.find(a => a.playerId === p.id);
                return (
                  <button key={p.id} onClick={() => toggleAttendee(p, periodId)} className={`text-[10px] px-3 py-2 rounded-xl font-black transition-all border ${isSelected ? 'bg-emerald-600 border-emerald-700 text-white shadow-md' : 'bg-white border-gray-100 text-gray-400'}`}>
                    {p.name}
                  </button>
                );
              })}
            </div>
          </div>
          <div className="flex gap-3 pt-4">
            <button onClick={() => saveSession(periodId)} className="flex-[2] bg-emerald-600 text-white py-3.5 rounded-2xl font-black text-sm active:scale-95 shadow-lg shadow-emerald-100">确认保存</button>
            <button onClick={() => { setActiveSessionPeriod(null); setEditingSessionId(null); }} className="flex-1 bg-gray-100 text-gray-500 py-3.5 rounded-2xl font-black text-sm">取消</button>
          </div>
        </div>
      </div>
    </div>
  );

  const handleOpenAddSession = (e: React.MouseEvent, periodId: string) => {
    e.stopPropagation();
    setActiveSessionPeriod(periodId);
    setEditingSessionId(null);
    setSessionFormDate(new Date().toISOString().split('T')[0]);
    setSessionFormCost(0);
    setSelectedAttendees([]);
  };

  const handleEditSession = (e: React.MouseEvent, periodId: string, session: Session) => {
    e.stopPropagation();
    setActiveSessionPeriod(periodId);
    setEditingSessionId(session.id);
    setSessionFormDate(session.date);
    setSessionFormCost(session.sessionCost || 0);
    setSelectedAttendees(session.attendees);
  };

  const saveSession = (periodId: string) => {
    if (selectedAttendees.length === 0) {
      alert('请至少选择一名出席成员');
      return;
    }
    if (editingSessionId) {
      setPeriods(prev => prev.map(p => p.id === periodId ? {
        ...p,
        sessions: p.sessions.map(s => s.id === editingSessionId ? { ...s, date: sessionFormDate, sessionCost: sessionFormCost, attendees: selectedAttendees } : s)
      } : p));
    } else {
      const session: Session = {
        id: Date.now().toString(),
        date: sessionFormDate,
        sessionCost: sessionFormCost,
        attendees: selectedAttendees
      };
      setPeriods(prev => prev.map(p => {
        if (p.id === periodId) {
          const newSessions = [session, ...p.sessions].sort((a, b) => b.date.localeCompare(a.date));
          return { ...p, sessions: newSessions };
        }
        return p;
      }));
    }
    setActiveSessionPeriod(null);
    setEditingSessionId(null);
  };

  const toggleAttendee = (player: Player, periodId: string) => {
    const exists = selectedAttendees.find(a => a.playerId === player.id);
    if (exists) {
      setSelectedAttendees(prev => prev.filter(a => a.playerId !== player.id));
    } else {
      const currentPeriod = periods.find(p => p.id === periodId);
      let defaultFee = player.defaultFee;
      if (player.type === PlayerType.MONTHLY && currentPeriod?.funderIds.includes(player.id)) {
        defaultFee = 0;
      }
      setSelectedAttendees(prev => [...prev, { playerId: player.id, fee: defaultFee }]);
    }
  };

  return (
    <div className="p-4 space-y-4 pb-32">
      <div className="px-1 mb-4 flex justify-between items-end">
        <div>
          <h2 className="text-2xl font-black text-gray-800">结算管理</h2>
          <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">Manage your sessions</p>
        </div>
        <div className="flex gap-2">
          <button onClick={() => setSortBy(sortBy === 'date' ? 'name' : 'date')} className="text-[10px] font-black px-3 py-1.5 bg-white border border-gray-100 rounded-full shadow-sm text-gray-500 active:bg-gray-50">
            {sortBy === 'date' ? '📅 时间' : '🔤 名称'}
          </button>
          <button onClick={() => setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc')} className="text-[10px] font-black px-2 py-1.5 bg-white border border-gray-100 rounded-full shadow-sm text-gray-500 active:bg-gray-50">
            {sortOrder === 'asc' ? '↑' : '↓'}
          </button>
        </div>
      </div>

      <div className="space-y-4">
        {sortedPeriods.map(period => {
          const isExpanded = expandedPeriodId === period.id;
          const totalIncome = period.sessions.reduce((acc, s) => acc + s.attendees.reduce((sum, a) => sum + a.fee, 0), 0);
          return (
            <div key={period.id} className={`bg-white rounded-[2rem] shadow-sm border border-gray-100 overflow-hidden transition-all ${isExpanded ? 'ring-2 ring-emerald-500/10 shadow-lg' : ''}`}>
              <div onClick={() => setExpandedPeriodId(isExpanded ? null : period.id)} className={`p-5 flex justify-between items-center cursor-pointer active:bg-gray-50 transition-colors ${isExpanded ? 'bg-emerald-50/20' : ''}`}>
                <div className="flex-1">
                  <div className="flex items-center gap-2 mb-1">
                    <h3 className="font-black text-gray-800 text-base">{period.name}</h3>
                    {(!period.endDate) && (
                      <span className="text-[8px] bg-emerald-500 text-white px-1.5 py-0.5 rounded-full font-black animate-pulse">进行中</span>
                    )}
                  </div>
                  <p className="text-[10px] text-gray-400 font-bold">{period.startDate} ~ {period.endDate || '至今'}</p>
                </div>
                <div className="flex items-center gap-4">
                   <div className="text-right">
                      <p className="text-[9px] text-gray-400 font-black">场次</p>
                      <p className="font-black text-emerald-600">{period.sessions.length}</p>
                   </div>
                   <div className={`transition-transform duration-300 ${isExpanded ? 'rotate-180 text-emerald-500' : 'text-gray-300'}`}>
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M19 9l-7 7-7-7" /></svg>
                  </div>
                </div>
              </div>

              {isExpanded && (
                <div className="p-5 bg-gray-50/30 border-t border-gray-50 space-y-6 animate-fade-in">
                  <div className="grid grid-cols-2 gap-3">
                    <div className="bg-white p-4 rounded-2xl border border-gray-100">
                      <p className="text-[9px] font-black text-gray-400 uppercase mb-1">场地费总支</p>
                      <p className="text-lg font-black text-red-500">¥{period.courtCost + period.sessions.reduce((a,s) => a+(s.sessionCost||0), 0)}</p>
                    </div>
                    <div className="bg-white p-4 rounded-2xl border border-gray-100">
                      <p className="text-[9px] font-black text-gray-400 uppercase mb-1">累计采集收入</p>
                      <p className="text-lg font-black text-emerald-600">¥{totalIncome}</p>
                    </div>
                  </div>
                  <div>
                    <div className="flex justify-between items-center mb-2 px-1">
                      <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">👑 集资名单</p>
                      <button onClick={(e) => { e.stopPropagation(); setEditingPeriodId(period.id); setPeriodFormData(period); }} className="text-[9px] text-emerald-600 font-black px-2 py-1 bg-emerald-50 rounded-lg">编辑周期</button>
                    </div>
                    <div className="flex flex-wrap gap-1.5 p-3 bg-white rounded-2xl border border-gray-100 shadow-sm">
                      {period.funderIds.map(fid => (
                        <span key={fid} className="text-[10px] bg-amber-50 text-amber-700 px-2.5 py-1 rounded-full font-black border border-amber-100">
                          {players.find(pl => pl.id === fid)?.name || '未知'}
                        </span>
                      ))}
                    </div>
                  </div>
                  <div className="pt-2">
                    <div className="flex justify-between items-center mb-3">
                      <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">🏸 打球流水</h4>
                      <button onClick={(e) => handleOpenAddSession(e, period.id)} className="text-[10px] bg-gray-900 text-white px-4 py-2 rounded-xl font-black active:scale-95">
                        + 录入单场
                      </button>
                    </div>
                    <div className="space-y-3">
                      {period.sessions.map(session => (
                        <div key={session.id} className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm">
                          <div className="flex justify-between items-center mb-2">
                             <div className="flex items-center gap-2">
                                <span className="text-xs font-black text-gray-800">{session.date}</span>
                                {session.sessionCost ? <span className="text-[8px] bg-red-100 text-red-600 px-1.5 py-0.5 rounded font-bold">加支 ¥{session.sessionCost}</span> : null}
                             </div>
                             <div className="flex gap-1">
                                <button onClick={(e) => handleEditSession(e, period.id, session)} className="text-gray-300 p-1.5"><Icons.Pencil /></button>
                                <button onClick={(e) => { e.stopPropagation(); if(confirm('确认删除?')) setPeriods(prev => prev.map(p => p.id === period.id ? {...p, sessions: p.sessions.filter(s => s.id !== session.id)} : p)); }} className="text-gray-300 p-1.5"><Icons.Trash /></button>
                             </div>
                          </div>
                          <div className="flex flex-wrap gap-1">
                            {session.attendees.map(a => (
                              <span key={a.playerId} className="text-[9px] bg-gray-50 text-gray-500 px-2 py-0.5 rounded border border-gray-100">
                                {players.find(pl => pl.id === a.playerId)?.name} {a.fee > 0 ? `(¥${a.fee})` : ''}
                              </span>
                            ))}
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                  <div className="pt-4 border-t border-gray-100 flex justify-center">
                    <button 
                      onClick={(e) => { e.stopPropagation(); setConfirmDeletePeriodId(period.id); }}
                      className="text-[10px] text-red-300 font-bold flex items-center gap-1 active:scale-95 transition-transform"
                    >
                      <Icons.Trash /> 永久移除此周期
                    </button>
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>

      <button onClick={() => { setIsAddingPeriod(true); setEditingPeriodId(null); setPeriodFormData(initialPeriodData); }} className="fixed bottom-24 right-6 w-14 h-14 bg-emerald-600 text-white rounded-full flex items-center justify-center shadow-2xl shadow-emerald-400 z-50 active:scale-90 transition-transform">
        <Icons.Plus />
      </button>

      {isAddingPeriod && renderPeriodDrawer("创建结算周期", () => setIsAddingPeriod(false))}
      {editingPeriodId && renderPeriodDrawer("编辑周期配置", () => setEditingPeriodId(null))}
      {activeSessionPeriod && renderSessionForm(activeSessionPeriod)}
      {confirmDeletePeriodId && renderDeleteModal()}

      {periods.length === 0 && (
        <div className="text-center py-24 text-gray-300">
          <p className="text-5xl mb-4 opacity-10">🏸</p>
          <p className="text-sm font-black uppercase tracking-widest">尚未创建结算周期</p>
        </div>
      )}
    </div>
  );
};

export default PeriodsList;

import React, { useState, useMemo } from 'react';
import DatePicker from 'react-datepicker';
import { Period, Player, Session, PlayerType } from '../types';
import { Icons } from '../constants';

interface PeriodsListProps {
  periods: Period[];
  setPeriods: React.Dispatch<React.SetStateAction<Period[]>>;
  players: Player[];
  setPlayers: React.Dispatch<React.SetStateAction<Player[]>>;
}

const PeriodsList: React.FC<PeriodsListProps> = ({ periods, setPeriods, players, setPlayers }) => {
  const [isAddingPeriod, setIsAddingPeriod] = useState(false);
  const [editingPeriodId, setEditingPeriodId] = useState<string | null>(null);
  const [expandedPeriodId, setExpandedPeriodId] = useState<string | null>(null);
  const [activeSessionPeriod, setActiveSessionPeriod] = useState<string | null>(null);
  const [editingSessionId, setEditingSessionId] = useState<string | null>(null);
  const [confirmDeletePeriodId, setConfirmDeletePeriodId] = useState<string | null>(null);

  const [sortBy, setSortBy] = useState<'date' | 'name'>('date');
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('desc');

  const funderPool = players.filter(p => p.isFunder);

  const initialPeriodData = {
    name: '',
    startDate: new Date().toISOString().split('T')[0],
    endDate: '',
    courtCost: 0,
    funderIds: funderPool.map(p => p.id),
    sessions: []
  };

  const [periodFormData, setPeriodFormData] = useState<Partial<Period>>(initialPeriodData);
  const [sessionFormDate, setSessionFormDate] = useState(new Date().toISOString().split('T')[0]);
  const [sessionFormCost, setSessionFormCost] = useState<number>(0);
  const [selectedAttendees, setSelectedAttendees] = useState<{playerId: string, fee: number}[]>([]);

  const sortedPeriods = useMemo(() => {
    return [...periods].sort((a, b) => {
      let comparison = 0;
      if (sortBy === 'date') {
        comparison = a.startDate.localeCompare(b.startDate);
      } else {
        comparison = a.name.localeCompare(b.name, 'zh-CN');
      }
      return sortOrder === 'asc' ? comparison : -comparison;
    });
  }, [periods, sortBy, sortOrder]);

  const stringToDate = (str: string | undefined) => {
    if (!str) return null;
    return new Date(str);
  };

  const dateToString = (date: Date | null) => {
    if (!date) return '';
    return date.toISOString().split('T')[0];
  };

  // --- 周期管理核心逻辑 ---

  const handleSavePeriod = () => {
    if (!periodFormData.name) {
      alert('请输入周期名称');
      return;
    }
    const finalFunderIds = periodFormData.funderIds || [];
    setPlayers(prevPlayers => prevPlayers.map(p => {
      if (finalFunderIds.includes(p.id)) {
        return { ...p, type: PlayerType.MONTHLY };
      }
      return p;
    }));
    if (editingPeriodId) {
      setPeriods(prev => prev.map(p => p.id === editingPeriodId ? { ...p, ...periodFormData } as Period : p));
      setEditingPeriodId(null);
    } else {
      const period: Period = {
        id: Date.now().toString(),
        name: periodFormData.name!,
        startDate: periodFormData.startDate!,
        endDate: periodFormData.endDate || '',
        courtCost: periodFormData.courtCost || 0,
        funderIds: finalFunderIds,
        sessions: []
      };
      setPeriods(prev => [period, ...prev]);
      setIsAddingPeriod(false);
    }
    setPeriodFormData(initialPeriodData);
  };

  const handleConfirmDeletePeriod = (e: React.MouseEvent, periodId: string) => {
    e.preventDefault();
    e.stopPropagation();
    setConfirmDeletePeriodId(periodId);
  };

  const handleDeletePeriodConfirmed = () => {
    if (!confirmDeletePeriodId) return;
    setPeriods(prev => prev.filter(p => p.id !== confirmDeletePeriodId));
    setConfirmDeletePeriodId(null);
    if (expandedPeriodId === confirmDeletePeriodId) setExpandedPeriodId(null);
  };

  // --- 打球场次核心逻辑 ---

  const handleRemoveSession = (e: React.MouseEvent, periodId: string, sessionId: string) => {
    e.preventDefault();
    e.stopPropagation();
    if (confirm('核心提醒：确定要删除这条打球记录吗？该操作不可撤销。')) {
      setPeriods(prev => prev.map(p => {
        if (p.id === periodId) {
          return {
            ...p,
            sessions: p.sessions.filter(s => s.id !== sessionId)
          };
        }
        return p;
      }));
    }
  };

  const saveSession = (periodId: string) => {
    if (selectedAttendees.length === 0) {
      alert('请至少选择一名出席成员');
      return;
    }
    if (editingSessionId) {
      setPeriods(prev => prev.map(p => p.id === periodId ? {
        ...p,
        sessions: p.sessions.map(s => s.id === editingSessionId ? { ...s, date: sessionFormDate, sessionCost: sessionFormCost, attendees: selectedAttendees } : s)
      } : p));
    } else {
      const session: Session = {
        id: Date.now().toString(),
        date: sessionFormDate,
        sessionCost: sessionFormCost,
        attendees: selectedAttendees
      };
      setPeriods(prev => prev.map(p => {
        if (p.id === periodId) {
          const newSessions = [session, ...p.sessions].sort((a, b) => b.date.localeCompare(a.date));
          return { ...p, sessions: newSessions };
        }
        return p;
      }));
    }
    setActiveSessionPeriod(null);
    setEditingSessionId(null);
  };

  const toggleAttendee = (player: Player, periodId: string) => {
    const exists = selectedAttendees.find(a => a.playerId === player.id);
    if (exists) {
      setSelectedAttendees(prev => prev.filter(a => a.playerId !== player.id));
    } else {
      const currentPeriod = periods.find(p => p.id === periodId);
      let defaultFee = player.defaultFee;
      if (player.type === PlayerType.MONTHLY && currentPeriod?.funderIds.includes(player.id)) {
        defaultFee = 0;
      }
      setSelectedAttendees(prev => [...prev, { playerId: player.id, fee: defaultFee }]);
    }
  };

  // --- 视图渲染辅助逻辑 ---

  const renderDeleteModal = () => {
    const period = periods.find(p => p.id === confirmDeletePeriodId);
    if (!period) return null;

    return (
      <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 animate-fade-in bg-black/60 backdrop-blur-md">
        <div className="w-full max-w-sm bg-white rounded-[2.5rem] p-8 shadow-2xl animate-fade-in">
          <div className="flex flex-col items-center text-center">
            <div className="w-16 h-16 bg-red-50 text-red-500 rounded-full flex items-center justify-center mb-4">
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
              </svg>
            </div>
            <h3 className="text-xl font-black text-gray-800 mb-2">确认删除周期？</h3>
            <div className="bg-red-50 rounded-2xl p-4 mb-6">
              <p className="text-xs text-red-600 font-bold leading-relaxed">
                删除周期 <span className="underline">"{period.name}"</span> 后，
                内部包含的 <span className="font-black">{period.sessions.length} 场打球记录</span> 将被永久清空。
              </p>
            </div>
          </div>
          <div className="flex flex-col gap-3">
            <button 
              onClick={handleDeletePeriodConfirmed} 
              className="w-full bg-red-600 text-white py-4 rounded-2xl font-black text-base shadow-lg shadow-red-200 active:scale-95 transition-all"
            >
              确认永久删除
            </button>
            <button 
              onClick={() => setConfirmDeletePeriodId(null)} 
              className="w-full bg-gray-100 text-gray-500 py-4 rounded-2xl font-black text-sm active:bg-gray-200"
            >
              取消
            </button>
          </div>
        </div>
      </div>
    );
  };

  const renderPeriodDrawer = (title: string, onCancel: () => void) => (
    <div className="fixed inset-0 z-[100] flex items-end justify-center animate-fade-in bg-black/40 backdrop-blur-[2px]">
      <div 
        className="w-full max-w-md bg-white rounded-t-[2.5rem] shadow-2xl p-6 pb-safe animate-slide-up overflow-y-auto max-h-[90vh]"
        onClick={e => e.stopPropagation()}
      >
        <div className="w-12 h-1.5 bg-gray-200 rounded-full mx-auto mb-6"></div>
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-xl font-black text-gray-800">{title}</h3>
          <button onClick={onCancel} className="text-gray-300 p-2 active:bg-gray-100 rounded-full">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>
        <div className="space-y-5">
          <div>
            <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">周期名称</label>
            <input type="text" placeholder="例如：2025年3月集资" value={periodFormData.name} onChange={e => setPeriodFormData({...periodFormData, name: e.target.value})} className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold focus:ring-2 focus:ring-emerald-500 outline-none" />
          </div>
          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">开始日期</label>
              <DatePicker selected={stringToDate(periodFormData.startDate)} onChange={(date) => setPeriodFormData({...periodFormData, startDate: dateToString(date)})} dateFormat="yyyy-MM-dd" className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold outline-none" />
            </div>
            <div>
              <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">结束日期 (选填)</label>
              <DatePicker selected={stringToDate(periodFormData.endDate)} onChange={(date) => setPeriodFormData({...periodFormData, endDate: dateToString(date)})} dateFormat="yyyy-MM-dd" placeholderText="进行中..." className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold outline-none" isClearable />
            </div>
          </div>
          <div className="bg-red-50 p-4 rounded-2xl border border-red-100">
            <label className="block text-[10px] font-black text-red-800 uppercase tracking-widest mb-1 ml-1">本周期预付场地费</label>
            <div className="relative flex items-center">
              <span className="absolute left-4 text-red-300 font-bold italic">¥</span>
              <input type="number" placeholder="0.00" value={periodFormData.courtCost || ''} onChange={e => setPeriodFormData({...periodFormData, courtCost: Number(e.target.value)})} className="w-full bg-transparent border-none p-0 pl-8 text-2xl font-black text-red-600 outline-none focus:ring-0" />
            </div>
          </div>
          <div className="bg-amber-50 p-4 rounded-2xl border border-amber-100">
            <p className="text-[10px] font-black text-amber-800 uppercase tracking-widest mb-3 flex justify-between items-center">
              <span>👑 确认集资名单 ({periodFormData.funderIds?.length || 0})</span>
            </p>
            <div className="grid grid-cols-3 gap-2">
              {funderPool.map(f => {
                const isSelected = periodFormData.funderIds?.includes(f.id);
                return (
                  <button key={f.id} type="button" onClick={() => {
                    const current = periodFormData.funderIds || [];
                    setPeriodFormData({...periodFormData, funderIds: current.includes(f.id) ? current.filter(id => id !== f.id) : [...current, f.id]});
                  }} className={`text-[10px] py-2.5 rounded-xl border transition-all font-black ${isSelected ? 'bg-amber-500 border-amber-600 text-white shadow-md' : 'bg-white border-amber-100 text-amber-200'}`}>
                    {f.name}
                  </button>
                )
              })}
            </div>
          </div>
          <div className="flex gap-3 pt-2">
            <button onClick={handleSavePeriod} className="flex-[2] bg-emerald-600 text-white py-4 rounded-2xl font-black text-base shadow-lg shadow-emerald-200 active:scale-95 transition-all">保存周期配置</button>
            <button onClick={onCancel} className="flex-1 bg-gray-100 text-gray-500 py-4 rounded-2xl font-black text-sm active:bg-gray-200">取消</button>
          </div>
        </div>
      </div>
    </div>
  );

  const renderSessionForm = (periodId: string) => (
    <div className="fixed inset-0 z-[120] flex items-center justify-center p-6 animate-fade-in bg-black/60 backdrop-blur-sm">
      <div className="w-full max-w-sm bg-white rounded-[2.5rem] p-6 shadow-2xl animate-fade-in">
        <h3 className="text-lg font-black text-gray-800 mb-6">{editingSessionId ? '✏️ 编辑场次' : '✨ 录入场次'}</h3>
        <div className="space-y-4">
          <div className="grid grid-cols-2 gap-3">
             <div>
                <label className="block text-[10px] font-black text-gray-400 mb-1">日期</label>
                <DatePicker selected={stringToDate(sessionFormDate)} onChange={(date) => setSessionFormDate(dateToString(date))} dateFormat="yyyy-MM-dd" className="w-full bg-gray-50 border border-gray-100 rounded-xl p-3 text-sm font-bold outline-none" />
             </div>
             <div>
                <label className="block text-[10px] font-black text-gray-400 mb-1">当日加支费</label>
                <input type="number" value={sessionFormCost || ''} onChange={e => setSessionFormCost(Number(e.target.value))} className="w-full bg-gray-50 border border-gray-100 rounded-xl p-3 text-sm font-bold outline-none text-red-500" placeholder="0.00" />
             </div>
          </div>
          <div>
            <p className="text-[10px] font-black text-gray-400 mb-2 uppercase">出席成员 ({selectedAttendees.length}):</p>
            <div className="flex flex-wrap gap-1.5 p-3 bg-gray-50 rounded-2xl border border-gray-100 max-h-48 overflow-y-auto">
              {players.map(p => {
                const isSelected = selectedAttendees.find(a => a.playerId === p.id);
                return (
                  <button key={p.id} onClick={() => toggleAttendee(p, periodId)} className={`text-[10px] px-3 py-2 rounded-xl font-black transition-all border ${isSelected ? 'bg-emerald-600 border-emerald-700 text-white shadow-md' : 'bg-white border-gray-100 text-gray-400'}`}>
                    {p.name}
                  </button>
                );
              })}
            </div>
          </div>
          <div className="flex gap-3 pt-4">
            <button onClick={() => saveSession(periodId)} className="flex-[2] bg-emerald-600 text-white py-3.5 rounded-2xl font-black text-sm active:scale-95 shadow-lg shadow-emerald-100">确认保存</button>
            <button onClick={() => { setActiveSessionPeriod(null); setEditingSessionId(null); }} className="flex-1 bg-gray-100 text-gray-500 py-3.5 rounded-2xl font-black text-sm">取消</button>
          </div>
        </div>
      </div>
    </div>
  );

  return (
    <div className="p-4 space-y-4 pb-32">
      <div className="px-1 mb-4 flex justify-between items-end">
        <div>
          <h2 className="text-2xl font-black text-gray-800">结算管理</h2>
          <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">Manage your sessions</p>
        </div>
        <div className="flex gap-2">
          <button onClick={() => setSortBy(sortBy === 'date' ? 'name' : 'date')} className="text-[10px] font-black px-3 py-1.5 bg-white border border-gray-100 rounded-full shadow-sm text-gray-500 active:bg-gray-50">
            {sortBy === 'date' ? '📅 时间' : '🔤 名称'}
          </button>
          <button onClick={() => setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc')} className="text-[10px] font-black px-2 py-1.5 bg-white border border-gray-100 rounded-full shadow-sm text-gray-500 active:bg-gray-50">
            {sortOrder === 'asc' ? '↑' : '↓'}
          </button>
        </div>
      </div>

      <div className="space-y-4">
        {sortedPeriods.map(period => {
          const isExpanded = expandedPeriodId === period.id;
          const totalIncome = period.sessions.reduce((acc, s) => acc + s.attendees.reduce((sum, a) => sum + a.fee, 0), 0);
          return (
            <div key={period.id} className={`bg-white rounded-[2rem] shadow-sm border border-gray-100 overflow-hidden transition-all ${isExpanded ? 'ring-2 ring-emerald-500/10 shadow-lg' : ''}`}>
              <div onClick={() => setExpandedPeriodId(isExpanded ? null : period.id)} className={`p-5 flex justify-between items-center cursor-pointer active:bg-gray-50 transition-colors ${isExpanded ? 'bg-emerald-50/20' : ''}`}>
                <div className="flex-1">
                  <div className="flex items-center gap-2 mb-1">
                    <h3 className="font-black text-gray-800 text-base">{period.name}</h3>
                    {(!period.endDate) && (
                      <span className="text-[8px] bg-emerald-500 text-white px-1.5 py-0.5 rounded-full font-black animate-pulse">进行中</span>
                    )}
                  </div>
                  <p className="text-[10px] text-gray-400 font-bold">{period.startDate} ~ {period.endDate || '至今'}</p>
                </div>
                <div className="flex items-center gap-4">
                   <div className="text-right">
                      <p className="text-[9px] text-gray-400 font-black">场次</p>
                      <p className="font-black text-emerald-600">{period.sessions.length}</p>
                   </div>
                   <div className={`transition-transform duration-300 ${isExpanded ? 'rotate-180 text-emerald-500' : 'text-gray-300'}`}>
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M19 9l-7 7-7-7" /></svg>
                  </div>
                </div>
              </div>

              {isExpanded && (
                <div className="p-5 bg-gray-50/30 border-t border-gray-50 space-y-6 animate-fade-in">
                  <div className="grid grid-cols-2 gap-3">
                    <div className="bg-white p-4 rounded-2xl border border-gray-100">
                      <p className="text-[9px] font-black text-gray-400 uppercase mb-1">场地费总支</p>
                      <p className="text-lg font-black text-red-500">¥{period.courtCost + period.sessions.reduce((a,s) => a+(s.sessionCost||0), 0)}</p>
                    </div>
                    <div className="bg-white p-4 rounded-2xl border border-gray-100">
                      <p className="text-[9px] font-black text-gray-400 uppercase mb-1">累计采集收入</p>
                      <p className="text-lg font-black text-emerald-600">¥{totalIncome}</p>
                    </div>
                  </div>
                  <div>
                    <div className="flex justify-between items-center mb-2 px-1">
                      <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">👑 集资名单</p>
                      <button onClick={(e) => { e.stopPropagation(); setEditingPeriodId(period.id); setPeriodFormData(period); }} className="text-[9px] text-emerald-600 font-black px-2 py-1 bg-emerald-50 rounded-lg">编辑周期</button>
                    </div>
                    <div className="flex flex-wrap gap-1.5 p-3 bg-white rounded-2xl border border-gray-100 shadow-sm">
                      {period.funderIds.map(fid => (
                        <span key={fid} className="text-[10px] bg-amber-50 text-amber-700 px-2.5 py-1 rounded-full font-black border border-amber-100">
                          {players.find(pl => pl.id === fid)?.name || '未知'}
                        </span>
                      ))}
                    </div>
                  </div>
                  <div className="pt-2">
                    <div className="flex justify-between items-center mb-3">
                      <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">🏸 打球流水</h4>
                      <button onClick={(e) => { e.stopPropagation(); setActiveSessionPeriod(period.id); setEditingSessionId(null); setSessionFormDate(new Date().toISOString().split('T')[0]); setSessionFormCost(0); setSelectedAttendees([]); }} className="text-[10px] bg-gray-900 text-white px-4 py-2 rounded-xl font-black active:scale-95">
                        + 录入单场
                      </button>
                    </div>
                    <div className="space-y-3">
                      {period.sessions.map(session => (
                        <div key={session.id} className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm">
                          <div className="flex justify-between items-center mb-2">
                             <div className="flex items-center gap-2">
                                <span className="text-xs font-black text-gray-800">{session.date}</span>
                                {session.sessionCost ? <span className="text-[8px] bg-red-100 text-red-600 px-1.5 py-0.5 rounded font-bold">加支 ¥{session.sessionCost}</span> : null}
                             </div>
                             <div className="flex gap-1">
                                <button onClick={(e) => { e.stopPropagation(); setActiveSessionPeriod(period.id); setEditingSessionId(session.id); setSessionFormDate(session.date); setSessionFormCost(session.sessionCost || 0); setSelectedAttendees(session.attendees); }} className="text-gray-300 p-1.5 active:text-emerald-500"><Icons.Pencil /></button>
                                <button onClick={(e) => handleRemoveSession(e, period.id, session.id)} className="text-gray-300 p-1.5 active:text-red-500"><Icons.Trash /></button>
                             </div>
                          </div>
                          <div className="flex flex-wrap gap-1">
                            {session.attendees.map(a => (
                              <span key={a.playerId} className="text-[9px] bg-gray-50 text-gray-500 px-2 py-0.5 rounded border border-gray-100">
                                {players.find(pl => pl.id === a.playerId)?.name} {a.fee > 0 ? `(¥${a.fee})` : ''}
                              </span>
                            ))}
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                  <div className="pt-4 border-t border-gray-100 flex justify-center">
                    <button 
                      onClick={(e) => handleConfirmDeletePeriod(e, period.id)}
                      className="text-[10px] text-red-300 font-bold flex items-center gap-1 active:scale-95 transition-transform"
                    >
                      <Icons.Trash /> 永久移除此周期
                    </button>
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>

      <button onClick={() => { setIsAddingPeriod(true); setEditingPeriodId(null); setPeriodFormData(initialPeriodData); }} className="fixed bottom-24 right-6 w-14 h-14 bg-emerald-600 text-white rounded-full flex items-center justify-center shadow-2xl shadow-emerald-400 z-50 active:scale-90 transition-transform">
        <Icons.Plus />
      </button>

      {isAddingPeriod && renderPeriodDrawer("创建结算周期", () => setIsAddingPeriod(false))}
      {editingPeriodId && renderPeriodDrawer("编辑周期配置", () => setEditingPeriodId(null))}
      {activeSessionPeriod && renderSessionForm(activeSessionPeriod)}
      {confirmDeletePeriodId && renderDeleteModal()}

      {periods.length === 0 && (
        <div className="text-center py-24 text-gray-300">
          <p className="text-5xl mb-4 opacity-10">🏸</p>
          <p className="text-sm font-black uppercase tracking-widest">尚未创建结算周期</p>
        </div>
      )}
    </div>
  );
};

export default PeriodsList;

import React, { useState, useMemo } from 'react';
import DatePicker from 'react-datepicker';
import { Period, Player, Session, PlayerType } from '../types';
import { Icons } from '../constants';

interface PeriodsListProps {
  periods: Period[];
  setPeriods: React.Dispatch<React.SetStateAction<Period[]>>;
  players: Player[];
  setPlayers: React.Dispatch<React.SetStateAction<Player[]>>;
}

const PeriodsList: React.FC<PeriodsListProps> = ({ periods, setPeriods, players, setPlayers }) => {
  const [isAddingPeriod, setIsAddingPeriod] = useState(false);
  const [editingPeriodId, setEditingPeriodId] = useState<string | null>(null);
  const [expandedPeriodId, setExpandedPeriodId] = useState<string | null>(null);
  const [activeSessionPeriod, setActiveSessionPeriod] = useState<string | null>(null);
  const [editingSessionId, setEditingSessionId] = useState<string | null>(null);
  const [confirmDeletePeriodId, setConfirmDeletePeriodId] = useState<string | null>(null);

  const [sortBy, setSortBy] = useState<'date' | 'name'>('date');
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('desc');

  const funderPool = players.filter(p => p.isFunder);

  const initialPeriodData = {
    name: '',
    startDate: new Date().toISOString().split('T')[0],
    endDate: '',
    courtCost: 0,
    funderIds: funderPool.map(p => p.id),
    sessions: []
  };

  const [periodFormData, setPeriodFormData] = useState<Partial<Period>>(initialPeriodData);
  const [sessionFormDate, setSessionFormDate] = useState(new Date().toISOString().split('T')[0]);
  const [sessionFormCost, setSessionFormCost] = useState<number>(0);
  const [selectedAttendees, setSelectedAttendees] = useState<{playerId: string, fee: number}[]>([]);

  const sortedPeriods = useMemo(() => {
    return [...periods].sort((a, b) => {
      let comparison = 0;
      if (sortBy === 'date') {
        comparison = a.startDate.localeCompare(b.startDate);
      } else {
        comparison = a.name.localeCompare(b.name, 'zh-CN');
      }
      return sortOrder === 'asc' ? comparison : -comparison;
    });
  }, [periods, sortBy, sortOrder]);

  const stringToDate = (str: string | undefined) => {
    if (!str) return null;
    return new Date(str);
  };

  const dateToString = (date: Date | null) => {
    if (!date) return '';
    return date.toISOString().split('T')[0];
  };

  // --- 周期管理核心逻辑 ---

  const handleSavePeriod = () => {
    if (!periodFormData.name) {
      alert('请输入周期名称');
      return;
    }
    const finalFunderIds = periodFormData.funderIds || [];
    setPlayers(prevPlayers => prevPlayers.map(p => {
      if (finalFunderIds.includes(p.id)) {
        return { ...p, type: PlayerType.MONTHLY };
      }
      return p;
    }));
    if (editingPeriodId) {
      setPeriods(prev => prev.map(p => p.id === editingPeriodId ? { ...p, ...periodFormData } as Period : p));
      setEditingPeriodId(null);
    } else {
      const period: Period = {
        id: Date.now().toString(),
        name: periodFormData.name!,
        startDate: periodFormData.startDate!,
        endDate: periodFormData.endDate || '',
        courtCost: periodFormData.courtCost || 0,
        funderIds: finalFunderIds,
        sessions: []
      };
      setPeriods(prev => [period, ...prev]);
      setIsAddingPeriod(false);
    }
    setPeriodFormData(initialPeriodData);
  };

  const handleConfirmDeletePeriod = (e: React.MouseEvent, periodId: string) => {
    e.preventDefault();
    e.stopPropagation();
    setConfirmDeletePeriodId(periodId);
  };

  const handleDeletePeriodConfirmed = () => {
    if (!confirmDeletePeriodId) return;
    setPeriods(prev => prev.filter(p => p.id !== confirmDeletePeriodId));
    setConfirmDeletePeriodId(null);
    if (expandedPeriodId === confirmDeletePeriodId) setExpandedPeriodId(null);
  };

  // --- 打球场次核心逻辑 ---

  const handleRemoveSession = (e: React.MouseEvent, periodId: string, sessionId: string) => {
    e.preventDefault();
    e.stopPropagation();
    if (confirm('核心提醒：确定要删除这条打球记录吗？该操作不可撤销。')) {
      setPeriods(prev => prev.map(p => {
        if (p.id === periodId) {
          return {
            ...p,
            sessions: p.sessions.filter(s => s.id !== sessionId)
          };
        }
        return p;
      }));
    }
  };

  const saveSession = (periodId: string) => {
    if (selectedAttendees.length === 0) {
      alert('请至少选择一名出席成员');
      return;
    }
    if (editingSessionId) {
      setPeriods(prev => prev.map(p => p.id === periodId ? {
        ...p,
        sessions: p.sessions.map(s => s.id === editingSessionId ? { ...s, date: sessionFormDate, sessionCost: sessionFormCost, attendees: selectedAttendees } : s)
      } : p));
    } else {
      const session: Session = {
        id: Date.now().toString(),
        date: sessionFormDate,
        sessionCost: sessionFormCost,
        attendees: selectedAttendees
      };
      setPeriods(prev => prev.map(p => {
        if (p.id === periodId) {
          const newSessions = [session, ...p.sessions].sort((a, b) => b.date.localeCompare(a.date));
          return { ...p, sessions: newSessions };
        }
        return p;
      }));
    }
    setActiveSessionPeriod(null);
    setEditingSessionId(null);
  };

  const toggleAttendee = (player: Player, periodId: string) => {
    const exists = selectedAttendees.find(a => a.playerId === player.id);
    if (exists) {
      setSelectedAttendees(prev => prev.filter(a => a.playerId !== player.id));
    } else {
      const currentPeriod = periods.find(p => p.id === periodId);
      let defaultFee = player.defaultFee;
      if (player.type === PlayerType.MONTHLY && currentPeriod?.funderIds.includes(player.id)) {
        defaultFee = 0;
      }
      setSelectedAttendees(prev => [...prev, { playerId: player.id, fee: defaultFee }]);
    }
  };

  const updateAttendeeFee = (playerId: string, fee: number) => {
    setSelectedAttendees(prev => prev.map(a => a.playerId === playerId ? { ...a, fee } : a));
  };

  // --- 视图渲染辅助逻辑 ---

  const renderDeleteModal = () => {
    const period = periods.find(p => p.id === confirmDeletePeriodId);
    if (!period) return null;

    return (
      <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 animate-fade-in bg-black/60 backdrop-blur-md">
        <div className="w-full max-w-sm bg-white rounded-[2.5rem] p-8 shadow-2xl animate-fade-in">
          <div className="flex flex-col items-center text-center">
            <div className="w-16 h-16 bg-red-50 text-red-500 rounded-full flex items-center justify-center mb-4">
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
              </svg>
            </div>
            <h3 className="text-xl font-black text-gray-800 mb-2">确认删除周期？</h3>
            <div className="bg-red-50 rounded-2xl p-4 mb-6">
              <p className="text-xs text-red-600 font-bold leading-relaxed">
                删除周期 <span className="underline">"{period.name}"</span> 后，
                内部包含的 <span className="font-black">{period.sessions.length} 场打球记录</span> 将被永久清空。
              </p>
            </div>
          </div>
          <div className="flex flex-col gap-3">
            <button 
              onClick={handleDeletePeriodConfirmed} 
              className="w-full bg-red-600 text-white py-4 rounded-2xl font-black text-base shadow-lg shadow-red-200 active:scale-95 transition-all"
            >
              确认永久删除
            </button>
            <button 
              onClick={() => setConfirmDeletePeriodId(null)} 
              className="w-full bg-gray-100 text-gray-500 py-4 rounded-2xl font-black text-sm active:bg-gray-200"
            >
              取消
            </button>
          </div>
        </div>
      </div>
    );
  };

  const renderPeriodDrawer = (title: string, onCancel: () => void) => (
    <div className="fixed inset-0 z-[100] flex items-end justify-center animate-fade-in bg-black/40 backdrop-blur-[2px]">
      <div 
        className="w-full max-w-md bg-white rounded-t-[2.5rem] shadow-2xl p-6 pb-safe animate-slide-up overflow-y-auto max-h-[90vh]"
        onClick={e => e.stopPropagation()}
      >
        <div className="w-12 h-1.5 bg-gray-200 rounded-full mx-auto mb-6"></div>
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-xl font-black text-gray-800">{title}</h3>
          <button onClick={onCancel} className="text-gray-300 p-2 active:bg-gray-100 rounded-full">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>
        <div className="space-y-5">
          <div>
            <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">周期名称</label>
            <input type="text" placeholder="例如：2025年3月集资" value={periodFormData.name} onChange={e => setPeriodFormData({...periodFormData, name: e.target.value})} className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold focus:ring-2 focus:ring-emerald-500 outline-none" />
          </div>
          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">开始日期</label>
              <DatePicker selected={stringToDate(periodFormData.startDate)} onChange={(date) => setPeriodFormData({...periodFormData, startDate: dateToString(date)})} dateFormat="yyyy-MM-dd" className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold outline-none" />
            </div>
            <div>
              <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">结束日期 (选填)</label>
              <DatePicker selected={stringToDate(periodFormData.endDate)} onChange={(date) => setPeriodFormData({...periodFormData, endDate: dateToString(date)})} dateFormat="yyyy-MM-dd" placeholderText="进行中..." className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold outline-none" isClearable />
            </div>
          </div>
          <div className="bg-red-50 p-4 rounded-2xl border border-red-100">
            <label className="block text-[10px] font-black text-red-800 uppercase tracking-widest mb-1 ml-1">本周期预付场地费</label>
            <div className="relative flex items-center">
              <span className="absolute left-4 text-red-300 font-bold italic">¥</span>
              <input type="number" placeholder="0.00" value={periodFormData.courtCost || ''} onChange={e => setPeriodFormData({...periodFormData, courtCost: Number(e.target.value)})} className="w-full bg-transparent border-none p-0 pl-8 text-2xl font-black text-red-600 outline-none focus:ring-0" />
            </div>
          </div>
          <div className="bg-amber-50 p-4 rounded-2xl border border-amber-100">
            <p className="text-[10px] font-black text-amber-800 uppercase tracking-widest mb-3 flex justify-between items-center">
              <span>👑 确认集资名单 ({periodFormData.funderIds?.length || 0})</span>
            </p>
            <div className="grid grid-cols-3 gap-2">
              {funderPool.map(f => {
                const isSelected = periodFormData.funderIds?.includes(f.id);
                return (
                  <button key={f.id} type="button" onClick={() => {
                    const current = periodFormData.funderIds || [];
                    setPeriodFormData({...periodFormData, funderIds: current.includes(f.id) ? current.filter(id => id !== f.id) : [...current, f.id]});
                  }} className={`text-[10px] py-2.5 rounded-xl border transition-all font-black ${isSelected ? 'bg-amber-500 border-amber-600 text-white shadow-md' : 'bg-white border-amber-100 text-amber-200'}`}>
                    {f.name}
                  </button>
                )
              })}
            </div>
          </div>
          <div className="flex gap-3 pt-2">
            <button onClick={handleSavePeriod} className="flex-[2] bg-emerald-600 text-white py-4 rounded-2xl font-black text-base shadow-lg shadow-emerald-200 active:scale-95 transition-all">保存周期配置</button>
            <button onClick={onCancel} className="flex-1 bg-gray-100 text-gray-500 py-4 rounded-2xl font-black text-sm active:bg-gray-200">取消</button>
          </div>
        </div>
      </div>
    </div>
  );

  const renderSessionForm = (periodId: string) => {
    const currentSubtotal = selectedAttendees.reduce((sum, a) => sum + a.fee, 0);

    return (
      <div className="fixed inset-0 z-[120] flex items-center justify-center p-6 animate-fade-in bg-black/60 backdrop-blur-sm">
        <div className="w-full max-w-sm bg-white rounded-[2.5rem] p-6 shadow-2xl animate-fade-in max-h-[90vh] overflow-y-auto">
          <h3 className="text-lg font-black text-gray-800 mb-6">{editingSessionId ? '✏️ 编辑打球记录' : '✨ 录入打球记录'}</h3>
          <div className="space-y-6">
            <div className="grid grid-cols-2 gap-3">
               <div>
                  <label className="block text-[10px] font-black text-gray-400 mb-1">活动日期</label>
                  <DatePicker selected={stringToDate(sessionFormDate)} onChange={(date) => setSessionFormDate(dateToString(date))} dateFormat="yyyy-MM-dd" className="w-full bg-gray-50 border border-gray-100 rounded-xl p-3 text-sm font-bold outline-none" />
               </div>
               <div>
                  <label className="block text-[10px] font-black text-gray-400 mb-1">额外费用(支)</label>
                  <input type="number" value={sessionFormCost || ''} onChange={e => setSessionFormCost(Number(e.target.value))} className="w-full bg-gray-50 border border-gray-100 rounded-xl p-3 text-sm font-bold outline-none text-red-500" placeholder="0.00" />
               </div>
            </div>

            <div>
              <p className="text-[10px] font-black text-gray-400 mb-2 uppercase tracking-widest">第一步：选择出席成员 ({selectedAttendees.length}):</p>
              <div className="flex flex-wrap gap-1.5 p-3 bg-gray-50 rounded-2xl border border-gray-100">
                {players.map(p => {
                  const isSelected = selectedAttendees.find(a => a.playerId === p.id);
                  return (
                    <button key={p.id} onClick={() => toggleAttendee(p, periodId)} className={`text-[10px] px-3 py-2 rounded-xl font-black transition-all border ${isSelected ? 'bg-emerald-600 border-emerald-700 text-white shadow-md' : 'bg-white border-gray-100 text-gray-400'}`}>
                      {p.name}
                    </button>
                  );
                })}
              </div>
            </div>

            {selectedAttendees.length > 0 && (
              <div>
                <p className="text-[10px] font-black text-gray-400 mb-2 uppercase tracking-widest">第二步：设置实收金额 (¥):</p>
                <div className="space-y-2 max-h-48 overflow-y-auto pr-1">
                  {selectedAttendees.map(attendee => {
                    const player = players.find(p => p.id === attendee.playerId);
                    return (
                      <div key={attendee.playerId} className="flex justify-between items-center bg-gray-50 p-2 rounded-xl border border-gray-100">
                        <span className="text-xs font-bold text-gray-700 ml-2">{player?.name}</span>
                        <div className="flex items-center gap-2">
                          <span className="text-[10px] text-gray-400 italic">实收 ¥</span>
                          <input 
                            type="number" 
                            value={attendee.fee} 
                            onChange={(e) => updateAttendeeFee(attendee.playerId, Number(e.target.value))}
                            className="w-16 bg-white border border-gray-200 rounded-lg p-1.5 text-xs font-black text-emerald-600 outline-none focus:ring-1 focus:ring-emerald-400"
                          />
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}

            <div className="bg-emerald-50 p-4 rounded-2xl border border-emerald-100">
               <div className="flex justify-between items-center">
                 <span className="text-[10px] font-black text-emerald-800 uppercase">本场预计实收:</span>
                 <span className="text-xl font-black text-emerald-600">¥{currentSubtotal.toFixed(2)}</span>
               </div>
            </div>

            <div className="flex gap-3 pt-2">
              <button onClick={() => saveSession(periodId)} className="flex-[2] bg-emerald-600 text-white py-4 rounded-2xl font-black text-sm active:scale-95 shadow-lg shadow-emerald-100">确认录入</button>
              <button onClick={() => { setActiveSessionPeriod(null); setEditingSessionId(null); }} className="flex-1 bg-gray-100 text-gray-500 py-4 rounded-2xl font-black text-sm">取消</button>
            </div>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="p-4 space-y-4 pb-32">
      <div className="px-1 mb-4 flex justify-between items-end">
        <div>
          <h2 className="text-2xl font-black text-gray-800">结算管理</h2>
          <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">Manage your sessions</p>
        </div>
        <div className="flex gap-2">
          <button onClick={() => setSortBy(sortBy === 'date' ? 'name' : 'date')} className="text-[10px] font-black px-3 py-1.5 bg-white border border-gray-100 rounded-full shadow-sm text-gray-500 active:bg-gray-50">
            {sortBy === 'date' ? '📅 时间' : '🔤 名称'}
          </button>
          <button onClick={() => setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc')} className="text-[10px] font-black px-2 py-1.5 bg-white border border-gray-100 rounded-full shadow-sm text-gray-500 active:bg-gray-50">
            {sortOrder === 'asc' ? '↑' : '↓'}
          </button>
        </div>
      </div>

      <div className="space-y-4">
        {sortedPeriods.map(period => {
          const isExpanded = expandedPeriodId === period.id;
          const totalIncome = period.sessions.reduce((acc, s) => acc + s.attendees.reduce((sum, a) => sum + a.fee, 0), 0);
          return (
            <div key={period.id} className={`bg-white rounded-[2rem] shadow-sm border border-gray-100 overflow-hidden transition-all ${isExpanded ? 'ring-2 ring-emerald-500/10 shadow-lg' : ''}`}>
              <div onClick={() => setExpandedPeriodId(isExpanded ? null : period.id)} className={`p-5 flex justify-between items-center cursor-pointer active:bg-gray-50 transition-colors ${isExpanded ? 'bg-emerald-50/20' : ''}`}>
                <div className="flex-1">
                  <div className="flex items-center gap-2 mb-1">
                    <h3 className="font-black text-gray-800 text-base">{period.name}</h3>
                    {(!period.endDate) && (
                      <span className="text-[8px] bg-emerald-500 text-white px-1.5 py-0.5 rounded-full font-black animate-pulse">进行中</span>
                    )}
                  </div>
                  <p className="text-[10px] text-gray-400 font-bold">{period.startDate} ~ {period.endDate || '至今'}</p>
                </div>
                <div className="flex items-center gap-4">
                   <div className="text-right">
                      <p className="text-[9px] text-gray-400 font-black">场次</p>
                      <p className="font-black text-emerald-600">{period.sessions.length}</p>
                   </div>
                   <div className={`transition-transform duration-300 ${isExpanded ? 'rotate-180 text-emerald-500' : 'text-gray-300'}`}>
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M19 9l-7 7-7-7" /></svg>
                  </div>
                </div>
              </div>

              {isExpanded && (
                <div className="p-5 bg-gray-50/30 border-t border-gray-50 space-y-6 animate-fade-in">
                  <div className="grid grid-cols-2 gap-3">
                    <div className="bg-white p-4 rounded-2xl border border-gray-100">
                      <p className="text-[9px] font-black text-gray-400 uppercase mb-1">场地费总支</p>
                      <p className="text-lg font-black text-red-500">¥{period.courtCost + period.sessions.reduce((a,s) => a+(s.sessionCost||0), 0)}</p>
                    </div>
                    <div className="bg-white p-4 rounded-2xl border border-gray-100">
                      <p className="text-[9px] font-black text-gray-400 uppercase mb-1">累计采集收入</p>
                      <p className="text-lg font-black text-emerald-600">¥{totalIncome}</p>
                    </div>
                  </div>
                  <div>
                    <div className="flex justify-between items-center mb-2 px-1">
                      <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">👑 集资名单</p>
                      <button onClick={(e) => { e.stopPropagation(); setEditingPeriodId(period.id); setPeriodFormData(period); }} className="text-[9px] text-emerald-600 font-black px-2 py-1 bg-emerald-50 rounded-lg">编辑周期</button>
                    </div>
                    <div className="flex flex-wrap gap-1.5 p-3 bg-white rounded-2xl border border-gray-100 shadow-sm">
                      {period.funderIds.map(fid => (
                        <span key={fid} className="text-[10px] bg-amber-50 text-amber-700 px-2.5 py-1 rounded-full font-black border border-amber-100">
                          {players.find(pl => pl.id === fid)?.name || '未知'}
                        </span>
                      ))}
                    </div>
                  </div>
                  <div className="pt-2">
                    <div className="flex justify-between items-center mb-3">
                      <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">🏸 打球流水</h4>
                      <button 
                        onClick={(e) => { 
                          e.stopPropagation(); 
                          setActiveSessionPeriod(period.id); 
                          setEditingSessionId(null); 
                          setSessionFormDate(new Date().toISOString().split('T')[0]); 
                          setSessionFormCost(0); 
                          setSelectedAttendees([]); 
                        }} 
                        className="text-[12px] bg-emerald-600 text-white px-5 py-2.5 rounded-xl font-black active:scale-95 shadow-lg shadow-emerald-100"
                      >
                        录入打球记录
                      </button>
                    </div>
                    <div className="space-y-3">
                      {period.sessions.map(session => (
                        <div key={session.id} className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm">
                          <div className="flex justify-between items-center mb-2">
                             <div className="flex items-center gap-2">
                                <span className="text-xs font-black text-gray-800">{session.date}</span>
                                {session.sessionCost ? <span className="text-[8px] bg-red-100 text-red-600 px-1.5 py-0.5 rounded font-bold">加支 ¥{session.sessionCost}</span> : null}
                             </div>
                             <div className="flex gap-1">
                                <button onClick={(e) => { e.stopPropagation(); setActiveSessionPeriod(period.id); setEditingSessionId(session.id); setSessionFormDate(session.date); setSessionFormCost(session.sessionCost || 0); setSelectedAttendees(session.attendees); }} className="text-gray-300 p-1.5 active:text-emerald-500"><Icons.Pencil /></button>
                                <button onClick={(e) => handleRemoveSession(e, period.id, session.id)} className="text-gray-300 p-1.5 active:text-red-500"><Icons.Trash /></button>
                             </div>
                          </div>
                          <div className="flex flex-wrap gap-1">
                            {session.attendees.map(a => (
                              <span key={a.playerId} className="text-[9px] bg-gray-50 text-gray-500 px-2 py-0.5 rounded border border-gray-100">
                                {players.find(pl => pl.id === a.playerId)?.name} {a.fee > 0 ? `(¥${a.fee})` : ''}
                              </span>
                            ))}
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                  <div className="pt-4 border-t border-gray-100 flex justify-center">
                    <button 
                      onClick={(e) => handleConfirmDeletePeriod(e, period.id)}
                      className="text-[10px] text-red-300 font-bold flex items-center gap-1 active:scale-95 transition-transform"
                    >
                      <Icons.Trash /> 永久移除此周期
                    </button>
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>

      <button onClick={() => { setIsAddingPeriod(true); setEditingPeriodId(null); setPeriodFormData(initialPeriodData); }} className="fixed bottom-24 right-6 w-14 h-14 bg-emerald-600 text-white rounded-full flex items-center justify-center shadow-2xl shadow-emerald-400 z-50 active:scale-90 transition-transform">
        <Icons.Plus />
      </button>

      {isAddingPeriod && renderPeriodDrawer("创建结算周期", () => setIsAddingPeriod(false))}
      {editingPeriodId && renderPeriodDrawer("编辑周期配置", () => setEditingPeriodId(null))}
      {activeSessionPeriod && renderSessionForm(activeSessionPeriod)}
      {confirmDeletePeriodId && renderDeleteModal()}

      {periods.length === 0 && (
        <div className="text-center py-24 text-gray-300">
          <p className="text-5xl mb-4 opacity-10">🏸</p>
          <p className="text-sm font-black uppercase tracking-widest">尚未创建结算周期</p>
        </div>
      )}
    </div>
  );
};

export default PeriodsList;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Player, PlayerType, Period } from '../types';
import { Icons, DEFAULT_SESSION_FEE } from '../constants';

interface PlayersListProps {
  players: Player[];
  setPlayers: React.Dispatch<React.SetStateAction<Player[]>>;
  periods: Period[];
}

const PlayersList: React.FC<PlayersListProps> = ({ players, setPlayers, periods }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [formData, setFormData] = useState<Partial<Player>>({
    name: '',
    type: PlayerType.PER_SESSION,
    defaultFee: DEFAULT_SESSION_FEE,
    isFunder: false
  });

  const latestPeriod = useMemo(() => {
    return periods.length > 0 ? periods[periods.length - 1] : null;
  }, [periods]);

  useEffect(() => {
    if (confirmDeleteId) {
      const timer = setTimeout(() => setConfirmDeleteId(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [confirmDeleteId]);

  const handleSave = () => {
    if (!formData.name) return;
    if (editingId) {
      setPlayers(prev => prev.map(p => p.id === editingId ? { ...p, ...formData } as Player : p));
      setEditingId(null);
    } else {
      const newPlayer: Player = {
        id: Date.now().toString(),
        name: formData.name!,
        type: formData.type as PlayerType || PlayerType.PER_SESSION,
        defaultFee: formData.defaultFee !== undefined ? formData.defaultFee : (formData.type === PlayerType.PER_SESSION ? DEFAULT_SESSION_FEE : 0),
        isFunder: !!formData.isFunder
      };
      setPlayers(prev => [...prev, newPlayer]);
      setIsAdding(false);
    }
    setFormData({ name: '', type: PlayerType.PER_SESSION, defaultFee: DEFAULT_SESSION_FEE, isFunder: false });
  };

  const startEdit = (player: Player) => {
    setEditingId(player.id);
    setFormData(player);
    setIsAdding(false);
  };

  const handleDelete = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    e.preventDefault();
    if (confirmDeleteId === id) {
      setPlayers(prev => prev.filter(p => p.id !== id));
      setConfirmDeleteId(null);
    } else {
      setConfirmDeleteId(id);
    }
  };

  const isCurrentlyFunder = (playerId: string) => {
    return latestPeriod?.funderIds.includes(playerId) || false;
  };

  // --- CSV 功能模块 ---

  const downloadCSV = (content: string, fileName: string) => {
    const blob = new Blob(["\ufeff" + content], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", fileName);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const exportToCSV = () => {
    const headers = ['姓名', '类型(包月/包半月/按次)', '单次收费金额', '是否核心集资备选(是/否)'];
    const rows = players.map(p => [p.name, p.type, p.defaultFee, p.isFunder ? '是' : '否']);
    const csvContent = [headers, ...rows].map(e => e.join(",")).join("\n");
    downloadCSV(csvContent, `羽球成员名单_${new Date().toISOString().split('T')[0]}.csv`);
  };

  const downloadTemplate = () => {
    const headers = ['姓名', '类型(包月/包半月/按次)', '单次收费金额', '是否核心集资备选(是/否)'];
    const example = ['张三', '按次', '25', '否'];
    const csvContent = [headers, example].map(e => e.join(",")).join("\n");
    downloadCSV(csvContent, "成员导入模板.csv");
  };

  const importFromCSV = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      const text = event.target?.result as string;
      const lines = text.split(/\r?\n/);
      const newPlayers: Player[] = [];

      // 跳过表头
      for (let i = 1; i < lines.length; i++) {
        const line = lines[i].trim();
        if (!line) continue;

        // 处理 CSV 分隔（简单处理，不处理包含逗号的引号内容）
        const parts = line.split(',').map(s => s.trim());
        const [name, typeStr, feeStr, isFunderStr] = parts;

        if (!name) continue;

        let type = PlayerType.PER_SESSION;
        if (typeStr?.includes('包月')) type = PlayerType.MONTHLY;
        else if (typeStr?.includes('包半月')) type = PlayerType.HALF_MONTHLY;

        const isFunder = ['是', 'yes', 'true', '1'].includes(isFunderStr?.toLowerCase());

        newPlayers.push({
          id: `imp-${Date.now()}-${i}`,
          name: name,
          type: type,
          defaultFee: Number(feeStr) || 0,
          isFunder: isFunder
        });
      }

      if (newPlayers.length > 0) {
        if (confirm(`识别到 ${newPlayers.length} 个新成员，是否确认导入？\n提示：建议先导出当前名单备份。`)) {
          setPlayers(prev => [...prev, ...newPlayers]);
        }
      } else {
        alert('未能识别到有效的成员数据，请检查文件格式。');
      }
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsText(file);
  };

  const renderPlayerForm = (title: string) => (
    <div className="bg-white p-4 rounded-xl shadow-lg border-2 border-emerald-500 animate-in zoom-in-95 duration-200">
      <h3 className="font-bold mb-4 text-emerald-800 text-sm">{title}</h3>
      <div className="space-y-4">
        <div>
          <label className="block text-[10px] text-gray-400 mb-1 font-black uppercase tracking-widest">姓名</label>
          <input 
            type="text" 
            value={formData.name} 
            onChange={e => setFormData({ ...formData, name: e.target.value })} 
            className="w-full border border-gray-200 rounded-lg p-2 text-sm focus:ring-2 focus:ring-emerald-500 outline-none font-bold" 
            placeholder="请输入姓名" 
          />
        </div>
        <div className="grid grid-cols-2 gap-3">
          <div>
            <label className="block text-[10px] text-gray-400 mb-1 font-black uppercase tracking-widest">性质</label>
            <select 
              value={formData.type} 
              onChange={e => {
                const type = e.target.value as PlayerType;
                const fee = type === PlayerType.PER_SESSION ? DEFAULT_SESSION_FEE : (formData.defaultFee || 0);
                setFormData({ ...formData, type, defaultFee: fee });
              }} 
              className="w-full border border-gray-200 rounded-lg p-2 text-sm bg-gray-50 outline-none font-bold"
            >
              <option value={PlayerType.MONTHLY}>包月</option>
              <option value={PlayerType.HALF_MONTHLY}>包半月</option>
              <option value={PlayerType.PER_SESSION}>按次</option>
            </select>
          </div>
          <div>
            <label className="block text-[10px] text-gray-400 mb-1 font-black uppercase tracking-widest">单次(元)</label>
            <input 
              type="number" 
              value={formData.defaultFee} 
              onChange={e => setFormData({ ...formData, defaultFee: Number(e.target.value) })} 
              className="w-full border border-gray-200 rounded-lg p-2 text-sm outline-none font-mono font-bold" 
            />
          </div>
        </div>
        <div className="flex items-center gap-2 p-3 bg-amber-50 rounded-xl border border-amber-100">
          <input 
            type="checkbox" 
            checked={formData.isFunder} 
            onChange={e => setFormData({ ...formData, isFunder: e.target.checked })} 
            id="isFunder" 
            className="w-5 h-5 text-amber-600 rounded-md border-amber-300 focus:ring-amber-500" 
          />
          <label htmlFor="isFunder" className="text-[10px] font-bold text-amber-800 cursor-pointer select-none leading-tight">
            核心集资备选人<br/>
            <span className="font-normal opacity-70">开启后，可勾选为此周期的预付包月人</span>
          </label>
        </div>
        <div className="flex gap-2 pt-2">
          <button type="button" onClick={handleSave} className="flex-1 bg-emerald-600 text-white py-2.5 rounded-lg font-black text-sm shadow-md active:scale-95 transition-all">保存</button>
          <button type="button" onClick={() => { setIsAdding(false); setEditingId(null); }} className="flex-1 bg-gray-100 text-gray-500 py-2.5 rounded-lg font-bold text-sm">取消</button>
        </div>
      </div>
    </div>
  );

  return (
    <div className="p-4">
      <div className="flex justify-between items-center mb-6">
        <div>
          <h2 className="text-xl font-black text-gray-800">成员档案</h2>
          <p className="text-[9px] text-gray-400 font-bold uppercase tracking-widest">MEMBER DIRECTORY</p>
        </div>
        <button 
          type="button"
          onClick={() => {
            setIsAdding(true);
            setEditingId(null);
            setFormData({ name: '', type: PlayerType.PER_SESSION, defaultFee: DEFAULT_SESSION_FEE, isFunder: false });
          }}
          className="bg-gray-900 text-white px-4 py-2 rounded-xl text-sm flex items-center gap-1 font-black shadow-lg shadow-gray-200 active:scale-95 transition-all"
        >
          <Icons.Plus /> 新增成员
        </button>
      </div>

      <div className="grid grid-cols-3 gap-2 mb-6">
        <button onClick={exportToCSV} className="flex flex-col items-center justify-center p-3 bg-white border border-gray-100 rounded-2xl shadow-sm active:bg-gray-50 group">
          <div className="text-emerald-500 mb-1 group-active:scale-110 transition-transform"><Icons.Download /></div>
          <span className="text-[10px] font-black text-gray-500">导出名单</span>
        </button>
        <button onClick={() => fileInputRef.current?.click()} className="flex flex-col items-center justify-center p-3 bg-white border border-gray-100 rounded-2xl shadow-sm active:bg-gray-50 group">
          <div className="text-blue-500 mb-1 group-active:scale-110 transition-transform"><Icons.Upload /></div>
          <span className="text-[10px] font-black text-gray-500">导入名单</span>
        </button>
        <button onClick={downloadTemplate} className="flex flex-col items-center justify-center p-3 bg-amber-50 border border-amber-100 rounded-2xl shadow-sm active:bg-amber-100 group">
          <div className="text-amber-600 mb-1 text-xs font-black">CSV</div>
          <span className="text-[10px] font-black text-amber-700">下载模板</span>
        </button>
        <input type="file" ref={fileInputRef} onChange={importFromCSV} accept=".csv" className="hidden" />
      </div>

      {isAdding && (
        <div className="mb-6">
          {renderPlayerForm("录入新成员")}
        </div>
      )}

      <div className="space-y-3">
        {players.map(player => {
          if (editingId === player.id) {
            return (
              <div key={player.id} className="animate-in slide-in-from-top-1 duration-200">
                {renderPlayerForm(`正在编辑: ${player.name}`)}
              </div>
            );
          }

          const activeFunder = isCurrentlyFunder(player.id);
          return (
            <div key={player.id} className={`bg-white p-4 rounded-2xl shadow-sm border flex justify-between items-center transition-all ${activeFunder ? 'border-amber-400 bg-amber-50/10 ring-1 ring-amber-400/20' : 'border-gray-100'}`}>
              <div className="flex-1">
                <div className="flex items-center gap-2">
                  <span className="font-black text-gray-800 text-base">{player.name}</span>
                  {activeFunder ? (
                    <span className="text-[9px] bg-amber-500 text-white px-2 py-0.5 rounded-full font-black shadow-sm flex items-center gap-0.5">
                      <span className="text-[11px]">👑</span> 本期集资
                    </span>
                  ) : player.isFunder ? (
                    <span className="text-[9px] bg-gray-100 text-gray-400 px-1.5 py-0.5 rounded font-black border border-gray-200">
                      备选
                    </span>
                  ) : null}
                </div>
                <div className="text-xs text-gray-500 mt-2 flex items-center gap-3">
                  <span className={`px-2 py-0.5 rounded font-black ${
                    player.type === PlayerType.MONTHLY ? 'bg-purple-100 text-purple-700' : 
                    player.type === PlayerType.HALF_MONTHLY ? 'bg-blue-100 text-blue-700' : 
                    'bg-green-100 text-green-700'
                  }`}>{player.type}</span>
                  <span className="font-mono font-black text-gray-700">¥{player.defaultFee}</span>
                </div>
              </div>
              <div className="flex gap-2 items-center">
                <button type="button" onClick={() => startEdit(player)} className="text-emerald-600 text-xs font-black bg-white border border-emerald-100 px-3 py-1.5 rounded-lg shadow-sm active:bg-emerald-50">编辑</button>
                <button 
                  type="button" 
                  onClick={(e) => handleDelete(e, player.id)} 
                  className={`transition-all p-2 rounded-xl flex items-center justify-center ${
                    confirmDeleteId === player.id 
                      ? 'bg-red-500 text-white w-20' 
                      : 'bg-red-50 text-red-500 w-10 active:bg-red-100'
                  }`}
                >
                  {confirmDeleteId === player.id ? <span className="text-[10px] font-black">确认?</span> : <Icons.Trash />}
                </button>
              </div>
            </div>
          );
        })}
      </div>

      {players.length === 0 && !isAdding && (
        <div className="text-center py-20 text-gray-300">
           <p className="text-4xl mb-4 opacity-20 text-emerald-500">🏸</p>
           <p className="text-sm font-black uppercase tracking-widest">暂无人员记录</p>
        </div>
      )}
    </div>
  );
};

export default PlayersList;

import React, { useState, useMemo } from 'react';
import DatePicker from 'react-datepicker';
import { Period, Player, Session, PlayerType } from '../types';
import { Icons } from '../constants';

interface PeriodsListProps {
  periods: Period[];
  setPeriods: React.Dispatch<React.SetStateAction<Period[]>>;
  players: Player[];
  setPlayers: React.Dispatch<React.SetStateAction<Player[]>>;
}

const PeriodsList: React.FC<PeriodsListProps> = ({ periods, setPeriods, players, setPlayers }) => {
  const [isAddingPeriod, setIsAddingPeriod] = useState(false);
  const [editingPeriodId, setEditingPeriodId] = useState<string | null>(null);
  const [expandedPeriodId, setExpandedPeriodId] = useState<string | null>(null);
  const [activeSessionPeriod, setActiveSessionPeriod] = useState<string | null>(null);
  const [editingSessionId, setEditingSessionId] = useState<string | null>(null);
  const [confirmDeletePeriodId, setConfirmDeletePeriodId] = useState<string | null>(null);

  const [sortBy, setSortBy] = useState<'date' | 'name'>('date');
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('desc');

  const funderPool = players.filter(p => p.isFunder);

  const initialPeriodData = {
    name: '',
    startDate: new Date().toISOString().split('T')[0],
    endDate: '',
    courtCost: 0,
    funderIds: funderPool.map(p => p.id),
    sessions: []
  };

  const [periodFormData, setPeriodFormData] = useState<Partial<Period>>(initialPeriodData);
  const [sessionFormDate, setSessionFormDate] = useState(new Date().toISOString().split('T')[0]);
  const [sessionFormCost, setSessionFormCost] = useState<number>(0);
  const [selectedAttendees, setSelectedAttendees] = useState<{playerId: string, fee: number}[]>([]);

  const sortedPeriods = useMemo(() => {
    return [...periods].sort((a, b) => {
      let comparison = 0;
      if (sortBy === 'date') {
        comparison = a.startDate.localeCompare(b.startDate);
      } else {
        comparison = a.name.localeCompare(b.name, 'zh-CN');
      }
      return sortOrder === 'asc' ? comparison : -comparison;
    });
  }, [periods, sortBy, sortOrder]);

  const stringToDate = (str: string | undefined) => {
    if (!str) return null;
    return new Date(str);
  };

  const dateToString = (date: Date | null) => {
    if (!date) return '';
    return date.toISOString().split('T')[0];
  };

  // --- 导出功能 ---

  const exportPeriodLedger = (period: Period) => {
    const headers = ['日期', '人员姓名', '实收金额(元)', '单场额外支出(元)'];
    const rows: string[][] = [];

    period.sessions.forEach(session => {
      session.attendees.forEach((a, idx) => {
        const playerName = players.find(p => p.id === a.playerId)?.name || '未知';
        // 只有该场次的第一行显示日期和额外支出，方便 Excel 统计
        rows.push([
          idx === 0 ? session.date : '',
          playerName,
          a.fee.toString(),
          idx === 0 ? (session.sessionCost || 0).toString() : ''
        ]);
      });
    });

    const csvContent = "\ufeff" + [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `${period.name}_流水记录.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // --- 周期管理核心逻辑 ---

  const handleSavePeriod = () => {
    if (!periodFormData.name) {
      alert('请输入周期名称');
      return;
    }
    const finalFunderIds = periodFormData.funderIds || [];
    setPlayers(prevPlayers => prevPlayers.map(p => {
      if (finalFunderIds.includes(p.id)) {
        return { ...p, type: PlayerType.MONTHLY };
      }
      return p;
    }));
    if (editingPeriodId) {
      setPeriods(prev => prev.map(p => p.id === editingPeriodId ? { ...p, ...periodFormData } as Period : p));
      setEditingPeriodId(null);
    } else {
      const period: Period = {
        id: Date.now().toString(),
        name: periodFormData.name!,
        startDate: periodFormData.startDate!,
        endDate: periodFormData.endDate || '',
        courtCost: periodFormData.courtCost || 0,
        funderIds: finalFunderIds,
        sessions: []
      };
      setPeriods(prev => [period, ...prev]);
      setIsAddingPeriod(false);
    }
    setPeriodFormData(initialPeriodData);
  };

  const handleConfirmDeletePeriod = (e: React.MouseEvent, periodId: string) => {
    e.preventDefault();
    e.stopPropagation();
    setConfirmDeletePeriodId(periodId);
  };

  const handleDeletePeriodConfirmed = () => {
    if (!confirmDeletePeriodId) return;
    setPeriods(prev => prev.filter(p => p.id !== confirmDeletePeriodId));
    setConfirmDeletePeriodId(null);
    if (expandedPeriodId === confirmDeletePeriodId) setExpandedPeriodId(null);
  };

  // --- 打球场次核心逻辑 ---

  const handleRemoveSession = (e: React.MouseEvent, periodId: string, sessionId: string) => {
    e.preventDefault();
    e.stopPropagation();
    if (confirm('核心提醒：确定要删除这条打球记录吗？该操作不可撤销。')) {
      setPeriods(prev => prev.map(p => {
        if (p.id === periodId) {
          return {
            ...p,
            sessions: p.sessions.filter(s => s.id !== sessionId)
          };
        }
        return p;
      }));
    }
  };

  const saveSession = (periodId: string) => {
    if (selectedAttendees.length === 0) {
      alert('请至少选择一名出席成员');
      return;
    }
    if (editingSessionId) {
      setPeriods(prev => prev.map(p => p.id === periodId ? {
        ...p,
        sessions: p.sessions.map(s => s.id === editingSessionId ? { ...s, date: sessionFormDate, sessionCost: sessionFormCost, attendees: selectedAttendees } : s)
      } : p));
    } else {
      const session: Session = {
        id: Date.now().toString(),
        date: sessionFormDate,
        sessionCost: sessionFormCost,
        attendees: selectedAttendees
      };
      setPeriods(prev => prev.map(p => {
        if (p.id === periodId) {
          const newSessions = [session, ...p.sessions].sort((a, b) => b.date.localeCompare(a.date));
          return { ...p, sessions: newSessions };
        }
        return p;
      }));
    }
    setActiveSessionPeriod(null);
    setEditingSessionId(null);
  };

  const toggleAttendee = (player: Player, periodId: string) => {
    const exists = selectedAttendees.find(a => a.playerId === player.id);
    if (exists) {
      setSelectedAttendees(prev => prev.filter(a => a.playerId !== player.id));
    } else {
      const currentPeriod = periods.find(p => p.id === periodId);
      let defaultFee = player.defaultFee;
      if (player.type === PlayerType.MONTHLY && currentPeriod?.funderIds.includes(player.id)) {
        defaultFee = 0;
      }
      setSelectedAttendees(prev => [...prev, { playerId: player.id, fee: defaultFee }]);
    }
  };

  const updateAttendeeFee = (playerId: string, fee: number) => {
    setSelectedAttendees(prev => prev.map(a => a.playerId === playerId ? { ...a, fee } : a));
  };

  // --- 视图渲染辅助逻辑 ---

  const renderDeleteModal = () => {
    const period = periods.find(p => p.id === confirmDeletePeriodId);
    if (!period) return null;

    return (
      <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 animate-fade-in bg-black/60 backdrop-blur-md">
        <div className="w-full max-w-sm bg-white rounded-[2.5rem] p-8 shadow-2xl animate-fade-in">
          <div className="flex flex-col items-center text-center">
            <div className="w-16 h-16 bg-red-50 text-red-500 rounded-full flex items-center justify-center mb-4">
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
              </svg>
            </div>
            <h3 className="text-xl font-black text-gray-800 mb-2">确认删除周期？</h3>
            <div className="bg-red-50 rounded-2xl p-4 mb-6">
              <p className="text-xs text-red-600 font-bold leading-relaxed">
                删除周期 <span className="underline">"{period.name}"</span> 后，
                内部包含的 <span className="font-black">{period.sessions.length} 场打球记录</span> 将被永久清空。
              </p>
            </div>
          </div>
          <div className="flex flex-col gap-3">
            <button 
              onClick={handleDeletePeriodConfirmed} 
              className="w-full bg-red-600 text-white py-4 rounded-2xl font-black text-base shadow-lg shadow-red-200 active:scale-95 transition-all"
            >
              确认永久删除
            </button>
            <button 
              onClick={() => setConfirmDeletePeriodId(null)} 
              className="w-full bg-gray-100 text-gray-500 py-4 rounded-2xl font-black text-sm active:bg-gray-200"
            >
              取消
            </button>
          </div>
        </div>
      </div>
    );
  };

  const renderPeriodDrawer = (title: string, onCancel: () => void) => (
    <div className="fixed inset-0 z-[100] flex items-end justify-center animate-fade-in bg-black/40 backdrop-blur-[2px]">
      <div 
        className="w-full max-w-md bg-white rounded-t-[2.5rem] shadow-2xl p-6 pb-safe animate-slide-up overflow-y-auto max-h-[90vh]"
        onClick={e => e.stopPropagation()}
      >
        <div className="w-12 h-1.5 bg-gray-200 rounded-full mx-auto mb-6"></div>
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-xl font-black text-gray-800">{title}</h3>
          <button onClick={onCancel} className="text-gray-300 p-2 active:bg-gray-100 rounded-full">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>
        <div className="space-y-5">
          <div>
            <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">周期名称</label>
            <input type="text" placeholder="例如：2025年3月集资" value={periodFormData.name} onChange={e => setPeriodFormData({...periodFormData, name: e.target.value})} className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold focus:ring-2 focus:ring-emerald-500 outline-none" />
          </div>
          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">开始日期</label>
              <DatePicker selected={stringToDate(periodFormData.startDate)} onChange={(date) => setPeriodFormData({...periodFormData, startDate: dateToString(date)})} dateFormat="yyyy-MM-dd" className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold outline-none" />
            </div>
            <div>
              <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">结束日期 (选填)</label>
              <DatePicker selected={stringToDate(periodFormData.endDate)} onChange={(date) => setPeriodFormData({...periodFormData, endDate: dateToString(date)})} dateFormat="yyyy-MM-dd" placeholderText="进行中..." className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold outline-none" isClearable />
            </div>
          </div>
          <div className="bg-red-50 p-4 rounded-2xl border border-red-100">
            <label className="block text-[10px] font-black text-red-800 uppercase tracking-widest mb-1 ml-1">本周期预付场地费</label>
            <div className="relative flex items-center">
              <span className="absolute left-4 text-red-300 font-bold italic">¥</span>
              <input type="number" placeholder="0.00" value={periodFormData.courtCost || ''} onChange={e => setPeriodFormData({...periodFormData, courtCost: Number(e.target.value)})} className="w-full bg-transparent border-none p-0 pl-8 text-2xl font-black text-red-600 outline-none focus:ring-0" />
            </div>
          </div>
          <div className="bg-amber-50 p-4 rounded-2xl border border-amber-100">
            <p className="text-[10px] font-black text-amber-800 uppercase tracking-widest mb-3 flex justify-between items-center">
              <span>👑 确认集资名单 ({periodFormData.funderIds?.length || 0})</span>
            </p>
            <div className="grid grid-cols-3 gap-2">
              {funderPool.map(f => {
                const isSelected = periodFormData.funderIds?.includes(f.id);
                return (
                  <button key={f.id} type="button" onClick={() => {
                    const current = periodFormData.funderIds || [];
                    setPeriodFormData({...periodFormData, funderIds: current.includes(f.id) ? current.filter(id => id !== f.id) : [...current, f.id]});
                  }} className={`text-[10px] py-2.5 rounded-xl border transition-all font-black ${isSelected ? 'bg-amber-500 border-amber-600 text-white shadow-md' : 'bg-white border-amber-100 text-amber-200'}`}>
                    {f.name}
                  </button>
                )
              })}
            </div>
          </div>
          <div className="flex gap-3 pt-2">
            <button onClick={handleSavePeriod} className="flex-[2] bg-emerald-600 text-white py-4 rounded-2xl font-black text-base shadow-lg shadow-emerald-200 active:scale-95 transition-all">保存周期配置</button>
            <button onClick={onCancel} className="flex-1 bg-gray-100 text-gray-500 py-4 rounded-2xl font-black text-sm active:bg-gray-200">取消</button>
          </div>
        </div>
      </div>
    </div>
  );

  const renderSessionForm = (periodId: string) => {
    const currentSubtotal = selectedAttendees.reduce((sum, a) => sum + a.fee, 0);

    return (
      <div className="fixed inset-0 z-[120] flex items-center justify-center p-6 animate-fade-in bg-black/60 backdrop-blur-sm">
        <div className="w-full max-w-sm bg-white rounded-[2.5rem] p-6 shadow-2xl animate-fade-in max-h-[90vh] overflow-y-auto">
          <h3 className="text-lg font-black text-gray-800 mb-6">{editingSessionId ? '✏️ 编辑打球记录' : '✨ 录入打球记录'}</h3>
          <div className="space-y-6">
            <div className="grid grid-cols-2 gap-3">
               <div>
                  <label className="block text-[10px] font-black text-gray-400 mb-1">活动日期</label>
                  <DatePicker selected={stringToDate(sessionFormDate)} onChange={(date) => setSessionFormDate(dateToString(date))} dateFormat="yyyy-MM-dd" className="w-full bg-gray-50 border border-gray-100 rounded-xl p-3 text-sm font-bold outline-none" />
               </div>
               <div>
                  <label className="block text-[10px] font-black text-gray-400 mb-1">额外费用(支)</label>
                  <input type="number" value={sessionFormCost || ''} onChange={e => setSessionFormCost(Number(e.target.value))} className="w-full bg-gray-50 border border-gray-100 rounded-xl p-3 text-sm font-bold outline-none text-red-500" placeholder="0.00" />
               </div>
            </div>

            <div>
              <p className="text-[10px] font-black text-gray-400 mb-2 uppercase tracking-widest">第一步：选择出席成员 ({selectedAttendees.length}):</p>
              <div className="flex flex-wrap gap-1.5 p-3 bg-gray-50 rounded-2xl border border-gray-100">
                {players.map(p => {
                  const isSelected = selectedAttendees.find(a => a.playerId === p.id);
                  return (
                    <button key={p.id} onClick={() => toggleAttendee(p, periodId)} className={`text-[10px] px-3 py-2 rounded-xl font-black transition-all border ${isSelected ? 'bg-emerald-600 border-emerald-700 text-white shadow-md' : 'bg-white border-gray-100 text-gray-400'}`}>
                      {p.name}
