                  <div className="pt-2">
                    <div className="flex justify-between items-center mb-3">
                      <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">🏸 打球流水</h4>
                      <div className="flex gap-2">
                        <button 
                          onClick={(e) => { e.stopPropagation(); exportPeriodLedger(period); }}
                          className="text-[10px] bg-white border border-gray-200 text-gray-500 px-3 py-2 rounded-xl font-black active:bg-gray-50 flex items-center gap-1 shadow-sm"
                        >
                          <Icons.Download /> 导出流水
                        </button>
                        <button 
                          onClick={(e) => { 
                            e.stopPropagation(); 
                            setActiveSessionPeriod(period.id); 
                            setEditingSessionId(null); 
                            setSessionFormDate(new Date().toISOString().split('T')[0]); 
                            setSessionFormCost(0); 
                            setSelectedAttendees([]); 
                          }} 
                          className="text-[10px] bg-emerald-600 text-white px-4 py-2 rounded-xl font-black active:scale-95 shadow-lg shadow-emerald-100"
                        >
                          录入记录
                        </button>
                      </div>
                    </div>
                    <div className="space-y-3">
                      {period.sessions.map(session => (
                        <div key={session.id} className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm">
                          <div className="flex justify-between items-center mb-2">
                             <div className="flex items-center gap-2">
                                <span className="text-xs font-black text-gray-800">{session.date}</span>
                                {session.sessionCost ? <span className="text-[8px] bg-red-100 text-red-600 px-1.5 py-0.5 rounded font-bold">加支 ¥{session.sessionCost}</span> : null}
                             </div>
                             <div className="flex gap-1">
                                <button onClick={(e) => { e.stopPropagation(); setActiveSessionPeriod(period.id); setEditingSessionId(session.id); setSessionFormDate(session.date); setSessionFormCost(session.sessionCost || 0); setSelectedAttendees(session.attendees); }} className="text-gray-300 p-1.5 active:text-emerald-500"><Icons.Pencil /></button>
                                <button onClick={(e) => handleRemoveSession(e, period.id, session.id)} className="text-gray-300 p-1.5 active:text-red-500"><Icons.Trash /></button>
                             </div>
                          </div>
                          <div className="flex flex-wrap gap-1">
                            {session.attendees.map(a => (
                              <span key={a.playerId} className="text-[9px] bg-gray-50 text-gray-500 px-2 py-0.5 rounded border border-gray-100">
                                {players.find(pl => pl.id === a.playerId)?.name} {a.fee > 0 ? `(¥${a.fee})` : ''}
                              </span>
                            ))}
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                  <div className="pt-4 border-t border-gray-100 flex justify-center">
                    <button 
                      onClick={(e) => handleConfirmDeletePeriod(e, period.id)}
                      className="text-[10px] text-red-300 font-bold flex items-center gap-1 active:scale-95 transition-transform"
                    >
                      <Icons.Trash /> 永久移除此周期
                    </button>
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>

      <button onClick={() => { setIsAddingPeriod(true); setEditingPeriodId(null); setPeriodFormData(initialPeriodData); }} className="fixed bottom-24 right-6 w-14 h-14 bg-emerald-600 text-white rounded-full flex items-center justify-center shadow-2xl shadow-emerald-400 z-50 active:scale-90 transition-transform">
        <Icons.Plus />
      </button>

      {isAddingPeriod && renderPeriodDrawer("创建结算周期", () => setIsAddingPeriod(false))}
      {editingPeriodId && renderPeriodDrawer("编辑周期配置", () => setEditingPeriodId(null))}
      {activeSessionPeriod && renderSessionForm(activeSessionPeriod)}
      {confirmDeletePeriodId && renderDeleteModal()}

      {periods.length === 0 && (
        <div className="text-center py-24 text-gray-300">
          <p className="text-5xl mb-4 opacity-10">🏸</p>
          <p className="text-sm font-black uppercase tracking-widest">尚未创建结算周期</p>
        </div>
      )}
    </div>
  );
};

export default PeriodsList;

import React, { useState, useMemo } from 'react';
import DatePicker from 'react-datepicker';
import { Period, Player, Session, PlayerType } from '../types';
import { Icons } from '../constants';

interface PeriodsListProps {
  periods: Period[];
  setPeriods: React.Dispatch<React.SetStateAction<Period[]>>;
  players: Player[];
  setPlayers: React.Dispatch<React.SetStateAction<Player[]>>;
}

const PeriodsList: React.FC<PeriodsListProps> = ({ periods, setPeriods, players, setPlayers }) => {
  const [isAddingPeriod, setIsAddingPeriod] = useState(false);
  const [editingPeriodId, setEditingPeriodId] = useState<string | null>(null);
  const [expandedPeriodId, setExpandedPeriodId] = useState<string | null>(null);
  const [activeSessionPeriod, setActiveSessionPeriod] = useState<string | null>(null);
  const [editingSessionId, setEditingSessionId] = useState<string | null>(null);
  const [confirmDeletePeriodId, setConfirmDeletePeriodId] = useState<string | null>(null);

  const [sortBy, setSortBy] = useState<'date' | 'name'>('date');
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('desc');

  const funderPool = players.filter(p => p.isFunder);

  const initialPeriodData = {
    name: '',
    startDate: new Date().toISOString().split('T')[0],
    endDate: '',
    courtCost: 0,
    funderIds: funderPool.map(p => p.id),
    sessions: []
  };

  const [periodFormData, setPeriodFormData] = useState<Partial<Period>>(initialPeriodData);
  const [sessionFormDate, setSessionFormDate] = useState(new Date().toISOString().split('T')[0]);
  const [sessionFormCost, setSessionFormCost] = useState<number>(0);
  const [selectedAttendees, setSelectedAttendees] = useState<{playerId: string, fee: number}[]>([]);

  const sortedPeriods = useMemo(() => {
    return [...periods].sort((a, b) => {
      let comparison = 0;
      if (sortBy === 'date') {
        comparison = a.startDate.localeCompare(b.startDate);
      } else {
        comparison = a.name.localeCompare(b.name, 'zh-CN');
      }
      return sortOrder === 'asc' ? comparison : -comparison;
    });
  }, [periods, sortBy, sortOrder]);

  const stringToDate = (str: string | undefined) => {
    if (!str) return null;
    return new Date(str);
  };

  const dateToString = (date: Date | null) => {
    if (!date) return '';
    return date.toISOString().split('T')[0];
  };

  // --- 导出功能 ---

  const exportPeriodLedger = (period: Period) => {
    const headers = ['日期', '人员姓名', '实收金额(元)', '单场额外支出(元)'];
    const rows: string[][] = [];

    period.sessions.forEach(session => {
      session.attendees.forEach((a, idx) => {
        const playerName = players.find(p => p.id === a.playerId)?.name || '未知';
        rows.push([
          idx === 0 ? session.date : '',
          playerName,
          a.fee.toString(),
          idx === 0 ? (session.sessionCost || 0).toString() : ''
        ]);
      });
    });

    const csvContent = "\ufeff" + [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `${period.name}_流水记录.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // --- 周期管理核心逻辑 ---

  const handleSavePeriod = () => {
    if (!periodFormData.name) {
      alert('请输入周期名称');
      return;
    }
    const finalFunderIds = periodFormData.funderIds || [];
    setPlayers(prevPlayers => prevPlayers.map(p => {
      if (finalFunderIds.includes(p.id)) {
        return { ...p, type: PlayerType.MONTHLY };
      }
      return p;
    }));
    if (editingPeriodId) {
      setPeriods(prev => prev.map(p => p.id === editingPeriodId ? { ...p, ...periodFormData } as Period : p));
      setEditingPeriodId(null);
    } else {
      const period: Period = {
        id: Date.now().toString(),
        name: periodFormData.name!,
        startDate: periodFormData.startDate!,
        endDate: periodFormData.endDate || '',
        courtCost: periodFormData.courtCost || 0,
        funderIds: finalFunderIds,
        sessions: []
      };
      setPeriods(prev => [period, ...prev]);
      setIsAddingPeriod(false);
    }
    setPeriodFormData(initialPeriodData);
  };

  const handleConfirmDeletePeriod = (e: React.MouseEvent, periodId: string) => {
    e.preventDefault();
    e.stopPropagation();
    setConfirmDeletePeriodId(periodId);
  };

  const handleDeletePeriodConfirmed = () => {
    if (!confirmDeletePeriodId) return;
    setPeriods(prev => prev.filter(p => p.id !== confirmDeletePeriodId));
    setConfirmDeletePeriodId(null);
    if (expandedPeriodId === confirmDeletePeriodId) setExpandedPeriodId(null);
  };

  // --- 打球场次核心逻辑 ---

  const handleRemoveSession = (e: React.MouseEvent, periodId: string, sessionId: string) => {
    e.preventDefault();
    e.stopPropagation();
    if (confirm('核心提醒：确定要删除这条打球记录吗？该操作不可撤销。')) {
      setPeriods(prev => prev.map(p => {
        if (p.id === periodId) {
          return {
            ...p,
            sessions: p.sessions.filter(s => s.id !== sessionId)
          };
        }
        return p;
      }));
    }
  };

  const saveSession = (periodId: string) => {
    if (selectedAttendees.length === 0) {
      alert('请至少选择一名出席成员');
      return;
    }
    if (editingSessionId) {
      setPeriods(prev => prev.map(p => p.id === periodId ? {
        ...p,
        sessions: p.sessions.map(s => s.id === editingSessionId ? { ...s, date: sessionFormDate, sessionCost: sessionFormCost, attendees: selectedAttendees } : s)
      } : p));
    } else {
      const session: Session = {
        id: Date.now().toString(),
        date: sessionFormDate,
        sessionCost: sessionFormCost,
        attendees: selectedAttendees
      };
      setPeriods(prev => prev.map(p => {
        if (p.id === periodId) {
          const newSessions = [session, ...p.sessions].sort((a, b) => b.date.localeCompare(a.date));
          return { ...p, sessions: newSessions };
        }
        return p;
      }));
    }
    setActiveSessionPeriod(null);
    setEditingSessionId(null);
  };

  const toggleAttendee = (player: Player, periodId: string) => {
    const exists = selectedAttendees.find(a => a.playerId === player.id);
    if (exists) {
      setSelectedAttendees(prev => prev.filter(a => a.playerId !== player.id));
    } else {
      const currentPeriod = periods.find(p => p.id === periodId);
      let defaultFee = player.defaultFee;

      // 核心判定逻辑：如果是包月或包半月人员，检查在当前周期的其他场次（不含当前正在编辑的场次）中是否已出现过
      if (player.type === PlayerType.MONTHLY || player.type === PlayerType.HALF_MONTHLY) {
        const alreadyRecorded = currentPeriod?.sessions.some(s => 
          s.id !== editingSessionId && 
          s.attendees.some(a => a.playerId === player.id)
        );

        if (alreadyRecorded) {
          // 如果在该周期其他场次已经出现过，则本场默认为 0
          defaultFee = 0;
        }
      }

      // 如果是集资名单里的人，默认也是 0（保留原有逻辑作为双重保障）
      if (player.type === PlayerType.MONTHLY && currentPeriod?.funderIds.includes(player.id)) {
        defaultFee = 0;
      }

      setSelectedAttendees(prev => [...prev, { playerId: player.id, fee: defaultFee }]);
    }
  };

  const updateAttendeeFee = (playerId: string, fee: number) => {
    setSelectedAttendees(prev => prev.map(a => a.playerId === playerId ? { ...a, fee } : a));
  };

  // --- 视图渲染辅助逻辑 ---

  const renderDeleteModal = () => {
    const period = periods.find(p => p.id === confirmDeletePeriodId);
    if (!period) return null;

    return (
      <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 animate-fade-in bg-black/60 backdrop-blur-md">
        <div className="w-full max-w-sm bg-white rounded-[2.5rem] p-8 shadow-2xl animate-fade-in">
          <div className="flex flex-col items-center text-center">
            <div className="w-16 h-16 bg-red-50 text-red-500 rounded-full flex items-center justify-center mb-4">
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
              </svg>
            </div>
            <h3 className="text-xl font-black text-gray-800 mb-2">确认删除周期？</h3>
            <div className="bg-red-50 rounded-2xl p-4 mb-6">
              <p className="text-xs text-red-600 font-bold leading-relaxed">
                删除周期 <span className="underline">"{period.name}"</span> 后，
                内部包含的 <span className="font-black">{period.sessions.length} 场打球记录</span> 将被永久清空。
              </p>
            </div>
          </div>
          <div className="flex flex-col gap-3">
            <button 
              onClick={handleDeletePeriodConfirmed} 
              className="w-full bg-red-600 text-white py-4 rounded-2xl font-black text-base shadow-lg shadow-red-200 active:scale-95 transition-all"
            >
              确认永久删除
            </button>
            <button 
              onClick={() => setConfirmDeletePeriodId(null)} 
              className="w-full bg-gray-100 text-gray-500 py-4 rounded-2xl font-black text-sm active:bg-gray-200"
            >
              取消
            </button>
          </div>
        </div>
      </div>
    );
  };

  const renderPeriodDrawer = (title: string, onCancel: () => void) => (
    <div className="fixed inset-0 z-[100] flex items-end justify-center animate-fade-in bg-black/40 backdrop-blur-[2px]">
      <div 
        className="w-full max-w-md bg-white rounded-t-[2.5rem] shadow-2xl p-6 pb-safe animate-slide-up overflow-y-auto max-h-[90vh]"
        onClick={e => e.stopPropagation()}
      >
        <div className="w-12 h-1.5 bg-gray-200 rounded-full mx-auto mb-6"></div>
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-xl font-black text-gray-800">{title}</h3>
          <button onClick={onCancel} className="text-gray-300 p-2 active:bg-gray-100 rounded-full">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>
        <div className="space-y-5">
          <div>
            <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">周期名称</label>
            <input type="text" placeholder="例如：2025年3月集资" value={periodFormData.name} onChange={e => setPeriodFormData({...periodFormData, name: e.target.value})} className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold focus:ring-2 focus:ring-emerald-500 outline-none" />
          </div>
          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">开始日期</label>
              <DatePicker selected={stringToDate(periodFormData.startDate)} onChange={(date) => setPeriodFormData({...periodFormData, startDate: dateToString(date)})} dateFormat="yyyy-MM-dd" className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold outline-none" />
            </div>
            <div>
              <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">结束日期 (选填)</label>
              <DatePicker selected={stringToDate(periodFormData.endDate)} onChange={(date) => setPeriodFormData({...periodFormData, endDate: dateToString(date)})} dateFormat="yyyy-MM-dd" placeholderText="进行中..." className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold outline-none" isClearable />
            </div>
          </div>
          <div className="bg-red-50 p-4 rounded-2xl border border-red-100">
            <label className="block text-[10px] font-black text-red-800 uppercase tracking-widest mb-1 ml-1">本周期预付场地费</label>
            <div className="relative flex items-center">
              <span className="absolute left-4 text-red-300 font-bold italic">¥</span>
              <input type="number" placeholder="0.00" value={periodFormData.courtCost || ''} onChange={e => setPeriodFormData({...periodFormData, courtCost: Number(e.target.value)})} className="w-full bg-transparent border-none p-0 pl-8 text-2xl font-black text-red-600 outline-none focus:ring-0" />
            </div>
          </div>
          <div className="bg-amber-50 p-4 rounded-2xl border border-amber-100">
            <p className="text-[10px] font-black text-amber-800 uppercase tracking-widest mb-3 flex justify-between items-center">
              <span>👑 确认集资名单 ({periodFormData.funderIds?.length || 0})</span>
            </p>
            <div className="grid grid-cols-3 gap-2">
              {funderPool.map(f => {
                const isSelected = periodFormData.funderIds?.includes(f.id);
                return (
                  <button key={f.id} type="button" onClick={() => {
                    const current = periodFormData.funderIds || [];
                    setPeriodFormData({...periodFormData, funderIds: current.includes(f.id) ? current.filter(id => id !== f.id) : [...current, f.id]});
                  }} className={`text-[10px] py-2.5 rounded-xl border transition-all font-black ${isSelected ? 'bg-amber-500 border-amber-600 text-white shadow-md' : 'bg-white border-amber-100 text-amber-200'}`}>
                    {f.name}
                  </button>
                )
              })}
            </div>
          </div>
          <div className="flex gap-3 pt-2">
            <button onClick={handleSavePeriod} className="flex-[2] bg-emerald-600 text-white py-4 rounded-2xl font-black text-base shadow-lg shadow-emerald-200 active:scale-95 transition-all">保存周期配置</button>
            <button onClick={onCancel} className="flex-1 bg-gray-100 text-gray-500 py-4 rounded-2xl font-black text-sm active:bg-gray-200">取消</button>
          </div>
        </div>
      </div>
    </div>
  );

  const renderSessionForm = (periodId: string) => {
    const currentSubtotal = selectedAttendees.reduce((sum, a) => sum + a.fee, 0);

    return (
      <div className="fixed inset-0 z-[120] flex items-center justify-center p-6 animate-fade-in bg-black/60 backdrop-blur-sm">
        <div className="w-full max-w-sm bg-white rounded-[2.5rem] p-6 shadow-2xl animate-fade-in max-h-[90vh] overflow-y-auto">
          <h3 className="text-lg font-black text-gray-800 mb-6">{editingSessionId ? '✏️ 编辑打球记录' : '✨ 录入打球记录'}</h3>
          <div className="space-y-6">
            <div className="grid grid-cols-2 gap-3">
               <div>
                  <label className="block text-[10px] font-black text-gray-400 mb-1">活动日期</label>
                  <DatePicker selected={stringToDate(sessionFormDate)} onChange={(date) => setSessionFormDate(dateToString(date))} dateFormat="yyyy-MM-dd" className="w-full bg-gray-50 border border-gray-100 rounded-xl p-3 text-sm font-bold outline-none" />
               </div>
               <div>
                  <label className="block text-[10px] font-black text-gray-400 mb-1">额外费用(支)</label>
                  <input type="number" value={sessionFormCost || ''} onChange={e => setSessionFormCost(Number(e.target.value))} className="w-full bg-gray-50 border border-gray-100 rounded-xl p-3 text-sm font-bold outline-none text-red-500" placeholder="0.00" />
               </div>
            </div>

            <div>
              <p className="text-[10px] font-black text-gray-400 mb-2 uppercase tracking-widest">第一步：选择出席成员 ({selectedAttendees.length}):</p>
              <div className="flex flex-wrap gap-1.5 p-3 bg-gray-50 rounded-2xl border border-gray-100">
                {players.map(p => {
                  const isSelected = selectedAttendees.find(a => a.playerId === p.id);
                  return (
                    <button key={p.id} onClick={() => toggleAttendee(p, periodId)} className={`text-[10px] px-3 py-2 rounded-xl font-black transition-all border ${isSelected ? 'bg-emerald-600 border-emerald-700 text-white shadow-md' : 'bg-white border-gray-100 text-gray-400'}`}>
                      {p.name}
                    </button>
                  );
                })}
              </div>
            </div>

            {selectedAttendees.length > 0 && (
              <div>
                <p className="text-[10px] font-black text-gray-400 mb-2 uppercase tracking-widest">第二步：设置实收金额 (¥):</p>
                <div className="space-y-2 max-h-48 overflow-y-auto pr-1">
                  {selectedAttendees.map(attendee => {
                    const player = players.find(p => p.id === attendee.playerId);
                    return (
                      <div key={attendee.playerId} className="flex justify-between items-center bg-gray-50 p-2 rounded-xl border border-gray-100">
                        <span className="text-xs font-bold text-gray-700 ml-2">{player?.name}</span>
                        <div className="flex items-center gap-2">
                          <span className="text-[10px] text-gray-400 italic">实收 ¥</span>
                          <input 
                            type="number" 
                            value={attendee.fee} 
                            onChange={(e) => updateAttendeeFee(attendee.playerId, Number(e.target.value))}
                            className="w-16 bg-white border border-gray-200 rounded-lg p-1.5 text-xs font-black text-emerald-600 outline-none focus:ring-1 focus:ring-emerald-400"
                          />
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}

            <div className="bg-emerald-50 p-4 rounded-2xl border border-emerald-100">
               <div className="flex justify-between items-center">
                 <span className="text-[10px] font-black text-emerald-800 uppercase">本场预计实收:</span>
                 <span className="text-xl font-black text-emerald-600">¥{currentSubtotal.toFixed(2)}</span>
               </div>
            </div>

            <div className="flex gap-3 pt-2">
              <button onClick={() => saveSession(periodId)} className="flex-[2] bg-emerald-600 text-white py-4 rounded-2xl font-black text-sm active:scale-95 shadow-lg shadow-emerald-100">确认录入</button>
              <button onClick={() => { setActiveSessionPeriod(null); setEditingSessionId(null); }} className="flex-1 bg-gray-100 text-gray-500 py-4 rounded-2xl font-black text-sm">取消</button>
            </div>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="p-4 space-y-4 pb-32">
      <div className="px-1 mb-4 flex justify-between items-end">
        <div>
          <h2 className="text-2xl font-black text-gray-800">结算管理</h2>
          <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">Manage your sessions</p>
        </div>
        <div className="flex gap-2">
          <button onClick={() => setSortBy(sortBy === 'date' ? 'name' : 'date')} className="text-[10px] font-black px-3 py-1.5 bg-white border border-gray-100 rounded-full shadow-sm text-gray-500 active:bg-gray-50">
            {sortBy === 'date' ? '📅 时间' : '🔤 名称'}
          </button>
          <button onClick={() => setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc')} className="text-[10px] font-black px-2 py-1.5 bg-white border border-gray-100 rounded-full shadow-sm text-gray-500 active:bg-gray-50">
            {sortOrder === 'asc' ? '↑' : '↓'}
          </button>
        </div>
      </div>

      <div className="space-y-4">
        {sortedPeriods.map(period => {
          const isExpanded = expandedPeriodId === period.id;
          const totalIncome = period.sessions.reduce((acc, s) => acc + s.attendees.reduce((sum, a) => sum + a.fee, 0), 0);
          return (
            <div key={period.id} className={`bg-white rounded-[2rem] shadow-sm border border-gray-100 overflow-hidden transition-all ${isExpanded ? 'ring-2 ring-emerald-500/10 shadow-lg' : ''}`}>
              <div onClick={() => setExpandedPeriodId(isExpanded ? null : period.id)} className={`p-5 flex justify-between items-center cursor-pointer active:bg-gray-50 transition-colors ${isExpanded ? 'bg-emerald-50/20' : ''}`}>
                <div className="flex-1">
                  <div className="flex items-center gap-2 mb-1">
                    <h3 className="font-black text-gray-800 text-base">{period.name}</h3>
                    {(!period.endDate) && (
                      <span className="text-[8px] bg-emerald-500 text-white px-1.5 py-0.5 rounded-full font-black animate-pulse">进行中</span>
                    )}
                  </div>
                  <p className="text-[10px] text-gray-400 font-bold">{period.startDate} ~ {period.endDate || '至今'}</p>
                </div>
                <div className="flex items-center gap-4">
                   <div className="text-right">
                      <p className="text-[9px] text-gray-400 font-black">场次</p>
                      <p className="font-black text-emerald-600">{period.sessions.length}</p>
                   </div>
                   <div className={`transition-transform duration-300 ${isExpanded ? 'rotate-180 text-emerald-500' : 'text-gray-300'}`}>
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M19 9l-7 7-7-7" /></svg>
                  </div>
                </div>
              </div>

              {isExpanded && (
                <div className="p-5 bg-gray-50/30 border-t border-gray-50 space-y-6 animate-fade-in">
                  <div className="grid grid-cols-2 gap-3">
                    <div className="bg-white p-4 rounded-2xl border border-gray-100">
                      <p className="text-[9px] font-black text-gray-400 uppercase mb-1">场地费总支</p>
                      <p className="text-lg font-black text-red-500">¥{(period.courtCost + period.sessions.reduce((a,s) => a+(s.sessionCost||0), 0)).toFixed(2)}</p>
                    </div>
                    <div className="bg-white p-4 rounded-2xl border border-gray-100">
                      <p className="text-[9px] font-black text-gray-400 uppercase mb-1">累计采集收入</p>
                      <p className="text-lg font-black text-emerald-600">¥{totalIncome.toFixed(2)}</p>
                    </div>
                  </div>
                  <div>
                    <div className="flex justify-between items-center mb-2 px-1">
                      <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">👑 集资名单</p>
                      <button onClick={(e) => { e.stopPropagation(); setEditingPeriodId(period.id); setPeriodFormData(period); }} className="text-[9px] text-emerald-600 font-black px-2 py-1 bg-emerald-50 rounded-lg">编辑周期</button>
                    </div>
                    <div className="flex flex-wrap gap-1.5 p-3 bg-white rounded-2xl border border-gray-100 shadow-sm">
                      {period.funderIds.map(fid => (
                        <span key={fid} className="text-[10px] bg-amber-50 text-amber-700 px-2.5 py-1 rounded-full font-black border border-amber-100">
                          {players.find(pl => pl.id === fid)?.name || '未知'}
                        </span>
                      ))}
                    </div>
                  </div>
                  <div className="pt-2">
                    <div className="flex justify-between items-center mb-3">
                      <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">🏸 打球流水</h4>
                      <div className="flex gap-2">
                        <button 
                          onClick={(e) => { e.stopPropagation(); exportPeriodLedger(period); }}
                          className="text-[10px] bg-white border border-gray-200 text-gray-500 px-3 py-2 rounded-xl font-black active:bg-gray-50 flex items-center gap-1 shadow-sm"
                        >
                          <Icons.Download /> 导出流水
                        </button>
                        <button 
                          onClick={(e) => { 
                            e.stopPropagation(); 
                            setActiveSessionPeriod(period.id); 
                            setEditingSessionId(null); 
                            setSessionFormDate(new Date().toISOString().split('T')[0]); 
                            setSessionFormCost(0); 
                            setSelectedAttendees([]); 
                          }} 
                          className="text-[10px] bg-emerald-600 text-white px-4 py-2 rounded-xl font-black active:scale-95 shadow-lg shadow-emerald-100"
                        >
                          录入记录
                        </button>
                      </div>
                    </div>
                    <div className="space-y-3">
                      {period.sessions.map(session => (
                        <div key={session.id} className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm">
                          <div className="flex justify-between items-center mb-2">
                             <div className="flex items-center gap-2">
                                <span className="text-xs font-black text-gray-800">{session.date}</span>
                                {session.sessionCost ? <span className="text-[8px] bg-red-100 text-red-600 px-1.5 py-0.5 rounded font-bold">加支 ¥{session.sessionCost}</span> : null}
                             </div>
                             <div className="flex gap-1">
                                <button onClick={(e) => { e.stopPropagation(); setActiveSessionPeriod(period.id); setEditingSessionId(session.id); setSessionFormDate(session.date); setSessionFormCost(session.sessionCost || 0); setSelectedAttendees(session.attendees); }} className="text-gray-300 p-1.5 active:text-emerald-500"><Icons.Pencil /></button>
                                <button onClick={(e) => handleRemoveSession(e, period.id, session.id)} className="text-gray-300 p-1.5 active:text-red-500"><Icons.Trash /></button>
                             </div>
                          </div>
                          <div className="flex flex-wrap gap-1">
                            {session.attendees.map(a => (
                              <span key={a.playerId} className="text-[9px] bg-gray-50 text-gray-500 px-2 py-0.5 rounded border border-gray-100">
                                {players.find(pl => pl.id === a.playerId)?.name} {a.fee > 0 ? `(¥${a.fee})` : ''}
                              </span>
                            ))}
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                  <div className="pt-4 border-t border-gray-100 flex justify-center">
                    <button 
                      onClick={(e) => handleConfirmDeletePeriod(e, period.id)}
                      className="text-[10px] text-red-300 font-bold flex items-center gap-1 active:scale-95 transition-transform"
                    >
                      <Icons.Trash /> 永久移除此周期
                    </button>
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>

      <button onClick={() => { setIsAddingPeriod(true); setEditingPeriodId(null); setPeriodFormData(initialPeriodData); }} className="fixed bottom-24 right-6 w-14 h-14 bg-emerald-600 text-white rounded-full flex items-center justify-center shadow-2xl shadow-emerald-400 z-50 active:scale-90 transition-transform">
        <Icons.Plus />
      </button>

      {isAddingPeriod && renderPeriodDrawer("创建结算周期", () => setIsAddingPeriod(false))}
      {editingPeriodId && renderPeriodDrawer("编辑周期配置", () => setEditingPeriodId(null))}
      {activeSessionPeriod && renderSessionForm(activeSessionPeriod)}
      {confirmDeletePeriodId && renderDeleteModal()}

      {periods.length === 0 && (
        <div className="text-center py-24 text-gray-300">
          <p className="text-5xl mb-4 opacity-10">🏸</p>
          <p className="text-sm font-black uppercase tracking-widest">尚未创建结算周期</p>
        </div>
      )}
    </div>
  );
};

export default PeriodsList;

import React, { useState, useMemo, useEffect } from 'react';
import DatePicker from 'react-datepicker';
import { Period, Player, Session, PlayerType } from '../types';
import { Icons } from '../constants';

interface PeriodsListProps {
  periods: Period[];
  setPeriods: React.Dispatch<React.SetStateAction<Period[]>>;
  players: Player[];
  setPlayers: React.Dispatch<React.SetStateAction<Player[]>>;
}

const PeriodsList: React.FC<PeriodsListProps> = ({ periods, setPeriods, players, setPlayers }) => {
  const [isAddingPeriod, setIsAddingPeriod] = useState(false);
  const [editingPeriodId, setEditingPeriodId] = useState<string | null>(null);
  const [expandedPeriodId, setExpandedPeriodId] = useState<string | null>(null);
  const [activeSessionPeriod, setActiveSessionPeriod] = useState<string | null>(null);
  const [editingSessionId, setEditingSessionId] = useState<string | null>(null);
  const [confirmDeletePeriodId, setConfirmDeletePeriodId] = useState<string | null>(null);
  const [sessionConfirmDeleteId, setSessionConfirmDeleteId] = useState<string | null>(null);

  const [sortBy, setSortBy] = useState<'date' | 'name'>('date');
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('desc');

  const funderPool = players.filter(p => p.isFunder);

  const initialPeriodData = {
    name: '',
    startDate: new Date().toISOString().split('T')[0],
    endDate: '',
    courtCost: 0,
    funderIds: funderPool.map(p => p.id),
    sessions: []
  };

  const [periodFormData, setPeriodFormData] = useState<Partial<Period>>(initialPeriodData);
  const [sessionFormDate, setSessionFormDate] = useState(new Date().toISOString().split('T')[0]);
  const [sessionFormCost, setSessionFormCost] = useState<number>(0);
  const [selectedAttendees, setSelectedAttendees] = useState<{playerId: string, fee: number}[]>([]);

  // 自动重置场次删除确认状态
  useEffect(() => {
    if (sessionConfirmDeleteId) {
      const timer = setTimeout(() => setSessionConfirmDeleteId(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [sessionConfirmDeleteId]);

  const sortedPeriods = useMemo(() => {
    return [...periods].sort((a, b) => {
      let comparison = 0;
      if (sortBy === 'date') {
        comparison = a.startDate.localeCompare(b.startDate);
      } else {
        comparison = a.name.localeCompare(b.name, 'zh-CN');
      }
      return sortOrder === 'asc' ? comparison : -comparison;
    });
  }, [periods, sortBy, sortOrder]);

  const stringToDate = (str: string | undefined) => {
    if (!str) return null;
    return new Date(str);
  };

  const dateToString = (date: Date | null) => {
    if (!date) return '';
    return date.toISOString().split('T')[0];
  };

  // --- 导出功能 ---

  const exportPeriodLedger = (period: Period) => {
    const headers = ['日期', '人员姓名', '实收金额(元)', '单场额外支出(元)'];
    const rows: string[][] = [];

    period.sessions.forEach(session => {
      session.attendees.forEach((a, idx) => {
        const playerName = players.find(p => p.id === a.playerId)?.name || '未知';
        rows.push([
          idx === 0 ? session.date : '',
          playerName,
          a.fee.toString(),
          idx === 0 ? (session.sessionCost || 0).toString() : ''
        ]);
      });
    });

    const csvContent = "\ufeff" + [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `${period.name}_流水记录.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // --- 周期管理核心逻辑 ---

  const handleSavePeriod = () => {
    if (!periodFormData.name) {
      alert('请输入周期名称');
      return;
    }
    const finalFunderIds = periodFormData.funderIds || [];
    setPlayers(prevPlayers => prevPlayers.map(p => {
      if (finalFunderIds.includes(p.id)) {
        return { ...p, type: PlayerType.MONTHLY };
      }
      return p;
    }));
    if (editingPeriodId) {
      setPeriods(prev => prev.map(p => p.id === editingPeriodId ? { ...p, ...periodFormData } as Period : p));
      setEditingPeriodId(null);
    } else {
      const period: Period = {
        id: Date.now().toString(),
        name: periodFormData.name!,
        startDate: periodFormData.startDate!,
        endDate: periodFormData.endDate || '',
        courtCost: periodFormData.courtCost || 0,
        funderIds: finalFunderIds,
        sessions: []
      };
      setPeriods(prev => [period, ...prev]);
      setIsAddingPeriod(false);
    }
    setPeriodFormData(initialPeriodData);
  };

  const handleConfirmDeletePeriod = (e: React.MouseEvent, periodId: string) => {
    e.preventDefault();
    e.stopPropagation();
    setConfirmDeletePeriodId(periodId);
  };

  const handleDeletePeriodConfirmed = () => {
    if (!confirmDeletePeriodId) return;
    setPeriods(prev => prev.filter(p => p.id !== confirmDeletePeriodId));
    setConfirmDeletePeriodId(null);
    if (expandedPeriodId === confirmDeletePeriodId) setExpandedPeriodId(null);
  };

  // --- 打球场次核心逻辑 ---

  const handleRemoveSession = (e: React.MouseEvent, periodId: string, sessionId: string) => {
    e.preventDefault();
    e.stopPropagation();

    // 如果还没进入确认状态，则设为确认状态
    if (sessionConfirmDeleteId !== sessionId) {
      setSessionConfirmDeleteId(sessionId);
      return;
    }

    // 第二次点击，真正执行删除
    setPeriods(prev => prev.map(p => {
      if (p.id === periodId) {
        return {
          ...p,
          sessions: p.sessions.filter(s => s.id !== sessionId)
        };
      }
      return p;
    }));
    setSessionConfirmDeleteId(null);
  };

  const saveSession = (periodId: string) => {
    if (selectedAttendees.length === 0) {
      alert('请至少选择一名出席成员');
      return;
    }
    if (editingSessionId) {
      setPeriods(prev => prev.map(p => p.id === periodId ? {
        ...p,
        sessions: p.sessions.map(s => s.id === editingSessionId ? { ...s, date: sessionFormDate, sessionCost: sessionFormCost, attendees: selectedAttendees } : s)
      } : p));
    } else {
      const session: Session = {
        id: Date.now().toString(),
        date: sessionFormDate,
        sessionCost: sessionFormCost,
        attendees: selectedAttendees
      };
      setPeriods(prev => prev.map(p => {
        if (p.id === periodId) {
          const newSessions = [session, ...p.sessions].sort((a, b) => b.date.localeCompare(a.date));
          return { ...p, sessions: newSessions };
        }
        return p;
      }));
    }
    setActiveSessionPeriod(null);
    setEditingSessionId(null);
  };

  const toggleAttendee = (player: Player, periodId: string) => {
    const exists = selectedAttendees.find(a => a.playerId === player.id);
    if (exists) {
      setSelectedAttendees(prev => prev.filter(a => a.playerId !== player.id));
    } else {
      const currentPeriod = periods.find(p => p.id === periodId);
      let defaultFee = player.defaultFee;

      if (player.type === PlayerType.MONTHLY || player.type === PlayerType.HALF_MONTHLY) {
        const alreadyRecorded = currentPeriod?.sessions.some(s => 
          s.id !== editingSessionId && 
          s.attendees.some(a => a.playerId === player.id)
        );

        if (alreadyRecorded) {
          defaultFee = 0;
        }
      }

      if (player.type === PlayerType.MONTHLY && currentPeriod?.funderIds.includes(player.id)) {
        defaultFee = 0;
      }

      setSelectedAttendees(prev => [...prev, { playerId: player.id, fee: defaultFee }]);
    }
  };

  const updateAttendeeFee = (playerId: string, fee: number) => {
    setSelectedAttendees(prev => prev.map(a => a.playerId === playerId ? { ...a, fee } : a));
  };

  // --- 视图渲染辅助逻辑 ---

  const renderDeleteModal = () => {
    const period = periods.find(p => p.id === confirmDeletePeriodId);
    if (!period) return null;

    return (
      <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 animate-fade-in bg-black/60 backdrop-blur-md">
        <div className="w-full max-w-sm bg-white rounded-[2.5rem] p-8 shadow-2xl animate-fade-in">
          <div className="flex flex-col items-center text-center">
            <div className="w-16 h-16 bg-red-50 text-red-500 rounded-full flex items-center justify-center mb-4">
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
              </svg>
            </div>
            <h3 className="text-xl font-black text-gray-800 mb-2">确认删除周期？</h3>
            <div className="bg-red-50 rounded-2xl p-4 mb-6">
              <p className="text-xs text-red-600 font-bold leading-relaxed">
                删除周期 <span className="underline">"{period.name}"</span> 后，
                内部包含的 <span className="font-black">{period.sessions.length} 场打球记录</span> 将被永久清空。
              </p>
            </div>
          </div>
          <div className="flex flex-col gap-3">
            <button 
              onClick={handleDeletePeriodConfirmed} 
              className="w-full bg-red-600 text-white py-4 rounded-2xl font-black text-base shadow-lg shadow-red-200 active:scale-95 transition-all"
            >
              确认永久删除
            </button>
            <button 
              onClick={() => setConfirmDeletePeriodId(null)} 
              className="w-full bg-gray-100 text-gray-500 py-4 rounded-2xl font-black text-sm active:bg-gray-200"
            >
              取消
            </button>
          </div>
        </div>
      </div>
    );
  };

  const renderPeriodDrawer = (title: string, onCancel: () => void) => (
    <div className="fixed inset-0 z-[100] flex items-end justify-center animate-fade-in bg-black/40 backdrop-blur-[2px]">
      <div 
        className="w-full max-w-md bg-white rounded-t-[2.5rem] shadow-2xl p-6 pb-safe animate-slide-up overflow-y-auto max-h-[90vh]"
        onClick={e => e.stopPropagation()}
      >
        <div className="w-12 h-1.5 bg-gray-200 rounded-full mx-auto mb-6"></div>
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-xl font-black text-gray-800">{title}</h3>
          <button onClick={onCancel} className="text-gray-300 p-2 active:bg-gray-100 rounded-full">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>
        <div className="space-y-5">
          <div>
            <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">周期名称</label>
            <input type="text" placeholder="例如：2025年3月集资" value={periodFormData.name} onChange={e => setPeriodFormData({...periodFormData, name: e.target.value})} className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold focus:ring-2 focus:ring-emerald-500 outline-none" />
          </div>
          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">开始日期</label>
              <DatePicker selected={stringToDate(periodFormData.startDate)} onChange={(date) => setPeriodFormData({...periodFormData, startDate: dateToString(date)})} dateFormat="yyyy-MM-dd" className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold outline-none" />
            </div>
            <div>
              <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">结束日期 (选填)</label>
              <DatePicker selected={stringToDate(periodFormData.endDate)} onChange={(date) => setPeriodFormData({...periodFormData, endDate: dateToString(date)})} dateFormat="yyyy-MM-dd" placeholderText="进行中..." className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold outline-none" isClearable />
            </div>
          </div>
          <div className="bg-red-50 p-4 rounded-2xl border border-red-100">
            <label className="block text-[10px] font-black text-red-800 uppercase tracking-widest mb-1 ml-1">本周期预付场地费</label>
            <div className="relative flex items-center">
              <span className="absolute left-4 text-red-300 font-bold italic">¥</span>
              <input type="number" placeholder="0.00" value={periodFormData.courtCost || ''} onChange={e => setPeriodFormData({...periodFormData, courtCost: Number(e.target.value)})} className="w-full bg-transparent border-none p-0 pl-8 text-2xl font-black text-red-600 outline-none focus:ring-0" />
            </div>
          </div>
          <div className="bg-amber-50 p-4 rounded-2xl border border-amber-100">
            <p className="text-[10px] font-black text-amber-800 uppercase tracking-widest mb-3 flex justify-between items-center">
              <span>👑 确认集资名单 ({periodFormData.funderIds?.length || 0})</span>
            </p>
            <div className="grid grid-cols-3 gap-2">
              {funderPool.map(f => {
                const isSelected = periodFormData.funderIds?.includes(f.id);
                return (
                  <button key={f.id} type="button" onClick={() => {
                    const current = periodFormData.funderIds || [];
                    setPeriodFormData({...periodFormData, funderIds: current.includes(f.id) ? current.filter(id => id !== f.id) : [...current, f.id]});
                  }} className={`text-[10px] py-2.5 rounded-xl border transition-all font-black ${isSelected ? 'bg-amber-500 border-amber-600 text-white shadow-md' : 'bg-white border-amber-100 text-amber-200'}`}>
                    {f.name}
                  </button>
                )
              })}
            </div>
          </div>
          <div className="flex gap-3 pt-2">
            <button onClick={handleSavePeriod} className="flex-[2] bg-emerald-600 text-white py-4 rounded-2xl font-black text-base shadow-lg shadow-emerald-200 active:scale-95 transition-all">保存周期配置</button>
            <button onClick={onCancel} className="flex-1 bg-gray-100 text-gray-500 py-4 rounded-2xl font-black text-sm active:bg-gray-200">取消</button>
          </div>
        </div>
      </div>
    </div>
  );

  const renderSessionForm = (periodId: string) => {
    const currentSubtotal = selectedAttendees.reduce((sum, a) => sum + a.fee, 0);

    return (
      <div className="fixed inset-0 z-[120] flex items-center justify-center p-6 animate-fade-in bg-black/60 backdrop-blur-sm">
        <div className="w-full max-w-sm bg-white rounded-[2.5rem] p-6 shadow-2xl animate-fade-in max-h-[90vh] overflow-y-auto">
          <h3 className="text-lg font-black text-gray-800 mb-6">{editingSessionId ? '✏️ 编辑打球记录' : '✨ 录入打球记录'}</h3>
          <div className="space-y-6">
            <div className="grid grid-cols-2 gap-3">
               <div>
                  <label className="block text-[10px] font-black text-gray-400 mb-1">活动日期</label>
                  <DatePicker selected={stringToDate(sessionFormDate)} onChange={(date) => setSessionFormDate(dateToString(date))} dateFormat="yyyy-MM-dd" className="w-full bg-gray-50 border border-gray-100 rounded-xl p-3 text-sm font-bold outline-none" />
               </div>
               <div>
                  <label className="block text-[10px] font-black text-gray-400 mb-1">额外费用(支)</label>
                  <input type="number" value={sessionFormCost || ''} onChange={e => setSessionFormCost(Number(e.target.value))} className="w-full bg-gray-50 border border-gray-100 rounded-xl p-3 text-sm font-bold outline-none text-red-500" placeholder="0.00" />
               </div>
            </div>

            <div>
              <p className="text-[10px] font-black text-gray-400 mb-2 uppercase tracking-widest">第一步：选择出席成员 ({selectedAttendees.length}):</p>
              <div className="flex flex-wrap gap-1.5 p-3 bg-gray-50 rounded-2xl border border-gray-100">
                {players.map(p => {
                  const isSelected = selectedAttendees.find(a => a.playerId === p.id);
                  return (
                    <button key={p.id} onClick={() => toggleAttendee(p, periodId)} className={`text-[10px] px-3 py-2 rounded-xl font-black transition-all border ${isSelected ? 'bg-emerald-600 border-emerald-700 text-white shadow-md' : 'bg-white border-gray-100 text-gray-400'}`}>
                      {p.name}
                    </button>
                  );
                })}
              </div>
            </div>

            {selectedAttendees.length > 0 && (
              <div>
                <p className="text-[10px] font-black text-gray-400 mb-2 uppercase tracking-widest">第二步：设置实收金额 (¥):</p>
                <div className="space-y-2 max-h-48 overflow-y-auto pr-1">
                  {selectedAttendees.map(attendee => {
                    const player = players.find(p => p.id === attendee.playerId);
                    return (
                      <div key={attendee.playerId} className="flex justify-between items-center bg-gray-50 p-2 rounded-xl border border-gray-100">
                        <span className="text-xs font-bold text-gray-700 ml-2">{player?.name}</span>
                        <div className="flex items-center gap-2">
                          <span className="text-[10px] text-gray-400 italic">实收 ¥</span>
                          <input 
                            type="number" 
                            value={attendee.fee} 
                            onChange={(e) => updateAttendeeFee(attendee.playerId, Number(e.target.value))}
                            className="w-16 bg-white border border-gray-200 rounded-lg p-1.5 text-xs font-black text-emerald-600 outline-none focus:ring-1 focus:ring-emerald-400"
                          />
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}

            <div className="bg-emerald-50 p-4 rounded-2xl border border-emerald-100">
               <div className="flex justify-between items-center">
                 <span className="text-[10px] font-black text-emerald-800 uppercase">本场预计实收:</span>
                 <span className="text-xl font-black text-emerald-600">¥{currentSubtotal.toFixed(2)}</span>
               </div>
            </div>

            <div className="flex gap-3 pt-2">
              <button onClick={() => saveSession(periodId)} className="flex-[2] bg-emerald-600 text-white py-4 rounded-2xl font-black text-sm active:scale-95 shadow-lg shadow-emerald-100">确认录入</button>
              <button onClick={() => { setActiveSessionPeriod(null); setEditingSessionId(null); }} className="flex-1 bg-gray-100 text-gray-500 py-4 rounded-2xl font-black text-sm">取消</button>
            </div>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="p-4 space-y-4 pb-32">
      <div className="px-1 mb-4 flex justify-between items-end">
        <div>
          <h2 className="text-2xl font-black text-gray-800">结算管理</h2>
          <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">Manage your sessions</p>
        </div>
        <div className="flex gap-2">
          <button onClick={() => setSortBy(sortBy === 'date' ? 'name' : 'date')} className="text-[10px] font-black px-3 py-1.5 bg-white border border-gray-100 rounded-full shadow-sm text-gray-500 active:bg-gray-50">
            {sortBy === 'date' ? '📅 时间' : '🔤 名称'}
          </button>
          <button onClick={() => setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc')} className="text-[10px] font-black px-2 py-1.5 bg-white border border-gray-100 rounded-full shadow-sm text-gray-500 active:bg-gray-50">
            {sortOrder === 'asc' ? '↑' : '↓'}
          </button>
        </div>
      </div>

      <div className="space-y-4">
        {sortedPeriods.map(period => {
          const isExpanded = expandedPeriodId === period.id;
          const totalIncome = period.sessions.reduce((acc, s) => acc + s.attendees.reduce((sum, a) => sum + a.fee, 0), 0);
          return (
            <div key={period.id} className={`bg-white rounded-[2rem] shadow-sm border border-gray-100 overflow-hidden transition-all ${isExpanded ? 'ring-2 ring-emerald-500/10 shadow-lg' : ''}`}>
              <div onClick={() => setExpandedPeriodId(isExpanded ? null : period.id)} className={`p-5 flex justify-between items-center cursor-pointer active:bg-gray-50 transition-colors ${isExpanded ? 'bg-emerald-50/20' : ''}`}>
                <div className="flex-1">
                  <div className="flex items-center gap-2 mb-1">
                    <h3 className="font-black text-gray-800 text-base">{period.name}</h3>
                    {(!period.endDate) && (
                      <span className="text-[8px] bg-emerald-500 text-white px-1.5 py-0.5 rounded-full font-black animate-pulse">进行中</span>
                    )}
                  </div>
                  <p className="text-[10px] text-gray-400 font-bold">{period.startDate} ~ {period.endDate || '至今'}</p>
                </div>
                <div className="flex items-center gap-4">
                   <div className="text-right">
                      <p className="text-[9px] text-gray-400 font-black">场次</p>
                      <p className="font-black text-emerald-600">{period.sessions.length}</p>
                   </div>
                   <div className={`transition-transform duration-300 ${isExpanded ? 'rotate-180 text-emerald-500' : 'text-gray-300'}`}>
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M19 9l-7 7-7-7" /></svg>
                  </div>
                </div>
              </div>

              {isExpanded && (
                <div className="p-5 bg-gray-50/30 border-t border-gray-50 space-y-6 animate-fade-in">
                  <div className="grid grid-cols-2 gap-3">
                    <div className="bg-white p-4 rounded-2xl border border-gray-100">
                      <p className="text-[9px] font-black text-gray-400 uppercase mb-1">场地费总支</p>
                      <p className="text-lg font-black text-red-500">¥{(period.courtCost + period.sessions.reduce((a,s) => a+(s.sessionCost||0), 0)).toFixed(2)}</p>
                    </div>
                    <div className="bg-white p-4 rounded-2xl border border-gray-100">
                      <p className="text-[9px] font-black text-gray-400 uppercase mb-1">累计采集收入</p>
                      <p className="text-lg font-black text-emerald-600">¥{totalIncome.toFixed(2)}</p>
                    </div>
                  </div>
                  <div>
                    <div className="flex justify-between items-center mb-2 px-1">
                      <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">👑 集资名单</p>
                      <button onClick={(e) => { e.stopPropagation(); setEditingPeriodId(period.id); setPeriodFormData(period); }} className="text-[9px] text-emerald-600 font-black px-2 py-1 bg-emerald-50 rounded-lg">编辑周期</button>
                    </div>
                    <div className="flex flex-wrap gap-1.5 p-3 bg-white rounded-2xl border border-gray-100 shadow-sm">
                      {period.funderIds.map(fid => (
                        <span key={fid} className="text-[10px] bg-amber-50 text-amber-700 px-2.5 py-1 rounded-full font-black border border-amber-100">
                          {players.find(pl => pl.id === fid)?.name || '未知'}
                        </span>
                      ))}
                    </div>
                  </div>
                  <div className="pt-2">
                    <div className="flex justify-between items-center mb-3">
                      <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">🏸 打球流水</h4>
                      <div className="flex gap-2">
                        <button 
                          onClick={(e) => { e.stopPropagation(); exportPeriodLedger(period); }}
                          className="text-[10px] bg-white border border-gray-200 text-gray-500 px-3 py-2 rounded-xl font-black active:bg-gray-50 flex items-center gap-1 shadow-sm"
                        >
                          <Icons.Download /> 导出流水
                        </button>
                        <button 
                          onClick={(e) => { 
                            e.stopPropagation(); 
                            setActiveSessionPeriod(period.id); 
                            setEditingSessionId(null); 
                            setSessionFormDate(new Date().toISOString().split('T')[0]); 
                            setSessionFormCost(0); 
                            setSelectedAttendees([]); 
                          }} 
                          className="text-[10px] bg-emerald-600 text-white px-4 py-2 rounded-xl font-black active:scale-95 shadow-lg shadow-emerald-100"
                        >
                          录入记录
                        </button>
                      </div>
                    </div>
                    <div className="space-y-3">
                      {period.sessions.map(session => (
                        <div key={session.id} className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm">
                          <div className="flex justify-between items-center mb-2">
                             <div className="flex items-center gap-2">
                                <span className="text-xs font-black text-gray-800">{session.date}</span>
                                {session.sessionCost ? <span className="text-[8px] bg-red-100 text-red-600 px-1.5 py-0.5 rounded font-bold">加支 ¥{session.sessionCost}</span> : null}
                             </div>
                             <div className="flex gap-1 items-center">
                                <button onClick={(e) => { e.stopPropagation(); setActiveSessionPeriod(period.id); setEditingSessionId(session.id); setSessionFormDate(session.date); setSessionFormCost(session.sessionCost || 0); setSelectedAttendees(session.attendees); }} className="text-gray-300 p-1.5 active:text-emerald-500"><Icons.Pencil /></button>

                                <button 
                                  onClick={(e) => handleRemoveSession(e, period.id, session.id)} 
                                  className={`transition-all duration-200 rounded-lg flex items-center justify-center p-1.5 ${
                                    sessionConfirmDeleteId === session.id 
                                      ? 'bg-red-500 text-white px-3' 
                                      : 'text-gray-300 hover:text-red-500'
                                  }`}
                                >
                                  {sessionConfirmDeleteId === session.id ? (
                                    <span className="text-[9px] font-black whitespace-nowrap">确认删除？</span>
                                  ) : (
                                    <Icons.Trash />
                                  )}
                                </button>
                             </div>
                          </div>
                          <div className="flex flex-wrap gap-1">
                            {session.attendees.map(a => (
                              <span key={a.playerId} className="text-[9px] bg-gray-50 text-gray-500 px-2 py-0.5 rounded border border-gray-100">
                                {players.find(pl => pl.id === a.playerId)?.name} {a.fee > 0 ? `(¥${a.fee})` : ''}
                              </span>
                            ))}
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                  <div className="pt-4 border-t border-gray-100 flex justify-center">
                    <button 
                      onClick={(e) => handleConfirmDeletePeriod(e, period.id)}
                      className="text-[10px] text-red-300 font-bold flex items-center gap-1 active:scale-95 transition-transform"
                    >
                      <Icons.Trash /> 永久移除此周期
                    </button>
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>

      <button onClick={() => { setIsAddingPeriod(true); setEditingPeriodId(null); setPeriodFormData(initialPeriodData); }} className="fixed bottom-24 right-6 w-14 h-14 bg-emerald-600 text-white rounded-full flex items-center justify-center shadow-2xl shadow-emerald-400 z-50 active:scale-90 transition-transform">
        <Icons.Plus />
      </button>

      {isAddingPeriod && renderPeriodDrawer("创建结算周期", () => setIsAddingPeriod(false))}
      {editingPeriodId && renderPeriodDrawer("编辑周期配置", () => setEditingPeriodId(null))}
      {activeSessionPeriod && renderSessionForm(activeSessionPeriod)}
      {confirmDeletePeriodId && renderDeleteModal()}

      {periods.length === 0 && (
        <div className="text-center py-24 text-gray-300">
          <p className="text-5xl mb-4 opacity-10">🏸</p>
          <p className="text-sm font-black uppercase tracking-widest">尚未创建结算周期</p>
        </div>
      )}
    </div>
  );
};

export default PeriodsList;

import React, { useState, useMemo, useEffect } from 'react';
import DatePicker from 'react-datepicker';
import { Period, Player, Session, PlayerType } from '../types';
import { Icons, DEFAULT_SESSION_FEE } from '../constants';

interface PeriodsListProps {
  periods: Period[];
  setPeriods: React.Dispatch<React.SetStateAction<Period[]>>;
  players: Player[];
  setPlayers: React.Dispatch<React.SetStateAction<Player[]>>;
}

const PeriodsList: React.FC<PeriodsListProps> = ({ periods, setPeriods, players, setPlayers }) => {
  const [isAddingPeriod, setIsAddingPeriod] = useState(false);
  const [editingPeriodId, setEditingPeriodId] = useState<string | null>(null);
  const [expandedPeriodId, setExpandedPeriodId] = useState<string | null>(null);
  const [activeSessionPeriod, setActiveSessionPeriod] = useState<string | null>(null);
  const [editingSessionId, setEditingSessionId] = useState<string | null>(null);
  const [confirmDeletePeriodId, setConfirmDeletePeriodId] = useState<string | null>(null);
  const [sessionConfirmDeleteId, setSessionConfirmDeleteId] = useState<string | null>(null);

  const [sortBy, setSortBy] = useState<'date' | 'name'>('date');
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('desc');

  const funderPool = players.filter(p => p.isFunder);

  const initialPeriodData = {
    name: '',
    startDate: new Date().toISOString().split('T')[0],
    endDate: '',
    courtCost: 0,
    funderIds: funderPool.map(p => p.id),
    sessions: []
  };

  const [periodFormData, setPeriodFormData] = useState<Partial<Period>>(initialPeriodData);
  const [sessionFormDate, setSessionFormDate] = useState(new Date().toISOString().split('T')[0]);
  const [sessionFormCost, setSessionFormCost] = useState<number>(0);
  const [selectedAttendees, setSelectedAttendees] = useState<{playerId: string, fee: number}[]>([]);

  // 自动重置场次删除确认状态
  useEffect(() => {
    if (sessionConfirmDeleteId) {
      const timer = setTimeout(() => setSessionConfirmDeleteId(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [sessionConfirmDeleteId]);

  const sortedPeriods = useMemo(() => {
    return [...periods].sort((a, b) => {
      let comparison = 0;
      if (sortBy === 'date') {
        comparison = a.startDate.localeCompare(b.startDate);
      } else {
        comparison = a.name.localeCompare(b.name, 'zh-CN');
      }
      return sortOrder === 'asc' ? comparison : -comparison;
    });
  }, [periods, sortBy, sortOrder]);

  const stringToDate = (str: string | undefined) => {
    if (!str) return null;
    return new Date(str);
  };

  const dateToString = (date: Date | null) => {
    if (!date) return '';
    return date.toISOString().split('T')[0];
  };

  // --- 导出功能 ---

  const exportPeriodLedger = (period: Period) => {
    const headers = ['日期', '人员姓名', '实收金额(元)', '单场额外支出(元)'];
    const rows: string[][] = [];

    period.sessions.forEach(session => {
      session.attendees.forEach((a, idx) => {
        const playerName = players.find(p => p.id === a.playerId)?.name || '未知';
        rows.push([
          idx === 0 ? session.date : '',
          playerName,
          a.fee.toString(),
          idx === 0 ? (session.sessionCost || 0).toString() : ''
        ]);
      });
    });

    const csvContent = "\ufeff" + [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `${period.name}_流水记录.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // --- 周期管理核心逻辑 ---

  const handleSavePeriod = () => {
    if (!periodFormData.name) {
      alert('请输入周期名称');
      return;
    }
    const finalFunderIds = periodFormData.funderIds || [];
    if (editingPeriodId) {
      setPeriods(prev => prev.map(p => p.id === editingPeriodId ? { ...p, ...periodFormData } as Period : p));
      setEditingPeriodId(null);
    } else {
      const period: Period = {
        id: Date.now().toString(),
        name: periodFormData.name!,
        startDate: periodFormData.startDate!,
        endDate: periodFormData.endDate || '',
        courtCost: periodFormData.courtCost || 0,
        funderIds: finalFunderIds,
        sessions: []
      };
      setPeriods(prev => [period, ...prev]);
      setIsAddingPeriod(false);
    }
    setPeriodFormData(initialPeriodData);
  };

  const handleConfirmDeletePeriod = (e: React.MouseEvent, periodId: string) => {
    e.preventDefault();
    e.stopPropagation();
    setConfirmDeletePeriodId(periodId);
  };

  const handleDeletePeriodConfirmed = () => {
    if (!confirmDeletePeriodId) return;
    setPeriods(prev => prev.filter(p => p.id !== confirmDeletePeriodId));
    setConfirmDeletePeriodId(null);
    if (expandedPeriodId === confirmDeletePeriodId) setExpandedPeriodId(null);
  };

  // --- 打球场次核心逻辑 ---

  const handleRemoveSession = (e: React.MouseEvent, periodId: string, sessionId: string) => {
    e.preventDefault();
    e.stopPropagation();

    if (sessionConfirmDeleteId !== sessionId) {
      setSessionConfirmDeleteId(sessionId);
      return;
    }

    setPeriods(prev => prev.map(p => {
      if (p.id === periodId) {
        return {
          ...p,
          sessions: p.sessions.filter(s => s.id !== sessionId)
        };
      }
      return p;
    }));
    setSessionConfirmDeleteId(null);
  };

  const saveSession = (periodId: string) => {
    if (selectedAttendees.length === 0) {
      alert('请至少选择一名出席成员');
      return;
    }
    if (editingSessionId) {
      setPeriods(prev => prev.map(p => p.id === periodId ? {
        ...p,
        sessions: p.sessions.map(s => s.id === editingSessionId ? { ...s, date: sessionFormDate, sessionCost: sessionFormCost, attendees: selectedAttendees } : s)
      } : p));
    } else {
      const session: Session = {
        id: Date.now().toString(),
        date: sessionFormDate,
        sessionCost: sessionFormCost,
        attendees: selectedAttendees
      };
      setPeriods(prev => prev.map(p => {
        if (p.id === periodId) {
          const newSessions = [session, ...p.sessions].sort((a, b) => b.date.localeCompare(a.date));
          return { ...p, sessions: newSessions };
        }
        return p;
      }));
    }
    setActiveSessionPeriod(null);
    setEditingSessionId(null);
  };

  const toggleAttendee = (player: Player, periodId: string) => {
    const exists = selectedAttendees.find(a => a.playerId === player.id);
    if (exists) {
      setSelectedAttendees(prev => prev.filter(a => a.playerId !== player.id));
    } else {
      const currentPeriod = periods.find(p => p.id === periodId);
      const isFunder = currentPeriod?.funderIds.includes(player.id);

      let defaultFee = DEFAULT_SESSION_FEE; // 默认 25 元

      if (isFunder) {
        // 如果是本期集资人，费用固定为 0
        defaultFee = 0;
      } else if (player.type === PlayerType.MONTHLY || player.type === PlayerType.HALF_MONTHLY) {
        // 非集资人，但属于包月类性质的人员，检查周期内是否已有记录
        const alreadyRecorded = currentPeriod?.sessions.some(s => 
          s.id !== editingSessionId && 
          s.attendees.some(a => a.playerId === player.id)
        );

        if (alreadyRecorded) {
          // 本周期第二次开始，自动设为 0
          defaultFee = 0;
        } else {
          // 本周期第一次出现，按档案里的收费标准收费（包月价或包半月价）
          defaultFee = player.defaultFee || DEFAULT_SESSION_FEE;
        }
      } else {
        // 普通按次人员，统一默认 25 元
        defaultFee = DEFAULT_SESSION_FEE;
      }

      setSelectedAttendees(prev => [...prev, { playerId: player.id, fee: defaultFee }]);
    }
  };

  const updateAttendeeFee = (playerId: string, fee: number) => {
    setSelectedAttendees(prev => prev.map(a => a.playerId === playerId ? { ...a, fee } : a));
  };

  // --- 视图渲染辅助逻辑 ---

  const renderDeleteModal = () => {
    const period = periods.find(p => p.id === confirmDeletePeriodId);
    if (!period) return null;

    return (
      <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 animate-fade-in bg-black/60 backdrop-blur-md">
        <div className="w-full max-w-sm bg-white rounded-[2.5rem] p-8 shadow-2xl animate-fade-in">
          <div className="flex flex-col items-center text-center">
            <div className="w-16 h-16 bg-red-50 text-red-500 rounded-full flex items-center justify-center mb-4">
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
              </svg>
            </div>
            <h3 className="text-xl font-black text-gray-800 mb-2">确认删除周期？</h3>
            <div className="bg-red-50 rounded-2xl p-4 mb-6">
              <p className="text-xs text-red-600 font-bold leading-relaxed">
                删除周期 <span className="underline">"{period.name}"</span> 后，
                内部包含的 <span className="font-black">{period.sessions.length} 场打球记录</span> 将被永久清空。
              </p>
            </div>
          </div>
          <div className="flex flex-col gap-3">
            <button 
              onClick={handleDeletePeriodConfirmed} 
              className="w-full bg-red-600 text-white py-4 rounded-2xl font-black text-base shadow-lg shadow-red-200 active:scale-95 transition-all"
            >
              确认永久删除
            </button>
            <button 
              onClick={() => setConfirmDeletePeriodId(null)} 
              className="w-full bg-gray-100 text-gray-500 py-4 rounded-2xl font-black text-sm active:bg-gray-200"
            >
              取消
            </button>
          </div>
        </div>
      </div>
    );
  };

  const renderPeriodDrawer = (title: string, onCancel: () => void) => (
    <div className="fixed inset-0 z-[100] flex items-end justify-center animate-fade-in bg-black/40 backdrop-blur-[2px]">
      <div 
        className="w-full max-w-md bg-white rounded-t-[2.5rem] shadow-2xl p-6 pb-safe animate-slide-up overflow-y-auto max-h-[90vh]"
        onClick={e => e.stopPropagation()}
      >
        <div className="w-12 h-1.5 bg-gray-200 rounded-full mx-auto mb-6"></div>
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-xl font-black text-gray-800">{title}</h3>
          <button onClick={onCancel} className="text-gray-300 p-2 active:bg-gray-100 rounded-full">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>
        <div className="space-y-5">
          <div>
            <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">周期名称</label>
            <input type="text" placeholder="例如：2025年3月集资" value={periodFormData.name} onChange={e => setPeriodFormData({...periodFormData, name: e.target.value})} className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold focus:ring-2 focus:ring-emerald-500 outline-none" />
          </div>
          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">开始日期</label>
              <DatePicker selected={stringToDate(periodFormData.startDate)} onChange={(date) => setPeriodFormData({...periodFormData, startDate: dateToString(date)})} dateFormat="yyyy-MM-dd" className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold outline-none" />
            </div>
            <div>
              <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">结束日期 (选填)</label>
              <DatePicker selected={stringToDate(periodFormData.endDate)} onChange={(date) => setPeriodFormData({...periodFormData, endDate: dateToString(date)})} dateFormat="yyyy-MM-dd" placeholderText="进行中..." className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold outline-none" isClearable />
            </div>
          </div>
          <div className="bg-red-50 p-4 rounded-2xl border border-red-100">
            <label className="block text-[10px] font-black text-red-800 uppercase tracking-widest mb-1 ml-1">本周期预付场地费</label>
            <div className="relative flex items-center">
              <span className="absolute left-4 text-red-300 font-bold italic">¥</span>
              <input type="number" placeholder="0.00" value={periodFormData.courtCost || ''} onChange={e => setPeriodFormData({...periodFormData, courtCost: Number(e.target.value)})} className="w-full bg-transparent border-none p-0 pl-8 text-2xl font-black text-red-600 outline-none focus:ring-0" />
            </div>
          </div>
          <div className="bg-amber-50 p-4 rounded-2xl border border-amber-100">
            <p className="text-[10px] font-black text-amber-800 uppercase tracking-widest mb-3 flex justify-between items-center">
              <span>👑 确认集资名单 ({periodFormData.funderIds?.length || 0})</span>
            </p>
            <div className="grid grid-cols-3 gap-2">
              {funderPool.map(f => {
                const isSelected = periodFormData.funderIds?.includes(f.id);
                return (
                  <button key={f.id} type="button" onClick={() => {
                    const current = periodFormData.funderIds || [];
                    setPeriodFormData({...periodFormData, funderIds: current.includes(f.id) ? current.filter(id => id !== f.id) : [...current, f.id]});
                  }} className={`text-[10px] py-2.5 rounded-xl border transition-all font-black ${isSelected ? 'bg-amber-500 border-amber-600 text-white shadow-md' : 'bg-white border-amber-100 text-amber-200'}`}>
                    {f.name}
                  </button>
                )
              })}
            </div>
          </div>
          <div className="flex gap-3 pt-2">
            <button onClick={handleSavePeriod} className="flex-[2] bg-emerald-600 text-white py-4 rounded-2xl font-black text-base shadow-lg shadow-emerald-200 active:scale-95 transition-all">保存周期配置</button>
            <button onClick={onCancel} className="flex-1 bg-gray-100 text-gray-500 py-4 rounded-2xl font-black text-sm active:bg-gray-200">取消</button>
          </div>
        </div>
      </div>
    </div>
  );

  const renderSessionForm = (periodId: string) => {
    const currentSubtotal = selectedAttendees.reduce((sum, a) => sum + a.fee, 0);

    return (
      <div className="fixed inset-0 z-[120] flex items-center justify-center p-6 animate-fade-in bg-black/60 backdrop-blur-sm" onClick={() => { setActiveSessionPeriod(null); setEditingSessionId(null); }}>
        <div className="w-full max-w-sm bg-white rounded-[2.5rem] p-6 shadow-2xl animate-fade-in max-h-[90vh] overflow-y-auto" onClick={e => e.stopPropagation()}>
          <h3 className="text-lg font-black text-gray-800 mb-6">{editingSessionId ? '✏️ 编辑打球记录' : '✨ 录入打球记录'}</h3>
          <div className="space-y-6">
            <div className="grid grid-cols-2 gap-3">
               <div>
                  <label className="block text-[10px] font-black text-gray-400 mb-1">活动日期</label>
                  <DatePicker selected={stringToDate(sessionFormDate)} onChange={(date) => setSessionFormDate(dateToString(date))} dateFormat="yyyy-MM-dd" className="w-full bg-gray-50 border border-gray-100 rounded-xl p-3 text-sm font-bold outline-none" />
               </div>
               <div>
                  <label className="block text-[10px] font-black text-gray-400 mb-1">额外费用(支)</label>
                  <input type="number" value={sessionFormCost || ''} onChange={e => setSessionFormCost(Number(e.target.value))} className="w-full bg-gray-50 border border-gray-100 rounded-xl p-3 text-sm font-bold outline-none text-red-500" placeholder="0.00" />
               </div>
            </div>

            <div>
              <p className="text-[10px] font-black text-gray-400 mb-2 uppercase tracking-widest">第一步：选择出席成员 ({selectedAttendees.length}):</p>
              <div className="flex flex-wrap gap-1.5 p-3 bg-gray-50 rounded-2xl border border-gray-100">
                {players.map(p => {
                  const isSelected = selectedAttendees.find(a => a.playerId === p.id);
                  return (
                    <button key={p.id} onClick={() => toggleAttendee(p, periodId)} className={`text-[10px] px-3 py-2 rounded-xl font-black transition-all border ${isSelected ? 'bg-emerald-600 border-emerald-700 text-white shadow-md' : 'bg-white border-gray-100 text-gray-400'}`}>
                      {p.name}
                    </button>
                  );
                })}
              </div>
            </div>

            {selectedAttendees.length > 0 && (
              <div>
                <p className="text-[10px] font-black text-gray-400 mb-2 uppercase tracking-widest">第二步：设置实收金额 (¥):</p>
                <div className="space-y-2 max-h-48 overflow-y-auto pr-1">
                  {selectedAttendees.map(attendee => {
                    const player = players.find(p => p.id === attendee.playerId);
                    return (
                      <div key={attendee.playerId} className="flex justify-between items-center bg-gray-50 p-2 rounded-xl border border-gray-100">
                        <span className="text-xs font-bold text-gray-700 ml-2">{player?.name}</span>
                        <div className="flex items-center gap-2">
                          <span className="text-[10px] text-gray-400 italic">实收 ¥</span>
                          <input 
                            type="number" 
                            value={attendee.fee} 
                            onChange={(e) => updateAttendeeFee(attendee.playerId, Number(e.target.value))}
                            className="w-16 bg-white border border-gray-200 rounded-lg p-1.5 text-xs font-black text-emerald-600 outline-none focus:ring-1 focus:ring-emerald-400"
                          />
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}

            <div className="bg-emerald-50 p-4 rounded-2xl border border-emerald-100">
               <div className="flex justify-between items-center">
                 <span className="text-[10px] font-black text-emerald-800 uppercase">本场预计实收:</span>
                 <span className="text-xl font-black text-emerald-600">¥{currentSubtotal.toFixed(2)}</span>
               </div>
            </div>

            <div className="flex gap-3 pt-2">
              <button onClick={() => saveSession(periodId)} className="flex-[2] bg-emerald-600 text-white py-4 rounded-2xl font-black text-sm active:scale-95 shadow-lg shadow-emerald-100">确认录入</button>
              <button onClick={() => { setActiveSessionPeriod(null); setEditingSessionId(null); }} className="flex-1 bg-gray-100 text-gray-500 py-4 rounded-2xl font-black text-sm">取消</button>
            </div>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="p-4 space-y-4 pb-32">
      <div className="px-1 mb-4 flex justify-between items-end">
        <div>
          <h2 className="text-2xl font-black text-gray-800">结算管理</h2>
          <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">Manage your sessions</p>
        </div>
        <div className="flex gap-2">
          <button onClick={() => setSortBy(sortBy === 'date' ? 'name' : 'date')} className="text-[10px] font-black px-3 py-1.5 bg-white border border-gray-100 rounded-full shadow-sm text-gray-500 active:bg-gray-50">
            {sortBy === 'date' ? '📅 时间' : '🔤 名称'}
          </button>
          <button onClick={() => setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc')} className="text-[10px] font-black px-2 py-1.5 bg-white border border-gray-100 rounded-full shadow-sm text-gray-500 active:bg-gray-50">
            {sortOrder === 'asc' ? '↑' : '↓'}
          </button>
        </div>
      </div>

      <div className="space-y-4">
        {sortedPeriods.map(period => {
          const isExpanded = expandedPeriodId === period.id;
          const totalIncome = period.sessions.reduce((acc, s) => acc + s.attendees.reduce((sum, a) => sum + a.fee, 0), 0);
          return (
            <div key={period.id} className={`bg-white rounded-[2rem] shadow-sm border border-gray-100 overflow-hidden transition-all ${isExpanded ? 'ring-2 ring-emerald-500/10 shadow-lg' : ''}`}>
              <div onClick={() => setExpandedPeriodId(isExpanded ? null : period.id)} className={`p-5 flex justify-between items-center cursor-pointer active:bg-gray-50 transition-colors ${isExpanded ? 'bg-emerald-50/20' : ''}`}>
                <div className="flex-1">
                  <div className="flex items-center gap-2 mb-1">
                    <h3 className="font-black text-gray-800 text-base">{period.name}</h3>
                    {(!period.endDate) && (
                      <span className="text-[8px] bg-emerald-500 text-white px-1.5 py-0.5 rounded-full font-black animate-pulse">进行中</span>
                    )}
                  </div>
                  <p className="text-[10px] text-gray-400 font-bold">{period.startDate} ~ {period.endDate || '至今'}</p>
                </div>
                <div className="flex items-center gap-4">
                   <div className="text-right">
                      <p className="text-[9px] text-gray-400 font-black">场次</p>
                      <p className="font-black text-emerald-600">{period.sessions.length}</p>
                   </div>
                   <div className={`transition-transform duration-300 ${isExpanded ? 'rotate-180 text-emerald-500' : 'text-gray-300'}`}>
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M19 9l-7 7-7-7" /></svg>
                  </div>
                </div>
              </div>

              {isExpanded && (
                <div className="p-5 bg-gray-50/30 border-t border-gray-50 space-y-6 animate-fade-in">
                  <div className="grid grid-cols-2 gap-3">
                    <div className="bg-white p-4 rounded-2xl border border-gray-100">
                      <p className="text-[9px] font-black text-gray-400 uppercase mb-1">场地费总支</p>
                      <p className="text-lg font-black text-red-500">¥{(period.courtCost + period.sessions.reduce((a,s) => a+(s.sessionCost||0), 0)).toFixed(2)}</p>
                    </div>
                    <div className="bg-white p-4 rounded-2xl border border-gray-100">
                      <p className="text-[9px] font-black text-gray-400 uppercase mb-1">累计采集收入</p>
                      <p className="text-lg font-black text-emerald-600">¥{totalIncome.toFixed(2)}</p>
                    </div>
                  </div>
                  <div>
                    <div className="flex justify-between items-center mb-2 px-1">
                      <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">👑 集资名单</p>
                      <button onClick={(e) => { e.stopPropagation(); setEditingPeriodId(period.id); setPeriodFormData(period); }} className="text-[9px] text-emerald-600 font-black px-2 py-1 bg-emerald-50 rounded-lg">编辑周期</button>
                    </div>
                    <div className="flex flex-wrap gap-1.5 p-3 bg-white rounded-2xl border border-gray-100 shadow-sm">
                      {period.funderIds.map(fid => (
                        <span key={fid} className="text-[10px] bg-amber-50 text-amber-700 px-2.5 py-1 rounded-full font-black border border-amber-100">
                          {players.find(pl => pl.id === fid)?.name || '未知'}
                        </span>
                      ))}
                    </div>
                  </div>
                  <div className="pt-2">
                    <div className="flex justify-between items-center mb-3">
                      <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">🏸 打球流水</h4>
                      <div className="flex gap-2">
                        <button 
                          onClick={(e) => { e.stopPropagation(); exportPeriodLedger(period); }}
                          className="text-[10px] bg-white border border-gray-200 text-gray-500 px-3 py-2 rounded-xl font-black active:bg-gray-50 flex items-center gap-1 shadow-sm"
                        >
                          <Icons.Download /> 导出流水
                        </button>
                        <button 
                          onClick={(e) => { 
                            e.stopPropagation(); 
                            setActiveSessionPeriod(period.id); 
                            setEditingSessionId(null); 
                            setSessionFormDate(new Date().toISOString().split('T')[0]); 
                            setSessionFormCost(0); 
                            setSelectedAttendees([]); 
                          }} 
                          className="text-[10px] bg-emerald-600 text-white px-4 py-2 rounded-xl font-black active:scale-95 shadow-lg shadow-emerald-100"
                        >
                          录入记录
                        </button>
                      </div>
                    </div>
                    <div className="space-y-3">
                      {period.sessions.map(session => (
                        <div key={session.id} className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm">
                          <div className="flex justify-between items-center mb-2">
                             <div className="flex items-center gap-2">
                                <span className="text-xs font-black text-gray-800">{session.date}</span>
                                {session.sessionCost ? <span className="text-[8px] bg-red-100 text-red-600 px-1.5 py-0.5 rounded font-bold">加支 ¥{session.sessionCost}</span> : null}
                             </div>
                             <div className="flex gap-1 items-center">
                                <button onClick={(e) => { e.stopPropagation(); setActiveSessionPeriod(period.id); setEditingSessionId(session.id); setSessionFormDate(session.date); setSessionFormCost(session.sessionCost || 0); setSelectedAttendees(session.attendees); }} className="text-gray-300 p-1.5 active:text-emerald-500"><Icons.Pencil /></button>

                                <button 
                                  onClick={(e) => handleRemoveSession(e, period.id, session.id)} 
                                  className={`transition-all duration-200 rounded-lg flex items-center justify-center p-1.5 ${
                                    sessionConfirmDeleteId === session.id 
                                      ? 'bg-red-500 text-white px-3' 
                                      : 'text-gray-300 hover:text-red-500'
                                  }`}
                                >
                                  {sessionConfirmDeleteId === session.id ? (
                                    <span className="text-[9px] font-black whitespace-nowrap">确认删除？</span>
                                  ) : (
                                    <Icons.Trash />
                                  )}
                                </button>
                             </div>
                          </div>
                          <div className="flex flex-wrap gap-1">
                            {session.attendees.map(a => (
                              <span key={a.playerId} className="text-[9px] bg-gray-50 text-gray-500 px-2 py-0.5 rounded border border-gray-100">
                                {players.find(pl => pl.id === a.playerId)?.name} {a.fee > 0 ? `(¥${a.fee})` : ''}
                              </span>
                            ))}
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                  <div className="pt-4 border-t border-gray-100 flex justify-center">
                    <button 
                      onClick={(e) => handleConfirmDeletePeriod(e, period.id)}
                      className="text-[10px] text-red-300 font-bold flex items-center gap-1 active:scale-95 transition-transform"
                    >
                      <Icons.Trash /> 永久移除此周期
                    </button>
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>

      <button onClick={() => { setIsAddingPeriod(true); setEditingPeriodId(null); setPeriodFormData(initialPeriodData); }} className="fixed bottom-24 right-6 w-14 h-14 bg-emerald-600 text-white rounded-full flex items-center justify-center shadow-2xl shadow-emerald-400 z-50 active:scale-90 transition-transform">
        <Icons.Plus />
      </button>

      {isAddingPeriod && renderPeriodDrawer("创建结算周期", () => setIsAddingPeriod(false))}
      {editingPeriodId && renderPeriodDrawer("编辑周期配置", () => setEditingPeriodId(null))}
      {activeSessionPeriod && renderSessionForm(activeSessionPeriod)}
      {confirmDeletePeriodId && renderDeleteModal()}

      {periods.length === 0 && (
        <div className="text-center py-24 text-gray-300">
          <p className="text-5xl mb-4 opacity-10">🏸</p>
          <p className="text-sm font-black uppercase tracking-widest">尚未创建结算周期</p>
        </div>
      )}
    </div>
  );
};

export default PeriodsList;

import React, { useState, useMemo, useEffect } from 'react';
import DatePicker from 'react-datepicker';
import { Period, Player, Session, PlayerType } from '../types';
import { Icons, DEFAULT_SESSION_FEE } from '../constants';

interface PeriodsListProps {
  periods: Period[];
  setPeriods: React.Dispatch<React.SetStateAction<Period[]>>;
  players: Player[];
  setPlayers: React.Dispatch<React.SetStateAction<Player[]>>;
}

const PeriodsList: React.FC<PeriodsListProps> = ({ periods, setPeriods, players, setPlayers }) => {
  const [isAddingPeriod, setIsAddingPeriod] = useState(false);
  const [editingPeriodId, setEditingPeriodId] = useState<string | null>(null);
  const [expandedPeriodId, setExpandedPeriodId] = useState<string | null>(null);
  const [activeSessionPeriod, setActiveSessionPeriod] = useState<string | null>(null);
  const [editingSessionId, setEditingSessionId] = useState<string | null>(null);
  const [confirmDeletePeriodId, setConfirmDeletePeriodId] = useState<string | null>(null);
  const [sessionConfirmDeleteId, setSessionConfirmDeleteId] = useState<string | null>(null);

  const [sortBy, setSortBy] = useState<'date' | 'name'>('date');
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('desc');

  const funderPool = players.filter(p => p.isFunder);

  const initialPeriodData = {
    name: '',
    startDate: new Date().toISOString().split('T')[0],
    endDate: '',
    courtCost: 0,
    funderIds: funderPool.map(p => p.id),
    sessions: []
  };

  const [periodFormData, setPeriodFormData] = useState<Partial<Period>>(initialPeriodData);
  const [sessionFormDate, setSessionFormDate] = useState(new Date().toISOString().split('T')[0]);
  const [sessionFormCost, setSessionFormCost] = useState<number>(0);
  const [selectedAttendees, setSelectedAttendees] = useState<{playerId: string, fee: number}[]>([]);

  // 自动重置场次删除确认状态
  useEffect(() => {
    if (sessionConfirmDeleteId) {
      const timer = setTimeout(() => setSessionConfirmDeleteId(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [sessionConfirmDeleteId]);

  const sortedPeriods = useMemo(() => {
    return [...periods].sort((a, b) => {
      let comparison = 0;
      if (sortBy === 'date') {
        comparison = a.startDate.localeCompare(b.startDate);
      } else {
        comparison = a.name.localeCompare(b.name, 'zh-CN');
      }
      return sortOrder === 'asc' ? comparison : -comparison;
    });
  }, [periods, sortBy, sortOrder]);

  const stringToDate = (str: string | undefined) => {
    if (!str) return null;
    return new Date(str);
  };

  const dateToString = (date: Date | null) => {
    if (!date) return '';
    return date.toISOString().split('T')[0];
  };

  // --- 导出功能 ---

  const exportPeriodLedger = (period: Period) => {
    // UTF-8 BOM，防止 Excel 乱码
    const BOM = "\ufeff";
    const headers = ['日期', '人员姓名', '实收金额(元)', '单场额外场地费(元)'];
    const rows: string[][] = [];

    // 按日期倒序导出
    const sortedSessions = [...period.sessions].sort((a, b) => b.date.localeCompare(a.date));

    sortedSessions.forEach(session => {
      session.attendees.forEach((a, idx) => {
        const playerName = players.find(p => p.id === a.playerId)?.name || '未知';
        rows.push([
          idx === 0 ? session.date : '', // 只有首行显示日期，便于阅读
          playerName,
          a.fee.toString(),
          idx === 0 ? (session.sessionCost || 0).toString() : '' // 只有首行显示额外费用
        ]);
      });
    });

    const csvContent = BOM + [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `${period.name}_流水账单_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // --- 周期管理核心逻辑 ---

  const handleSavePeriod = () => {
    if (!periodFormData.name) {
      alert('请输入周期名称');
      return;
    }
    const finalFunderIds = periodFormData.funderIds || [];
    if (editingPeriodId) {
      setPeriods(prev => prev.map(p => p.id === editingPeriodId ? { ...p, ...periodFormData } as Period : p));
      setEditingPeriodId(null);
    } else {
      const period: Period = {
        id: Date.now().toString(),
        name: periodFormData.name!,
        startDate: periodFormData.startDate!,
        endDate: periodFormData.endDate || '',
        courtCost: periodFormData.courtCost || 0,
        funderIds: finalFunderIds,
        sessions: []
      };
      setPeriods(prev => [period, ...prev]);
      setIsAddingPeriod(false);
    }
    setPeriodFormData(initialPeriodData);
  };

  const handleConfirmDeletePeriod = (e: React.MouseEvent, periodId: string) => {
    e.preventDefault();
    e.stopPropagation();
    setConfirmDeletePeriodId(periodId);
  };

  const handleDeletePeriodConfirmed = () => {
    if (!confirmDeletePeriodId) return;
    setPeriods(prev => prev.filter(p => p.id !== confirmDeletePeriodId));
    setConfirmDeletePeriodId(null);
    if (expandedPeriodId === confirmDeletePeriodId) setExpandedPeriodId(null);
  };

  // --- 打球场次核心逻辑 ---

  const handleRemoveSession = (e: React.MouseEvent, periodId: string, sessionId: string) => {
    e.preventDefault();
    e.stopPropagation();

    if (sessionConfirmDeleteId !== sessionId) {
      setSessionConfirmDeleteId(sessionId);
      return;
    }

    setPeriods(prev => prev.map(p => {
      if (p.id === periodId) {
        return {
          ...p,
          sessions: p.sessions.filter(s => s.id !== sessionId)
        };
      }
      return p;
    }));
    setSessionConfirmDeleteId(null);
  };

  const saveSession = (periodId: string) => {
    if (selectedAttendees.length === 0) {
      alert('请至少选择一名出席成员');
      return;
    }
    if (editingSessionId) {
      setPeriods(prev => prev.map(p => p.id === periodId ? {
        ...p,
        sessions: p.sessions.map(s => s.id === editingSessionId ? { ...s, date: sessionFormDate, sessionCost: sessionFormCost, attendees: selectedAttendees } : s)
      } : p));
    } else {
      const session: Session = {
        id: Date.now().toString(),
        date: sessionFormDate,
        sessionCost: sessionFormCost,
        attendees: selectedAttendees
      };
      setPeriods(prev => prev.map(p => {
        if (p.id === periodId) {
          const newSessions = [session, ...p.sessions].sort((a, b) => b.date.localeCompare(a.date));
          return { ...p, sessions: newSessions };
        }
        return p;
      }));
    }
    setActiveSessionPeriod(null);
    setEditingSessionId(null);
  };

  const toggleAttendee = (player: Player, periodId: string) => {
    const exists = selectedAttendees.find(a => a.playerId === player.id);
    if (exists) {
      setSelectedAttendees(prev => prev.filter(a => a.playerId !== player.id));
    } else {
      const currentPeriod = periods.find(p => p.id === periodId);
      const isFunder = currentPeriod?.funderIds.includes(player.id);

      let defaultFee = DEFAULT_SESSION_FEE; // 默认 25 元

      if (isFunder) {
        // 如果是本期集资人，费用固定为 0
        defaultFee = 0;
      } else if (player.type === PlayerType.MONTHLY || player.type === PlayerType.HALF_MONTHLY) {
        // 非集资人，但属于包月类性质的人员，检查周期内是否已有记录
        const alreadyRecorded = currentPeriod?.sessions.some(s => 
          s.id !== editingSessionId && 
          s.attendees.some(a => a.playerId === player.id)
        );

        if (alreadyRecorded) {
          // 本周期第二次开始，自动设为 0
          defaultFee = 0;
        } else {
          // 本周期第一次出现，按档案里的收费标准收费（包月价或包半月价）
          defaultFee = player.defaultFee || DEFAULT_SESSION_FEE;
        }
      } else {
        // 普通按次人员，统一默认 25 元
        defaultFee = DEFAULT_SESSION_FEE;
      }

      setSelectedAttendees(prev => [...prev, { playerId: player.id, fee: defaultFee }]);
    }
  };

  const updateAttendeeFee = (playerId: string, fee: number) => {
    setSelectedAttendees(prev => prev.map(a => a.playerId === playerId ? { ...a, fee } : a));
  };

  // --- 视图渲染辅助逻辑 ---

  const renderDeleteModal = () => {
    const period = periods.find(p => p.id === confirmDeletePeriodId);
    if (!period) return null;

    return (
      <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 animate-fade-in bg-black/60 backdrop-blur-md">
        <div className="w-full max-w-sm bg-white rounded-[2.5rem] p-8 shadow-2xl animate-fade-in">
          <div className="flex flex-col items-center text-center">
            <div className="w-16 h-16 bg-red-50 text-red-500 rounded-full flex items-center justify-center mb-4">
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
              </svg>
            </div>
            <h3 className="text-xl font-black text-gray-800 mb-2">确认删除周期？</h3>
            <div className="bg-red-50 rounded-2xl p-4 mb-6">
              <p className="text-xs text-red-600 font-bold leading-relaxed">
                删除周期 <span className="underline">"{period.name}"</span> 后，
                内部包含的 <span className="font-black">{period.sessions.length} 场打球记录</span> 将被永久清空。
              </p>
            </div>
          </div>
          <div className="flex flex-col gap-3">
            <button 
              onClick={handleDeletePeriodConfirmed} 
              className="w-full bg-red-600 text-white py-4 rounded-2xl font-black text-base shadow-lg shadow-red-200 active:scale-95 transition-all"
            >
              确认永久删除
            </button>
            <button 
              onClick={() => setConfirmDeletePeriodId(null)} 
              className="w-full bg-gray-100 text-gray-500 py-4 rounded-2xl font-black text-sm active:bg-gray-200"
            >
              取消
            </button>
          </div>
        </div>
      </div>
    );
  };

  const renderPeriodDrawer = (title: string, onCancel: () => void) => (
    <div className="fixed inset-0 z-[100] flex items-end justify-center animate-fade-in bg-black/40 backdrop-blur-[2px]">
      <div 
        className="w-full max-w-md bg-white rounded-t-[2.5rem] shadow-2xl p-6 pb-safe animate-slide-up overflow-y-auto max-h-[90vh]"
        onClick={e => e.stopPropagation()}
      >
        <div className="w-12 h-1.5 bg-gray-200 rounded-full mx-auto mb-6"></div>
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-xl font-black text-gray-800">{title}</h3>
          <button onClick={onCancel} className="text-gray-300 p-2 active:bg-gray-100 rounded-full">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>
        <div className="space-y-5">
          <div>
            <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">周期名称</label>
            <input type="text" placeholder="例如：2025年3月集资" value={periodFormData.name} onChange={e => setPeriodFormData({...periodFormData, name: e.target.value})} className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold focus:ring-2 focus:ring-emerald-500 outline-none" />
          </div>
          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">开始日期</label>
              <DatePicker selected={stringToDate(periodFormData.startDate)} onChange={(date) => setPeriodFormData({...periodFormData, startDate: dateToString(date)})} dateFormat="yyyy-MM-dd" className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold outline-none" />
            </div>
            <div>
              <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">结束日期 (选填)</label>
              <DatePicker selected={stringToDate(periodFormData.endDate)} onChange={(date) => setPeriodFormData({...periodFormData, endDate: dateToString(date)})} dateFormat="yyyy-MM-dd" placeholderText="进行中..." className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold outline-none" isClearable />
            </div>
          </div>
          <div className="bg-red-50 p-4 rounded-2xl border border-red-100">
            <label className="block text-[10px] font-black text-red-800 uppercase tracking-widest mb-1 ml-1">本周期预付场地费</label>
            <div className="relative flex items-center">
              <span className="absolute left-4 text-red-300 font-bold italic">¥</span>
              <input type="number" placeholder="0.00" value={periodFormData.courtCost || ''} onChange={e => setPeriodFormData({...periodFormData, courtCost: Number(e.target.value)})} className="w-full bg-transparent border-none p-0 pl-8 text-2xl font-black text-red-600 outline-none focus:ring-0" />
            </div>
          </div>
          <div className="bg-amber-50 p-4 rounded-2xl border border-amber-100">
            <p className="text-[10px] font-black text-amber-800 uppercase tracking-widest mb-3 flex justify-between items-center">
              <span>👑 确认集资名单 ({periodFormData.funderIds?.length || 0})</span>
            </p>
            <div className="grid grid-cols-3 gap-2">
              {funderPool.map(f => {
                const isSelected = periodFormData.funderIds?.includes(f.id);
                return (
                  <button key={f.id} type="button" onClick={() => {
                    const current = periodFormData.funderIds || [];
                    setPeriodFormData({...periodFormData, funderIds: current.includes(f.id) ? current.filter(id => id !== f.id) : [...current, f.id]});
                  }} className={`text-[10px] py-2.5 rounded-xl border transition-all font-black ${isSelected ? 'bg-amber-500 border-amber-600 text-white shadow-md' : 'bg-white border-amber-100 text-amber-200'}`}>
                    {f.name}
                  </button>
                )
              })}
            </div>
          </div>
          <div className="flex gap-3 pt-2">
            <button onClick={handleSavePeriod} className="flex-[2] bg-emerald-600 text-white py-4 rounded-2xl font-black text-base shadow-lg shadow-emerald-200 active:scale-95 transition-all">保存周期配置</button>
            <button onClick={onCancel} className="flex-1 bg-gray-100 text-gray-500 py-4 rounded-2xl font-black text-sm active:bg-gray-200">取消</button>
          </div>
        </div>
      </div>
    </div>
  );

  const renderSessionForm = (periodId: string) => {
    const currentSubtotal = selectedAttendees.reduce((sum, a) => sum + a.fee, 0);

    return (
      <div className="fixed inset-0 z-[120] flex items-center justify-center p-6 animate-fade-in bg-black/60 backdrop-blur-sm" onClick={() => { setActiveSessionPeriod(null); setEditingSessionId(null); }}>
        <div className="w-full max-w-sm bg-white rounded-[2.5rem] p-6 shadow-2xl animate-fade-in max-h-[90vh] overflow-y-auto" onClick={e => e.stopPropagation()}>
          <h3 className="text-lg font-black text-gray-800 mb-6">{editingSessionId ? '✏️ 编辑打球记录' : '✨ 录入打球记录'}</h3>
          <div className="space-y-6">
            <div className="grid grid-cols-2 gap-3">
               <div>
                  <label className="block text-[10px] font-black text-gray-400 mb-1">活动日期</label>
                  <DatePicker selected={stringToDate(sessionFormDate)} onChange={(date) => setSessionFormDate(dateToString(date))} dateFormat="yyyy-MM-dd" className="w-full bg-gray-50 border border-gray-100 rounded-xl p-3 text-sm font-bold outline-none" />
               </div>
               <div>
                  <label className="block text-[10px] font-black text-gray-400 mb-1">额外费用(支)</label>
                  <input type="number" value={sessionFormCost || ''} onChange={e => setSessionFormCost(Number(e.target.value))} className="w-full bg-gray-50 border border-gray-100 rounded-xl p-3 text-sm font-bold outline-none text-red-500" placeholder="0.00" />
               </div>
            </div>

            <div>
              <p className="text-[10px] font-black text-gray-400 mb-2 uppercase tracking-widest">第一步：选择出席成员 ({selectedAttendees.length}):</p>
              <div className="flex flex-wrap gap-1.5 p-3 bg-gray-50 rounded-2xl border border-gray-100">
                {players.map(p => {
                  const isSelected = selectedAttendees.find(a => a.playerId === p.id);
                  return (
                    <button key={p.id} onClick={() => toggleAttendee(p, periodId)} className={`text-[10px] px-3 py-2 rounded-xl font-black transition-all border ${isSelected ? 'bg-emerald-600 border-emerald-700 text-white shadow-md' : 'bg-white border-gray-100 text-gray-400'}`}>
                      {p.name}
                    </button>
                  );
                })}
              </div>
            </div>

            {selectedAttendees.length > 0 && (
              <div>
                <p className="text-[10px] font-black text-gray-400 mb-2 uppercase tracking-widest">第二步：设置实收金额 (¥):</p>
                <div className="space-y-2 max-h-48 overflow-y-auto pr-1">
                  {selectedAttendees.map(attendee => {
                    const player = players.find(p => p.id === attendee.playerId);
                    return (
                      <div key={attendee.playerId} className="flex justify-between items-center bg-gray-50 p-2 rounded-xl border border-gray-100">
                        <span className="text-xs font-bold text-gray-700 ml-2">{player?.name}</span>
                        <div className="flex items-center gap-2">
                          <span className="text-[10px] text-gray-400 italic">实收 ¥</span>
                          <input 
                            type="number" 
                            value={attendee.fee} 
                            onChange={(e) => updateAttendeeFee(attendee.playerId, Number(e.target.value))}
                            className="w-16 bg-white border border-gray-200 rounded-lg p-1.5 text-xs font-black text-emerald-600 outline-none focus:ring-1 focus:ring-emerald-400"
                          />
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}

            <div className="bg-emerald-50 p-4 rounded-2xl border border-emerald-100">
               <div className="flex justify-between items-center">
                 <span className="text-[10px] font-black text-emerald-800 uppercase">本场预计实收:</span>
                 <span className="text-xl font-black text-emerald-600">¥{currentSubtotal.toFixed(2)}</span>
               </div>
            </div>

            <div className="flex gap-3 pt-2">
              <button onClick={() => saveSession(periodId)} className="flex-[2] bg-emerald-600 text-white py-4 rounded-2xl font-black text-sm active:scale-95 shadow-lg shadow-emerald-100">确认录入</button>
              <button onClick={() => { setActiveSessionPeriod(null); setEditingSessionId(null); }} className="flex-1 bg-gray-100 text-gray-500 py-4 rounded-2xl font-black text-sm">取消</button>
            </div>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="p-4 space-y-4 pb-32">
      <div className="px-1 mb-4 flex justify-between items-end">
        <div>
          <h2 className="text-2xl font-black text-gray-800">结算管理</h2>
          <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">Manage your sessions</p>
        </div>
        <div className="flex gap-2">
          <button onClick={() => setSortBy(sortBy === 'date' ? 'name' : 'date')} className="text-[10px] font-black px-3 py-1.5 bg-white border border-gray-100 rounded-full shadow-sm text-gray-500 active:bg-gray-50">
            {sortBy === 'date' ? '📅 时间' : '🔤 名称'}
          </button>
          <button onClick={() => setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc')} className="text-[10px] font-black px-2 py-1.5 bg-white border border-gray-100 rounded-full shadow-sm text-gray-500 active:bg-gray-50">
            {sortOrder === 'asc' ? '↑' : '↓'}
          </button>
        </div>
      </div>

      <div className="space-y-4">
        {sortedPeriods.map(period => {
          const isExpanded = expandedPeriodId === period.id;
          const totalIncome = period.sessions.reduce((acc, s) => acc + s.attendees.reduce((sum, a) => sum + a.fee, 0), 0);
          return (
            <div key={period.id} className={`bg-white rounded-[2rem] shadow-sm border border-gray-100 overflow-hidden transition-all ${isExpanded ? 'ring-2 ring-emerald-500/10 shadow-lg' : ''}`}>
              <div onClick={() => setExpandedPeriodId(isExpanded ? null : period.id)} className={`p-5 flex justify-between items-center cursor-pointer active:bg-gray-50 transition-colors ${isExpanded ? 'bg-emerald-50/20' : ''}`}>
                <div className="flex-1">
                  <div className="flex items-center gap-2 mb-1">
                    <h3 className="font-black text-gray-800 text-base">{period.name}</h3>
                    {(!period.endDate) && (
                      <span className="text-[8px] bg-emerald-500 text-white px-1.5 py-0.5 rounded-full font-black animate-pulse">进行中</span>
                    )}
                  </div>
                  <p className="text-[10px] text-gray-400 font-bold">{period.startDate} ~ {period.endDate || '至今'}</p>
                </div>
                <div className="flex items-center gap-2">
                   {/* 快速导出按钮 */}
                   <button 
                     onClick={(e) => { e.stopPropagation(); exportPeriodLedger(period); }}
                     className="p-2 text-gray-400 hover:text-emerald-600 active:scale-90 transition-all bg-gray-50 rounded-xl border border-gray-100"
                     title="导出流水"
                   >
                     <Icons.Download />
                   </button>
                   <div className="text-right ml-2">
                      <p className="text-[9px] text-gray-400 font-black">场次</p>
                      <p className="font-black text-emerald-600">{period.sessions.length}</p>
                   </div>
                   <div className={`transition-transform duration-300 ml-2 ${isExpanded ? 'rotate-180 text-emerald-500' : 'text-gray-300'}`}>
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M19 9l-7 7-7-7" /></svg>
                  </div>
                </div>
              </div>

              {isExpanded && (
                <div className="p-5 bg-gray-50/30 border-t border-gray-50 space-y-6 animate-fade-in">
                  <div className="grid grid-cols-2 gap-3">
                    <div className="bg-white p-4 rounded-2xl border border-gray-100">
                      <p className="text-[9px] font-black text-gray-400 uppercase mb-1">场地费总支</p>
                      <p className="text-lg font-black text-red-500">¥{(period.courtCost + period.sessions.reduce((a,s) => a+(s.sessionCost||0), 0)).toFixed(2)}</p>
                    </div>
                    <div className="bg-white p-4 rounded-2xl border border-gray-100">
                      <p className="text-[9px] font-black text-gray-400 uppercase mb-1">累计采集收入</p>
                      <p className="text-lg font-black text-emerald-600">¥{totalIncome.toFixed(2)}</p>
                    </div>
                  </div>
                  <div>
                    <div className="flex justify-between items-center mb-2 px-1">
                      <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">👑 集资名单</p>
                      <button onClick={(e) => { e.stopPropagation(); setEditingPeriodId(period.id); setPeriodFormData(period); }} className="text-[9px] text-emerald-600 font-black px-2 py-1 bg-emerald-50 rounded-lg">编辑周期</button>
                    </div>
                    <div className="flex flex-wrap gap-1.5 p-3 bg-white rounded-2xl border border-gray-100 shadow-sm">
                      {period.funderIds.map(fid => (
                        <span key={fid} className="text-[10px] bg-amber-50 text-amber-700 px-2.5 py-1 rounded-full font-black border border-amber-100">
                          {players.find(pl => pl.id === fid)?.name || '未知'}
                        </span>
                      ))}
                    </div>
                  </div>
                  <div className="pt-2">
                    <div className="flex justify-between items-center mb-3">
                      <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">🏸 打球流水</h4>
                      <div className="flex gap-2">
                        <button 
                          onClick={(e) => { e.stopPropagation(); 
                            setActiveSessionPeriod(period.id); 
                            setEditingSessionId(null); 
                            setSessionFormDate(new Date().toISOString().split('T')[0]); 
                            setSessionFormCost(0); 
                            setSelectedAttendees([]); 
                          }} 
                          className="text-[10px] bg-emerald-600 text-white px-4 py-2 rounded-xl font-black active:scale-95 shadow-lg shadow-emerald-100"
                        >
                          录入新记录
                        </button>
                      </div>
                    </div>
                    <div className="space-y-3">
                      {period.sessions.map(session => (
                        <div key={session.id} className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm">
                          <div className="flex justify-between items-center mb-2">
                             <div className="flex items-center gap-2">
                                <span className="text-xs font-black text-gray-800">{session.date}</span>
                                {session.sessionCost ? <span className="text-[8px] bg-red-100 text-red-600 px-1.5 py-0.5 rounded font-bold">加支 ¥{session.sessionCost}</span> : null}
                             </div>
                             <div className="flex gap-1 items-center">
                                <button onClick={(e) => { e.stopPropagation(); setActiveSessionPeriod(period.id); setEditingSessionId(session.id); setSessionFormDate(session.date); setSessionFormCost(session.sessionCost || 0); setSelectedAttendees(session.attendees); }} className="text-gray-300 p-1.5 active:text-emerald-500"><Icons.Pencil /></button>

                                <button 
                                  onClick={(e) => handleRemoveSession(e, period.id, session.id)} 
                                  className={`transition-all duration-200 rounded-lg flex items-center justify-center p-1.5 ${
                                    sessionConfirmDeleteId === session.id 
                                      ? 'bg-red-500 text-white px-3' 
                                      : 'text-gray-300 hover:text-red-500'
                                  }`}
                                >
                                  {sessionConfirmDeleteId === session.id ? (
                                    <span className="text-[9px] font-black whitespace-nowrap">确认删除？</span>
                                  ) : (
                                    <Icons.Trash />
                                  )}
                                </button>
                             </div>
                          </div>
                          <div className="flex flex-wrap gap-1">
                            {session.attendees.map(a => (
                              <span key={a.playerId} className="text-[9px] bg-gray-50 text-gray-500 px-2 py-0.5 rounded border border-gray-100">
                                {players.find(pl => pl.id === a.playerId)?.name} {a.fee > 0 ? `(¥${a.fee})` : ''}
                              </span>
                            ))}
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                  <div className="pt-4 border-t border-gray-100 flex justify-center">
                    <button 
                      onClick={(e) => handleConfirmDeletePeriod(e, period.id)}
                      className="text-[10px] text-red-300 font-bold flex items-center gap-1 active:scale-95 transition-transform"
                    >
                      <Icons.Trash /> 永久移除此周期
                    </button>
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>

      <button onClick={() => { setIsAddingPeriod(true); setEditingPeriodId(null); setPeriodFormData(initialPeriodData); }} className="fixed bottom-24 right-6 w-14 h-14 bg-emerald-600 text-white rounded-full flex items-center justify-center shadow-2xl shadow-emerald-400 z-50 active:scale-90 transition-transform">
        <Icons.Plus />
      </button>

      {isAddingPeriod && renderPeriodDrawer("创建结算周期", () => setIsAddingPeriod(false))}
      {editingPeriodId && renderPeriodDrawer("编辑周期配置", () => setEditingPeriodId(null))}
      {activeSessionPeriod && renderSessionForm(activeSessionPeriod)}
      {confirmDeletePeriodId && renderDeleteModal()}

      {periods.length === 0 && (
        <div className="text-center py-24 text-gray-300">
          <p className="text-5xl mb-4 opacity-10">🏸</p>
          <p className="text-sm font-black uppercase tracking-widest">尚未创建结算周期</p>
        </div>
      )}
    </div>
  );
};

export default PeriodsList;

import React, { useState, useMemo, useEffect } from 'react';
import DatePicker from 'react-datepicker';
import { Period, Player, Session, PlayerType } from '../types';
import { Icons, DEFAULT_SESSION_FEE } from '../constants';

interface PeriodsListProps {
  periods: Period[];
  setPeriods: React.Dispatch<React.SetStateAction<Period[]>>;
  players: Player[];
  setPlayers: React.Dispatch<React.SetStateAction<Player[]>>;
}

const PeriodsList: React.FC<PeriodsListProps> = ({ periods, setPeriods, players, setPlayers }) => {
  const [isAddingPeriod, setIsAddingPeriod] = useState(false);
  const [editingPeriodId, setEditingPeriodId] = useState<string | null>(null);
  const [expandedPeriodId, setExpandedPeriodId] = useState<string | null>(null);
  const [activeSessionPeriod, setActiveSessionPeriod] = useState<string | null>(null);
  const [editingSessionId, setEditingSessionId] = useState<string | null>(null);
  const [confirmDeletePeriodId, setConfirmDeletePeriodId] = useState<string | null>(null);
  const [sessionConfirmDeleteId, setSessionConfirmDeleteId] = useState<string | null>(null);

  const [sortBy, setSortBy] = useState<'date' | 'name'>('date');
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('desc');

  const funderPool = players.filter(p => p.isFunder);

  const initialPeriodData = {
    name: '',
    startDate: new Date().toISOString().split('T')[0],
    endDate: '',
    courtCost: 0,
    funderIds: funderPool.map(p => p.id),
    sessions: []
  };

  const [periodFormData, setPeriodFormData] = useState<Partial<Period>>(initialPeriodData);
  const [sessionFormDate, setSessionFormDate] = useState(new Date().toISOString().split('T')[0]);
  const [sessionFormCost, setSessionFormCost] = useState<number>(0);
  const [selectedAttendees, setSelectedAttendees] = useState<{playerId: string, fee: number}[]>([]);

  // 自动重置场次删除确认状态
  useEffect(() => {
    if (sessionConfirmDeleteId) {
      const timer = setTimeout(() => setSessionConfirmDeleteId(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [sessionConfirmDeleteId]);

  const sortedPeriods = useMemo(() => {
    return [...periods].sort((a, b) => {
      let comparison = 0;
      if (sortBy === 'date') {
        comparison = a.startDate.localeCompare(b.startDate);
      } else {
        comparison = a.name.localeCompare(b.name, 'zh-CN');
      }
      return sortOrder === 'asc' ? comparison : -comparison;
    });
  }, [periods, sortBy, sortOrder]);

  const stringToDate = (str: string | undefined) => {
    if (!str) return null;
    return new Date(str);
  };

  const dateToString = (date: Date | null) => {
    if (!date) return '';
    return date.toISOString().split('T')[0];
  };

  // --- 导出功能 ---

  const exportPeriodLedger = (period: Period) => {
    const BOM = "\ufeff";
    const headers = ['日期', '人员姓名', '实收金额(元)', '单场额外场地费(元)'];
    const rows: string[][] = [];

    const sortedSessions = [...period.sessions].sort((a, b) => b.date.localeCompare(a.date));

    sortedSessions.forEach(session => {
      session.attendees.forEach((a, idx) => {
        const playerName = players.find(p => p.id === a.playerId)?.name || '未知';
        rows.push([
          idx === 0 ? session.date : '',
          playerName,
          a.fee.toString(),
          idx === 0 ? (session.sessionCost || 0).toString() : ''
        ]);
      });
    });

    const csvContent = BOM + [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `${period.name}_流水记录.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // --- 周期管理核心逻辑 ---

  const handleSavePeriod = () => {
    if (!periodFormData.name) {
      alert('请输入周期名称');
      return;
    }
    const finalFunderIds = periodFormData.funderIds || [];
    if (editingPeriodId) {
      setPeriods(prev => prev.map(p => p.id === editingPeriodId ? { ...p, ...periodFormData } as Period : p));
      setEditingPeriodId(null);
    } else {
      const period: Period = {
        id: Date.now().toString(),
        name: periodFormData.name!,
        startDate: periodFormData.startDate!,
        endDate: periodFormData.endDate || '',
        courtCost: periodFormData.courtCost || 0,
        funderIds: finalFunderIds,
        sessions: []
      };
      setPeriods(prev => [period, ...prev]);
      setIsAddingPeriod(false);
    }
    setPeriodFormData(initialPeriodData);
  };

  const handleConfirmDeletePeriod = (e: React.MouseEvent, periodId: string) => {
    e.preventDefault();
    e.stopPropagation();
    setConfirmDeletePeriodId(periodId);
  };

  const handleDeletePeriodConfirmed = () => {
    if (!confirmDeletePeriodId) return;
    setPeriods(prev => prev.filter(p => p.id !== confirmDeletePeriodId));
    setConfirmDeletePeriodId(null);
    if (expandedPeriodId === confirmDeletePeriodId) setExpandedPeriodId(null);
  };

  // --- 打球场次核心逻辑 ---

  const handleRemoveSession = (e: React.MouseEvent, periodId: string, sessionId: string) => {
    e.preventDefault();
    e.stopPropagation();

    // 如果还没进入确认状态，则设为确认状态
    if (sessionConfirmDeleteId !== sessionId) {
      setSessionConfirmDeleteId(sessionId);
      return;
    }

    // 第二次点击，执行函数式更新确保 UI 同步
    setPeriods(prev => prev.map(p => {
      if (p.id === periodId) {
        return {
          ...p,
          sessions: p.sessions.filter(s => s.id !== sessionId)
        };
      }
      return p;
    }));
    setSessionConfirmDeleteId(null);
  };

  const saveSession = (periodId: string) => {
    if (selectedAttendees.length === 0) {
      alert('请至少选择一名出席成员');
      return;
    }
    if (editingSessionId) {
      setPeriods(prev => prev.map(p => p.id === periodId ? {
        ...p,
        sessions: p.sessions.map(s => s.id === editingSessionId ? { ...s, date: sessionFormDate, sessionCost: sessionFormCost, attendees: selectedAttendees } : s)
      } : p));
    } else {
      const session: Session = {
        id: Date.now().toString(),
        date: sessionFormDate,
        sessionCost: sessionFormCost,
        attendees: selectedAttendees
      };
      setPeriods(prev => prev.map(p => {
        if (p.id === periodId) {
          const newSessions = [session, ...p.sessions].sort((a, b) => b.date.localeCompare(a.date));
          return { ...p, sessions: newSessions };
        }
        return p;
      }));
    }
    setActiveSessionPeriod(null);
    setEditingSessionId(null);
  };

  const toggleAttendee = (player: Player, periodId: string) => {
    const exists = selectedAttendees.find(a => a.playerId === player.id);
    if (exists) {
      setSelectedAttendees(prev => prev.filter(a => a.playerId !== player.id));
    } else {
      const currentPeriod = periods.find(p => p.id === periodId);
      const isFunder = currentPeriod?.funderIds.includes(player.id);

      let defaultFee = DEFAULT_SESSION_FEE; // 默认 25 元

      if (isFunder) {
        // 如果是本期集资人，费用固定为 0
        defaultFee = 0;
      } else {
        // 凡是不是集资人的，在这个周期录入时一律默认 25 元
        defaultFee = DEFAULT_SESSION_FEE;
      }

      setSelectedAttendees(prev => [...prev, { playerId: player.id, fee: defaultFee }]);
    }
  };

  const updateAttendeeFee = (playerId: string, fee: number) => {
    setSelectedAttendees(prev => prev.map(a => a.playerId === playerId ? { ...a, fee } : a));
  };

  // --- 视图渲染辅助逻辑 ---

  const renderDeleteModal = () => {
    const period = periods.find(p => p.id === confirmDeletePeriodId);
    if (!period) return null;

    return (
      <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 animate-fade-in bg-black/60 backdrop-blur-md">
        <div className="w-full max-w-sm bg-white rounded-[2.5rem] p-8 shadow-2xl animate-fade-in">
          <div className="flex flex-col items-center text-center">
            <div className="w-16 h-16 bg-red-50 text-red-500 rounded-full flex items-center justify-center mb-4">
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
              </svg>
            </div>
            <h3 className="text-xl font-black text-gray-800 mb-2">确认删除周期？</h3>
            <div className="bg-red-50 rounded-2xl p-4 mb-6">
              <p className="text-xs text-red-600 font-bold leading-relaxed">
                删除周期 <span className="underline">"{period.name}"</span> 后，
                内部包含的 <span className="font-black">{period.sessions.length} 场打球记录</span> 将被永久清空。
              </p>
            </div>
          </div>
          <div className="flex flex-col gap-3">
            <button 
              onClick={handleDeletePeriodConfirmed} 
              className="w-full bg-red-600 text-white py-4 rounded-2xl font-black text-base shadow-lg shadow-red-200 active:scale-95 transition-all"
            >
              确认永久删除
            </button>
            <button 
              onClick={() => setConfirmDeletePeriodId(null)} 
              className="w-full bg-gray-100 text-gray-500 py-4 rounded-2xl font-black text-sm active:bg-gray-200"
            >
              取消
            </button>
          </div>
        </div>
      </div>
    );
