          </div>
          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-1">开始日期</label>
              <DatePicker selected={stringToDate(periodFormData.startDate)} onChange={(date) => setPeriodFormData({...periodFormData, startDate: dateToString(date)})} dateFormat="yyyy-MM-dd" className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm font-bold outline-none" />
